window.COURSE_REGISTRY = window.COURSE_REGISTRY || {};
window.COURSE_REGISTRY["c20-exam"] = [
  {"id":1,"sec":"Principles & Load Calculations","q":"An air conditioner provides 36,000 BTU/h of cooling and draws 3,000 watts. What is its EER?","opts":["6.0","12.0","9.0","18.0"],"correct":1,"re":"EER = cooling capacity (BTU/h) ÷ power input (watts) = 36,000 ÷ 3,000 = 12.0. EER rates steady-state efficiency at a fixed condition (95°F outdoor).","rr":"EER = мощность охлаждения (BTU/h) ÷ потребляемая мощность (ватт) = 36,000 ÷ 3,000 = 12.0. EER — КПД в установившемся режиме при фиксированных условиях (95°F снаружи).","qr":"Кондиционер даёт 36,000 BTU/h охлаждения и потребляет 3,000 ватт. Какой у него EER?","optsr":["6.0","12.0","9.0","18.0"],"qs":"Un aire acondicionado proporciona 36,000 BTU/h de enfriamiento y consume 3,000 watts. ¿Cuál es su EER?","optss":["6.0","12.0","9.0","18.0"],"rs":"EER = capacidad de enfriamiento (BTU/h) ÷ potencia de entrada (watts) = 36,000 ÷ 3,000 = 12.0. El EER califica la eficiencia en estado estable a una condición fija (95°F exterior)."},
  {"id":2,"sec":"Principles & Load Calculations","q":"One ton of refrigeration equals how many BTU/h?","opts":["15,000","6,000","10,000","12,000"],"correct":3,"re":"One ton of refrigeration = 12,000 BTU/h — the heat needed to melt one ton of ice in 24 hours (288,000 BTU ÷ 24 h).","rr":"Одна тонна (ton of refrigeration) = 12,000 BTU/h — тепло, нужное чтобы растопить одну тонну льда за 24 часа (288,000 BTU ÷ 24 ч).","qr":"Одна тонна холодопроизводительности (ton) равна скольким BTU/h?","optsr":["15,000","6,000","10,000","12,000"],"qs":"Una tonelada de refrigeración equivale a cuántos BTU/h?","optss":["15,000","6,000","10,000","12,000"],"rs":"Una tonelada de refrigeración = 12,000 BTU/h — el calor necesario para derretir una tonelada de hielo en 24 horas (288,000 BTU ÷ 24 h)."},
  {"id":3,"sec":"Principles & Load Calculations","q":"A common rule of thumb for residential cooling airflow is approximately how much CFM per ton?","opts":["200 CFM","400 CFM","100 CFM","800 CFM"],"correct":1,"re":"About 400 CFM per ton (range 350–450) is standard residential design airflow — lower (~350) for humid climates, higher (~450) for dry climates.","rr":"Около 400 CFM на тонну (диапазон 350–450) — стандартный проектный воздухопоток для жилья; меньше (~350) во влажном климате, больше (~450) в сухом.","qr":"Грубое правило для жилого охлаждения — сколько примерно CFM на тонну?","optsr":["200 CFM","400 CFM","100 CFM","800 CFM"],"qs":"Una regla general común para el flujo de aire de enfriamiento residencial es aproximadamente cuántos CFM por tonelada?","optss":["200 CFM","400 CFM","100 CFM","800 CFM"],"rs":"Alrededor de 400 CFM por tonelada (rango 350–450) es el flujo de aire de diseño residencial estándar — más bajo (~350) para climas húmedos, más alto (~450) para climas secos."},
  {"id":4,"sec":"Principles & Load Calculations","q":"Which formula calculates the sensible heat of an airstream?","opts":["Qs = 500 × GPM × ΔT","Qs = 1.08 × CFM × ΔT","Qs = 4.5 × CFM × Δh","Qs = 0.68 × CFM × Δgrains"],"correct":1,"re":"Sensible heat: Qs = 1.08 × CFM × ΔT(°F). The 1.08 factor combines air density and specific heat at standard conditions. 0.68 = latent (grains), 4.5 = total (enthalpy), 500 = water.","rr":"Явное тепло: Qs = 1.08 × CFM × ΔT(°F). Коэффициент 1.08 учитывает плотность и теплоёмкость воздуха при стандартных условиях. 0.68 — скрытое (grains), 4.5 — полное (enthalpy), 500 — вода.","qr":"Какая формула считает явное (sensible) тепло воздушного потока?","optsr":["Qs = 500 × GPM × ΔT","Qs = 1.08 × CFM × ΔT","Qs = 4.5 × CFM × Δh","Qs = 0.68 × CFM × Δgrains"],"qs":"¿Qué fórmula calcula el calor sensible de una corriente de aire?","optss":["Qs = 500 × GPM × ΔT","Qs = 1.08 × CFM × ΔT","Qs = 4.5 × CFM × Δh","Qs = 0.68 × CFM × Δgrains"],"rs":"Calor sensible: Qs = 1.08 × CFM × ΔT(°F). El factor 1.08 combina la densidad del aire y el calor específico en condiciones estándar. 0.68 = latente (granos), 4.5 = total (entalpía), 500 = agua."},
  {"id":5,"sec":"Principles & Load Calculations","q":"Total heat (sensible + latent) of an airstream is found using which factor?","opts":["4.5","0.68","1.08","60"],"correct":0,"re":"Total heat Qt = 4.5 × CFM × Δh (enthalpy, BTU/lb). 1.08 = sensible, 0.68 = latent (grains of moisture).","rr":"Полное тепло Qt = 4.5 × CFM × Δh (enthalpy, BTU/lb). 1.08 — явное, 0.68 — скрытое (по grains влаги).","qr":"Полное тепло (явное + скрытое) воздушного потока считают с каким коэффициентом?","optsr":["4.5","0.68","1.08","60"],"qs":"El calor total (sensible + latente) de una corriente de aire se obtiene usando cuál factor?","optss":["4.5","0.68","1.08","60"],"rs":"Calor total Qt = 4.5 × CFM × Δh (entalpía, BTU/lb). 1.08 = sensible, 0.68 = latente (granos de humedad)."},
  {"id":6,"sec":"Principles & Load Calculations","q":"ACCA Manual J is used to determine what?","opts":["Commercial load","Equipment model selection","Duct sizing","Residential heating and cooling load"],"correct":3,"re":"Manual J = Residential Load Calculation — it finds the building's heating/cooling load (BTU/h). Manual D = duct design, Manual S = equipment selection, Manual N = commercial load.","rr":"Manual J = Residential Load Calculation — определяет тепловую нагрузку здания (BTU/h). Manual D — воздуховоды, Manual S — подбор оборудования, Manual N — коммерческая нагрузка.","qr":"Для чего используется ACCA Manual J?","optsr":["Коммерческая нагрузка","Подбор модели оборудования","Подбор воздуховодов","Тепловая нагрузка жилья (отопление/охлаждение)"],"qs":"¿Para qué se usa el Manual J de ACCA?","optss":["Carga comercial","Selección del modelo de equipo","Dimensionamiento de ductos","Carga residencial de calefacción y enfriamiento"],"rs":"El Manual J = Cálculo de Carga Residencial — determina la carga de calefacción/enfriamiento del edificio (BTU/h). Manual D = diseño de ductos, Manual S = selección de equipo, Manual N = carga comercial."},
  {"id":7,"sec":"Principles & Load Calculations","q":"Which ACCA manual covers residential duct system design?","opts":["Manual D","Manual S","Manual P","Manual J"],"correct":0,"re":"Manual D = Residential Duct Systems. It sizes ducts using the available static pressure and the resulting friction rate.","rr":"Manual D = Residential Duct Systems. Подбирает воздуховоды по доступному статическому давлению и итоговому friction rate.","qr":"Какой ACCA manual описывает проектирование жилых воздуховодов?","optsr":["Manual D","Manual S","Manual P","Manual J"],"qs":"¿Qué manual de ACCA cubre el diseño del sistema de ductos residencial?","optss":["Manual D","Manual S","Manual P","Manual J"],"rs":"Manual D = Sistemas de Ductos Residenciales. Dimensiona los ductos usando la presión estática disponible y la tasa de fricción resultante."},
  {"id":8,"sec":"Principles & Load Calculations","q":"After calculating the load, which ACCA manual guides correct equipment selection?","opts":["Manual S","Manual D","Manual J","Manual N"],"correct":0,"re":"Manual S = Residential Equipment Selection — it matches equipment capacity to the Manual J load so the system isn't oversized.","rr":"Manual S = Residential Equipment Selection — подбирает мощность оборудования под нагрузку из Manual J, чтобы не было oversizing.","qr":"После расчёта нагрузки какой ACCA manual ведёт правильный подбор оборудования?","optsr":["Manual S","Manual D","Manual J","Manual N"],"qs":"Después de calcular la carga, ¿qué manual de ACCA guía la selección correcta del equipo?","optss":["Manual S","Manual D","Manual J","Manual N"],"rs":"Manual S = Selección de Equipo Residencial — ajusta la capacidad del equipo a la carga del Manual J para que el sistema no quede sobredimensionado."},
  {"id":9,"sec":"Principles & Load Calculations","q":"How does SEER differ from EER?","opts":["SEER measures airflow","SEER applies only to heat pumps","SEER is measured at full load only","SEER is a seasonal average over a range of conditions"],"correct":3,"re":"SEER (Seasonal Energy Efficiency Ratio) averages efficiency across a cooling season and varying outdoor temps; EER is a single steady-state rating at 95°F. SEER is higher than EER for the same unit.","rr":"SEER (Seasonal EER) усредняет КПД за сезон при разной наружной температуре; EER — одна точка при 95°F. У одного и того же агрегата SEER выше, чем EER.","qr":"Чем SEER отличается от EER?","optsr":["SEER измеряет воздухопоток","SEER только для тепловых насосов","SEER меряется только при полной нагрузке","SEER — сезонное среднее по диапазону условий"],"qs":"¿En qué se diferencia el SEER del EER?","optss":["El SEER mide el flujo de aire","El SEER se aplica solo a bombas de calor","El SEER se mide solo a plena carga","El SEER es un promedio estacional sobre un rango de condiciones"],"rs":"El SEER (Seasonal Energy Efficiency Ratio) promedia la eficiencia a lo largo de una temporada de enfriamiento y temperaturas exteriores variables; el EER es una calificación única en estado estable a 95°F. El SEER es más alto que el EER para la misma unidad."},
  {"id":10,"sec":"Principles & Load Calculations","q":"The coefficient of performance (COP) of a heat pump is defined as:","opts":["BTU ÷ ton","Heat output ÷ work input","CFM ÷ watts","Work input ÷ heat output"],"correct":1,"re":"COP = useful heat output ÷ energy input (same units). COP of 3 means 3 units of heat per unit of electricity. COP ≈ EER ÷ 3.412.","rr":"COP = полезное тепло на выходе ÷ затраченная энергия (в одних единицах). COP=3 значит 3 единицы тепла на 1 единицу электричества. COP ≈ EER ÷ 3.412.","qr":"Коэффициент эффективности (COP) теплового насоса определяется как:","optsr":["BTU ÷ тонна","Тепло на выходе ÷ работа на входе","CFM ÷ ватт","Работа на входе ÷ тепло на выходе"],"qs":"El coeficiente de rendimiento (COP) de una bomba de calor se define como:","optss":["BTU ÷ tonelada","Calor de salida ÷ trabajo de entrada","CFM ÷ watts","Trabajo de entrada ÷ calor de salida"],"rs":"COP = calor útil de salida ÷ energía de entrada (mismas unidades). Un COP de 3 significa 3 unidades de calor por unidad de electricidad. COP ≈ EER ÷ 3.412."},
  {"id":11,"sec":"Principles & Load Calculations","q":"On a psychrometric chart, the moisture in the air relative to the maximum it can hold at that temperature is called:","opts":["Wet-bulb temperature","Enthalpy","Dew point","Relative humidity"],"correct":3,"re":"Relative humidity (RH) = actual moisture ÷ maximum the air can hold at that dry-bulb temp, as a percent.","rr":"Relative humidity (RH) = фактическая влага ÷ максимум, который воздух может удержать при этой dry-bulb температуре, в процентах.","qr":"На психрометрической диаграмме влага в воздухе относительно максимума при данной температуре — это:","optsr":["Wet-bulb температура","Enthalpy","Точка росы (dew point)","Relative humidity (отн. влажность)"],"qs":"En una carta psicrométrica, la humedad en el aire en relación con el máximo que puede contener a esa temperatura se llama:","optss":["Temperatura de bulbo húmedo","Entalpía","Punto de rocío","Humedad relativa"],"rs":"Humedad relativa (HR) = humedad real ÷ máximo que el aire puede contener a esa temperatura de bulbo seco, como porcentaje."},
  {"id":12,"sec":"Principles & Load Calculations","q":"The temperature at which water vapor in the air begins to condense is the:","opts":["Dry-bulb temperature","Wet-bulb temperature","Design temperature","Dew point"],"correct":3,"re":"Dew point is where air becomes saturated (100% RH) and moisture condenses. Coil surfaces below dew point produce condensate (dehumidification).","rr":"Dew point — точка, где воздух насыщается (100% RH) и влага конденсируется. Поверхности испарителя ниже точки росы дают конденсат (осушение).","qr":"Температура, при которой пар в воздухе начинает конденсироваться, — это:","optsr":["Dry-bulb температура","Wet-bulb температура","Проектная температура","Dew point (точка росы)"],"qs":"La temperatura a la cual el vapor de agua en el aire comienza a condensarse es el:","optss":["Temperatura de bulbo seco","Temperatura de bulbo húmedo","Temperatura de diseño","Punto de rocío"],"rs":"El punto de rocío es donde el aire se satura (100% HR) y la humedad se condensa. Las superficies del serpentín por debajo del punto de rocío producen condensado (deshumidificación)."},
  {"id":13,"sec":"Principles & Load Calculations","q":"A sling psychrometer is used to measure:","opts":["Refrigerant pressure","Airflow velocity","Wet-bulb and dry-bulb temperatures","Static pressure"],"correct":2,"re":"A sling psychrometer reads dry-bulb and wet-bulb; the wet-bulb depression gives RH and dew point on the psychrometric chart.","rr":"Sling psychrometer показывает dry-bulb и wet-bulb; разница (wet-bulb depression) даёт RH и точку росы по психрометрической диаграмме.","qr":"Sling psychrometer используется для измерения:","optsr":["Давления хладагента","Скорости воздуха","Wet-bulb и dry-bulb температур","Статического давления"],"qs":"Un psicrómetro de honda se usa para medir:","optss":["Presión del refrigerante","Velocidad del flujo de aire","Temperaturas de bulbo húmedo y bulbo seco","Presión estática"],"rs":"Un psicrómetro de honda lee el bulbo seco y el bulbo húmedo; la depresión del bulbo húmedo da la HR y el punto de rocío en la carta psicrométrica."},
  {"id":14,"sec":"Principles & Load Calculations","q":"Outdoor design conditions for load calculations are typically based on:","opts":["A code-mandated 110°F","The single hottest day on record","The average yearly temperature","ASHRAE/ACCA 1% and 99% design values"],"correct":3,"re":"Manual J uses ASHRAE statistical design conditions (e.g., 1% summer, 99% winter) so equipment is sized for typical extremes, not record extremes — avoiding oversizing.","rr":"Manual J использует статистические условия ASHRAE (напр., 1% лето, 99% зима), чтобы подобрать под типичные экстремумы, а не рекордные — это исключает oversizing.","qr":"Наружные расчётные условия для load calc обычно берут из:","optsr":["Обязательных по коду 110°F","Самого жаркого дня в истории","Среднегодовой температуры","Значений ASHRAE/ACCA 1% и 99%"],"qs":"Las condiciones de diseño exterior para los cálculos de carga normalmente se basan en:","optss":["Un valor de 110°F obligatorio por código","El día más caluroso registrado","La temperatura promedio anual","Los valores de diseño del 1% y 99% de ASHRAE/ACCA"],"rs":"El Manual J usa condiciones de diseño estadísticas de ASHRAE (p. ej., 1% verano, 99% invierno) para que el equipo se dimensione para extremos típicos, no extremos récord — evitando el sobredimensionamiento."},
  {"id":15,"sec":"Principles & Load Calculations","q":"A residential air handler is typically rated for a total external static pressure (TESP) of about:","opts":["5.0 in. w.c.","0.5 in. w.c.","0.05 in. w.c.","15 in. w.c."],"correct":1,"re":"Most residential air handlers/furnaces are rated near 0.5 in. w.c. TESP. Measured static above this signals restrictive ducts, a dirty filter, or undersized returns.","rr":"Большинство жилых air handler/печей рассчитаны на ~0.5 in. w.c. TESP. Замеренный статик выше — признак узких воздуховодов, грязного фильтра или малого return.","qr":"Жилой воздухообрабатывающий агрегат обычно рассчитан на TESP около:","optsr":["5.0 in. w.c.","0.5 in. w.c.","0.05 in. w.c.","15 in. w.c."],"qs":"Un manejador de aire residencial normalmente está clasificado para una presión estática externa total (TESP) de aproximadamente:","optss":["5.0 in. w.c.","0.5 in. w.c.","0.05 in. w.c.","15 in. w.c."],"rs":"La mayoría de los manejadores de aire/calefactores residenciales están clasificados cerca de 0.5 in. w.c. de TESP. Una presión estática medida por encima de esto indica ductos restrictivos, un filtro sucio o retornos subdimensionados."},
  {"id":16,"sec":"Principles & Load Calculations","q":"In the equal-friction duct design method, the friction rate is expressed in:","opts":["BTU per hour","CFM per ton","Inches of water column per 100 ft","Degrees per foot"],"correct":2,"re":"Friction rate is in inches of water column per 100 ft of duct. Manual D derives it from available static pressure and total effective length.","rr":"Friction rate — в дюймах вод. ст. (in. w.c.) на 100 футов воздуховода. Manual D выводит его из доступного статического давления и общей эффективной длины.","qr":"В методе equal-friction для воздуховодов friction rate выражается в:","optsr":["BTU в час","CFM на тонну","Дюймах вод. ст. на 100 футов","Градусах на фут"],"qs":"En el método de diseño de ductos de fricción igual, la tasa de fricción se expresa en:","optss":["BTU por hora","CFM por tonelada","Pulgadas de columna de agua por 100 ft","Grados por pie"],"rs":"La tasa de fricción se expresa en pulgadas de columna de agua por 100 ft de ducto. El Manual D la deriva de la presión estática disponible y la longitud efectiva total."},
  {"id":17,"sec":"Principles & Load Calculations","q":"Recommended air velocity in residential main supply trunks is generally:","opts":["700–900 fpm","2,000–2,500 fpm","100–300 fpm","4,000+ fpm"],"correct":0,"re":"Residential supply trunks run roughly 700–900 fpm (branches lower) to limit noise and friction; commercial systems use higher velocities.","rr":"В жилых supply-магистралях обычно 700–900 fpm (ветки ниже), чтобы ограничить шум и трение; в коммерции скорости выше.","qr":"Рекомендуемая скорость воздуха в магистральных supply-воздуховодах жилья обычно:","optsr":["700–900 fpm","2,000–2,500 fpm","100–300 fpm","4,000+ fpm"],"qs":"La velocidad del aire recomendada en los troncales de suministro principales residenciales es generalmente:","optss":["700–900 fpm","2,000–2,500 fpm","100–300 fpm","4,000+ fpm"],"rs":"Los troncales de suministro residenciales funcionan aproximadamente entre 700–900 fpm (las ramas más bajas) para limitar el ruido y la fricción; los sistemas comerciales usan velocidades más altas."},
  {"id":18,"sec":"Principles & Load Calculations","q":"To estimate nominal tonnage from design airflow, you divide CFM by approximately:","opts":["400","12,000","200","100"],"correct":0,"re":"At ~400 CFM/ton, tonnage ≈ CFM ÷ 400 (e.g., 1,600 CFM ÷ 400 ≈ 4 tons). This is airflow-based; actual capacity comes from a Manual J load.","rr":"При ~400 CFM/тонну тоннаж ≈ CFM ÷ 400 (напр., 1,600 ÷ 400 ≈ 4 тонны). Это по воздуху; реальная мощность — из Manual J.","qr":"Чтобы оценить номинальную тоннажность по проектному воздухопотоку, CFM делят примерно на:","optsr":["400","12,000","200","100"],"qs":"Para estimar el tonelaje nominal a partir del flujo de aire de diseño, se divide el CFM entre aproximadamente:","optss":["400","12,000","200","100"],"rs":"A ~400 CFM/tonelada, el tonelaje ≈ CFM ÷ 400 (p. ej., 1,600 CFM ÷ 400 ≈ 4 toneladas). Esto se basa en el flujo de aire; la capacidad real proviene de una carga del Manual J."},
  {"id":19,"sec":"Principles & Load Calculations","q":"Summer cooling load on a building is most affected by:","opts":["The furnace paint color","Duct length alone","Floor area only","Windows/solar gain, insulation, and infiltration"],"correct":3,"re":"Cooling load is driven by solar gain through glazing, conduction through walls/roof/insulation, infiltration, and internal gains (people, appliances) — all in Manual J.","rr":"Нагрузку охлаждения определяют солнечный приток через остекление, теплопередача через стены/крышу/утепление, инфильтрация и внутренние притоки (люди, приборы) — всё в Manual J.","qr":"На летнюю нагрузку охлаждения здания сильнее всего влияют:","optsr":["Цвет краски печи","Только длина воздуховодов","Только площадь пола","Окна/солнечный приток, утепление и инфильтрация"],"qs":"La carga de enfriamiento de verano en un edificio se ve más afectada por:","optss":["El color de la pintura del calefactor","Solo la longitud del ducto","Solo el área del piso","Ventanas/ganancia solar, aislamiento e infiltración"],"rs":"La carga de enfriamiento es impulsada por la ganancia solar a través de los vidrios, la conducción a través de paredes/techo/aislamiento, la infiltración y las ganancias internas (personas, electrodomésticos) — todo en el Manual J."},
  {"id":20,"sec":"Principles & Load Calculations","q":"Air infiltration into a building is commonly expressed as:","opts":["Air changes per hour (ACH)","BTU per ton","Microns","Static pressure"],"correct":0,"re":"Infiltration/ventilation is often given in ACH (air changes per hour) or CFM. Tighter homes have lower ACH and a lower infiltration load.","rr":"Инфильтрацию/вентиляцию часто задают в ACH (воздухообмен в час) или CFM. У более герметичных домов ниже ACH и меньше нагрузка от инфильтрации.","qr":"Инфильтрацию воздуха в здание обычно выражают в:","optsr":["Воздухообменах в час (ACH)","BTU на тонну","Микронах","Статическом давлении"],"qs":"La infiltración de aire en un edificio comúnmente se expresa como:","optss":["Cambios de aire por hora (ACH)","BTU por tonelada","Micrones","Presión estática"],"rs":"La infiltración/ventilación a menudo se da en ACH (cambios de aire por hora) o CFM. Las casas más herméticas tienen menor ACH y una menor carga de infiltración."},
  {"id":21,"sec":"Principles & Load Calculations","q":"An undersized return air grille will most likely cause:","opts":["Lower amp draw","Increased SEER","Low head pressure","High static pressure and reduced airflow"],"correct":3,"re":"Undersized returns raise static pressure, starve the blower, cut airflow (CFM), and can freeze the coil and raise energy use.","rr":"Малый return повышает статическое давление, «душит» вентилятор, снижает CFM и может приводить к обмерзанию испарителя и росту энергопотребления.","qr":"Недостаточный по размеру return-грилль скорее всего вызовет:","optsr":["Снижение тока (amp)","Рост SEER","Низкое head давление","Высокий статик и снижение воздухопотока"],"qs":"Una rejilla de aire de retorno subdimensionada probablemente causará:","optss":["Menor consumo de amperios","Aumento del SEER","Baja presión de descarga","Alta presión estática y reducción del flujo de aire"],"rs":"Los retornos subdimensionados elevan la presión estática, ahogan el soplador, reducen el flujo de aire (CFM) y pueden congelar el serpentín y aumentar el uso de energía."},
  {"id":22,"sec":"Principles & Load Calculations","q":"A nominal 4-ton air conditioner has a rated cooling capacity of:","opts":["24,000 BTU/h","36,000 BTU/h","60,000 BTU/h","48,000 BTU/h"],"correct":3,"re":"4 tons × 12,000 BTU/h = 48,000 BTU/h nominal cooling capacity.","rr":"4 тонны × 12,000 BTU/h = 48,000 BTU/h номинальной холодопроизводительности.","qr":"Номинальный 4-тонный кондиционер имеет холодопроизводительность:","optsr":["24,000 BTU/h","36,000 BTU/h","60,000 BTU/h","48,000 BTU/h"],"qs":"Un aire acondicionado nominal de 4 toneladas tiene una capacidad de enfriamiento clasificada de:","optss":["24,000 BTU/h","36,000 BTU/h","60,000 BTU/h","48,000 BTU/h"],"rs":"4 toneladas × 12,000 BTU/h = 48,000 BTU/h de capacidad de enfriamiento nominal."},
  {"id":23,"sec":"Principles & Load Calculations","q":"A complete job estimate should include material, labor, overhead, and:","opts":["Profit (markup)","Only sales tax","Refrigerant only","The customer's utility bill"],"correct":0,"re":"A complete estimate covers material, labor, equipment, overhead, permits, and a profit markup. Omitting overhead/profit leads to losses.","rr":"Полная смета учитывает материалы, труд, оборудование, накладные, разрешения и наценку-прибыль. Без накладных/прибыли — убытки.","qr":"Полная смета по объекту должна включать материалы, труд, накладные и:","optsr":["Прибыль (markup)","Только налог с продаж","Только хладагент","Счёт клиента за коммуналку"],"qs":"Un presupuesto de trabajo completo debe incluir material, mano de obra, gastos generales y:","optss":["Ganancia (margen)","Solo el impuesto sobre las ventas","Solo refrigerante","La factura de servicios públicos del cliente"],"rs":"Un presupuesto completo cubre material, mano de obra, equipo, gastos generales, permisos y un margen de ganancia. Omitir los gastos generales/ganancia conduce a pérdidas."},
  {"id":24,"sec":"Principles & Load Calculations","q":"Oversizing an air conditioner most commonly results in:","opts":["Higher SEER","Short cycling and poor humidity control","Lower installation cost","Better dehumidification"],"correct":1,"re":"An oversized unit short-cycles: it hits setpoint before removing enough moisture, leaving the space cold and clammy. Manual J/S sizing prevents this.","rr":"Завышенный агрегат работает короткими циклами: достигает уставки раньше, чем убирает влагу — холодно и сыро. Подбор по Manual J/S это предотвращает.","qr":"Завышение мощности (oversizing) кондиционера чаще всего ведёт к:","optsr":["Более высокому SEER","Short cycling и плохому контролю влажности","Меньшей стоимости монтажа","Лучшему осушению"],"qs":"El sobredimensionamiento de un aire acondicionado más comúnmente resulta en:","optss":["Mayor SEER","Ciclos cortos y mal control de humedad","Menor costo de instalación","Mejor deshumidificación"],"rs":"Una unidad sobredimensionada hace ciclos cortos: alcanza el punto de ajuste antes de remover suficiente humedad, dejando el espacio frío y húmedo. El dimensionamiento según Manual J/S evita esto."},
  {"id":25,"sec":"Principles & Load Calculations","q":"On a psychrometric chart, lines of constant enthalpy run nearly parallel to lines of constant:","opts":["Dry-bulb temperature","Relative humidity","Dew point","Wet-bulb temperature"],"correct":3,"re":"Constant-enthalpy lines closely follow constant wet-bulb lines, which is why wet-bulb is a good index of total heat content.","rr":"Линии постоянной enthalpy почти совпадают с линиями постоянной wet-bulb — поэтому wet-bulb хороший индикатор полного теплосодержания.","qr":"На психрометрической диаграмме линии постоянной enthalpy почти параллельны линиям постоянной:","optsr":["Dry-bulb температуры","Relative humidity","Точки росы","Wet-bulb температуры"],"qs":"En una carta psicrométrica, las líneas de entalpía constante corren casi paralelas a las líneas de:","optss":["Temperatura de bulbo seco constante","Humedad relativa constante","Punto de rocío constante","Temperatura de bulbo húmedo constante"],"rs":"Las líneas de entalpía constante siguen de cerca las líneas de bulbo húmedo constante, razón por la cual el bulbo húmedo es un buen índice del contenido total de calor."},
  {"id":26,"sec":"Fabrication & Installation","q":"Joining copper refrigerant tubing on a high-pressure system is normally done by:","opts":["Compression fittings only","Soldering below 840°F","Brazing above 840°F","Gluing"],"correct":2,"re":"Refrigerant joints are brazed with filler melting above 840°F (often ~1,150°F) for strength under high pressure. Soldering (<840°F) is too weak for refrigerant lines.","rr":"Соединения хладагента паяют brazing с припоем, плавящимся выше 840°F (часто ~1,150°F) — для прочности под высоким давлением. Мягкая пайка (<840°F) слишком слаба.","qr":"Соединение медных трубок хладагента на системе высокого давления обычно делают:","optsr":["Только обжимными фитингами","Пайкой мягким припоем ниже 840°F","Brazing (твёрдой пайкой) выше 840°F","Клеем"],"qs":"Unir tubería de cobre para refrigerante en un sistema de alta presión normalmente se hace mediante:","optss":["Solo accesorios de compresión","Soldadura blanda por debajo de 840°F","Soldadura fuerte por encima de 840°F","Pegamento"],"rs":"Las uniones de refrigerante se sueldan con soldadura fuerte con material de aporte que funde por encima de 840°F (a menudo ~1,150°F) para resistir bajo alta presión. La soldadura blanda (<840°F) es demasiado débil para las líneas de refrigerante."},
  {"id":27,"sec":"Fabrication & Installation","q":"Why is dry nitrogen flowed through tubing while brazing refrigerant lines?","opts":["To add charge","To test for leaks","To prevent internal oxidation/scale","To cool the joint"],"correct":2,"re":"Flowing nitrogen purges oxygen so no copper oxide (black scale) forms inside the tubing. Scale can clog metering devices and contaminate the system.","rr":"Продувка азотом вытесняет кислород, и внутри трубки не образуется оксид меди (чёрная окалина). Окалина забивает дозаторы и загрязняет систему.","qr":"Зачем при brazing продувают трубки сухим азотом (nitrogen)?","optsr":["Чтобы добавить заправку","Чтобы найти течь","Чтобы не было внутреннего окисления/окалины","Чтобы охладить шов"],"qs":"¿Por qué se hace fluir nitrógeno seco a través de la tubería al hacer soldadura fuerte en las líneas de refrigerante?","optss":["Para agregar carga","Para detectar fugas","Para prevenir la oxidación/escamas internas","Para enfriar la unión"],"rs":"Hacer fluir nitrógeno purga el oxígeno para que no se forme óxido de cobre (escama negra) dentro de la tubería. La escama puede obstruir los dispositivos de medición y contaminar el sistema."},
  {"id":28,"sec":"Fabrication & Installation","q":"A deep vacuum on a refrigerant system is typically pulled to about:","opts":["0 psig","500 microns","28 in. Hg","5 psig"],"correct":1,"re":"Target ~500 microns (and the system holds it) to remove moisture and noncondensables. A micron gauge — not a compound gauge — confirms the level.","rr":"Цель — ~500 микрон (и система держит), чтобы убрать влагу и неконденсируемые газы. Уровень подтверждает micron gauge, а не обычный манометр.","qr":"Глубокий вакуум в системе хладагента обычно тянут примерно до:","optsr":["0 psig","500 микрон","28 in. Hg","5 psig"],"qs":"Un vacío profundo en un sistema de refrigerante normalmente se logra hasta aproximadamente:","optss":["0 psig","500 micrones","28 in. Hg","5 psig"],"rs":"El objetivo es ~500 micrones (y que el sistema lo mantenga) para remover la humedad y los no condensables. Un medidor de micrones — no un manómetro compuesto — confirma el nivel."},
  {"id":29,"sec":"Fabrication & Installation","q":"Moisture left in a refrigerant system can combine with refrigerant and oil to form:","opts":["Acids and sludge","Pure water vapor only","Nitrogen","Extra capacity"],"correct":0,"re":"Moisture reacts with refrigerant and oil to form acids that corrode components and damage the compressor — why evacuation and a filter-drier matter.","rr":"Влага реагирует с хладагентом и маслом, образуя кислоты, которые корродируют узлы и убивают компрессор — поэтому важны вакуумирование и filter-drier.","qr":"Влага, оставшаяся в системе, в сочетании с хладагентом и маслом образует:","optsr":["Кислоты и шлам","Только чистый водяной пар","Азот","Дополнительную мощность"],"qs":"La humedad que queda en un sistema de refrigerante puede combinarse con el refrigerante y el aceite para formar:","optss":["Ácidos y lodos","Solo vapor de agua puro","Nitrógeno","Capacidad adicional"],"rs":"La humedad reacciona con el refrigerante y el aceite para formar ácidos que corroen los componentes y dañan el compresor — por eso son importantes la evacuación y un filtro deshidratador."},
  {"id":30,"sec":"Fabrication & Installation","q":"In a split system, the larger-diameter, insulated refrigerant line is the:","opts":["Liquid line","Hot gas bypass","Suction (vapor) line","Drain line"],"correct":2,"re":"The suction line carries cool low-pressure vapor to the compressor; it's larger and insulated to prevent heat gain and sweating. The liquid line is smaller and uninsulated.","rr":"Suction line несёт холодный пар низкого давления к компрессору; она толще и изолирована, чтобы не было нагрева и конденсата. Liquid line тоньше и без изоляции.","qr":"В сплит-системе бóльшая по диаметру, изолированная трубка хладагента — это:","optsr":["Liquid line (жидкостная)","Hot gas bypass","Suction (паровая) line","Дренаж"],"qs":"En un sistema dividido, la línea de refrigerante de mayor diámetro y aislada es la:","optss":["Línea de líquido","Bypass de gas caliente","Línea de succión (vapor)","Línea de drenaje"],"rs":"La línea de succión transporta vapor frío de baja presión al compresor; es más grande y está aislada para prevenir la ganancia de calor y el sudor. La línea de líquido es más pequeña y sin aislamiento."},
  {"id":31,"sec":"Fabrication & Installation","q":"A condensate drain from a cooling coil should include a:","opts":["P-trap","Relief valve","Check valve","Pressure switch"],"correct":0,"re":"A P-trap stops blower pressure from pulling air in or pushing it out through the drain, lets condensate flow, and blocks odors/air bypass.","rr":"P-trap не даёт давлению вентилятора подсасывать или выдувать воздух через дренаж, обеспечивает сток конденсата и блокирует запахи/перетоки воздуха.","qr":"Дренаж конденсата от испарителя должен включать:","optsr":["P-trap (сифон)","Предохранительный клапан","Обратный клапан","Реле давления"],"qs":"Un drenaje de condensado de un serpentín de enfriamiento debe incluir un:","optss":["Sifón en P (P-trap)","Válvula de alivio","Válvula de retención","Interruptor de presión"],"rs":"Un sifón en P (P-trap) impide que la presión del soplador succione aire hacia adentro o lo empuje hacia afuera a través del drenaje, permite que el condensado fluya y bloquea olores/derivación de aire."},
  {"id":32,"sec":"Fabrication & Installation","q":"Minimum slope for a horizontal condensate drain line is generally:","opts":["Uphill","1 in. per foot","No slope needed","1/8 in. per foot"],"correct":3,"re":"At least 1/8 in. per foot (about 1%) toward the drain so condensate flows by gravity and doesn't pool, which causes overflow and microbial growth.","rr":"Не менее 1/8 in. на фут (~1%) в сторону слива, чтобы конденсат шёл самотёком и не застаивался (иначе перелив и рост биоплёнки).","qr":"Минимальный уклон горизонтальной дренажной линии конденсата обычно:","optsr":["Вверх","1 in. на фут","Уклон не нужен","1/8 in. на фут"],"qs":"La pendiente mínima para una línea de drenaje de condensado horizontal es generalmente:","optss":["Cuesta arriba","1 in. por pie","No se necesita pendiente","1/8 in. por pie"],"rs":"Al menos 1/8 in. por pie (alrededor del 1%) hacia el drenaje para que el condensado fluya por gravedad y no se acumule, lo que causa desbordamiento y crecimiento microbiano."},
  {"id":33,"sec":"Fabrication & Installation","q":"The electrical disconnect for an outdoor condensing unit must be located:","opts":["Anywhere convenient","Within sight of the unit","In the attic","At the meter only"],"correct":1,"re":"NEC requires a disconnecting means within sight of and readily accessible to the equipment so a technician can lock it out before servicing.","rr":"NEC требует средство отключения в пределах видимости и в лёгком доступе у оборудования, чтобы техник мог сделать LOTO перед обслуживанием.","qr":"Электрический disconnect для наружного конденсатора должен находиться:","optsr":["Где удобно","В пределах видимости агрегата","На чердаке","Только у счётчика"],"qs":"El desconectador eléctrico para una unidad condensadora exterior debe ubicarse:","optss":["En cualquier lugar conveniente","A la vista de la unidad","En el ático","Solo en el medidor"],"rs":"El NEC requiere un medio de desconexión a la vista y de fácil acceso para el equipo, de modo que un técnico pueda bloquearlo antes de dar servicio."},
  {"id":34,"sec":"Fabrication & Installation","q":"On a condensing unit nameplate, MOCP refers to the:","opts":["Motor oil capacity","Maximum overcurrent protection (breaker/fuse)","Minimum circuit ampacity","Maximum operating pressure"],"correct":1,"re":"MOCP = Maximum Overcurrent Protection — the largest breaker/fuse allowed. MCA (Minimum Circuit Ampacity) sets the minimum wire size. Both must be followed.","rr":"MOCP = Maximum Overcurrent Protection — наибольший допустимый автомат/предохранитель. MCA (Minimum Circuit Ampacity) задаёт минимальное сечение провода. Соблюдают оба.","qr":"На шильдике конденсатора MOCP означает:","optsr":["Объём моторного масла","Макс. защита от сверхтока (автомат/предохранитель)","Минимальная токопроводимость цепи","Макс. рабочее давление"],"qs":"En la placa de datos de una unidad condensadora, MOCP se refiere a la:","optss":["Capacidad de aceite del motor","Protección máxima contra sobrecorriente (interruptor/fusible)","Ampacidad mínima del circuito","Presión máxima de operación"],"rs":"MOCP = Protección Máxima contra Sobrecorriente — el interruptor/fusible más grande permitido. La MCA (Ampacidad Mínima del Circuito) establece el tamaño mínimo del cable. Ambos deben respetarse."},
  {"id":35,"sec":"Fabrication & Installation","q":"A thermostatic expansion valve (TXV) controls refrigerant flow to maintain constant:","opts":["Head pressure","Subcooling","Condenser temperature","Evaporator superheat"],"correct":3,"re":"A TXV modulates to hold relatively constant evaporator superheat across loads, feeding the coil efficiently. A fixed orifice does not adjust.","rr":"TXV модулирует, удерживая относительно постоянный superheat испарителя при разной нагрузке, эффективно питая змеевик. Фиксированный orifice не подстраивается.","qr":"Терморегулирующий вентиль (TXV) регулирует поток хладагента, поддерживая постоянным:","optsr":["Head давление","Subcooling","Температуру конденсатора","Superheat испарителя"],"qs":"Una válvula de expansión termostática (TXV) controla el flujo de refrigerante para mantener constante:","optss":["La presión de descarga","El subenfriamiento","La temperatura del condensador","El sobrecalentamiento del evaporador"],"rs":"Una TXV modula para mantener un sobrecalentamiento del evaporador relativamente constante a través de las cargas, alimentando el serpentín eficientemente. Un orificio fijo no se ajusta."},
  {"id":36,"sec":"Fabrication & Installation","q":"A filter-drier is normally installed in the:","opts":["Condensate drain","Suction line near the compressor","Discharge line","Liquid line ahead of the metering device"],"correct":3,"re":"The liquid-line filter-drier removes moisture and debris and protects the metering device. The arrow on the drier must point in the flow direction.","rr":"Filter-drier на liquid line убирает влагу и мусор и защищает дозатор. Стрелка на drier должна смотреть по направлению потока.","qr":"Filter-drier обычно ставят в:","optsr":["Дренаж конденсата","Suction line у компрессора","Discharge line","Liquid line перед дозатором"],"qs":"Un filtro deshidratador normalmente se instala en la:","optss":["Línea de drenaje de condensado","Línea de succión cerca del compresor","Línea de descarga","Línea de líquido antes del dispositivo de medición"],"rs":"El filtro deshidratador de la línea de líquido remueve la humedad y los desechos y protege el dispositivo de medición. La flecha en el deshidratador debe apuntar en la dirección del flujo."},
  {"id":37,"sec":"Fabrication & Installation","q":"A system with a TXV is most accurately charged using the:","opts":["Box-weight guess","Superheat method","Subcooling method","Sight only"],"correct":2,"re":"TXV systems are charged by subcooling (liquid line), since the TXV already controls superheat. Fixed-orifice (piston) systems use the superheat method.","rr":"Системы с TXV заправляют по subcooling (liquid line), т.к. TXV уже держит superheat. Системы с фиксированным orifice (piston) — по методу superheat.","qr":"Систему с TXV точнее всего заправлять методом:","optsr":["На глаз по коробке","Superheat","Subcooling","Визуально"],"qs":"Un sistema con una TXV se carga con mayor precisión usando el:","optss":["Estimación del peso de la caja","Método de sobrecalentamiento","Método de subenfriamiento","Solo la vista"],"rs":"Los sistemas con TXV se cargan por subenfriamiento (línea de líquido), ya que la TXV ya controla el sobrecalentamiento. Los sistemas de orificio fijo (pistón) usan el método de sobrecalentamiento."},
  {"id":38,"sec":"Fabrication & Installation","q":"Superheat is the number of degrees a refrigerant vapor is heated:","opts":["Above its saturation (boiling) temperature","Below dew point","Above ambient","Below its condensing temperature"],"correct":0,"re":"Superheat = vapor temp − saturation temp at that pressure. It confirms all liquid has boiled off before the compressor, protecting it from slugging.","rr":"Superheat = темп. пара − темп. насыщения при этом давлении. Подтверждает, что вся жидкость выкипела до компрессора, защищая его от гидроудара.","qr":"Superheat — это число градусов, на которое пар хладагента нагрет:","optsr":["Выше температуры насыщения (кипения)","Ниже точки росы","Выше окружающей","Ниже температуры конденсации"],"qs":"El sobrecalentamiento es el número de grados que un vapor de refrigerante se calienta:","optss":["Por encima de su temperatura de saturación (ebullición)","Por debajo del punto de rocío","Por encima del ambiente","Por debajo de su temperatura de condensación"],"rs":"Sobrecalentamiento = temperatura del vapor − temperatura de saturación a esa presión. Confirma que todo el líquido se ha evaporado antes del compresor, protegiéndolo del golpe de líquido."},
  {"id":39,"sec":"Fabrication & Installation","q":"Subcooling is the number of degrees liquid refrigerant is cooled:","opts":["Above ambient","Above its saturation temperature","Below its condensing (saturation) temperature","Below the evaporator temperature"],"correct":2,"re":"Subcooling = saturation temp − liquid temp at the condenser/liquid line. Adequate subcooling ensures solid liquid feeds the metering device.","rr":"Subcooling = темп. насыщения − темп. жидкости на конденсаторе/liquid line. Достаточный subcooling гарантирует, что в дозатор идёт чистая жидкость.","qr":"Subcooling — это число градусов, на которое жидкий хладагент охлаждён:","optsr":["Выше окружающей","Выше температуры насыщения","Ниже температуры конденсации (насыщения)","Ниже температуры испарителя"],"qs":"El subenfriamiento es el número de grados que el refrigerante líquido se enfría:","optss":["Por encima del ambiente","Por encima de su temperatura de saturación","Por debajo de su temperatura de condensación (saturación)","Por debajo de la temperatura del evaporador"],"rs":"Subenfriamiento = temperatura de saturación − temperatura del líquido en el condensador/línea de líquido. Un subenfriamiento adecuado asegura que líquido sólido alimente el dispositivo de medición."},
  {"id":40,"sec":"Fabrication & Installation","q":"The correct instrument to verify a deep vacuum is a:","opts":["Micron (vacuum) gauge","Clamp ammeter","Manometer","Compound gauge"],"correct":0,"re":"A micron gauge reads the deep-vacuum range accurately; a standard compound gauge can't tell 1,000 from 25,000 microns.","rr":"Micron gauge точно показывает диапазон глубокого вакуума; обычный compound gauge не различит 1,000 и 25,000 микрон.","qr":"Правильный прибор для проверки глубокого вакуума — это:","optsr":["Micron (вакуумный) gauge","Токовые клещи","Манометр","Compound gauge"],"qs":"El instrumento correcto para verificar un vacío profundo es un:","optss":["Medidor de micrones (vacío)","Amperímetro de gancho","Manómetro","Manómetro compuesto"],"rs":"Un medidor de micrones lee el rango de vacío profundo con precisión; un manómetro compuesto estándar no puede distinguir 1,000 de 25,000 micrones."},
  {"id":41,"sec":"Fabrication & Installation","q":"Typical manifold (outlet) gas pressure for a natural-gas furnace is about:","opts":["11 in. w.c.","1 psi","3.5 in. w.c.","25 in. w.c."],"correct":2,"re":"Natural-gas furnaces run ~3.5 in. w.c. manifold pressure; LP (propane) runs ~10–11 in. w.c. Always set per the rating plate with a manometer.","rr":"Печи на природном газе — ~3.5 in. w.c. manifold; на LP (пропан) — ~10–11 in. w.c. Всегда выставляют по шильдику манометром.","qr":"Типичное manifold (выходное) давление газа для печи на природном газе:","optsr":["11 in. w.c.","1 psi","3.5 in. w.c.","25 in. w.c."],"qs":"La presión de gas del múltiple (salida) típica para un calefactor de gas natural es de aproximadamente:","optss":["11 in. w.c.","1 psi","3.5 in. w.c.","25 in. w.c."],"rs":"Los calefactores de gas natural funcionan a ~3.5 in. w.c. de presión del múltiple; el LP (propano) funciona a ~10–11 in. w.c. Siempre ajuste según la placa de clasificación con un manómetro."},
  {"id":42,"sec":"Fabrication & Installation","q":"Fuel-burning furnaces installed in a confined space require:","opts":["No special air","Adequate combustion and ventilation air","Only return air","A larger filter"],"correct":1,"re":"Combustion appliances need sufficient combustion/ventilation air per the Mechanical Code; too little air causes incomplete combustion, CO, and backdrafting.","rr":"Топливным приборам нужен достаточный воздух для горения/вентиляции по Mechanical Code; нехватка ведёт к неполному сгоранию, CO и обратной тяге.","qr":"Печи на топливе в стеснённом пространстве требуют:","optsr":["Никакого особого воздуха","Достаточного воздуха для горения и вентиляции","Только return-воздуха","Большего фильтра"],"qs":"Los calefactores que queman combustible instalados en un espacio confinado requieren:","optss":["Ningún aire especial","Aire adecuado de combustión y ventilación","Solo aire de retorno","Un filtro más grande"],"rs":"Los artefactos de combustión necesitan suficiente aire de combustión/ventilación según el Código Mecánico; muy poco aire causa combustión incompleta, CO y retroceso de tiro."},
  {"id":43,"sec":"Fabrication & Installation","q":"A standard mid-efficiency furnace using a Type-B vent is classified as:","opts":["Category III","Category I","Category IV","Category II"],"correct":1,"re":"Category I appliances vent with natural draft (non-positive, non-condensing) into a B-vent. Category IV (condensing, 90%+) uses sealed PVC venting.","rr":"Category I — естественная тяга (без избыточного давления, не конденсационная) в B-vent. Category IV (конденсационная, 90%+) — герметичный PVC vent.","qr":"Стандартная печь средней эффективности с Type-B vent относится к:","optsr":["Category III","Category I","Category IV","Category II"],"qs":"Un calefactor estándar de eficiencia media que usa un ducto de ventilación Tipo B se clasifica como:","optss":["Categoría III","Categoría I","Categoría IV","Categoría II"],"rs":"Los artefactos de Categoría I ventilan con tiro natural (no positivo, no condensante) hacia un ducto B. La Categoría IV (condensante, 90%+) usa ventilación sellada de PVC."},
  {"id":44,"sec":"Fabrication & Installation","q":"Per California Title 24, newly installed ducts in unconditioned space must be insulated to at least:","opts":["R-4","R-6 / R-8 (climate dependent)","R-2","No insulation"],"correct":1,"re":"Title 24 typically requires duct insulation of R-6 to R-8 depending on climate zone, plus duct-leakage sealing/testing on most alterations.","rr":"Title 24 обычно требует изоляцию воздуховодов R-6…R-8 в зависимости от климатической зоны, плюс герметизацию и тест на утечки при большинстве работ.","qr":"По California Title 24 новые воздуховоды в неконд. пространстве изолируют минимум до:","optsr":["R-4","R-6 / R-8 (по климату)","R-2","Без изоляции"],"qs":"Según el Título 24 de California, los ductos recién instalados en espacios no acondicionados deben aislarse al menos a:","optss":["R-4","R-6 / R-8 (depende del clima)","R-2","Sin aislamiento"],"rs":"El Título 24 normalmente requiere aislamiento de ductos de R-6 a R-8 según la zona climática, además del sellado/prueba de fugas de ductos en la mayoría de las alteraciones."},
  {"id":45,"sec":"Fabrication & Installation","q":"The preferred material for permanently sealing duct joints is:","opts":["Mastic (with mesh on gaps)","Spray paint","Caulk only","Cloth-backed (gray) duct tape"],"correct":0,"re":"Duct mastic (with fiberglass mesh on larger gaps) gives a durable, code-accepted seal. Standard cloth duct tape dries and fails; UL-181 tapes are allowed where listed.","rr":"Duct mastic (с сеткой на больших зазорах) даёт прочный и принимаемый кодом шов. Обычная тканевая лента пересыхает и отваливается; ленты UL-181 допустимы там, где сертифицированы.","qr":"Предпочтительный материал для постоянной герметизации стыков воздуховодов:","optsr":["Mastic (с mesh на зазорах)","Краска из баллона","Только герметик","Серая тканевая duct tape"],"qs":"El material preferido para sellar permanentemente las uniones de ductos es:","optss":["Mástique (con malla en los espacios)","Pintura en aerosol","Solo sellador (caulk)","Cinta de ducto (gris) con respaldo de tela"],"rs":"El mástique para ductos (con malla de fibra de vidrio en los espacios más grandes) da un sello duradero y aceptado por el código. La cinta de ducto de tela estándar se seca y falla; las cintas UL-181 se permiten donde estén certificadas."},
  {"id":46,"sec":"Fabrication & Installation","q":"Flexible duct should be supported at intervals not exceeding about:","opts":["4 ft","1 ft","12 ft","No support needed"],"correct":0,"re":"Flex duct is typically supported at intervals up to ~4 ft with max sag near 1/2 in. per foot of spacing, using wide straps to avoid pinching and airflow restriction.","rr":"Flex duct обычно поддерживают с шагом до ~4 футов, провис не более ~1/2 in. на фут шага, широкими хомутами — чтобы не пережать и не задушить поток.","qr":"Гибкий воздуховод (flex duct) поддерживают с интервалом не более примерно:","optsr":["4 фута","1 фут","12 футов","Опора не нужна"],"qs":"El ducto flexible debe soportarse a intervalos que no excedan aproximadamente:","optss":["4 ft","1 ft","12 ft","No se necesita soporte"],"rs":"El ducto flexible normalmente se soporta a intervalos de hasta ~4 ft con una flecha máxima cercana a 1/2 in. por pie de espaciamiento, usando correas anchas para evitar el pellizco y la restricción del flujo de aire."},
  {"id":47,"sec":"Fabrication & Installation","q":"Before opening a sealed refrigerant system for repair, the technician must first:","opts":["Cut the line open","Add refrigerant","Recover the refrigerant per EPA 608","Run the compressor"],"correct":2,"re":"EPA Section 608 requires recovering refrigerant into approved equipment before opening the system; venting to atmosphere is illegal.","rr":"EPA Section 608 требует откачать хладагент в одобренное оборудование до вскрытия; выпуск в атмосферу незаконен.","qr":"Перед вскрытием герметичной системы хладагента для ремонта техник должен сначала:","optsr":["Срезать линию","Добавить хладагент","Откачать (recover) хладагент по EPA 608","Запустить компрессор"],"qs":"Antes de abrir un sistema de refrigerante sellado para reparación, el técnico primero debe:","optss":["Cortar la línea para abrirla","Agregar refrigerante","Recuperar el refrigerante según EPA 608","Hacer funcionar el compresor"],"rs":"La Sección 608 de la EPA requiere recuperar el refrigerante en equipo aprobado antes de abrir el sistema; ventilarlo a la atmósfera es ilegal."},
  {"id":48,"sec":"Fabrication & Installation","q":"A normal cooling temperature split (return minus supply air) is about:","opts":["2–5°F","50°F+","14–22°F","30–40°F"],"correct":2,"re":"A properly charged system with correct airflow shows roughly a 14–22°F drop across the evaporator. Outside this range points to airflow or charge problems.","rr":"Правильно заправленная система с верным воздухопотоком даёт перепад ~14–22°F на испарителе. Вне диапазона — проблемы с воздухом или заправкой.","qr":"Нормальный temperature split при охлаждении (return минус supply) около:","optsr":["2–5°F","50°F+","14–22°F","30–40°F"],"qs":"Un diferencial de temperatura de enfriamiento normal (aire de retorno menos suministro) es de aproximadamente:","optss":["2–5°F","50°F+","14–22°F","30–40°F"],"rs":"Un sistema correctamente cargado con el flujo de aire correcto muestra una caída de aproximadamente 14–22°F a través del evaporador. Fuera de este rango apunta a problemas de flujo de aire o de carga."},
  {"id":49,"sec":"Fabrication & Installation","q":"On a typical low-voltage thermostat, the 'Y' terminal controls the:","opts":["Fan only","Common","Heat","Cooling (compressor) contactor"],"correct":3,"re":"Y = cooling call (energizes the compressor contactor). G = fan, W = heat, R = 24V power, C = common. Correct wiring is essential.","rr":"Y = вызов охлаждения (включает контактор компрессора). G = вентилятор, W = тепло, R = 24V питание, C = common. Правильная разводка обязательна.","qr":"На обычном низковольтном термостате клемма 'Y' управляет:","optsr":["Только вентилятором","Common","Отоплением","Cooling (контактор компрессора)"],"qs":"En un termostato típico de bajo voltaje, la terminal 'Y' controla el:","optss":["Solo el ventilador","Común","Calefacción","Contactor de enfriamiento (compresor)"],"rs":"Y = llamada de enfriamiento (energiza el contactor del compresor). G = ventilador, W = calefacción, R = energía de 24V, C = común. El cableado correcto es esencial."},
  {"id":50,"sec":"Fabrication & Installation","q":"A condensing unit should be set on a level pad primarily to:","opts":["Increase SEER","Improve appearance","Ensure proper compressor oil return and drainage","Reduce wire size"],"correct":2,"re":"A level unit ensures correct oil return to the compressor and proper water drainage; an unlevel pad causes oil migration and premature compressor failure.","rr":"Ровный агрегат обеспечивает правильный возврат масла в компрессор и сток воды; перекос ведёт к миграции масла и преждевременному выходу компрессора.","qr":"Конденсатор ставят на ровную площадку (pad) в первую очередь чтобы:","optsr":["Поднять SEER","Улучшить вид","Обеспечить возврат масла в компрессор и сток воды","Уменьшить сечение провода"],"qs":"Una unidad condensadora debe colocarse sobre una base nivelada principalmente para:","optss":["Aumentar el SEER","Mejorar la apariencia","Asegurar el retorno y drenaje correcto del aceite del compresor","Reducir el tamaño del cable"],"rs":"Una unidad nivelada asegura el retorno correcto del aceite al compresor y el drenaje adecuado del agua; una base desnivelada causa migración del aceite y falla prematura del compresor."},
  {"id":51,"sec":"Fabrication & Installation","q":"When silver-brazing near a service valve, the technician should:","opts":["Skip the nitrogen","Braze with the valve fully open and unprotected","Protect/cool the valve and keep nitrogen flowing","Pump down only"],"correct":2,"re":"Heat-sensitive valves should be protected (wet rag/heat sink) with nitrogen flowing to prevent seal damage and internal oxidation.","rr":"Теплочувствительные вентили защищают (мокрая ветошь/теплоотвод) и держат продувку азотом, чтобы не повредить уплотнения и не дать внутреннего окисления.","qr":"При brazing рядом с сервисным вентилем техник должен:","optsr":["Обойтись без азота","Паять с полностью открытым незащищённым вентилем","Защитить/охлаждать вентиль и продувать азотом","Только сделать pump down"],"qs":"Al hacer soldadura fuerte con plata cerca de una válvula de servicio, el técnico debe:","optss":["Omitir el nitrógeno","Soldar con la válvula completamente abierta y sin protección","Proteger/enfriar la válvula y mantener el nitrógeno fluyendo","Solo hacer pump down"],"rs":"Las válvulas sensibles al calor deben protegerse (trapo húmedo/disipador de calor) con nitrógeno fluyendo para prevenir daños en los sellos y oxidación interna."},
  {"id":52,"sec":"Fabrication & Installation","q":"Suction-line insulation is installed to:","opts":["Reduce noise only","Prevent heat gain and sweating on the cold line","Increase head pressure","Block sunlight only"],"correct":1,"re":"Insulating the cold suction line prevents heat gain (efficiency loss) and condensation that drips and causes damage.","rr":"Изоляция холодной suction-линии предотвращает нагрев (потеря КПД) и конденсат, который капает и портит конструкции.","qr":"Изоляцию suction-линии ставят, чтобы:","optsr":["Только снизить шум","Не допустить нагрева и конденсата на холодной линии","Поднять head давление","Только закрыть от солнца"],"qs":"El aislamiento de la línea de succión se instala para:","optss":["Solo reducir el ruido","Prevenir la ganancia de calor y el sudor en la línea fría","Aumentar la presión de descarga","Solo bloquear la luz solar"],"rs":"Aislar la línea de succión fría previene la ganancia de calor (pérdida de eficiencia) y la condensación que gotea y causa daños."},
  {"id":53,"sec":"Fabrication & Installation","q":"For sheet-metal duct, a lower gauge number means the metal is:","opts":["Always galvanized","The same thickness","Thicker","Thinner"],"correct":2,"re":"Lower gauge = thicker sheet metal. Larger ducts need heavier (lower-gauge) metal and reinforcement per SMACNA.","rr":"Меньший gauge = более толстый лист. Бóльшие воздуховоды требуют более толстого (меньший gauge) металла и усиления по SMACNA.","qr":"Для листового металла воздуховода меньший номер gauge означает металл:","optsr":["Всегда оцинкованный","Той же толщины","Толще","Тоньше"],"qs":"Para ducto de lámina metálica, un número de calibre más bajo significa que el metal es:","optss":["Siempre galvanizado","El mismo espesor","Más grueso","Más delgado"],"rs":"Calibre más bajo = lámina metálica más gruesa. Los ductos más grandes necesitan metal más pesado (calibre más bajo) y refuerzo según SMACNA."},
  {"id":54,"sec":"Fabrication & Installation","q":"During startup, verifying correct airflow before checking the charge matters because:","opts":["It saves refrigerant","Charge doesn't matter","Refrigerant readings are only valid at correct airflow","Airflow has no effect"],"correct":2,"re":"Pressures, superheat, and subcooling are only meaningful at proper airflow. Confirm airflow/temperature split first, then evaluate and adjust charge.","rr":"Давления, superheat и subcooling имеют смысл только при правильном воздухопотоке. Сначала подтверждают airflow/temperature split, затем оценивают и корректируют заправку.","qr":"При пуске сначала проверяют правильный воздухопоток, а потом заправку, потому что:","optsr":["Это экономит хладагент","Заправка не важна","Показания по хладагенту верны только при правильном воздухопотоке","Воздухопоток не влияет"],"qs":"Durante el arranque, verificar el flujo de aire correcto antes de revisar la carga es importante porque:","optss":["Ahorra refrigerante","La carga no importa","Las lecturas del refrigerante solo son válidas con el flujo de aire correcto","El flujo de aire no tiene efecto"],"rs":"Las presiones, el sobrecalentamiento y el subenfriamiento solo tienen sentido con el flujo de aire adecuado. Confirme primero el flujo de aire/diferencial de temperatura, luego evalúe y ajuste la carga."},
  {"id":55,"sec":"Service & Troubleshooting","q":"A frozen evaporator coil is most commonly caused by:","opts":["Low airflow or low refrigerant charge","High head pressure only","Too clean a filter","Oversized ducts"],"correct":0,"re":"Restricted airflow (dirty filter/coil, blower issue) or low charge drops coil temperature below freezing, icing it. Diagnose airflow first, then charge.","rr":"Зажатый воздухопоток (грязный фильтр/змеевик, вентилятор) или нехватка заправки опускают температуру змеевика ниже нуля. Сначала проверяют airflow, потом заправку.","qr":"Обмерзание испарителя чаще всего вызвано:","optsr":["Низким воздухопотоком или нехваткой хладагента","Только высоким head давлением","Слишком чистым фильтром","Слишком большими воздуховодами"],"qs":"Un serpentín del evaporador congelado es causado más comúnmente por:","optss":["Bajo flujo de aire o baja carga de refrigerante","Solo alta presión de descarga","Un filtro demasiado limpio","Ductos sobredimensionados"],"rs":"El flujo de aire restringido (filtro/serpentín sucio, problema del soplador) o la carga baja hacen que la temperatura del serpentín caiga por debajo del punto de congelación, congelándolo. Diagnostique primero el flujo de aire, luego la carga."},
  {"id":56,"sec":"Service & Troubleshooting","q":"Low refrigerant charge typically produces:","opts":["High head pressure","High suction and low superheat","Low suction pressure and high superheat","High subcooling"],"correct":2,"re":"Undercharge starves the evaporator: low suction, high superheat, low subcooling. Confirm, weigh-in correctly, and find the leak.","rr":"Недозаправка «душит» испаритель: низкое suction, высокий superheat, низкий subcooling. Подтверждают, дозаправляют по весу и ищут течь.","qr":"Недозаправка хладагентом обычно даёт:","optsr":["Высокое head давление","Высокое suction и низкий superheat","Низкое suction давление и высокий superheat","Высокий subcooling"],"qs":"Una carga baja de refrigerante típicamente produce:","optss":["Alta presión de descarga","Alta succión y bajo sobrecalentamiento","Baja presión de succión y alto sobrecalentamiento","Alto subenfriamiento"],"rs":"La carga insuficiente ahoga el evaporador: baja succión, alto sobrecalentamiento, bajo subenfriamiento. Confirme, agregue carga por peso correctamente y encuentre la fuga."},
  {"id":57,"sec":"Service & Troubleshooting","q":"An overcharged system most often shows:","opts":["Low subcooling","Low head pressure","High head pressure and high subcooling","High superheat"],"correct":2,"re":"Overcharge backs liquid into the condenser: high head pressure and high subcooling, low superheat. Recover refrigerant to correct the charge.","rr":"Перезаправка загоняет жидкость в конденсатор: высокое head давление и высокий subcooling, низкий superheat. Откачивают часть хладагента до нормы.","qr":"Перезаправленная система чаще всего показывает:","optsr":["Низкий subcooling","Низкое head давление","Высокое head давление и высокий subcooling","Высокий superheat"],"qs":"Un sistema sobrecargado muestra más a menudo:","optss":["Bajo subenfriamiento","Baja presión de descarga","Alta presión de descarga y alto subenfriamiento","Alto sobrecalentamiento"],"rs":"La sobrecarga acumula líquido en el condensador: alta presión de descarga y alto subenfriamiento, bajo sobrecalentamiento. Recupere refrigerante para corregir la carga."},
  {"id":58,"sec":"Service & Troubleshooting","q":"A dirty or blocked outdoor condenser coil will cause:","opts":["High head (discharge) pressure","Low head pressure","Low amp draw","A frozen condenser"],"correct":0,"re":"Poor condenser heat rejection raises head pressure and compressor amps, cuts capacity, and can trip on high pressure. Clean the coil.","rr":"Плохой отвод тепла конденсатором повышает head давление и ток компрессора, снижает мощность и может выбивать по высокому давлению. Чистят змеевик.","qr":"Грязный или забитый наружный конденсатор вызовет:","optsr":["Высокое head (discharge) давление","Низкое head давление","Низкий ток","Обмерзание конденсатора"],"qs":"Un serpentín del condensador exterior sucio o bloqueado causará:","optss":["Alta presión de descarga","Baja presión de descarga","Bajo consumo de amperios","Un condensador congelado"],"rs":"El mal rechazo de calor del condensador eleva la presión de descarga y los amperios del compresor, reduce la capacidad y puede dispararse por alta presión. Limpie el serpentín."},
  {"id":59,"sec":"Service & Troubleshooting","q":"A failed (open) run capacitor on a single-phase compressor will typically cause it to:","opts":["Be unaffected","Have a higher SEER","Run faster","Hum, draw high amps, and not start"],"correct":3,"re":"A failed run/start capacitor prevents starting torque: the motor hums, draws locked-rotor amps, and may trip. Test microfarads against the rating.","rr":"Неисправный run/start-capacitor лишает пускового момента: мотор гудит, тянет locked-rotor amps и может выбить. Проверяют ёмкость (microfarads) против номинала.","qr":"Неисправный (обрыв) run-capacitor у однофазного компрессора обычно приводит к тому, что он:","optsr":["Не затронут","Имеет более высокий SEER","Работает быстрее","Гудит, тянет высокий ток и не запускается"],"qs":"Un capacitor de marcha fallado (abierto) en un compresor monofásico típicamente causará que:","optss":["No se vea afectado","Tenga un SEER más alto","Funcione más rápido","Zumbe, consuma altos amperios y no arranque"],"rs":"Un capacitor de marcha/arranque fallado impide el torque de arranque: el motor zumba, consume amperios de rotor bloqueado y puede dispararse. Pruebe los microfaradios contra la clasificación."},
  {"id":60,"sec":"Service & Troubleshooting","q":"A contactor in an air-conditioning condenser functions to:","opts":["Drain condensate","Switch line voltage to the compressor and fan","Meter refrigerant","Filter air"],"correct":1,"re":"The contactor is an electrically operated switch that closes on a 24V call to send line voltage to the compressor and condenser fan. Pitted contacts cause failures.","rr":"Контактор — электрически управляемый выключатель, который по сигналу 24V подаёт сетевое напряжение на компрессор и вентилятор конденсатора. Подгоревшие контакты дают отказы.","qr":"Контактор в наружном блоке кондиционера служит для:","optsr":["Слива конденсата","Подачи сетевого напряжения на компрессор и вентилятор","Дозирования хладагента","Фильтрации воздуха"],"qs":"Un contactor en un condensador de aire acondicionado funciona para:","optss":["Drenar el condensado","Conmutar el voltaje de línea al compresor y al ventilador","Medir el refrigerante","Filtrar el aire"],"rs":"El contactor es un interruptor operado eléctricamente que se cierra ante una llamada de 24V para enviar voltaje de línea al compresor y al ventilador del condensador. Los contactos picados causan fallas."},
  {"id":61,"sec":"Service & Troubleshooting","q":"In a heat pump, a stuck reversing valve will cause:","opts":["Higher efficiency","Correct operation","Frozen condensate","Failure to switch between heating and cooling, or pressure bypass"],"correct":3,"re":"A stuck reversing (4-way) valve traps one mode or bypasses high/low sides (pressures equalize). Check the solenoid and the temperature split across the valve ports.","rr":"Заклинивший reversing (4-ходовой) клапан запирает один режим или перепускает между high/low сторонами (давления выравниваются). Проверяют соленоид и перепад температур на портах клапана.","qr":"В тепловом насосе заклинивший reversing valve вызовет:","optsr":["Более высокий КПД","Нормальную работу","Обмерзание конденсата","Невозможность переключения отопление/охлаждение или перепуск давления"],"qs":"En una bomba de calor, una válvula reversora atascada causará:","optss":["Mayor eficiencia","Operación correcta","Condensado congelado","Falla para cambiar entre calefacción y enfriamiento, o derivación de presión"],"rs":"Una válvula reversora (de 4 vías) atascada atrapa un modo o deriva los lados de alta/baja (las presiones se igualan). Revise el solenoide y el diferencial de temperatura a través de los puertos de la válvula."},
  {"id":62,"sec":"Service & Troubleshooting","q":"The purpose of a heat pump's defrost cycle is to:","opts":["Cool the house","Melt frost from the outdoor coil in heating mode","Charge the system","Clean the filter"],"correct":1,"re":"In heating, the outdoor coil collects frost; defrost briefly reverses the cycle (and may energize aux heat) to melt the ice, then returns to heating.","rr":"В отоплении наружный змеевик покрывается инеем; defrost кратко реверсирует цикл (может включить aux heat), растапливает лёд и возвращается к отоплению.","qr":"Назначение цикла оттайки (defrost) теплового насоса:","optsr":["Охлаждать дом","Растопить иней с наружного змеевика в режиме отопления","Заправить систему","Почистить фильтр"],"qs":"El propósito del ciclo de descongelamiento de una bomba de calor es:","optss":["Enfriar la casa","Derretir la escarcha del serpentín exterior en modo de calefacción","Cargar el sistema","Limpiar el filtro"],"rs":"En calefacción, el serpentín exterior acumula escarcha; el descongelamiento invierte brevemente el ciclo (y puede energizar el calor auxiliar) para derretir el hielo, luego regresa a calefacción."},
  {"id":63,"sec":"Service & Troubleshooting","q":"A large temperature drop across a liquid-line filter-drier usually indicates:","opts":["Overcharge","Normal operation","Low airflow","A restriction (clogged drier)"],"correct":3,"re":"A noticeable temperature drop/sweating across the drier signals a restriction. A restricted drier/metering device starves the evaporator (low suction, high superheat).","rr":"Заметный перепад/потение на drier — признак засора. Забитый drier/дозатор «душит» испаритель (низкое suction, высокий superheat).","qr":"Большой перепад температур на liquid-line filter-drier обычно указывает на:","optsr":["Перезаправку","Нормальную работу","Низкий воздухопоток","Засор (забитый drier)"],"qs":"Una gran caída de temperatura a través de un filtro deshidratador de la línea de líquido usualmente indica:","optss":["Sobrecarga","Operación normal","Bajo flujo de aire","Una restricción (deshidratador obstruido)"],"rs":"Una caída de temperatura/sudor notable a través del deshidratador indica una restricción. Un deshidratador/dispositivo de medición restringido ahoga el evaporador (baja succión, alto sobrecalentamiento)."},
  {"id":64,"sec":"Service & Troubleshooting","q":"Noncondensable gases (air) in a refrigerant system cause:","opts":["Low head pressure","More subcooling","Low superheat","Abnormally high head pressure"],"correct":3,"re":"Air/noncondensables raise head pressure above the normal saturation value for the temperature. Recover, evacuate to a deep vacuum, and recharge.","rr":"Воздух/неконденсируемые поднимают head давление выше нормального значения насыщения для данной температуры. Откачивают, тянут глубокий вакуум и заправляют заново.","qr":"Неконденсируемые газы (воздух) в системе хладагента вызывают:","optsr":["Низкое head давление","Больший subcooling","Низкий superheat","Аномально высокое head давление"],"qs":"Los gases no condensables (aire) en un sistema de refrigerante causan:","optss":["Baja presión de descarga","Más subenfriamiento","Bajo sobrecalentamiento","Presión de descarga anormalmente alta"],"rs":"El aire/no condensables elevan la presión de descarga por encima del valor de saturación normal para la temperatura. Recupere, evacúe a un vacío profundo y recargue."},
  {"id":65,"sec":"Service & Troubleshooting","q":"A gas furnace that lights but shuts off after a few seconds most likely has a faulty:","opts":["Flame sensor/thermocouple not proving flame","Condensate pump","Air filter","Blower wheel"],"correct":0,"re":"If the flame sensor/thermocouple doesn't prove flame, the control closes the gas valve as a safety. Clean or replace the sensor and verify the microamp signal and ground.","rr":"Если flame sensor/thermocouple не подтверждает пламя, плата закрывает газовый клапан как защиту. Чистят или меняют датчик, проверяют сигнал в microamp и заземление.","qr":"Газовая печь зажигается, но гаснет через несколько секунд — вероятнее всего неисправен:","optsr":["Flame sensor/thermocouple, не подтверждающий пламя","Помпа конденсата","Воздушный фильтр","Крыльчатка вентилятора"],"qs":"Un calefactor de gas que enciende pero se apaga después de unos segundos lo más probable tiene un defectuoso:","optss":["Sensor de llama/termopar que no detecta llama","Bomba de condensado","Filtro de aire","Rotor del soplador"],"rs":"Si el sensor de llama/termopar no detecta la llama, el control cierra la válvula de gas como medida de seguridad. Limpie o reemplace el sensor y verifique la señal en microamperios y la conexión a tierra."},
  {"id":66,"sec":"Service & Troubleshooting","q":"A hot surface igniter (HSI) that is cracked or open will result in:","opts":["No ignition (no heat)","Continuous heating","Cooling only","High head pressure"],"correct":0,"re":"A cracked/open HSI won't glow, so ignition fails — no heat. Check resistance and for visible cracks; handle without touching the element.","rr":"Треснувший/оборванный HSI не раскаляется, розжиг не проходит — нет тепла. Проверяют сопротивление и трещины; берут, не касаясь самого элемента.","qr":"Треснувший или оборванный hot surface igniter (HSI) приведёт к:","optsr":["Отсутствию розжига (нет тепла)","Непрерывному нагреву","Только охлаждению","Высокому head давлению"],"qs":"Un encendedor de superficie caliente (HSI) que está agrietado o abierto resultará en:","optss":["Sin encendido (sin calor)","Calefacción continua","Solo enfriamiento","Alta presión de descarga"],"rs":"Un HSI agrietado/abierto no brillará, por lo que el encendido falla — sin calor. Revise la resistencia y busque grietas visibles; manipúlelo sin tocar el elemento."},
  {"id":67,"sec":"Service & Troubleshooting","q":"A furnace rollout or high-limit switch that trips repeatedly indicates:","opts":["Normal operation","Overheating from blocked flue or low airflow","A dirty condenser","Low gas pressure only"],"correct":1,"re":"Limit/rollout trips signal overheating from restricted airflow (dirty filter/coil/blower) or a blocked flue/heat-exchanger problem. Find the root cause — don't just reset.","rr":"Срабатывания limit/rollout — признак перегрева из-за зажатого воздухопотока (фильтр/змеевик/вентилятор) или забитого дымохода/проблемы теплообменника. Ищут причину, а не просто сбрасывают.","qr":"Повторное срабатывание rollout или high-limit switch печи указывает на:","optsr":["Нормальную работу","Перегрев из-за забитого дымохода или малого воздухопотока","Грязный конденсатор","Только низкое давление газа"],"qs":"Un interruptor de rollout o de límite alto de un calefactor que se dispara repetidamente indica:","optss":["Operación normal","Sobrecalentamiento por chimenea bloqueada o bajo flujo de aire","Un condensador sucio","Solo baja presión de gas"],"rs":"Los disparos del límite/rollout indican sobrecalentamiento por flujo de aire restringido (filtro/serpentín/soplador sucio) o una chimenea bloqueada/problema del intercambiador de calor. Encuentre la causa raíz — no solo reinicie."},
  {"id":68,"sec":"Service & Troubleshooting","q":"If a furnace inducer runs but the pressure switch won't close, check for:","opts":["Low refrigerant","A dirty evaporator","A blocked flue/condensate or cracked hose to the switch","Open windows"],"correct":2,"re":"The pressure switch proves inducer draft. Failure to close is often a blocked vent/condensate, plugged or cracked sensing hose, or weak inducer — verify before replacing the switch.","rr":"Pressure switch подтверждает тягу inducer. Несрабатывание часто из-за забитого vent/конденсата, засорённого или треснувшего сигнального шланга или слабого inducer — проверяют до замены реле.","qr":"Если inducer печи работает, но pressure switch не замыкается, проверяют:","optsr":["Нехватку хладагента","Грязный испаритель","Забитый дымоход/конденсат или треснувший шланг к реле","Открытые окна"],"qs":"Si el inductor de un calefactor funciona pero el interruptor de presión no cierra, revise si hay:","optss":["Bajo refrigerante","Un evaporador sucio","Una chimenea/condensado bloqueado o una manguera agrietada hacia el interruptor","Ventanas abiertas"],"rs":"El interruptor de presión verifica el tiro del inductor. La falla para cerrar a menudo es una ventilación/condensado bloqueado, una manguera de detección tapada o agrietada, o un inductor débil — verifique antes de reemplazar el interruptor."},
  {"id":69,"sec":"Service & Troubleshooting","q":"An ECM blower motor offers what advantage over a standard PSC motor?","opts":["Variable speed and constant-airflow control","Lower efficiency","No electronics","Higher amp draw"],"correct":0,"re":"ECM (electronically commutated) motors vary speed to maintain target airflow against changing static pressure, improving comfort and efficiency vs. fixed-speed PSC motors.","rr":"ECM (electronically commutated) меняет скорость, удерживая заданный воздухопоток при меняющемся статическом давлении — лучше комфорт и КПД, чем у PSC с фикс. скоростью.","qr":"Какое преимущество даёт ECM-двигатель вентилятора по сравнению с обычным PSC?","optsr":["Переменная скорость и постоянный воздухопоток","Меньший КПД","Отсутствие электроники","Больший ток"],"qs":"¿Qué ventaja ofrece un motor de soplador ECM sobre un motor PSC estándar?","optss":["Velocidad variable y control de flujo de aire constante","Menor eficiencia","Sin electrónica","Mayor consumo de amperios"],"rs":"Los motores ECM (conmutados electrónicamente) varían la velocidad para mantener el flujo de aire objetivo frente a la presión estática cambiante, mejorando el confort y la eficiencia en comparación con los motores PSC de velocidad fija."},
  {"id":70,"sec":"Service & Troubleshooting","q":"The best first step to confirm a suspected refrigerant leak is to:","opts":["Add refrigerant and hope","Use an electronic leak detector, bubbles, or UV dye","Replace the compressor","Ignore it"],"correct":1,"re":"Locate the leak with an electronic detector, soap bubbles, or UV dye before repairing. EPA requires repairing significant leaks rather than topping off repeatedly.","rr":"Сначала находят течь электронным детектором, пузырьками или UV-краской, затем чинят. EPA требует устранять значимые течи, а не доливать снова и снова.","qr":"Лучший первый шаг при подозрении на течь хладагента:","optsr":["Добавить хладагент и надеяться","Использовать электронный течеискатель, пузырьки или UV-краску","Поменять компрессор","Игнорировать"],"qs":"El mejor primer paso para confirmar una sospecha de fuga de refrigerante es:","optss":["Agregar refrigerante y esperar","Usar un detector electrónico de fugas, burbujas o tinte UV","Reemplazar el compresor","Ignorarlo"],"rs":"Localice la fuga con un detector electrónico, burbujas de jabón o tinte UV antes de reparar. La EPA requiere reparar fugas significativas en lugar de rellenar repetidamente."},
  {"id":71,"sec":"Service & Troubleshooting","q":"Measured compressor amperage well above the rated RLA indicates:","opts":["A problem such as high head pressure, low voltage, or a mechanical issue","Correct operation","An oversized air filter","Normal light load"],"correct":0,"re":"Amps above RLA (Rated Load Amps) point to high head pressure, a restricted condenser, low voltage, or a failing compressor. Investigate before it overheats.","rr":"Ток выше RLA (Rated Load Amps) — признак высокого head давления, забитого конденсатора, низкого напряжения или умирающего компрессора. Разбираются до перегрева.","qr":"Замеренный ток компрессора заметно выше номинального RLA указывает на:","optsr":["Проблему: высокое head давление, низкое напряжение или механику","Нормальную работу","Завышенный фильтр","Нормальную малую нагрузку"],"qs":"Un amperaje del compresor medido muy por encima de la RLA clasificada indica:","optss":["Un problema como alta presión de descarga, bajo voltaje o un problema mecánico","Operación correcta","Un filtro de aire sobredimensionado","Carga ligera normal"],"rs":"Los amperios por encima de la RLA (Rated Load Amps) apuntan a alta presión de descarga, un condensador restringido, bajo voltaje o un compresor en falla. Investigue antes de que se sobrecaliente."},
  {"id":72,"sec":"Service & Troubleshooting","q":"A system with high superheat and low suction pressure most likely has:","opts":["An overcharge","Too much airflow","An undercharge or a restriction","A dirty condenser"],"correct":2,"re":"High superheat + low suction = a starved evaporator, from undercharge or a liquid-line/metering restriction. Check subcooling to distinguish the two.","rr":"Высокий superheat + низкое suction = «голодный» испаритель из-за недозаправки или засора liquid-line/дозатора. Smотрят subcooling, чтобы отличить одно от другого.","qr":"Система с высоким superheat и низким suction давлением скорее всего имеет:","optsr":["Перезаправку","Слишком большой воздухопоток","Недозаправку или засор","Грязный конденсатор"],"qs":"Un sistema con alto sobrecalentamiento y baja presión de succión lo más probable tiene:","optss":["Una sobrecarga","Demasiado flujo de aire","Una carga insuficiente o una restricción","Un condensador sucio"],"rs":"Alto sobrecalentamiento + baja succión = un evaporador ahogado, por carga insuficiente o una restricción en la línea de líquido/dispositivo de medición. Revise el subenfriamiento para distinguir entre los dos."},
  {"id":73,"sec":"Service & Troubleshooting","q":"A condensate float (safety) switch is designed to:","opts":["Increase airflow","Shut the system off if the drain pan overflows","Boost the charge","Defrost the coil"],"correct":1,"re":"A float switch interrupts the cooling call when condensate backs up, preventing water damage. A tripped float points to a clogged drain or trap.","rr":"Float switch разрывает вызов охлаждения при переполнении конденсата, предотвращая залив. Сработавший поплавок указывает на забитый дренаж или сифон.","qr":"Поплавковый (float) выключатель конденсата предназначен, чтобы:","optsr":["Увеличить воздухопоток","Отключить систему при переполнении поддона","Поднять заправку","Оттаять змеевик"],"qs":"Un interruptor de flotador (de seguridad) de condensado está diseñado para:","optss":["Aumentar el flujo de aire","Apagar el sistema si la bandeja de drenaje se desborda","Aumentar la carga","Descongelar el serpentín"],"rs":"Un interruptor de flotador interrumpe la llamada de enfriamiento cuando el condensado se acumula, previniendo daños por agua. Un flotador disparado apunta a un drenaje o sifón obstruido."},
  {"id":74,"sec":"Service & Troubleshooting","q":"In cold weather a heat pump relies on supplemental (auxiliary) heat because:","opts":["The reversing valve fails","It runs in cooling","Capacity and COP drop as outdoor temperature falls","The compressor stops"],"correct":2,"re":"As outdoor temperature drops, a heat pump's capacity and COP decline, so electric or gas auxiliary/backup heat supplements it to meet the load.","rr":"С падением наружной температуры мощность и COP теплового насоса снижаются, поэтому электрический или газовый auxiliary/backup обогрев его дополняет, чтобы покрыть нагрузку.","qr":"В холода тепловой насос опирается на доп. (auxiliary) обогрев, потому что:","optsr":["Reversing valve отказывает","Он работает на охлаждение","Мощность и COP падают со снижением наружной температуры","Компрессор останавливается"],"qs":"En clima frío, una bomba de calor depende del calor suplementario (auxiliar) porque:","optss":["La válvula reversora falla","Funciona en enfriamiento","La capacidad y el COP disminuyen a medida que baja la temperatura exterior","El compresor se detiene"],"rs":"A medida que baja la temperatura exterior, la capacidad y el COP de una bomba de calor disminuyen, por lo que el calor auxiliar/de respaldo eléctrico o de gas la complementa para satisfacer la carga."},
  {"id":75,"sec":"Service & Troubleshooting","q":"Low indoor airflow during cooling will typically cause:","opts":["No effect on the coil","High subcooling","High suction pressure","Low suction pressure and possible coil freezing"],"correct":3,"re":"Reduced airflow lowers evaporator load, dropping suction pressure and coil temperature — leading to icing. Check the filter, coil, blower speed, and ducts.","rr":"Снижение воздухопотока уменьшает нагрузку на испаритель, опуская suction давление и температуру змеевика — отсюда обмерзание. Проверяют фильтр, змеевик, скорость вентилятора и воздуховоды.","qr":"Низкий воздухопоток в помещении при охлаждении обычно вызывает:","optsr":["Нет влияния на змеевик","Высокий subcooling","Высокое suction давление","Низкое suction давление и возможное обмерзание"],"qs":"Un bajo flujo de aire interior durante el enfriamiento típicamente causará:","optss":["Ningún efecto en el serpentín","Alto subenfriamiento","Alta presión de succión","Baja presión de succión y posible congelamiento del serpentín"],"rs":"El flujo de aire reducido disminuye la carga del evaporador, bajando la presión de succión y la temperatura del serpentín — llevando al congelamiento. Revise el filtro, el serpentín, la velocidad del soplador y los ductos."},
  {"id":76,"sec":"Service & Troubleshooting","q":"Routine maintenance that most improves condenser efficiency is:","opts":["Removing the filter","Adding refrigerant every visit","Increasing fan speed","Cleaning the outdoor coil and clearing debris"],"correct":3,"re":"A clean condenser coil rejects heat properly, lowering head pressure and amp draw. Coil cleaning and clearance around the unit are key maintenance items.","rr":"Чистый конденсатор нормально отводит тепло, снижая head давление и ток. Чистка змеевика и зазор вокруг агрегата — ключевые пункты обслуживания.","qr":"Регулярное обслуживание, сильнее всего повышающее эффективность конденсатора:","optsr":["Снимать фильтр","Доливать хладагент каждый визит","Повышать скорость вентилятора","Чистить наружный змеевик и убирать мусор"],"qs":"El mantenimiento de rutina que más mejora la eficiencia del condensador es:","optss":["Quitar el filtro","Agregar refrigerante en cada visita","Aumentar la velocidad del ventilador","Limpiar el serpentín exterior y despejar los desechos"],"rs":"Un serpentín del condensador limpio rechaza el calor adecuadamente, bajando la presión de descarga y el consumo de amperios. La limpieza del serpentín y el espacio libre alrededor de la unidad son elementos clave de mantenimiento."},
  {"id":77,"sec":"Service & Troubleshooting","q":"The recommended interval to inspect/replace a standard 1-inch air filter is roughly:","opts":["Every 5 years","Never","Only when it disintegrates","Every 1–3 months"],"correct":3,"re":"Standard 1-inch filters are checked monthly and replaced every 1–3 months (sooner with pets/dust). Clogged filters restrict airflow and freeze coils.","rr":"Обычные 1-дюймовые фильтры проверяют ежемесячно и меняют каждые 1–3 месяца (чаще при животных/пыли). Забитые фильтры душат поток и морозят змеевик.","qr":"Рекомендуемый интервал проверки/замены обычного 1-дюймового фильтра примерно:","optsr":["Раз в 5 лет","Никогда","Только когда развалится","Каждые 1–3 месяца"],"qs":"El intervalo recomendado para inspeccionar/reemplazar un filtro de aire estándar de 1 pulgada es aproximadamente:","optss":["Cada 5 años","Nunca","Solo cuando se desintegra","Cada 1–3 meses"],"rs":"Los filtros estándar de 1 pulgada se revisan mensualmente y se reemplazan cada 1–3 meses (antes con mascotas/polvo). Los filtros obstruidos restringen el flujo de aire y congelan los serpentines."},
  {"id":78,"sec":"Service & Troubleshooting","q":"A 'short cycling' compressor (frequent on/off) can be caused by:","opts":["Proper airflow","A clean filter","Correct sizing","Oversized equipment, low charge, or a control/pressure problem"],"correct":3,"re":"Short cycling stems from oversizing, charge issues, dirty coils tripping safeties, or faulty controls. Diagnose the root cause to protect the compressor.","rr":"Short cycling возникает из-за oversizing, проблем с заправкой, грязных змеевиков, выбивающих защиты, или неисправных контролей. Ищут причину, чтобы спасти компрессор.","qr":"Short cycling компрессора (частые вкл/выкл) может быть вызван:","optsr":["Нормальным воздухопотоком","Чистым фильтром","Правильным подбором","Завышенным оборудованием, недозаправкой или проблемой контроля/давления"],"qs":"Un compresor con 'ciclos cortos' (encendido/apagado frecuente) puede ser causado por:","optss":["Flujo de aire adecuado","Un filtro limpio","Dimensionamiento correcto","Equipo sobredimensionado, carga baja o un problema de control/presión"],"rs":"Los ciclos cortos provienen del sobredimensionamiento, problemas de carga, serpentines sucios que disparan los dispositivos de seguridad o controles defectuosos. Diagnostique la causa raíz para proteger el compresor."},
  {"id":79,"sec":"Safety & Field Practices","q":"Lockout/tagout (LOTO) procedures are required to:","opts":["Test capacitors","Prevent accidental energizing of equipment during service","Speed up work","Improve efficiency"],"correct":1,"re":"Cal/OSHA LOTO (Title 8) requires de-energizing and locking/tagging energy sources before service so equipment can't start unexpectedly and injure the worker.","rr":"Cal/OSHA LOTO (Title 8) требует обесточить и заблокировать/обозначить источники энергии до обслуживания, чтобы оборудование не запустилось внезапно и не травмировало работника.","qr":"Процедуры lockout/tagout (LOTO) нужны, чтобы:","optsr":["Проверить конденсаторы","Не допустить случайной подачи питания при обслуживании","Ускорить работу","Повысить КПД"],"qs":"Los procedimientos de bloqueo/etiquetado (LOTO) se requieren para:","optss":["Probar capacitores","Prevenir la energización accidental del equipo durante el servicio","Acelerar el trabajo","Mejorar la eficiencia"],"rs":"El LOTO de Cal/OSHA (Título 8) requiere desenergizar y bloquear/etiquetar las fuentes de energía antes del servicio, de modo que el equipo no pueda arrancar inesperadamente y lesionar al trabajador."},
  {"id":80,"sec":"Safety & Field Practices","q":"Before working inside a disconnected condenser, a technician should still:","opts":["Add refrigerant","Run the fan","Assume it's safe","Discharge the capacitor and verify zero voltage"],"correct":3,"re":"Capacitors store a lethal charge after power is off. Discharge them safely and verify the absence of voltage with a meter before touching terminals.","rr":"Конденсаторы хранят смертельный заряд и после снятия питания. Их безопасно разряжают и проверяют отсутствие напряжения прибором до касания клемм.","qr":"Перед работой внутри обесточенного конденсатора техник всё равно должен:","optsr":["Добавить хладагент","Запустить вентилятор","Считать, что безопасно","Разрядить конденсатор и проверить отсутствие напряжения"],"qs":"Antes de trabajar dentro de un condensador desconectado, un técnico aún debe:","optss":["Agregar refrigerante","Hacer funcionar el ventilador","Asumir que es seguro","Descargar el capacitor y verificar voltaje cero"],"rs":"Los capacitores almacenan una carga letal después de quitar la energía. Descárguelos de forma segura y verifique la ausencia de voltaje con un medidor antes de tocar las terminales."},
  {"id":81,"sec":"Safety & Field Practices","q":"Appropriate eye protection when brazing is:","opts":["Shaded brazing goggles","No protection","Sunglasses only","A dust mask"],"correct":0,"re":"Brazing produces intense light and heat; shaded brazing goggles (plus gloves and ventilation) protect the eyes from glare and sparks.","rr":"Brazing даёт яркий свет и жар; затемнённые очки для пайки (плюс перчатки и вентиляция) защищают глаза от блеска и искр.","qr":"Подходящая защита глаз при brazing:","optsr":["Затемнённые очки для пайки","Без защиты","Только солнцезащитные очки","Пылевая маска"],"qs":"La protección ocular apropiada al hacer soldadura fuerte es:","optss":["Gafas de soldadura fuerte con tinte","Sin protección","Solo lentes de sol","Una mascarilla contra polvo"],"rs":"La soldadura fuerte produce luz y calor intensos; las gafas de soldadura fuerte con tinte (además de guantes y ventilación) protegen los ojos del resplandor y las chispas."},
  {"id":82,"sec":"Safety & Field Practices","q":"Refrigerant leaking into a confined, unventilated space is dangerous mainly because it can:","opts":["Raise humidity","Displace oxygen and cause asphyxiation","Increase outdoor pressure","Improve air quality"],"correct":1,"re":"Most refrigerants are heavier than air and can displace oxygen in low/confined spaces, causing asphyxiation. Ensure ventilation and follow the SDS.","rr":"Большинство хладагентов тяжелее воздуха и вытесняют кислород в низких/замкнутых местах, вызывая удушье. Обеспечивают вентиляцию и следуют SDS.","qr":"Утечка хладагента в замкнутое непроветриваемое пространство опасна в основном тем, что может:","optsr":["Повысить влажность","Вытеснить кислород и вызвать удушье","Повысить наружное давление","Улучшить качество воздуха"],"qs":"El refrigerante que se fuga en un espacio confinado y sin ventilación es peligroso principalmente porque puede:","optss":["Aumentar la humedad","Desplazar el oxígeno y causar asfixia","Aumentar la presión exterior","Mejorar la calidad del aire"],"rs":"La mayoría de los refrigerantes son más pesados que el aire y pueden desplazar el oxígeno en espacios bajos/confinados, causando asfixia. Asegure la ventilación y siga la SDS."},
  {"id":83,"sec":"Safety & Field Practices","q":"A2L refrigerants such as R-32 and R-454B are classified as:","opts":["Mildly flammable, lower toxicity","Nonflammable","Explosive like propane","Highly toxic"],"correct":0,"re":"A2L refrigerants are mildly flammable (lower flammability) and low toxicity. Follow equipment listings, leak detection/mitigation, and use no open flames during service.","rr":"A2L — слабогорючие (низкая горючесть) и малотоксичные. Соблюдают листинги оборудования, детекцию/митигацию утечек и не используют открытый огонь при обслуживании.","qr":"Хладагенты A2L, такие как R-32 и R-454B, классифицируются как:","optsr":["Слабогорючие, низкой токсичности","Негорючие","Взрывоопасные как пропан","Высокотоксичные"],"qs":"Los refrigerantes A2L como el R-32 y el R-454B se clasifican como:","optss":["Ligeramente inflamables, menor toxicidad","No inflamables","Explosivos como el propano","Altamente tóxicos"],"rs":"Los refrigerantes A2L son ligeramente inflamables (baja inflamabilidad) y de baja toxicidad. Siga las certificaciones del equipo, la detección/mitigación de fugas y no use llamas abiertas durante el servicio."},
  {"id":84,"sec":"Safety & Field Practices","q":"The correct way to confirm a circuit is de-energized before service is to:","opts":["Use a properly rated meter (test-known-test)","Touch the wires","Listen for humming","Ask a coworker"],"correct":0,"re":"Verify zero voltage with a rated meter using the test-known-live-test method. Never rely on a breaker label alone before contacting conductors.","rr":"Проверяют отсутствие напряжения прибором нужного класса методом «проверь-на-известном-проверь». Нельзя полагаться только на надпись автомата перед касанием проводников.","qr":"Правильный способ убедиться, что цепь обесточена перед работой:","optsr":["Использовать прибор нужного класса (test-known-test)","Потрогать провода","Слушать гудение","Спросить коллегу"],"qs":"La forma correcta de confirmar que un circuito está desenergizado antes del servicio es:","optss":["Usar un medidor con clasificación adecuada (probar-conocido-probar)","Tocar los cables","Escuchar el zumbido","Preguntar a un compañero de trabajo"],"rs":"Verifique voltaje cero con un medidor con clasificación adecuada usando el método de probar-conocido-vivo-probar. Nunca confíe solo en la etiqueta de un interruptor antes de contactar los conductores."},
  {"id":85,"sec":"Safety & Field Practices","q":"Portable electric tools used outdoors or in damp areas should be protected by a:","opts":["GFCI","Transformer only","Surge strip","Larger fuse"],"correct":0,"re":"A GFCI (ground-fault circuit interrupter) trips on small ground-fault currents, preventing electrocution in wet/outdoor conditions — required by Cal/OSHA and NEC.","rr":"GFCI (ground-fault circuit interrupter) срабатывает на малые токи утечки на землю, предотвращая поражение во влажных/наружных условиях — требуется Cal/OSHA и NEC.","qr":"Переносной электроинструмент на улице или во влажных местах должен защищаться:","optsr":["GFCI","Только трансформатором","Сетевым фильтром","Бóльшим предохранителем"],"qs":"Las herramientas eléctricas portátiles usadas al aire libre o en áreas húmedas deben protegerse con un:","optss":["GFCI","Solo un transformador","Regleta supresora","Un fusible más grande"],"rs":"Un GFCI (interruptor de circuito por falla a tierra) se dispara ante pequeñas corrientes de falla a tierra, previniendo la electrocución en condiciones húmedas/exteriores — requerido por Cal/OSHA y el NEC."},
  {"id":86,"sec":"Safety & Field Practices","q":"A straight (extension) ladder should be set at a base-to-height ratio of about:","opts":["1:1","1:4","1:20","1:10"],"correct":1,"re":"The 4-to-1 rule: place the base 1 ft out for every 4 ft of working height. Use the proper duty rating and secure/tie off the ladder.","rr":"Правило 4-к-1: основание отодвигают на 1 фут на каждые 4 фута рабочей высоты. Используют нужный класс нагрузки и фиксируют лестницу.","qr":"Прямую (раздвижную) лестницу ставят с соотношением основание-к-высоте примерно:","optsr":["1:1","1:4","1:20","1:10"],"qs":"Una escalera recta (de extensión) debe colocarse con una relación base-a-altura de aproximadamente:","optss":["1:1","1:4","1:20","1:10"],"rs":"La regla 4-a-1: coloque la base 1 ft hacia afuera por cada 4 ft de altura de trabajo. Use la clasificación de servicio adecuada y asegure/amarre la escalera."},
  {"id":87,"sec":"Safety & Field Practices","q":"Compressed-gas cylinders (refrigerant or nitrogen) must be:","opts":["Secured upright and kept away from heat sources","Laid on their side near heat","Left uncapped while moved","Filled to 100%"],"correct":0,"re":"Cylinders are secured upright with the cap on when moved, kept below ~125°F, and never overfilled (refrigerant ≤80%) to prevent rupture.","rr":"Баллоны закрепляют вертикально с колпачком при перемещении, держат ниже ~125°F и никогда не переполняют (хладагент ≤80%), чтобы не разорвало.","qr":"Баллоны со сжатым газом (хладагент или nitrogen) должны быть:","optsr":["Закреплены вертикально и вдали от тепла","Положены набок у источника тепла","Без колпачка при перемещении","Заполнены на 100%"],"qs":"Los cilindros de gas comprimido (refrigerante o nitrógeno) deben:","optss":["Asegurarse en posición vertical y mantenerse alejados de fuentes de calor","Acostarse de lado cerca del calor","Dejarse sin tapa al moverlos","Llenarse al 100%"],"rs":"Los cilindros se aseguran en posición vertical con la tapa puesta al moverlos, se mantienen por debajo de ~125°F y nunca se sobrellenan (refrigerante ≤80%) para prevenir la ruptura."},
  {"id":88,"sec":"Safety & Field Practices","q":"A pressurized nitrogen cylinder must always be used with a:","opts":["Torch","Pressure regulator","No regulator","Vacuum pump"],"correct":1,"re":"Nitrogen is stored at very high pressure; a regulator reduces it to a safe working pressure. Never pressure-test a system above its rated test pressure.","rr":"Азот хранится под очень высоким давлением; регулятор снижает его до безопасного рабочего. Систему нельзя опрессовывать выше её допустимого test pressure.","qr":"Баллон со сжатым азотом (nitrogen) всегда используют с:","optsr":["Горелкой","Регулятором давления","Без регулятора","Вакуумным насосом"],"qs":"Un cilindro de nitrógeno presurizado siempre debe usarse con un:","optss":["Soplete","Regulador de presión","Sin regulador","Bomba de vacío"],"rs":"El nitrógeno se almacena a muy alta presión; un regulador lo reduce a una presión de trabajo segura. Nunca pruebe la presión de un sistema por encima de su presión de prueba clasificada."},
  {"id":89,"sec":"Safety & Field Practices","q":"Venting CFC/HCFC/HFC refrigerant to the atmosphere during service is:","opts":["Required","Only illegal indoors","Allowed in small amounts","Prohibited under the Clean Air Act (EPA 608)"],"correct":3,"re":"EPA Section 608 prohibits knowingly venting refrigerants. Technicians must recover refrigerant with certified equipment and hold EPA 608 certification.","rr":"EPA Section 608 запрещает осознанный выпуск хладагентов. Техник обязан откачивать хладагент сертифицированным оборудованием и иметь сертификат EPA 608.","qr":"Выпуск хладагента CFC/HCFC/HFC в атмосферу при обслуживании:","optsr":["Обязателен","Незаконен только внутри помещений","Разрешён в малых количествах","Запрещён по Clean Air Act (EPA 608)"],"qs":"Ventilar refrigerante CFC/HCFC/HFC a la atmósfera durante el servicio es:","optss":["Requerido","Solo ilegal en interiores","Permitido en pequeñas cantidades","Prohibido bajo la Clean Air Act (EPA 608)"],"rs":"La Sección 608 de la EPA prohíbe ventilar refrigerantes a sabiendas. Los técnicos deben recuperar el refrigerante con equipo certificado y poseer la certificación EPA 608."},
  {"id":90,"sec":"Safety & Field Practices","q":"Carbon monoxide (CO) from incomplete combustion is dangerous because it is:","opts":["Harmless outdoors","Visible and smelly","Colorless, odorless, and toxic","Heavier than refrigerant"],"correct":2,"re":"CO is colorless and odorless and binds hemoglobin, causing poisoning. Proper combustion air, venting, and a CO detector are essential; investigate any spillage.","rr":"CO бесцветен и без запаха, связывает гемоглобин и вызывает отравление. Нужны достаточный воздух для горения, тяга и CO-детектор; любой spillage расследуют.","qr":"Угарный газ (CO) от неполного сгорания опасен тем, что он:","optsr":["Безвреден на улице","Видимый и пахучий","Бесцветный, без запаха и токсичный","Тяжелее хладагента"],"qs":"El monóxido de carbono (CO) de la combustión incompleta es peligroso porque es:","optss":["Inofensivo al aire libre","Visible y con olor","Incoloro, inodoro y tóxico","Más pesado que el refrigerante"],"rs":"El CO es incoloro e inodoro y se une a la hemoglobina, causando intoxicación. El aire de combustión adecuado, la ventilación y un detector de CO son esenciales; investigue cualquier derrame."},
  {"id":91,"sec":"Safety & Field Practices","q":"A Safety Data Sheet (SDS) provides information on:","opts":["Equipment SEER","Duct sizing","Hazards, handling, and first aid for a chemical","Warranty terms"],"correct":2,"re":"Under HazCom, an SDS lists a product's hazards, safe handling, PPE, first aid, and emergency measures. It must be accessible to workers on the job.","rr":"По HazCom SDS перечисляет опасности продукта, безопасное обращение, PPE, первую помощь и аварийные меры. Он должен быть доступен работникам на объекте.","qr":"Safety Data Sheet (SDS) содержит информацию о:","optsr":["SEER оборудования","Подборе воздуховодов","Опасностях, обращении и первой помощи по химвеществу","Условиях гарантии"],"qs":"Una Hoja de Datos de Seguridad (SDS) proporciona información sobre:","optss":["El SEER del equipo","El dimensionamiento de ductos","Los peligros, manejo y primeros auxilios de un químico","Los términos de la garantía"],"rs":"Bajo HazCom, una SDS enumera los peligros de un producto, el manejo seguro, el PPE, los primeros auxilios y las medidas de emergencia. Debe estar accesible para los trabajadores en el trabajo."},
  {"id":92,"sec":"Safety & Field Practices","q":"Cal/OSHA's Heat Illness Prevention standard requires employers to provide:","opts":["Only overtime pay","Extra refrigerant","Water, shade, rest, and training","Nothing outdoors"],"correct":2,"re":"Cal/OSHA's Heat Illness Prevention standard (Title 8 §3395) requires drinking water, shade for rest, rest breaks, training, and acclimatization for outdoor work.","rr":"Стандарт Cal/OSHA Heat Illness Prevention (Title 8 §3395) требует питьевую воду, тень для отдыха, перерывы, обучение и акклиматизацию при работе на улице.","qr":"Стандарт Cal/OSHA по профилактике теплового удара требует от работодателя обеспечить:","optsr":["Только оплату сверхурочных","Дополнительный хладагент","Воду, тень, отдых и обучение","Ничего на улице"],"qs":"El estándar de Prevención de Enfermedades por Calor de Cal/OSHA requiere que los empleadores proporcionen:","optss":["Solo pago de horas extra","Refrigerante adicional","Agua, sombra, descanso y capacitación","Nada al aire libre"],"rs":"El estándar de Prevención de Enfermedades por Calor de Cal/OSHA (Título 8 §3395) requiere agua potable, sombra para descansar, pausas de descanso, capacitación y aclimatación para el trabajo al aire libre."},
  {"id":93,"sec":"Safety & Field Practices","q":"The correct fire extinguisher class for an energized electrical fire is:","opts":["Class A","Class D","Class C","Class B"],"correct":2,"re":"Class C extinguishers are rated for energized electrical equipment (non-conductive agent). Class A = ordinary combustibles, B = flammable liquids, D = metals.","rr":"Огнетушители Class C рассчитаны на электрооборудование под напряжением (непроводящий состав). Class A — обычные горючие, B — горючие жидкости, D — металлы.","qr":"Правильный класс огнетушителя для пожара под напряжением:","optsr":["Class A","Class D","Class C","Class B"],"qs":"La clase correcta de extintor de incendios para un incendio eléctrico energizado es:","optss":["Clase A","Clase D","Clase C","Clase B"],"rs":"Los extintores Clase C están clasificados para equipo eléctrico energizado (agente no conductor). Clase A = combustibles ordinarios, B = líquidos inflamables, D = metales."},
  {"id":94,"sec":"Safety & Field Practices","q":"Before disturbing suspect old pipe or duct insulation that may contain asbestos, the technician should:","opts":["Vacuum it with a shop vac","Burn it","Stop and have it tested/handled by qualified personnel","Cut it freely"],"correct":2,"re":"Disturbing asbestos releases hazardous fibers. Suspect materials must be tested and handled per regulations by trained/certified personnel — not by untrained workers.","rr":"Нарушение asbestos высвобождает опасные волокна. Подозрительные материалы тестируют и обрабатывают по нормам обученные/сертифицированные люди — не неподготовленные работники.","qr":"Перед тем как тронуть старую изоляцию труб/воздуховодов, возможно содержащую asbestos, техник должен:","optsr":["Пропылесосить shop-vac'ом","Сжечь её","Остановиться и поручить тест/работу квалифицированным специалистам","Резать свободно"],"qs":"Antes de perturbar un aislamiento sospechoso de tubería o ducto viejo que pueda contener asbesto, el técnico debe:","optss":["Aspirarlo con una aspiradora de taller","Quemarlo","Detenerse y hacer que personal calificado lo pruebe/maneje","Cortarlo libremente"],"rs":"Perturbar el asbesto libera fibras peligrosas. Los materiales sospechosos deben probarse y manejarse según las regulaciones por personal capacitado/certificado — no por trabajadores sin capacitación."},
  {"id":95,"sec":"Safety & Field Practices","q":"When entering a confined space such as a crawlspace or tank, the first thing to test for is:","opts":["Oxygen level and a hazardous/toxic atmosphere","Wi-Fi signal","Noise","Paint color"],"correct":0,"re":"Confined spaces require atmospheric testing (oxygen, flammable, toxic) and a permit/procedure before entry, since oxygen deficiency or toxic gases can be fatal.","rr":"Замкнутые пространства требуют замера атмосферы (кислород, горючее, токсины) и разрешения/процедуры до входа, т.к. нехватка кислорода или токсичные газы смертельны.","qr":"При входе в замкнутое пространство (подполье, бак) в первую очередь проверяют:","optsr":["Уровень кислорода и опасную/токсичную атмосферу","Сигнал Wi-Fi","Шум","Цвет краски"],"qs":"Al entrar a un espacio confinado como un sótano de poca altura o un tanque, lo primero que se debe probar es:","optss":["El nivel de oxígeno y una atmósfera peligrosa/tóxica","La señal de Wi-Fi","El ruido","El color de la pintura"],"rs":"Los espacios confinados requieren prueba atmosférica (oxígeno, inflamables, tóxicos) y un permiso/procedimiento antes de entrar, ya que la deficiencia de oxígeno o los gases tóxicos pueden ser fatales."},
  {"id":96,"sec":"Safety & Field Practices","q":"Proper PPE when handling liquid refrigerant includes:","opts":["Shorts","Open-toe shoes","No gloves","Safety glasses and gloves to prevent frostbite/eye injury"],"correct":3,"re":"Liquid refrigerant can cause frostbite and eye injury. Wear safety glasses and gloves and work in a ventilated area per the SDS.","rr":"Жидкий хладагент вызывает обморожение и травмы глаз. Надевают защитные очки и перчатки, работают в проветриваемом месте по SDS.","qr":"Правильный PPE при работе с жидким хладагентом включает:","optsr":["Шорты","Открытую обувь","Без перчаток","Защитные очки и перчатки против обморожения/травмы глаз"],"qs":"El PPE adecuado al manipular refrigerante líquido incluye:","optss":["Pantalones cortos","Zapatos abiertos en la punta","Sin guantes","Lentes de seguridad y guantes para prevenir congelación/lesión ocular"],"rs":"El refrigerante líquido puede causar congelación y lesión ocular. Use lentes de seguridad y guantes y trabaje en un área ventilada según la SDS."},
  {"id":97,"sec":"Safety & Field Practices","q":"Fall protection considerations under Cal/OSHA apply when working:","opts":["At elevated heights and roof edges per Cal/OSHA thresholds","Only on ladders","Only above 50 ft","Never on residential jobs"],"correct":0,"re":"Cal/OSHA requires fall protection at defined heights (e.g., roof edges, elevated platforms). Use guardrails, personal fall arrest, or other approved methods per Title 8.","rr":"Cal/OSHA требует защиту от падения на установленных высотах (края крыш, поднятые площадки). Применяют ограждения, страховочные системы (PFAS) или иные одобренные методы по Title 8.","qr":"Защита от падения по Cal/OSHA применяется при работе:","optsr":["На высоте и у краёв крыши по порогам Cal/OSHA","Только на лестницах","Только выше 50 футов","Никогда на жилых объектах"],"qs":"Las consideraciones de protección contra caídas bajo Cal/OSHA aplican al trabajar:","optss":["En alturas elevadas y bordes de techo según los umbrales de Cal/OSHA","Solo en escaleras","Solo por encima de 50 ft","Nunca en trabajos residenciales"],"rs":"Cal/OSHA requiere protección contra caídas a alturas definidas (p. ej., bordes de techo, plataformas elevadas). Use barandillas, sistemas personales de detención de caídas u otros métodos aprobados según el Título 8."},
  {"id":98,"sec":"Safety & Field Practices","q":"Cutting or grinding materials that produce silica dust requires:","opts":["Only gloves","More refrigerant","Dust controls and respiratory protection","No precautions"],"correct":2,"re":"Respirable crystalline silica is a serious health hazard; Cal/OSHA requires water/dust controls and respiratory protection when cutting concrete, masonry, etc.","rr":"Вдыхаемый кристаллический silica — серьёзная опасность для здоровья; Cal/OSHA требует водяное/пылевое подавление и респираторную защиту при резке бетона, кладки и т.п.","qr":"Резка или шлифовка материалов, дающих кремнеземную (silica) пыль, требует:","optsr":["Только перчаток","Больше хладагента","Пылеподавления и защиты органов дыхания","Никаких мер"],"qs":"Cortar o esmerilar materiales que producen polvo de sílice requiere:","optss":["Solo guantes","Más refrigerante","Controles de polvo y protección respiratoria","Sin precauciones"],"rs":"La sílice cristalina respirable es un riesgo grave para la salud; Cal/OSHA requiere controles de agua/polvo y protección respiratoria al cortar concreto, mampostería, etc."},
  {"id":99,"sec":"Safety & Field Practices","q":"When servicing rooftop equipment, the technician should be most aware of:","opts":["The SEER rating","Paint","Filter size","Roof edges, skylights, and fall/heat hazards"],"correct":3,"re":"Rooftop work adds fall hazards (edges, skylights), heat exposure, and electrical/refrigerant hazards. Plan access, fall protection, and heat-illness measures.","rr":"Работа на крыше добавляет риски падения (края, световые люки), жару и электро/хладагентные опасности. Планируют доступ, защиту от падения и меры против теплового удара.","qr":"При обслуживании оборудования на крыше техник в первую очередь учитывает:","optsr":["Рейтинг SEER","Краску","Размер фильтра","Края крыши, световые люки и опасности падения/жары"],"qs":"Al dar servicio a equipo en la azotea, el técnico debe estar más consciente de:","optss":["La clasificación SEER","La pintura","El tamaño del filtro","Los bordes del techo, tragaluces y peligros de caída/calor"],"rs":"El trabajo en azoteas agrega peligros de caída (bordes, tragaluces), exposición al calor y peligros eléctricos/de refrigerante. Planifique el acceso, la protección contra caídas y las medidas contra enfermedades por calor."},
  {"id":100,"sec":"Safety & Field Practices","q":"The first action if liquid refrigerant contacts the skin (frostbite) is to:","opts":["Apply direct heat","Ignore it","Rub vigorously","Flush with plenty of lukewarm water and seek medical care"],"correct":3,"re":"For refrigerant frostbite, flush with plenty of lukewarm (not hot) water, do not rub, protect the area, and get medical attention per the SDS.","rr":"При обморожении хладагентом промывают большим количеством тёплой (не горячей) воды, не растирают, защищают участок и обращаются за медпомощью по SDS.","qr":"Первое действие при попадании жидкого хладагента на кожу (обморожение):","optsr":["Приложить прямой жар","Игнорировать","Энергично растереть","Промыть большим количеством тёплой воды и обратиться к врачу"],"qs":"La primera acción si el refrigerante líquido entra en contacto con la piel (congelación) es:","optss":["Aplicar calor directo","Ignorarlo","Frotar vigorosamente","Enjuagar con abundante agua tibia y buscar atención médica"],"rs":"Para la congelación por refrigerante, enjuague con abundante agua tibia (no caliente), no frote, proteja el área y obtenga atención médica según la SDS."},
  {"id":101,"sec":"Principles & Load Calculations","q":"On a psychrometric chart, the wet-bulb temperature lines are used primarily to determine:","opts":["Air velocity","Total heat content (enthalpy)","Duct size","Refrigerant charge"],"correct":1,"re":"Wet-bulb temperature relates directly to enthalpy (total heat). Lines of constant wet-bulb run nearly parallel to enthalpy lines on the psychrometric chart.","rr":"Wet-bulb напрямую связан с enthalpy (полным теплом); линии постоянного wet-bulb идут почти параллельно линиям enthalpy.","qr":"На психрометрической диаграмме линии температуры по мокрому термометру (wet-bulb) служат прежде всего для определения:","optsr":["Скорости воздуха","Полного теплосодержания (enthalpy)","Размера воздуховода","Заправки хладагентом"],"qs":"En una carta psicrométrica, las líneas de temperatura de bulbo húmedo se utilizan principalmente para determinar:","optss":["La velocidad del aire","El contenido total de calor (entalpía)","El tamaño del ducto","La carga de refrigerante"],"rs":"La temperatura de bulbo húmedo se relaciona directamente con la entalpía (calor total). Las líneas de bulbo húmedo constante corren casi paralelas a las líneas de entalpía en la carta psicrométrica."},
  {"id":102,"sec":"Principles & Load Calculations","q":"The sensible heat ratio (SHR) of a cooling load is the ratio of:","opts":["Total to sensible heat","Latent to total heat","Sensible to total heat","Airflow to load"],"correct":2,"re":"SHR = sensible heat ÷ total (sensible + latent) heat. A lower SHR means more moisture removal is required from the equipment.","rr":"SHR = sensible ÷ total (sensible + latent). Чем ниже SHR, тем больше влаги должно удалять оборудование.","qr":"Коэффициент явного тепла (SHR) охлаждающей нагрузки — это отношение:","optsr":["Полного к явному теплу","Скрытого к полному теплу","Явного к полному теплу","Расхода воздуха к нагрузке"],"qs":"La relación de calor sensible (SHR) de una carga de enfriamiento es la relación entre:","optss":["Calor total y sensible","Calor latente y total","Calor sensible y total","Flujo de aire y carga"],"rs":"SHR = calor sensible ÷ calor total (sensible + latente). Un SHR más bajo significa que se requiere mayor remoción de humedad del equipo."},
  {"id":103,"sec":"Principles & Load Calculations","q":"ACCA Manual D is used to:","opts":["Calculate the heat load","Design and size the duct system","Select the thermostat","Size the equipment"],"correct":1,"re":"Manual D is the residential duct-design standard: it sizes ducts based on the available static pressure (friction rate) and required airflow.","rr":"Manual D — стандарт проектирования воздуховодов: рассчитывает дакты по доступному статическому давлению (friction rate) и нужному расходу.","qr":"ACCA Manual D применяется для:","optsr":["Расчёта тепловой нагрузки","Проектирования и расчёта воздуховодов","Выбора термостата","Подбора оборудования"],"qs":"El Manual D de ACCA se utiliza para:","optss":["Calcular la carga térmica","Diseñar y dimensionar el sistema de ductos","Seleccionar el termostato","Dimensionar el equipo"],"rs":"El Manual D es la norma de diseño de ductos residenciales: dimensiona los ductos según la presión estática disponible (tasa de fricción) y el flujo de aire requerido."},
  {"id":104,"sec":"Principles & Load Calculations","q":"In Manual D, the friction rate is determined from the available static pressure and the:","opts":["Roof slope","Total equivalent length of the longest run","Number of registers","Refrigerant type"],"correct":1,"re":"Friction rate = (available static pressure × 100) ÷ total effective length of the longest supply-and-return run, including fitting equivalent lengths.","rr":"Friction rate = (доступное статическое × 100) ÷ полная эффективная длина самого длинного участка подачи+обратки, включая эквив. длины фитингов.","qr":"В Manual D friction rate определяется по доступному статическому давлению и:","optsr":["Уклону крыши","Полной эквивалентной длине самого длинного участка","Числу решёток","Типу хладагента"],"qs":"En el Manual D, la tasa de fricción se determina a partir de la presión estática disponible y de:","optss":["La pendiente del techo","La longitud equivalente total del tramo más largo","El número de rejillas","El tipo de refrigerante"],"rs":"Tasa de fricción = (presión estática disponible × 100) ÷ longitud efectiva total del tramo de suministro y retorno más largo, incluyendo las longitudes equivalentes de los accesorios."},
  {"id":105,"sec":"Principles & Load Calculations","q":"ACCA Manual S is used to:","opts":["Design ventilation","Calculate heat loss","Select equipment to match the Manual J load","Size ductwork"],"correct":2,"re":"Manual S selects equipment so that its sensible and latent capacity (at design conditions) matches the Manual J load, limiting oversizing.","rr":"Manual S подбирает оборудование так, чтобы его sensible и latent производительность (при расчётных условиях) соответствовала нагрузке Manual J, ограничивая завышение.","qr":"ACCA Manual S применяется для:","optsr":["Проектирования вентиляции","Расчёта теплопотерь","Подбора оборудования под нагрузку Manual J","Расчёта воздуховодов"],"qs":"El Manual S de ACCA se utiliza para:","optss":["Diseñar la ventilación","Calcular la pérdida de calor","Seleccionar el equipo para que coincida con la carga del Manual J","Dimensionar los ductos"],"rs":"El Manual S selecciona el equipo de modo que su capacidad sensible y latente (en condiciones de diseño) coincida con la carga del Manual J, limitando el sobredimensionamiento."},
  {"id":106,"sec":"Principles & Load Calculations","q":"Per Manual S, cooling equipment should generally not be oversized beyond about what percentage of the design cooling load?","opts":["115% (15% over) for AC","200%","15% over","No limit"],"correct":0,"re":"Manual S typically limits AC sizing to about 115% of the design sensible load (and up to ~125% for heat pumps in some cases) to maintain dehumidification and efficiency.","rr":"Manual S обычно ограничивает подбор AC примерно 115% расчётной sensible-нагрузки (до ~125% для тепловых насосов в части случаев) ради осушения и КПД.","qr":"Согласно Manual S, охлаждающее оборудование, как правило, не завышают сверх примерно какого процента расчётной нагрузки?","optsr":["115% (на 15% выше) для AC","200%","На 15%","Без ограничения"],"qs":"Según el Manual S, el equipo de enfriamiento generalmente no debe sobredimensionarse más allá de aproximadamente qué porcentaje de la carga de enfriamiento de diseño?","optss":["115% (15% por encima) para AC","200%","15% por encima","Sin límite"],"rs":"El Manual S normalmente limita el dimensionamiento del AC a aproximadamente 115% de la carga sensible de diseño (y hasta ~125% para bombas de calor en algunos casos) para mantener la deshumidificación y la eficiencia."},
  {"id":107,"sec":"Principles & Load Calculations","q":"A common residential design airflow target for a cooling system is approximately:","opts":["50 CFM per ton","400 CFM per ton","100 CFM per ton","1200 CFM per ton"],"correct":1,"re":"The standard design airflow for comfort cooling is about 400 CFM per ton (350–450 CFM/ton range), adjusted for climate humidity.","rr":"Стандартный расчётный расход для комфортного охлаждения — около 400 CFM на тонну (диапазон 350–450), с поправкой на влажность климата.","qr":"Типовой расчётный расход воздуха для жилого охлаждения составляет примерно:","optsr":["50 CFM на тонну","400 CFM на тонну","100 CFM на тонну","1200 CFM на тонну"],"qs":"Un objetivo común de flujo de aire de diseño residencial para un sistema de enfriamiento es de aproximadamente:","optss":["50 CFM por tonelada","400 CFM por tonelada","100 CFM por tonelada","1200 CFM por tonelada"],"rs":"El flujo de aire de diseño estándar para enfriamiento de confort es de aproximadamente 400 CFM por tonelada (rango de 350–450 CFM/tonelada), ajustado según la humedad del clima."},
  {"id":108,"sec":"Principles & Load Calculations","q":"In dry desert climates, design airflow is often raised toward 450 CFM/ton, while in humid climates it may be lowered toward 350 CFM/ton in order to:","opts":["Lower the SEER","Increase noise","Reduce wire size","Balance sensible vs latent removal"],"correct":3,"re":"Higher airflow boosts sensible capacity (dry climates); lower airflow increases latent (moisture) removal needed in humid climates.","rr":"Больший расход повышает sensible (сухой климат); меньший расход усиливает удаление latent (влаги), нужное во влажном климате.","qr":"В сухом климате расчётный расход часто поднимают к 450 CFM/тонна, а во влажном снижают к 350 CFM/тонна, чтобы:","optsr":["Снизить SEER","Увеличить шум","Уменьшить сечение провода","Сбалансировать удаление явного и скрытого тепла"],"qs":"En climas desérticos secos, el flujo de aire de diseño suele elevarse hacia 450 CFM/tonelada, mientras que en climas húmedos puede reducirse hacia 350 CFM/tonelada con el fin de:","optss":["Reducir el SEER","Aumentar el ruido","Reducir el calibre del cable","Equilibrar la remoción sensible y latente"],"rs":"Un mayor flujo de aire aumenta la capacidad sensible (climas secos); un menor flujo de aire incrementa la remoción latente (humedad) necesaria en climas húmedos."},
  {"id":109,"sec":"Principles & Load Calculations","q":"The 'design temperature difference' in a heating load calculation is the difference between:","opts":["Wet and dry bulb","Two adjacent rooms","Supply and return air","Indoor design temp and outdoor design temp"],"correct":3,"re":"Heating design ΔT = indoor design temperature minus the 99% winter outdoor design temperature for the location (from Manual J tables / ASHRAE data).","rr":"Расчётный ΔT отопления = внутренняя расчётная температура минус 99% зимняя наружная расчётная температура для местности (таблицы Manual J / ASHRAE).","qr":"«Расчётная разность температур» в расчёте отопительной нагрузки — это разница между:","optsr":["Мокрым и сухим термометром","Двумя соседними комнатами","Подачей и обраткой","Внутренней и наружной расчётной температурой"],"qs":"La 'diferencia de temperatura de diseño' en un cálculo de carga de calefacción es la diferencia entre:","optss":["Bulbo húmedo y seco","Dos habitaciones adyacentes","Aire de suministro y retorno","Temperatura interior de diseño y temperatura exterior de diseño"],"rs":"ΔT de diseño de calefacción = temperatura interior de diseño menos la temperatura exterior de diseño de invierno al 99% para la localidad (de las tablas del Manual J / datos de ASHRAE)."},
  {"id":110,"sec":"Principles & Load Calculations","q":"Latent heat load in a building comes primarily from:","opts":["Lighting","Moisture sources (people, cooking, infiltration)","Sunlight through windows","Wall conduction"],"correct":1,"re":"Latent load is moisture: occupants, cooking, showers, plants, and humid infiltration/ventilation air. Solar, conduction and lighting are sensible loads.","rr":"Latent — это влага: люди, готовка, душ, растения, влажный приточный/инфильтрационный воздух. Солнце, теплопроводность и свет — sensible.","qr":"Скрытая (latent) нагрузка в здании возникает в основном от:","optsr":["Освещения","Источников влаги (люди, готовка, инфильтрация)","Солнца через окна","Теплопроводности стен"],"qs":"La carga de calor latente en un edificio proviene principalmente de:","optss":["La iluminación","Fuentes de humedad (personas, cocina, infiltración)","La luz solar a través de las ventanas","La conducción por las paredes"],"rs":"La carga latente es humedad: ocupantes, cocina, duchas, plantas y aire de infiltración/ventilación húmedo. La radiación solar, la conducción y la iluminación son cargas sensibles."},
  {"id":111,"sec":"Principles & Load Calculations","q":"When reading a psychrometric chart, the dew-point temperature is found by following a horizontal line to the saturation curve from the:","opts":["Dry-bulb axis","Enthalpy scale","Humidity ratio (moisture content)","CFM scale"],"correct":2,"re":"Dew point corresponds to the humidity ratio: move horizontally (constant moisture content) left to the 100% saturation curve to read dew-point temperature.","rr":"Dew point соответствует humidity ratio: двигаясь горизонтально (постоянное влагосодержание) влево к кривой 100% насыщения, читаем точку росы.","qr":"На психрометрической диаграмме температура точки росы (dew point) находится движением по горизонтали к кривой насыщения от:","optsr":["Оси сухого термометра","Шкалы enthalpy","Влагосодержания (humidity ratio)","Шкалы CFM"],"qs":"Al leer una carta psicrométrica, la temperatura de punto de rocío se encuentra siguiendo una línea horizontal hacia la curva de saturación desde:","optss":["El eje de bulbo seco","La escala de entalpía","La razón de humedad (contenido de humedad)","La escala de CFM"],"rs":"El punto de rocío corresponde a la razón de humedad: muévase horizontalmente (contenido de humedad constante) a la izquierda hasta la curva de saturación del 100% para leer la temperatura de punto de rocío."},
  {"id":112,"sec":"Principles & Load Calculations","q":"A ductulator is a tool used to relate duct size, airflow, friction loss, and:","opts":["Air velocity","Voltage","Refrigerant pressure","Flame temperature"],"correct":0,"re":"A ductulator (round/rectangular slide chart) relates CFM, friction rate per 100 ft, duct dimension, and velocity for duct sizing.","rr":"Ductulator (круглая/прямоугольная линейка) связывает CFM, friction rate на 100 футов, размер дакта и скорость для подбора воздуховодов.","qr":"Ductulator — инструмент, связывающий размер воздуховода, расход, потери на трение и:","optsr":["Скорость воздуха","Напряжение","Давление хладагента","Температуру пламени"],"qs":"Un ductulador es una herramienta que se usa para relacionar el tamaño del ducto, el flujo de aire, la pérdida por fricción y:","optss":["La velocidad del aire","El voltaje","La presión del refrigerante","La temperatura de la llama"],"rs":"Un ductulador (regla de cálculo redonda/rectangular) relaciona el CFM, la tasa de fricción por cada 100 ft, la dimensión del ducto y la velocidad para el dimensionamiento de ductos."},
  {"id":113,"sec":"Principles & Load Calculations","q":"Infiltration in a load calculation refers to:","opts":["Unintended air leakage through the building envelope","Oil in the compressor","Water in the duct","Refrigerant leaking"],"correct":0,"re":"Infiltration is uncontrolled outdoor air leaking through cracks, gaps and openings, adding both sensible and latent load.","rr":"Инфильтрация — неконтролируемый наружный воздух через щели, зазоры и проёмы, добавляющий и sensible, и latent нагрузку.","qr":"Инфильтрация в расчёте нагрузки — это:","optsr":["Неконтролируемая утечка воздуха через ограждения здания","Масло в компрессоре","Вода в воздуховоде","Утечка хладагента"],"qs":"La infiltración en un cálculo de carga se refiere a:","optss":["La fuga de aire no intencional a través de la envolvente del edificio","El aceite en el compresor","El agua en el ducto","La fuga de refrigerante"],"rs":"La infiltración es aire exterior no controlado que se filtra por grietas, huecos y aberturas, agregando carga tanto sensible como latente."},
  {"id":114,"sec":"Principles & Load Calculations","q":"Manual J design uses the 1% cooling and 99% heating outdoor design temperatures, which means the equipment is sized for:","opts":["Near-extreme but typical seasonal conditions","Indoor temperature only","The absolute record extremes","Average annual temperature"],"correct":0,"re":"The 1%/99% values are exceeded only ~1% of the time, so sizing to true record extremes would oversize the system most of the year.","rr":"Значения 1%/99% превышаются лишь ~1% времени; подбор под истинные рекорды завысил бы систему большую часть года.","qr":"Manual J использует расчётные наружные температуры 1% (охлаждение) и 99% (отопление), то есть оборудование подбирается под:","optsr":["Близкие к экстремальным, но типичные сезонные условия","Только внутреннюю температуру","Абсолютные рекордные экстремумы","Среднегодовую температуру"],"qs":"El diseño del Manual J utiliza las temperaturas exteriores de diseño al 1% para enfriamiento y al 99% para calefacción, lo que significa que el equipo se dimensiona para:","optss":["Condiciones estacionales típicas cercanas a los extremos","Solo la temperatura interior","Los extremos récord absolutos","La temperatura promedio anual"],"rs":"Los valores de 1%/99% se exceden solo ~1% del tiempo, por lo que dimensionar para los verdaderos extremos récord sobredimensionaría el sistema la mayor parte del año."},
  {"id":115,"sec":"Principles & Load Calculations","q":"Duct gain/loss in an unconditioned attic is reduced primarily by:","opts":["Higher voltage","Sealing and insulating the ducts","Larger registers","More refrigerant"],"correct":1,"re":"Sealing leaks (mastic) and insulating ducts (e.g., R-8) cuts conductive and leakage losses through hot/cold unconditioned spaces.","rr":"Герметизация (mastic) и утепление дактов (например R-8) уменьшают потери теплопроводностью и через утечки в жарких/холодных неотапливаемых зонах.","qr":"Теплопотери/теплопритоки воздуховодов в неотапливаемом чердаке снижаются прежде всего за счёт:","optsr":["Более высокого напряжения","Герметизации и утепления воздуховодов","Бо́льших решёток","Большего количества хладагента"],"qs":"La ganancia/pérdida de calor del ducto en un ático no acondicionado se reduce principalmente mediante:","optss":["Mayor voltaje","Sellado y aislamiento de los ductos","Rejillas más grandes","Más refrigerante"],"rs":"Sellar las fugas (con mástique) y aislar los ductos (por ejemplo, R-8) reduce las pérdidas por conducción y fuga a través de espacios no acondicionados calientes/fríos."},
  {"id":116,"sec":"Principles & Load Calculations","q":"For residential ventilation, ASHRAE Standard 62.2 specifies a minimum amount of:","opts":["Mechanical fresh-air ventilation based on floor area and occupants","Compressor oil","Refrigerant per ton","Duct insulation"],"correct":0,"re":"ASHRAE 62.2 sets a whole-house mechanical ventilation rate from floor area and number of bedrooms/occupants to ensure indoor air quality.","rr":"ASHRAE 62.2 задаёт расход механической вентиляции всего дома по площади и числу спален/жильцов для качества воздуха.","qr":"Для жилой вентиляции стандарт ASHRAE 62.2 задаёт минимум:","optsr":["Механической приточной вентиляции по площади и числу жильцов","Масла компрессора","Хладагента на тонну","Изоляции воздуховодов"],"qs":"Para la ventilación residencial, la Norma 62.2 de ASHRAE especifica una cantidad mínima de:","optss":["Ventilación mecánica de aire fresco según el área de piso y los ocupantes","Aceite del compresor","Refrigerante por tonelada","Aislamiento de ductos"],"rs":"ASHRAE 62.2 establece una tasa de ventilación mecánica para toda la vivienda a partir del área de piso y el número de dormitorios/ocupantes para garantizar la calidad del aire interior."},
  {"id":117,"sec":"Principles & Load Calculations","q":"A blower's external static pressure (ESP) rating represents the static pressure it can overcome across:","opts":["The duct system, coil, and filter combined","The refrigerant lines","The compressor","Only the filter"],"correct":0,"re":"ESP is the total static the blower must work against — supply ducts, return ducts, coil, filter, and registers — at the rated airflow.","rr":"ESP — суммарное статическое, против которого работает вентилятор: подача, обратка, испаритель, фильтр и решётки при номинальном расходе.","qr":"Внешнее статическое давление (ESP) вентилятора — это давление, которое он преодолевает по:","optsr":["Системе воздуховодов, испарителю и фильтру вместе","Линиям хладагента","Компрессору","Только фильтру"],"qs":"La clasificación de presión estática externa (ESP) de un ventilador representa la presión estática que puede vencer a través de:","optss":["El sistema de ductos, el serpentín y el filtro en conjunto","Las líneas de refrigerante","El compresor","Solo el filtro"],"rs":"La ESP es la presión estática total contra la que el ventilador debe trabajar: ductos de suministro, ductos de retorno, serpentín, filtro y rejillas, al flujo de aire nominal."},
  {"id":118,"sec":"Principles & Load Calculations","q":"When estimating a job, the difference between 'direct' and 'overhead' costs is that overhead includes:","opts":["Costs not tied to one specific job (office, insurance, trucks)","Refrigerant only","Materials installed in the job","Permit fees only"],"correct":0,"re":"Direct costs are job-specific (material, labor on that job); overhead is ongoing business cost spread across all jobs (rent, insurance, vehicles, admin).","rr":"Прямые затраты — по объекту (материал, труд на нём); накладные — постоянные расходы бизнеса на все объекты (аренда, страховка, авто, администрирование).","qr":"При составлении сметы разница между «прямыми» и «накладными» расходами в том, что накладные включают:","optsr":["Затраты, не привязанные к одному объекту (офис, страховка, машины)","Только хладагент","Материалы, установленные на объекте","Только пошлины за разрешение"],"qs":"Al estimar un trabajo, la diferencia entre costos 'directos' e 'indirectos' (overhead) es que los costos indirectos incluyen:","optss":["Costos no atados a un trabajo específico (oficina, seguros, camiones)","Solo el refrigerante","Materiales instalados en el trabajo","Solo las tarifas de permisos"],"rs":"Los costos directos son específicos del trabajo (material, mano de obra en ese trabajo); los costos indirectos son gastos continuos del negocio repartidos entre todos los trabajos (renta, seguros, vehículos, administración)."},
  {"id":119,"sec":"Principles & Load Calculations","q":"A heat pump's supplemental (auxiliary) heat must be sized to cover:","opts":["The heating load not met by the heat pump below the balance point","The duct loss only","The cooling load","The latent load only"],"correct":0,"re":"Below the balance point the heat pump can't meet the full heating load, so auxiliary heat (often electric strips) covers the shortfall down to design temp.","rr":"Ниже точки баланса насос не покрывает полную отопительную нагрузку, поэтому aux-нагрев (часто ТЭНы) добирает разницу до расчётной температуры.","qr":"Дополнительный (auxiliary) нагрев теплового насоса подбирается, чтобы покрыть:","optsr":["Отопительную нагрузку, не покрываемую насосом ниже точки баланса","Только потери воздуховодов","Охлаждающую нагрузку","Только скрытую нагрузку"],"qs":"El calor suplementario (auxiliar) de una bomba de calor debe dimensionarse para cubrir:","optss":["La carga de calefacción no cubierta por la bomba de calor por debajo del punto de equilibrio","Solo la pérdida del ducto","La carga de enfriamiento","Solo la carga latente"],"rs":"Por debajo del punto de equilibrio, la bomba de calor no puede satisfacer toda la carga de calefacción, por lo que el calor auxiliar (a menudo resistencias eléctricas) cubre el déficit hasta la temperatura de diseño."},
  {"id":120,"sec":"Principles & Load Calculations","q":"The 'balance point' of a heat pump is the outdoor temperature at which:","opts":["Heat pump output exactly equals the building heat loss","Defrost begins","The compressor fails","The SEER is highest"],"correct":0,"re":"At the balance point, the heat pump's declining capacity equals the building's rising heat loss; below it, supplemental heat is needed.","rr":"В точке баланса падающая производительность насоса равна растущим теплопотерям здания; ниже неё нужен дополнительный нагрев.","qr":"«Точка баланса» теплового насоса — это наружная температура, при которой:","optsr":["Отдача насоса точно равна теплопотерям здания","Начинается разморозка","Компрессор выходит из строя","SEER максимален"],"qs":"El 'punto de equilibrio' de una bomba de calor es la temperatura exterior a la cual:","optss":["La salida de la bomba de calor iguala exactamente la pérdida de calor del edificio","Comienza el descongelamiento","Falla el compresor","El SEER es más alto"],"rs":"En el punto de equilibrio, la capacidad decreciente de la bomba de calor iguala la pérdida de calor creciente del edificio; por debajo de él, se necesita calor suplementario."},
  {"id":121,"sec":"Principles & Load Calculations","q":"To convert sensible heat removed to required CFM, the standard formula uses the constant 1.08 with:","opts":["Voltage","ΔT and CFM","Wet-bulb only","Refrigerant subcooling"],"correct":1,"re":"Sensible heat (BTU/h) = 1.08 × CFM × ΔT (dry-bulb temperature difference) at standard air conditions.","rr":"Sensible (BTU/ч) = 1.08 × CFM × ΔT (разность по сухому термометру) при стандартных условиях воздуха.","qr":"Чтобы связать удаляемое явное тепло с нужным CFM, стандартная формула использует коэффициент 1.08 совместно с:","optsr":["Напряжением","ΔT и CFM","Только мокрым термометром","Subcooling хладагента"],"qs":"Para convertir el calor sensible removido en el CFM requerido, la fórmula estándar utiliza la constante 1.08 con:","optss":["El voltaje","El ΔT y el CFM","Solo el bulbo húmedo","El subenfriamiento del refrigerante"],"rs":"Calor sensible (BTU/h) = 1.08 × CFM × ΔT (diferencia de temperatura de bulbo seco) en condiciones de aire estándar."},
  {"id":122,"sec":"Principles & Load Calculations","q":"In a load calculation, north-facing windows generally contribute ___ solar heat gain than west-facing windows.","opts":["Less","No window gain exists","More","Identical"],"correct":0,"re":"West-facing glass receives intense low-angle afternoon sun (peak cooling time), so it gains far more solar heat than north glass.","rr":"Западное остекление получает интенсивное низкое послеполуденное солнце (пик нагрузки), поэтому даёт гораздо больше теплопритока, чем северное.","qr":"В расчёте нагрузки окна, выходящие на север, дают ___ солнечного теплопритока, чем окна на запад.","optsr":["Меньше","Окна не дают притока","Больше","Одинаково"],"qs":"En un cálculo de carga, las ventanas orientadas al norte generalmente aportan ___ ganancia de calor solar que las ventanas orientadas al oeste.","optss":["Menos","No existe ganancia por ventana","Más","Idéntica"],"rs":"El vidrio orientado al oeste recibe el intenso sol de la tarde en ángulo bajo (hora pico de enfriamiento), por lo que gana mucho más calor solar que el vidrio orientado al norte."},
  {"id":123,"sec":"Principles & Load Calculations","q":"A 'manual takeoff' during estimating refers to:","opts":["Pumping down refrigerant","Removing old equipment","Shutting off the gas","Counting/listing all materials and quantities from the plans"],"correct":3,"re":"A takeoff is itemizing every fitting, length of duct/pipe, register, and unit from the drawings to build an accurate material list and bid.","rr":"Takeoff — перечисление каждого фитинга, длины дакта/трубы, решётки и блока по чертежам, чтобы составить точный список материалов и заявку.","qr":"«Takeoff» (выборка) при составлении сметы — это:","optsr":["Откачка хладагента","Демонтаж старого оборудования","Отключение газа","Подсчёт и перечень всех материалов и количеств по чертежам"],"qs":"Un 'conteo manual' (takeoff) durante la estimación se refiere a:","optss":["Bombear el refrigerante","Retirar el equipo antiguo","Cerrar el gas","Contar/enumerar todos los materiales y cantidades a partir de los planos"],"rs":"Un conteo (takeoff) consiste en detallar cada accesorio, longitud de ducto/tubería, rejilla y unidad de los planos para elaborar una lista de materiales y una propuesta precisas."},
  {"id":124,"sec":"Principles & Load Calculations","q":"Selecting a furnace, the output capacity (not input) should be matched to the heating load because output reflects:","opts":["The SEER","Heat actually delivered after combustion efficiency (AFUE)","The gas line size","The filter size"],"correct":1,"re":"Input × AFUE = output (delivered heat). The building heat-loss load must be met by output BTU/h, not the higher input rating.","rr":"Input × AFUE = output (отданное тепло). Теплопотери здания должны покрываться выходными BTU/ч, а не более высоким input.","qr":"При подборе печи под нагрузку сравнивают выходную (output), а не входную мощность, потому что output отражает:","optsr":["SEER","Реально отданное тепло с учётом КПД сгорания (AFUE)","Размер газовой линии","Размер фильтра"],"qs":"Al seleccionar un horno (furnace), la capacidad de salida (no la de entrada) debe igualarse a la carga de calefacción porque la salida refleja:","optss":["El SEER","El calor realmente entregado después de la eficiencia de combustión (AFUE)","El tamaño de la línea de gas","El tamaño del filtro"],"rs":"Entrada × AFUE = salida (calor entregado). La carga de pérdida de calor del edificio debe cubrirse con los BTU/h de salida, no con la clasificación de entrada, que es mayor."},
  {"id":125,"sec":"Principles & Load Calculations","q":"A jurisdiction requires a permit for an HVAC changeout primarily to ensure:","opts":["Lower refrigerant cost","Higher contractor profit","Code compliance and inspection of the installation","Faster installation"],"correct":2,"re":"Permits trigger inspection so the work meets mechanical, electrical, and energy codes — protecting safety and property value.","rr":"Permit запускает инспекцию, чтобы работа отвечала механическим, электрическим и энергетическим нормам — защита безопасности и стоимости объекта.","qr":"Юрисдикция требует разрешение (permit) на замену HVAC прежде всего чтобы обеспечить:","optsr":["Снижение цены хладагента","Бо́льшую прибыль подрядчика","Соответствие нормам и инспекцию монтажа","Более быстрый монтаж"],"qs":"Una jurisdicción requiere un permiso para el reemplazo (changeout) de un sistema HVAC principalmente para asegurar:","optss":["Menor costo de refrigerante","Mayor ganancia del contratista","El cumplimiento del código y la inspección de la instalación","Una instalación más rápida"],"rs":"Los permisos activan la inspección para que el trabajo cumpla con los códigos mecánicos, eléctricos y de energía, protegiendo la seguridad y el valor de la propiedad."},
  {"id":126,"sec":"Fabrication & Installation","q":"When brazing copper-to-copper refrigerant joints, a BCuP (copper-phosphorus) alloy is preferred because it:","opts":["Cannot be used on refrigeration","Requires flux on copper","Melts at room temperature","Is self-fluxing on copper-to-copper joints"],"correct":3,"re":"BCuP alloys are self-fluxing on copper-to-copper joints due to the phosphorus; flux is still required when brazing copper to brass or steel.","rr":"Сплавы BCuP самофлюсуются на медь-медь благодаря фосфору; флюс всё же нужен при пайке меди к латуни или стали.","qr":"При пайке медь-медь в холодильных линиях предпочитают сплав BCuP (медь-фосфор), потому что он:","optsr":["Непригоден для холодильной техники","Требует флюс на меди","Плавится при комнатной температуре","Самофлюсуется на соединениях медь-медь"],"qs":"Al soldar con bronce (brazing) juntas de cobre a cobre de refrigeración, se prefiere una aleación BCuP (cobre-fósforo) porque:","optss":["No se puede usar en refrigeración","Requiere fundente sobre el cobre","Se funde a temperatura ambiente","Es autofundente en juntas de cobre a cobre"],"rs":"Las aleaciones BCuP son autofundentes en juntas de cobre a cobre debido al fósforo; aún se requiere fundente al soldar cobre con latón o acero."},
  {"id":127,"sec":"Fabrication & Installation","q":"Flowing dry nitrogen through tubing while brazing prevents:","opts":["High superheat","Overheating the torch","Refrigerant loss","Formation of copper-oxide scale inside the pipe"],"correct":3,"re":"Without an inert nitrogen purge, the inside of the tubing oxidizes, forming flaky copper-oxide scale that can clog metering devices and contaminate the system.","rr":"Без инертной продувки азотом внутренняя поверхность трубы окисляется, образуя хлопья окиси меди, забивающие дозаторы и загрязняющие систему.","qr":"Продувка сухим азотом через трубу во время пайки предотвращает:","optsr":["Высокий superheat","Перегрев горелки","Потерю хладагента","Образование окалины окиси меди внутри трубы"],"qs":"Hacer fluir nitrógeno seco a través de la tubería mientras se suelda con bronce previene:","optss":["El sobrecalentamiento alto","El sobrecalentamiento del soplete","La pérdida de refrigerante","La formación de escamas de óxido de cobre dentro de la tubería"],"rs":"Sin una purga inerte de nitrógeno, el interior de la tubería se oxida, formando escamas de óxido de cobre que pueden obstruir los dispositivos de medición y contaminar el sistema."},
  {"id":128,"sec":"Fabrication & Installation","q":"A typical low-flow nitrogen purge pressure while brazing is about:","opts":["0 psig","500 psig","150 psig","2–3 psig (a gentle flow)"],"correct":3,"re":"Only a gentle nitrogen flow (a few psig) is needed to displace oxygen; high pressure would blow molten braze out of the joint.","rr":"Нужен лишь мягкий поток азота (несколько psig), чтобы вытеснить кислород; высокое давление выдует расплавленный припой из стыка.","qr":"Типовое давление продувки азотом при пайке (малый поток) составляет около:","optsr":["0 psig","500 psig","150 psig","2–3 psig (мягкий поток)"],"qs":"Una presión típica de purga de nitrógeno de bajo flujo durante la soldadura con bronce es de aproximadamente:","optss":["0 psig","500 psig","150 psig","2–3 psig (un flujo suave)"],"rs":"Solo se necesita un flujo suave de nitrógeno (unos pocos psig) para desplazar el oxígeno; una presión alta expulsaría la soldadura fundida fuera de la junta."},
  {"id":129,"sec":"Fabrication & Installation","q":"Before charging a new system, a deep vacuum is pulled to remove moisture and:","opts":["Raise head pressure","Boil off and evacuate non-condensables and water vapor","Increase superheat","Add refrigerant"],"correct":1,"re":"A deep vacuum (e.g., ≤500 microns) lowers the boiling point of water so trapped moisture vaporizes and is evacuated along with air/non-condensables.","rr":"Глубокий вакуум (например ≤500 микрон) снижает точку кипения воды, так что влага испаряется и откачивается вместе с воздухом/неконденсируемыми.","qr":"Перед заправкой новой системы создают глубокий вакуум, чтобы удалить влагу и:","optsr":["Поднять давление нагнетания","Выпарить и откачать неконденсируемые газы и пары воды","Повысить superheat","Добавить хладагент"],"qs":"Antes de cargar un sistema nuevo, se realiza un vacío profundo para eliminar la humedad y:","optss":["Aumentar la presión de descarga","Evaporar y evacuar los no condensables y el vapor de agua","Aumentar el sobrecalentamiento","Agregar refrigerante"],"rs":"Un vacío profundo (por ejemplo, ≤500 micrones) reduce el punto de ebullición del agua para que la humedad atrapada se vaporice y se evacúe junto con el aire/no condensables."},
  {"id":130,"sec":"Fabrication & Installation","q":"A system is considered properly evacuated when a micron gauge holds below 500 microns and:","opts":["Holds stable (decay test passes) after isolating the pump","Shows high superheat","Rises quickly when valved off","Reads 0 psig"],"correct":0,"re":"After isolating the vacuum pump, the micron level should hold (a slow, small rise that levels off); a rapid rise indicates remaining moisture or a leak.","rr":"После отсечки вакуумного насоса уровень микрон должен держаться (медленный малый рост с выходом на плато); быстрый рост — остаточная влага или утечка.","qr":"Систему считают правильно отвакуумированной, когда микронный вакуумметр держит ниже 500 микрон и:","optsr":["Держится стабильно (decay-тест пройден) после отсечки насоса","Показывает высокий superheat","Быстро растёт после перекрытия","Показывает 0 psig"],"qs":"Se considera que un sistema está correctamente evacuado cuando un vacuómetro de micrones se mantiene por debajo de 500 micrones y:","optss":["Se mantiene estable (pasa la prueba de decaimiento) tras aislar la bomba","Muestra alto sobrecalentamiento","Sube rápidamente al cerrar la válvula","Marca 0 psig"],"rs":"Después de aislar la bomba de vacío, el nivel de micrones debe mantenerse (un aumento lento y pequeño que se estabiliza); un aumento rápido indica humedad remanente o una fuga."},
  {"id":131,"sec":"Fabrication & Installation","q":"Suction-line refrigerant piping that rises vertically may require a P-trap or proper sizing to ensure:","opts":["Lower voltage","Faster defrost","Oil return to the compressor","Higher subcooling"],"correct":2,"re":"Oil travels with refrigerant; on long vertical risers, correct velocity (and traps where needed) keeps oil moving back to the compressor instead of pooling.","rr":"Масло движется с хладагентом; на длинных вертикальных стояках правильная скорость (и ловушки где нужно) возвращают масло в компрессор, а не дают ему скапливаться.","qr":"Всасывающая линия хладагента, поднимающаяся вертикально, может требовать P-trap или правильного диаметра, чтобы обеспечить:","optsr":["Меньшее напряжение","Быструю разморозку","Возврат масла в компрессор","Более высокий subcooling"],"qs":"La tubería de refrigerante de la línea de succión que sube verticalmente puede requerir una trampa P (P-trap) o un dimensionamiento adecuado para asegurar:","optss":["Menor voltaje","Descongelamiento más rápido","El retorno de aceite al compresor","Mayor subenfriamiento"],"rs":"El aceite viaja con el refrigerante; en montantes verticales largos, la velocidad correcta (y trampas donde sea necesario) mantiene el aceite en movimiento de regreso al compresor en lugar de acumularse."},
  {"id":132,"sec":"Fabrication & Installation","q":"Refrigerant suction lines should be insulated primarily to:","opts":["Prevent heat gain and surface condensation/sweating","Increase pressure","Reduce noise only","Speed up brazing"],"correct":0,"re":"Insulating the cold suction line prevents capacity-robbing heat gain and stops condensation that can drip and cause water damage.","rr":"Изоляция холодной всасывающей линии предотвращает теплоприток (потерю производительности) и образование конденсата, который капает и портит конструкции.","qr":"Всасывающие линии хладагента изолируют прежде всего чтобы:","optsr":["Предотвратить теплоприток и конденсат/потение на поверхности","Повысить давление","Только снизить шум","Ускорить пайку"],"qs":"Las líneas de succión de refrigerante deben aislarse principalmente para:","optss":["Prevenir la ganancia de calor y la condensación/sudoración superficial","Aumentar la presión","Solo reducir el ruido","Acelerar la soldadura con bronce"],"rs":"Aislar la línea de succión fría previene la ganancia de calor que reduce la capacidad y evita la condensación que puede gotear y causar daños por agua."},
  {"id":133,"sec":"Fabrication & Installation","q":"A condensate drain line from a cooling coil typically requires:","opts":["Upward slope","Pressurization","A trap and proper downward slope","No slope"],"correct":2,"re":"A trap counters blower negative pressure so condensate drains freely; the line must slope downward (e.g., 1/8 in per foot) toward the drain.","rr":"Сифон компенсирует разрежение от вентилятора, чтобы конденсат стекал свободно; линия должна идти под уклон вниз (например 1/8 дюйма на фут) к дренажу.","qr":"Дренажная линия конденсата от испарителя обычно требует:","optsr":["Уклона вверх","Наддува","Сифон (trap) и правильный уклон вниз","Без уклона"],"qs":"Una línea de drenaje de condensado de un serpentín de enfriamiento normalmente requiere:","optss":["Pendiente hacia arriba","Presurización","Una trampa y una pendiente descendente adecuada","Ninguna pendiente"],"rs":"Una trampa contrarresta la presión negativa del ventilador para que el condensado drene libremente; la línea debe tener pendiente descendente (por ejemplo, 1/8 in por pie) hacia el drenaje."},
  {"id":134,"sec":"Fabrication & Installation","q":"A secondary (overflow) condensate switch or pan is installed to:","opts":["Lower head pressure","Boost refrigerant","Increase airflow","Shut the system off or catch water if the primary drain clogs"],"correct":3,"re":"Codes require overflow protection (float switch and/or secondary pan) to prevent water damage when the primary condensate drain backs up.","rr":"Нормы требуют защиту от перелива (поплавковый выключатель и/или вторичный поддон) для предотвращения протечек при засоре основного дренажа.","qr":"Вторичный (аварийный) выключатель или поддон конденсата ставят, чтобы:","optsr":["Снизить давление нагнетания","Добавить хладагент","Увеличить расход воздуха","Отключить систему или собрать воду при засоре основного дренажа"],"qs":"Se instala un interruptor o bandeja de condensado secundario (de derrame) para:","optss":["Reducir la presión de descarga","Aumentar el refrigerante","Aumentar el flujo de aire","Apagar el sistema o captar el agua si el drenaje primario se obstruye"],"rs":"Los códigos exigen protección contra derrames (interruptor de flotador y/o bandeja secundaria) para prevenir daños por agua cuando el drenaje de condensado primario se obstruye."},
  {"id":135,"sec":"Fabrication & Installation","q":"The minimum circuit ampacity (MCA) on a unit's data plate is used to size the:","opts":["Duct","Branch-circuit conductors (wire)","Filter","Refrigerant charge"],"correct":1,"re":"MCA tells the installer the minimum wire ampacity required; MOP/MOCP gives the maximum overcurrent (breaker/fuse) size.","rr":"MCA указывает минимальную ампачность провода; MOP/MOCP задаёт максимальный номинал защиты (автомат/предохранитель).","qr":"Минимальная токовая нагрузка цепи (MCA) на шильдике блока используется для подбора:","optsr":["Воздуховода","Проводников ответвления (провода)","Фильтра","Заправки хладагентом"],"qs":"La amperidad mínima de circuito (MCA) en la placa de datos de una unidad se utiliza para dimensionar:","optss":["El ducto","Los conductores del circuito derivado (cable)","El filtro","La carga de refrigerante"],"rs":"La MCA le indica al instalador la amperidad mínima del cable requerida; la MOP/MOCP indica la máxima protección contra sobrecorriente (tamaño de interruptor/fusible)."},
  {"id":136,"sec":"Fabrication & Installation","q":"The MOP (maximum overcurrent protection) value on the data plate sets the:","opts":["Refrigerant type","Duct gauge","Largest allowable breaker/fuse size","Wire color"],"correct":2,"re":"MOP (a.k.a. MOCP) is the largest breaker or fuse permitted to protect the equipment; you may not exceed it even if larger wire is used.","rr":"MOP (он же MOCP) — наибольший допустимый автомат или предохранитель для защиты оборудования; превышать нельзя, даже если провод толще.","qr":"Значение MOP (максимальная защита от сверхтока) на шильдике задаёт:","optsr":["Тип хладагента","Толщину дакта","Наибольший допустимый номинал автомата/предохранителя","Цвет провода"],"qs":"El valor MOP (máxima protección contra sobrecorriente) en la placa de datos establece:","optss":["El tipo de refrigerante","El calibre del ducto","El mayor tamaño permitido de interruptor/fusible","El color del cable"],"rs":"La MOP (también llamada MOCP) es el mayor interruptor o fusible permitido para proteger el equipo; no se puede exceder aunque se use un cable más grande."},
  {"id":137,"sec":"Fabrication & Installation","q":"In standard low-voltage thermostat wiring, the 'C' terminal provides:","opts":["The common (return) side of the 24 V transformer","The fan signal","The cooling call","The heat call"],"correct":0,"re":"R is the 24 V hot, C is the common return; together they power the thermostat. Y=cool, G=fan, W=heat, O/B=reversing valve.","rr":"R — это 24 В «горячий», C — общий обратный; вместе они питают термостат. Y=охлаждение, G=вентилятор, W=нагрев, O/B=реверс-клапан.","qr":"В стандартной низковольтной разводке термостата клемма «C» обеспечивает:","optsr":["Общий (обратный) провод трансформатора 24 В","Сигнал вентилятора","Вызов охлаждения","Вызов нагрева"],"qs":"En el cableado estándar de termostatos de bajo voltaje, la terminal 'C' proporciona:","optss":["El lado común (de retorno) del transformador de 24 V","La señal del ventilador","La llamada de enfriamiento","La llamada de calefacción"],"rs":"R es la fase viva de 24 V, C es el retorno común; juntas alimentan el termostato. Y=enfriamiento, G=ventilador, W=calefacción, O/B=válvula reversora."},
  {"id":138,"sec":"Fabrication & Installation","q":"On a heat pump thermostat, the 'O' terminal energizes the reversing valve in:","opts":["Cooling mode","Heating mode","Emergency heat","Defrost only"],"correct":0,"re":"Most heat pumps energize the reversing valve with 'O' in cooling. (Some older systems use 'B' to energize in heating instead.)","rr":"Большинство тепловых насосов запитывают реверс-клапан через «O» в охлаждении. (Некоторые старые системы используют «B» для запитки в нагреве.)","qr":"На термостате теплового насоса клемма «O» запитывает реверс-клапан в режиме:","optsr":["Охлаждения","Нагрева","Аварийного нагрева","Только разморозки"],"qs":"En un termostato de bomba de calor, la terminal 'O' energiza la válvula reversora en:","optss":["Modo de enfriamiento","Modo de calefacción","Calor de emergencia","Solo en descongelamiento"],"rs":"La mayoría de las bombas de calor energizan la válvula reversora con 'O' en enfriamiento. (Algunos sistemas más antiguos usan 'B' para energizarla en calefacción)."},
  {"id":139,"sec":"Fabrication & Installation","q":"A 24 V control transformer rated in VA is selected so its VA capacity:","opts":["Equals line voltage","Is always 5 VA","Matches the SEER","Meets or exceeds the total connected control load"],"correct":3,"re":"The transformer VA must supply the combined draw of contactor coil, relays, and accessories; undersizing causes voltage droop and chatter.","rr":"VA трансформатора должно покрывать суммарный ток катушки контактора, реле и аксессуаров; занижение даёт просадку напряжения и дребезг.","qr":"Управляющий трансформатор 24 В, измеряемый в VA, подбирают так, чтобы его мощность:","optsr":["Равнялась линейному напряжению","Всегда была 5 VA","Совпадала с SEER","Покрывала суммарную нагрузку управления"],"qs":"Un transformador de control de 24 V clasificado en VA se selecciona de modo que su capacidad en VA:","optss":["Iguale el voltaje de línea","Sea siempre 5 VA","Coincida con el SEER","Cumpla o supere la carga de control total conectada"],"rs":"Los VA del transformador deben suministrar el consumo combinado de la bobina del contactor, los relés y los accesorios; un subdimensionamiento causa caída de voltaje y vibración (chatter)."},
  {"id":140,"sec":"Fabrication & Installation","q":"SMACNA standards for sheet-metal duct specify minimum metal gauge based primarily on:","opts":["Paint color","Thermostat brand","Duct size and operating pressure class","Refrigerant type"],"correct":2,"re":"Larger ducts and higher static-pressure classes require thicker (lower-gauge) metal and more reinforcement per SMACNA HVAC Duct Construction Standards.","rr":"Бо́льшие дакты и более высокий класс статического давления требуют более толстого (меньший gauge) металла и усиления по SMACNA HVAC Duct Construction Standards.","qr":"Стандарты SMACNA для металлических воздуховодов задают минимальную толщину металла в основном по:","optsr":["Цвету краски","Бренду термостата","Размеру дакта и классу рабочего давления","Типу хладагента"],"qs":"Las normas SMACNA para ductos de lámina metálica especifican el calibre mínimo del metal principalmente según:","optss":["El color de la pintura","La marca del termostato","El tamaño del ducto y la clase de presión de operación","El tipo de refrigerante"],"rs":"Los ductos más grandes y las clases de presión estática más altas requieren metal más grueso (de menor calibre) y más refuerzo, según las normas SMACNA de construcción de ductos HVAC."},
  {"id":141,"sec":"Fabrication & Installation","q":"Duct seams and joints are best sealed with:","opts":["Standard cloth 'duct tape'","Refrigerant oil","UL-181 mastic or approved foil tape","Silicone caulk only"],"correct":2,"re":"Cloth duct tape fails over time; codes call for UL-181 listed mastic or foil tape on seams to limit leakage.","rr":"Тканевая duct tape со временем отслаивается; нормы требуют мастику или фольгированную ленту с листингом UL-181 на швы для снижения утечек.","qr":"Швы и стыки воздуховодов лучше всего герметизировать:","optsr":["Обычной тканевой «duct tape»","Холодильным маслом","Мастикой UL-181 или одобренной фольгированной лентой","Только силиконовым герметиком"],"qs":"Las costuras y juntas de los ductos se sellan mejor con:","optss":["Cinta de tela estándar ('duct tape')","Aceite de refrigerante","Mástique UL-181 o cinta de aluminio aprobada","Solo silicón sellador"],"rs":"La cinta de tela falla con el tiempo; los códigos exigen mástique o cinta de aluminio listada UL-181 en las costuras para limitar las fugas."},
  {"id":142,"sec":"Fabrication & Installation","q":"A gas furnace requires combustion air. An atmospherically-vented furnace in a confined space needs:","opts":["Two openings (high and low) for combustion/ventilation air","More refrigerant","No air openings","Only an exhaust fan"],"correct":0,"re":"Confined spaces need two permanent openings (one near the top, one near the bottom) sized per code to supply combustion and dilution air.","rr":"Тесным помещениям нужны два постоянных отверстия (вверху и внизу), рассчитанные по нормам, для воздуха горения и разбавления.","qr":"Газовой печи нужен воздух для горения. Печь с атмосферным дымоудалением в тесном помещении требует:","optsr":["Два отверстия (верхнее и нижнее) для воздуха горения/вентиляции","Больше хладагента","Никаких отверстий","Только вытяжной вентилятор"],"qs":"Un horno de gas requiere aire de combustión. Un horno de tiro atmosférico en un espacio confinado necesita:","optss":["Dos aberturas (alta y baja) para el aire de combustión/ventilación","Más refrigerante","Ninguna abertura de aire","Solo un ventilador de extracción"],"rs":"Los espacios confinados necesitan dos aberturas permanentes (una cerca de la parte superior, otra cerca de la inferior) dimensionadas según el código para suministrar aire de combustión y dilución."},
  {"id":143,"sec":"Fabrication & Installation","q":"A Category IV gas furnace (high-efficiency condensing) is vented with:","opts":["Masonry chimney only","No vent","Sealed plastic (PVC/CPVC) because flue gases are cool and positive-pressure","Single-wall metal pipe"],"correct":2,"re":"Condensing (Cat IV) furnaces produce cool, positive-pressure, moisture-laden flue gas, vented through sealed plastic with a condensate drain.","rr":"Конденсационные печи (Cat IV) дают холодный, под избыточным давлением, насыщенный влагой дымовой газ — удаляется герметичным пластиком с дренажом конденсата.","qr":"Газовая печь Category IV (высокоэффективная конденсационная) удаляет продукты сгорания через:","optsr":["Только кирпичный дымоход","Без дымохода","Герметичный пластик (PVC/CPVC), т.к. газы холодные и под давлением","Одностенную металлическую трубу"],"qs":"Un horno de gas Categoría IV (condensante de alta eficiencia) se ventila con:","optss":["Solo chimenea de mampostería","Sin ventilación","Plástico sellado (PVC/CPVC) porque los gases de combustión son fríos y de presión positiva","Tubo metálico de pared sencilla"],"rs":"Los hornos condensantes (Cat IV) producen gases de combustión fríos, de presión positiva y cargados de humedad, ventilados a través de plástico sellado con un drenaje de condensado."},
  {"id":144,"sec":"Fabrication & Installation","q":"During startup, measuring total external static pressure (TESP) verifies the:","opts":["Gas pressure","Refrigerant charge","Flame color","Airflow/duct performance against the blower table"],"correct":3,"re":"Comparing measured TESP to the blower performance table confirms whether the system is moving the design airflow; high TESP means restriction.","rr":"Сравнение измеренного TESP с таблицей вентилятора подтверждает, движет ли система расчётный расход; высокий TESP — сужение/сопротивление.","qr":"При запуске измерение полного внешнего статического давления (TESP) проверяет:","optsr":["Давление газа","Заправку хладагентом","Цвет пламени","Производительность воздуховодов/расход по таблице вентилятора"],"qs":"Durante el arranque, medir la presión estática externa total (TESP) verifica:","optss":["La presión del gas","La carga de refrigerante","El color de la llama","El rendimiento del flujo de aire/ducto frente a la tabla del ventilador"],"rs":"Comparar la TESP medida con la tabla de rendimiento del ventilador confirma si el sistema está moviendo el flujo de aire de diseño; una TESP alta indica restricción."},
  {"id":145,"sec":"Fabrication & Installation","q":"The gas manifold pressure on a typical residential natural-gas furnace is set near:","opts":["25 in WC","3.5 in WC","11 in WC","0.5 in WC"],"correct":1,"re":"Natural-gas furnaces commonly run about 3.5 in WC manifold pressure (LP propane near 10–11 in WC); always verify with the rating plate and a manometer.","rr":"Печи на природном газе обычно работают около 3.5 in WC на манифольде (пропан LP около 10–11 in WC); всегда сверяйтесь с шильдиком и манометром.","qr":"Давление газа на манифольде типовой бытовой печи на природном газе устанавливается около:","optsr":["25 in WC","3.5 in WC","11 in WC","0.5 in WC"],"qs":"La presión del múltiple de gas (manifold) en un horno residencial típico de gas natural se ajusta cerca de:","optss":["25 in WC","3.5 in WC","11 in WC","0.5 in WC"],"rs":"Los hornos de gas natural comúnmente operan con aproximadamente 3.5 in WC de presión de múltiple (el propano LP cerca de 10–11 in WC); siempre verifique con la placa de clasificación y un manómetro."},
  {"id":146,"sec":"Fabrication & Installation","q":"After installing a new condenser, the technician verifies charge on a fixed-orifice (piston) system primarily by:","opts":["Voltage","Subcooling","Duct size","Superheat (with a charging chart)"],"correct":3,"re":"Fixed-orifice/piston systems are charged by superheat (using a target chart with indoor wet-bulb and outdoor dry-bulb); TXV systems use subcooling.","rr":"Системы с фикс. дросселем/piston заправляют по superheat (по целевой таблице с indoor wet-bulb и outdoor dry-bulb); системы с TXV — по subcooling.","qr":"После установки нового конденсатора заправку системы с фикс. дросселем (piston) проверяют прежде всего по:","optsr":["Напряжению","Subcooling","Размеру дакта","Superheat (по charging-таблице)"],"qs":"Después de instalar un condensador nuevo, el técnico verifica la carga en un sistema de orificio fijo (pistón) principalmente mediante:","optss":["El voltaje","El subenfriamiento","El tamaño del ducto","El sobrecalentamiento (con una carta de carga)"],"rs":"Los sistemas de orificio fijo/pistón se cargan por sobrecalentamiento (usando una carta objetivo con bulbo húmedo interior y bulbo seco exterior); los sistemas con TXV usan subenfriamiento."},
  {"id":147,"sec":"Fabrication & Installation","q":"A TXV-equipped system is charged to a target:","opts":["Superheat value","Voltage value","Subcooling value","CFM value"],"correct":2,"re":"Because a TXV maintains evaporator superheat automatically, correct charge is verified at the condenser by subcooling per the manufacturer's spec.","rr":"Поскольку TXV сам поддерживает superheat испарителя, правильную заправку проверяют на конденсаторе по subcooling согласно спецификации производителя.","qr":"Систему с TXV заправляют до целевого значения:","optsr":["Superheat","Напряжения","Subcooling","CFM"],"qs":"Un sistema equipado con TXV se carga a un objetivo de:","optss":["Valor de sobrecalentamiento","Valor de voltaje","Valor de subenfriamiento","Valor de CFM"],"rs":"Dado que una TXV mantiene automáticamente el sobrecalentamiento del evaporador, la carga correcta se verifica en el condensador mediante el subenfriamiento según la especificación del fabricante."},
  {"id":148,"sec":"Fabrication & Installation","q":"Line-set sizing matters because an oversized suction line can cause:","opts":["Too much subcooling","High voltage","Low refrigerant velocity and poor oil return","Excess airflow"],"correct":2,"re":"If suction velocity is too low (line too large or run too long without proper sizing), oil won't return to the compressor, risking lubrication failure.","rr":"Если скорость всасывания слишком мала (линия велика или длинна без правильного расчёта), масло не вернётся в компрессор — риск отказа смазки.","qr":"Подбор диаметра линий важен, потому что завышенная всасывающая линия может вызвать:","optsr":["Слишком большой subcooling","Высокое напряжение","Низкую скорость хладагента и плохой возврат масла","Избыточный расход воздуха"],"qs":"El dimensionamiento del juego de líneas (line-set) importa porque una línea de succión sobredimensionada puede causar:","optss":["Demasiado subenfriamiento","Voltaje alto","Baja velocidad del refrigerante y mal retorno de aceite","Exceso de flujo de aire"],"rs":"Si la velocidad de succión es demasiado baja (línea demasiado grande o tramo demasiado largo sin el dimensionamiento adecuado), el aceite no retornará al compresor, arriesgando una falla de lubricación."},
  {"id":149,"sec":"Fabrication & Installation","q":"A disconnecting means (service disconnect) must be installed:","opts":["Within sight of the outdoor unit","In the attic only","Inside the compressor","At the thermostat"],"correct":0,"re":"Electrical code requires a disconnect within sight of and readily accessible to the outdoor unit so it can be safely de-energized for service.","rr":"Электрические нормы требуют разъединитель в зоне прямой видимости и в лёгком доступе у наружного блока, чтобы безопасно его обесточить для обслуживания.","qr":"Разъединитель (service disconnect) должен быть установлен:","optsr":["В зоне видимости от наружного блока","Только на чердаке","Внутри компрессора","У термостата"],"qs":"Un medio de desconexión (desconexión de servicio) debe instalarse:","optss":["A la vista de la unidad exterior","Solo en el ático","Dentro del compresor","En el termostato"],"rs":"El código eléctrico exige una desconexión a la vista y de fácil acceso de la unidad exterior para que pueda desenergizarse de forma segura para su mantenimiento."},
  {"id":150,"sec":"Fabrication & Installation","q":"When connecting flexible duct, it should be:","opts":["Left disconnected","Compressed and kinked to save space","Pulled taut and supported to avoid sag and restriction","Filled with refrigerant"],"correct":2,"re":"Flex duct must be stretched tight and supported at intervals; sags, kinks, and compression sharply increase static pressure and cut airflow.","rr":"Гибкий дакт натягивают и поддерживают через интервалы; провисания, заломы и сжатие резко повышают статическое давление и режут расход.","qr":"При подключении гибкого воздуховода его следует:","optsr":["Оставить отсоединённым","Сжать и заломить для экономии места","Натянуть и поддержать, избегая провисания и сужения","Заполнить хладагентом"],"qs":"Al conectar ducto flexible, este debe:","optss":["Dejarse desconectado","Comprimirse y doblarse para ahorrar espacio","Tensarse y apoyarse para evitar combaduras y restricciones","Llenarse con refrigerante"],"rs":"El ducto flexible debe estirarse bien tenso y apoyarse a intervalos; las combaduras, dobleces y compresiones aumentan drásticamente la presión estática y reducen el flujo de aire."},
  {"id":151,"sec":"Fabrication & Installation","q":"The purpose of a P-trap/condensate trap depth being adequate is to:","opts":["Increase airflow","Lower gas pressure","Add refrigerant","Prevent air pull-through or bubbling that blocks drainage"],"correct":3,"re":"On draw-through coils the blower's negative pressure can hold water in the line; a properly sized trap seals against it so condensate drains.","rr":"На draw-through испарителях разрежение вентилятора удерживает воду в линии; правильный сифон герметизирует от него, и конденсат стекает.","qr":"Достаточная глубина P-trap/сифона конденсата нужна, чтобы:","optsr":["Увеличить расход воздуха","Снизить давление газа","Добавить хладагент","Не дать подсосу воздуха или бульканью блокировать слив"],"qs":"El propósito de que la profundidad de una trampa P/trampa de condensado sea adecuada es:","optss":["Aumentar el flujo de aire","Reducir la presión del gas","Agregar refrigerante","Prevenir el paso de aire o el burbujeo que bloquea el drenaje"],"rs":"En serpentines de tiro inducido (draw-through), la presión negativa del ventilador puede retener agua en la línea; una trampa correctamente dimensionada sella contra ella para que el condensado drene."},
  {"id":152,"sec":"Fabrication & Installation","q":"Before opening a system to replace a component, the refrigerant must be:","opts":["Recovered into an approved recovery cylinder","Burned off","Vented to atmosphere","Mixed with nitrogen"],"correct":0,"re":"EPA Section 608 prohibits venting; refrigerant must be recovered with certified equipment into a DOT-approved recovery cylinder.","rr":"EPA Section 608 запрещает стравливание; хладагент откачивают сертифицированным оборудованием в одобренный DOT recovery-баллон.","qr":"Перед вскрытием системы для замены компонента хладагент необходимо:","optsr":["Откачать в одобренный recovery-баллон","Сжечь","Стравить в атмосферу","Смешать с азотом"],"qs":"Antes de abrir un sistema para reemplazar un componente, el refrigerante debe ser:","optss":["Recuperado en un cilindro de recuperación aprobado","Quemado","Ventilado a la atmósfera","Mezclado con nitrógeno"],"rs":"La Sección 608 de la EPA prohíbe la ventilación; el refrigerante debe recuperarse con equipo certificado en un cilindro de recuperación aprobado por el DOT."},
  {"id":153,"sec":"Fabrication & Installation","q":"A new line set is pressure-tested for leaks before evacuation using:","opts":["Water","Propane","Pure oxygen","Dry nitrogen (often with a trace of refrigerant for a detector)"],"correct":3,"re":"Dry nitrogen is used for pressure/leak testing because it's inert and dry; oxygen is dangerous (combustion) and must never be used.","rr":"Для опрессовки/поиска утечек применяют сухой азот — он инертен и сух; кислород опасен (горение) и применять его нельзя.","qr":"Новый комплект линий перед вакуумированием проверяют на утечки с помощью:","optsr":["Воды","Пропана","Чистого кислорода","Сухого азота (иногда с примесью хладагента для детектора)"],"qs":"Un juego de líneas nuevo se somete a una prueba de presión para detectar fugas antes de la evacuación usando:","optss":["Agua","Propano","Oxígeno puro","Nitrógeno seco (a menudo con una traza de refrigerante para un detector)"],"rs":"El nitrógeno seco se usa para la prueba de presión/fugas porque es inerte y seco; el oxígeno es peligroso (combustión) y nunca debe usarse."},
  {"id":154,"sec":"Fabrication & Installation","q":"Commissioning a heat pump includes verifying defrost operation, which is best confirmed by:","opts":["Reading the thermostat brand","Initiating/observing a defrost cycle and reversing-valve shift","Checking the filter","Measuring SEER"],"correct":1,"re":"During defrost the unit reverses to cooling, the outdoor fan stops, and the coil clears ice; observing this cycle confirms the defrost board and reversing valve work.","rr":"При разморозке блок переходит в охлаждение, наружный вентилятор останавливается, иней сходит; наблюдение этого цикла подтверждает работу defrost-платы и реверс-клапана.","qr":"Пусконаладка теплового насоса включает проверку разморозки, которую лучше всего подтвердить:","optsr":["Чтением бренда термостата","Запуском/наблюдением цикла defrost и переключения реверс-клапана","Проверкой фильтра","Измерением SEER"],"qs":"La puesta en marcha (commissioning) de una bomba de calor incluye verificar la operación de descongelamiento, lo cual se confirma mejor mediante:","optss":["La lectura de la marca del termostato","Iniciar/observar un ciclo de descongelamiento y el cambio de la válvula reversora","Revisar el filtro","Medir el SEER"],"rs":"Durante el descongelamiento la unidad se invierte a enfriamiento, el ventilador exterior se detiene y el serpentín elimina el hielo; observar este ciclo confirma que la tarjeta de descongelamiento y la válvula reversora funcionan."},
  {"id":155,"sec":"Service & Troubleshooting","q":"High superheat together with low subcooling most often indicates the system is:","opts":["Undercharged (low on refrigerant)","Airflow too high","Overcharged","Voltage too high"],"correct":0,"re":"Low charge starves the evaporator (high superheat) and leaves little liquid in the condenser (low subcooling) — classic undercharge signature.","rr":"Недозаправка обедняет испаритель (высокий superheat) и оставляет мало жидкости в конденсаторе (низкий subcooling) — классическая картина недозаправки.","qr":"Высокий superheat вместе с низким subcooling чаще всего указывает, что система:","optsr":["Недозаправлена (мало хладагента)","Слишком большой расход воздуха","Перезаправлена","Слишком высокое напряжение"],"qs":"Un sobrecalentamiento alto junto con un subenfriamiento bajo indica con mayor frecuencia que el sistema está:","optss":["Con carga insuficiente (bajo de refrigerante)","Con flujo de aire demasiado alto","Sobrecargado","Con voltaje demasiado alto"],"rs":"Una carga baja deja al evaporador hambriento (sobrecalentamiento alto) y deja poco líquido en el condensador (subenfriamiento bajo): la firma clásica de carga insuficiente."},
  {"id":156,"sec":"Service & Troubleshooting","q":"Low superheat with high subcooling most often indicates:","opts":["Open contactor","Overcharge (too much refrigerant)","Dirty filter","Undercharge"],"correct":1,"re":"Excess charge floods the condenser (high subcooling) and can flood the evaporator (low superheat) — the overcharge signature.","rr":"Избыток заряда переполняет конденсатор (высокий subcooling) и может затапливать испаритель (низкий superheat) — картина перезаправки.","qr":"Низкий superheat при высоком subcooling чаще всего указывает на:","optsr":["Разомкнутый контактор","Перезаправку (слишком много хладагента)","Грязный фильтр","Недозаправку"],"qs":"Un sobrecalentamiento bajo con un subenfriamiento alto indica con mayor frecuencia:","optss":["Contactor abierto","Sobrecarga (demasiado refrigerante)","Filtro sucio","Carga insuficiente"],"rs":"El exceso de carga inunda el condensador (subenfriamiento alto) y puede inundar el evaporador (sobrecalentamiento bajo): la firma de sobrecarga."},
  {"id":157,"sec":"Service & Troubleshooting","q":"A TXV that is 'hunting' (bulb signal unstable) typically causes:","opts":["Superheat that swings up and down erratically","High voltage","Steady superheat","No effect on superheat"],"correct":0,"re":"A hunting TXV over- and under-feeds the evaporator, causing superheat to oscillate; causes include a loose/poorly insulated sensing bulb or wrong valve size.","rr":"«Охотящийся» TXV то переподаёт, то недоподаёт в испаритель, и superheat колеблется; причины — слабо закреплённая/плохо изолированная колба или неверный размер клапана.","qr":"TXV, который «охотится» (нестабильный сигнал колбы), обычно вызывает:","optsr":["Superheat, который беспорядочно скачет вверх-вниз","Высокое напряжение","Стабильный superheat","Никакого влияния на superheat"],"qs":"Una TXV que está 'cazando' (señal del bulbo inestable) típicamente causa:","optss":["Sobrecalentamiento que oscila hacia arriba y hacia abajo de forma errática","Voltaje alto","Sobrecalentamiento estable","Ningún efecto sobre el sobrecalentamiento"],"rs":"Una TXV que caza sobrealimenta y subalimenta el evaporador, haciendo que el sobrecalentamiento oscile; las causas incluyen un bulbo sensor suelto/mal aislado o un tamaño de válvula incorrecto."},
  {"id":158,"sec":"Service & Troubleshooting","q":"A compressor that hums and trips on overload but won't start, with the windings reading good, often has a failed:","opts":["Thermostat","Start/run capacitor","Reversing valve","Filter drier"],"correct":1,"re":"A weak or failed capacitor robs the motor of starting torque; the compressor draws locked-rotor amps and trips. Verify capacitor microfarads before condemning the compressor.","rr":"Слабый или отказавший конденсатор лишает двигатель пускового момента; компрессор тянет ток заторможенного ротора и выбивает. Проверьте микрофарады конденсатора, прежде чем менять компрессор.","qr":"Компрессор гудит и выбивает по перегрузке, но не запускается, при этом обмотки в норме — часто неисправен:","optsr":["Термостат","Пусковой/рабочий конденсатор","Реверс-клапан","Фильтр-осушитель"],"qs":"Un compresor que zumba y se dispara por sobrecarga pero no arranca, con los devanados leyendo bien, a menudo tiene un/una:","optss":["Termostato","Capacitor de arranque/marcha","Válvula reversora","Filtro deshidratador"],"rs":"Un capacitor débil o fallado le quita al motor el par de arranque; el compresor consume amperaje de rotor bloqueado y se dispara. Verifique los microfaradios del capacitor antes de condenar el compresor."},
  {"id":159,"sec":"Service & Troubleshooting","q":"A run capacitor is tested by:","opts":["Checking refrigerant","Reading the voltage only","Smelling it","Measuring its capacitance (µF) against the rated value"],"correct":3,"re":"With the cap discharged and disconnected, a meter on capacitance compares actual µF to the rating; out-of-tolerance or bulged caps must be replaced.","rr":"Разрядив и отключив конденсатор, мультиметром в режиме ёмкости сравнивают реальные µF с номиналом; вне допуска или вздутый — под замену.","qr":"Рабочий конденсатор проверяют:","optsr":["Проверкой хладагента","Только измерением напряжения","По запаху","Измерением ёмкости (µF) и сравнением с номиналом"],"qs":"Un capacitor de marcha se prueba mediante:","optss":["La revisión del refrigerante","La lectura solo del voltaje","Su olor","La medición de su capacitancia (µF) frente al valor nominal"],"rs":"Con el capacitor descargado y desconectado, un medidor en capacitancia compara los µF reales con el valor nominal; los capacitores fuera de tolerancia o abultados deben reemplazarse."},
  {"id":160,"sec":"Service & Troubleshooting","q":"Pitted, burned contactor points are best addressed by:","opts":["Filing them smooth","Increasing airflow","Replacing the contactor","Adding refrigerant"],"correct":2,"re":"Filing contacts removes plating and worsens arcing; a pitted contactor should be replaced to ensure reliable, low-resistance switching.","rr":"Опиливание снимает покрытие и усиливает искрение; изъеденный контактор меняют для надёжной коммутации с малым сопротивлением.","qr":"Подгоревшие, изъеденные контакты контактора правильнее всего:","optsr":["Зачистить напильником","Увеличить расход воздуха","Заменить контактор","Добавить хладагент"],"qs":"Los puntos del contactor picados y quemados se atienden mejor:","optss":["Limándolos hasta alisarlos","Aumentando el flujo de aire","Reemplazando el contactor","Agregando refrigerante"],"rs":"Limar los contactos elimina el recubrimiento y empeora el arqueo; un contactor picado debe reemplazarse para asegurar una conmutación confiable y de baja resistencia."},
  {"id":161,"sec":"Service & Troubleshooting","q":"To diagnose a suspected grounded compressor motor, the technician measures resistance from the C, S, and R terminals to:","opts":["The thermostat","Ground/chassis (any continuity to ground indicates a grounded winding)","The refrigerant","The duct"],"correct":1,"re":"Common-Start-Run windings should read continuity and roughly C-R + C-S = S-R; any winding-to-ground continuity means a grounded (shorted-to-case) compressor that must be replaced.","rr":"Обмотки Common-Start-Run должны иметь проводимость и примерно C-R + C-S = S-R; любая проводимость обмотки на землю означает пробитый на корпус компрессор — под замену.","qr":"Чтобы диагностировать предполагаемый пробой обмотки компрессора на корпус, техник измеряет сопротивление от клемм C, S, R к:","optsr":["Термостату","Земле/корпусу (любая проводимость на землю = пробой обмотки)","Хладагенту","Воздуховоду"],"qs":"Para diagnosticar una sospecha de motor de compresor a tierra, el técnico mide la resistencia desde las terminales C, S y R hacia:","optss":["El termostato","Tierra/chasis (cualquier continuidad a tierra indica un devanado a tierra)","El refrigerante","El ducto"],"rs":"Los devanados Común-Arranque-Marcha deben leer continuidad y aproximadamente C-R + C-S = S-R; cualquier continuidad de devanado a tierra significa un compresor a tierra (en corto con la carcasa) que debe reemplazarse."},
  {"id":162,"sec":"Service & Troubleshooting","q":"Abnormally high head (discharge) pressure is commonly caused by:","opts":["Clean coil","A dirty condenser coil, overcharge, or non-condensables","Low ambient only","Low refrigerant"],"correct":1,"re":"Restricted condenser heat rejection (dirty coil, failed fan, overcharge, or air/non-condensables in the system) raises head pressure.","rr":"Ухудшение теплоотвода конденсатора (грязная батарея, отказ вентилятора, перезаправка или воздух/неконденсируемые в системе) поднимает давление нагнетания.","qr":"Аномально высокое давление нагнетания (head) обычно вызвано:","optsr":["Чистым конденсатором","Грязным конденсатором, перезаправкой или неконденсируемыми","Только низкой наружной температурой","Недостатком хладагента"],"qs":"Una presión de descarga (head) anormalmente alta es causada comúnmente por:","optss":["Serpentín limpio","Un serpentín de condensador sucio, sobrecarga o no condensables","Solo baja temperatura ambiente","Bajo refrigerante"],"rs":"El rechazo de calor restringido del condensador (serpentín sucio, ventilador fallado, sobrecarga, o aire/no condensables en el sistema) eleva la presión de descarga."},
  {"id":163,"sec":"Service & Troubleshooting","q":"A gas furnace lights then shuts off after a few seconds ('flame proving' fault). The most likely cause is a:","opts":["Dirty or failed flame sensor","Low refrigerant","Oversized duct","Bad SEER rating"],"correct":0,"re":"If the flame sensor can't prove flame (dirty, cracked, or misaligned), the control closes the gas valve for safety — flame lights then drops out.","rr":"Если датчик пламени не подтверждает пламя (загрязнён, треснул или смещён), плата закрывает газовый клапан для безопасности — пламя вспыхивает и гаснет.","qr":"Газовая печь зажигается, затем гаснет через несколько секунд (ошибка контроля пламени). Наиболее вероятная причина:","optsr":["Грязный или неисправный датчик пламени (flame sensor)","Недостаток хладагента","Завышенный дакт","Плохой SEER"],"qs":"Un horno de gas enciende y luego se apaga después de unos segundos (falla de 'comprobación de llama'). La causa más probable es un/una:","optss":["Sensor de llama sucio o fallado","Bajo refrigerante","Ducto sobredimensionado","Mala clasificación SEER"],"rs":"Si el sensor de llama no puede comprobar la llama (sucio, agrietado o desalineado), el control cierra la válvula de gas por seguridad: la llama enciende y luego se apaga."},
  {"id":164,"sec":"Service & Troubleshooting","q":"The flame-sensor (flame-rectification) signal is measured in:","opts":["Microns","Pounds","Volts AC","Microamps (µA) DC"],"correct":3,"re":"A clean flame sensor passes a small DC current (microamps) by rectification; a low microamp reading indicates a dirty sensor or weak flame.","rr":"Чистый датчик пламени проводит малый постоянный ток (микроамперы) за счёт ректификации; низкий µA — загрязнение датчика или слабое пламя.","qr":"Сигнал датчика пламени (flame rectification) измеряется в:","optsr":["Микронах","Фунтах","Вольтах переменного тока","Микроамперах (µA) постоянного тока"],"qs":"La señal del sensor de llama (rectificación de llama) se mide en:","optss":["Micrones","Libras","Voltios CA","Microamperios (µA) CC"],"rs":"Un sensor de llama limpio deja pasar una pequeña corriente CC (microamperios) por rectificación; una lectura baja de microamperios indica un sensor sucio o una llama débil."},
  {"id":165,"sec":"Service & Troubleshooting","q":"A furnace that short-cycles on the high-limit switch usually has:","opts":["A clean filter","Insufficient airflow (overheating heat exchanger)","Low gas pressure only","Too much airflow"],"correct":1,"re":"Restricted airflow (dirty filter/coil, blocked ducts, weak blower) lets the heat exchanger overheat, tripping the limit and short-cycling the burner.","rr":"Ограниченный расход (грязный фильтр/испаритель, забитые дакты, слабый вентилятор) перегревает теплообменник, лимит срабатывает и горелка циклит.","qr":"Печь, циклящая по верхнему лимиту (high-limit), обычно имеет:","optsr":["Чистый фильтр","Недостаточный расход воздуха (перегрев теплообменника)","Только низкое давление газа","Слишком большой расход воздуха"],"qs":"Un horno que cicla de forma corta por el interruptor de límite alto usualmente tiene:","optss":["Un filtro limpio","Flujo de aire insuficiente (sobrecalentamiento del intercambiador de calor)","Solo baja presión de gas","Demasiado flujo de aire"],"rs":"El flujo de aire restringido (filtro/serpentín sucio, ductos bloqueados, ventilador débil) deja que el intercambiador de calor se sobrecaliente, disparando el límite y ciclando de forma corta el quemador."},
  {"id":166,"sec":"Service & Troubleshooting","q":"A cracked heat exchanger is a safety concern because it can:","opts":["Increase airflow","Save gas","Allow combustion products (CO) to mix with supply air","Lower the SEER"],"correct":2,"re":"A crack can leak carbon monoxide and flue gases into the conditioned airstream — a life-safety hazard requiring shutdown until repaired/replaced.","rr":"Трещина может пропускать угарный газ и дымовые газы в приточный воздух — угроза жизни; до ремонта/замены оборудование выводят из работы.","qr":"Трещина в теплообменнике опасна, потому что может:","optsr":["Увеличить расход воздуха","Экономить газ","Допустить смешивание продуктов сгорания (CO) с приточным воздухом","Снизить SEER"],"qs":"Un intercambiador de calor agrietado es una preocupación de seguridad porque puede:","optss":["Aumentar el flujo de aire","Ahorrar gas","Permitir que los productos de combustión (CO) se mezclen con el aire de suministro","Reducir el SEER"],"rs":"Una grieta puede filtrar monóxido de carbono y gases de combustión hacia el flujo de aire acondicionado: un peligro mortal que requiere apagar el equipo hasta repararlo/reemplazarlo."},
  {"id":167,"sec":"Service & Troubleshooting","q":"A heat pump that blows cold air in heating mode and never warms up may have a:","opts":["High SEER","Stuck reversing valve (still in cooling)","Clogged condensate drain","Dirty filter only"],"correct":1,"re":"If the reversing valve fails to shift (or its solenoid/wiring fails), the unit stays in cooling during a heat call, delivering cold air.","rr":"Если реверс-клапан не переключается (или отказали соленоид/проводка), блок остаётся в охлаждении при запросе нагрева и дует холодным.","qr":"Тепловой насос дует холодным в режиме нагрева и не прогревается — возможна:","optsr":["Высокий SEER","Заклинивший реверс-клапан (остался в охлаждении)","Засорённая дренажная линия","Только грязный фильтр"],"qs":"Una bomba de calor que sopla aire frío en modo de calefacción y nunca se calienta puede tener una:","optss":["SEER alta","Válvula reversora atascada (todavía en enfriamiento)","Drenaje de condensado obstruido","Solo un filtro sucio"],"rs":"Si la válvula reversora no logra cambiar (o falla su solenoide/cableado), la unidad permanece en enfriamiento durante una llamada de calor, entregando aire frío."},
  {"id":168,"sec":"Service & Troubleshooting","q":"In heating mode, a heat pump's outdoor coil acts as the:","opts":["Condenser","Filter","Metering device","Evaporator (absorbing heat from outdoor air)"],"correct":3,"re":"In heating the refrigerant flow reverses: the outdoor coil absorbs heat (evaporator) and the indoor coil rejects it (condenser).","rr":"В нагреве поток реверсируется: наружный змеевик поглощает тепло (испаритель), а внутренний отдаёт его (конденсатор).","qr":"В режиме нагрева наружный змеевик теплового насоса работает как:","optsr":["Конденсатор","Фильтр","Дозатор","Испаритель (забирает тепло из наружного воздуха)"],"qs":"En modo de calefacción, el serpentín exterior de una bomba de calor actúa como el:","optss":["Condensador","Filtro","Dispositivo de medición","Evaporador (absorbiendo calor del aire exterior)"],"rs":"En calefacción el flujo de refrigerante se invierte: el serpentín exterior absorbe calor (evaporador) y el serpentín interior lo rechaza (condensador)."},
  {"id":169,"sec":"Service & Troubleshooting","q":"A compressor drawing locked-rotor amps (LRA) continuously will:","opts":["Run efficiently","Overheat and trip its overload/breaker","Improve subcooling","Lower head pressure"],"correct":1,"re":"Continuous LRA means the rotor isn't turning (seized, no start torque, low voltage); the motor overheats and the overload or breaker trips.","rr":"Постоянный LRA означает, что ротор не вращается (заклинил, нет пускового момента, низкое напряжение); двигатель перегревается, и срабатывает защита или автомат.","qr":"Компрессор, постоянно потребляющий ток заторможенного ротора (LRA):","optsr":["Работает эффективно","Перегревается и выбивает защиту/автомат","Улучшает subcooling","Снижает давление нагнетания"],"qs":"Un compresor que consume amperaje de rotor bloqueado (LRA) de forma continua:","optss":["Funcionará eficientemente","Se sobrecalentará y disparará su sobrecarga/interruptor","Mejorará el subenfriamiento","Reducirá la presión de descarga"],"rs":"Un LRA continuo significa que el rotor no está girando (agarrotado, sin par de arranque, bajo voltaje); el motor se sobrecalienta y la sobrecarga o el interruptor se disparan."},
  {"id":170,"sec":"Service & Troubleshooting","q":"A refrigerant restriction (e.g., a clogged filter drier) typically shows:","opts":["A temperature drop and frost at the restriction with low evaporator pressure","Equal pressures","High subcooling everywhere","No symptoms"],"correct":0,"re":"Flow restriction causes a pressure/temperature drop across the blockage (often frost there), starving the evaporator and lowering its pressure.","rr":"Засор даёт перепад давления/температуры на месте сужения (часто иней там), обедняя испаритель и снижая его давление.","qr":"Засор в контуре хладагента (например забитый фильтр-осушитель) обычно проявляется:","optsr":["Перепадом температуры и инеем на засоре при низком давлении испарителя","Равными давлениями","Высоким subcooling везде","Без симптомов"],"qs":"Una restricción de refrigerante (por ejemplo, un filtro deshidratador obstruido) típicamente muestra:","optss":["Una caída de temperatura y escarcha en la restricción con baja presión de evaporador","Presiones iguales","Subenfriamiento alto en todas partes","Ningún síntoma"],"rs":"La restricción de flujo causa una caída de presión/temperatura a través de la obstrucción (a menudo escarcha ahí), dejando hambriento al evaporador y reduciendo su presión."},
  {"id":171,"sec":"Service & Troubleshooting","q":"To find a small refrigerant leak, the most precise method among these is:","opts":["Guessing","An electronic leak detector or UV dye, confirmed with bubbles","Adding more charge","Listening only"],"correct":1,"re":"Electronic detectors and UV dye (plus soap bubbles for confirmation) pinpoint small leaks; a nitrogen standing-pressure test confirms tightness.","rr":"Электронные детекторы и УФ-краситель (плюс мыльные пузыри для подтверждения) точно находят малые утечки; азотная опрессовка под давлением подтверждает герметичность.","qr":"Чтобы найти небольшую утечку хладагента, наиболее точный из методов:","optsr":["Догадка","Электронный течеискатель или УФ-краситель, подтверждённый пузырьками","Добавить ещё заправки","Только на слух"],"qs":"Para encontrar una fuga pequeña de refrigerante, el método más preciso entre estos es:","optss":["Adivinar","Un detector electrónico de fugas o tinte UV, confirmado con burbujas","Agregar más carga","Solo escuchar"],"rs":"Los detectores electrónicos y el tinte UV (más burbujas de jabón para confirmar) localizan con precisión las fugas pequeñas; una prueba de presión estática con nitrógeno confirma la hermeticidad."},
  {"id":172,"sec":"Service & Troubleshooting","q":"A blower motor running but moving little air, with high static pressure, suggests:","opts":["High SEER","Refrigerant leak","Low gas pressure","A duct/coil/filter restriction or a slipping/failing blower wheel"],"correct":3,"re":"High static with low airflow points to restriction (dirty filter/coil, undersized or blocked ducts) or a degraded blower wheel/belt.","rr":"Высокое статическое при малом расходе — это сужение (грязный фильтр/испаритель, узкие или забитые дакты) либо изношенное колесо/ремень вентилятора.","qr":"Вентилятор крутится, но воздуха мало, при высоком статическом давлении — это указывает на:","optsr":["Высокий SEER","Утечку хладагента","Низкое давление газа","Засор дакта/испарителя/фильтра или проскальзывающее/изношенное колесо вентилятора"],"qs":"Un motor de ventilador que funciona pero mueve poco aire, con alta presión estática, sugiere:","optss":["SEER alta","Fuga de refrigerante","Baja presión de gas","Una restricción de ducto/serpentín/filtro o una rueda de ventilador que patina/falla"],"rs":"Una presión estática alta con bajo flujo de aire apunta a una restricción (filtro/serpentín sucio, ductos subdimensionados o bloqueados) o a una rueda de ventilador/banda degradada."},
  {"id":173,"sec":"Service & Troubleshooting","q":"Routine maintenance to maintain capacity and efficiency includes:","opts":["Cleaning coils, replacing filters, and checking airflow/charge","Adding refrigerant every visit","Disabling safeties","Removing the disconnect"],"correct":0,"re":"Clean coils and filters, verified airflow, correct charge, tight electrical connections, and clear condensate drains keep the system efficient and reliable.","rr":"Чистые батареи и фильтры, проверенный расход, правильная заправка, затянутые электроконтакты и свободные дренажи держат систему эффективной и надёжной.","qr":"Регулярное обслуживание для сохранения производительности и КПД включает:","optsr":["Чистку батарей, замену фильтров и проверку расхода/заправки","Добавление хладагента каждый визит","Отключение защит","Снятие разъединителя"],"qs":"El mantenimiento rutinario para conservar la capacidad y la eficiencia incluye:","optss":["Limpiar serpentines, reemplazar filtros y verificar el flujo de aire/carga","Agregar refrigerante en cada visita","Deshabilitar las seguridades","Retirar la desconexión"],"rs":"Serpentines y filtros limpios, flujo de aire verificado, carga correcta, conexiones eléctricas apretadas y drenajes de condensado despejados mantienen el sistema eficiente y confiable."},
  {"id":174,"sec":"Service & Troubleshooting","q":"Adding refrigerant to a system without finding the leak is:","opts":["Required by EPA","Improper — the leak must be found and repaired (and venting is illegal)","Faster and recommended","Best practice"],"correct":1,"re":"'Topping off' a leaking system wastes refrigerant, harms the environment, and violates good practice/EPA rules — locate and repair the leak.","rr":"«Долив» в текущую систему расходует хладагент, вредит экологии и нарушает правила/EPA — утечку находят и устраняют.","qr":"Доливать хладагент, не найдя утечку, —","optsr":["Требование EPA","Неправильно — утечку нужно найти и устранить (стравливание запрещено)","Быстрее и рекомендуется","Лучшая практика"],"qs":"Agregar refrigerante a un sistema sin encontrar la fuga es:","optss":["Requerido por la EPA","Inadecuado: la fuga debe encontrarse y repararse (y ventilar es ilegal)","Más rápido y recomendado","La mejor práctica"],"rs":"'Rellenar' un sistema con fuga desperdicia refrigerante, daña el medio ambiente y viola las buenas prácticas/reglas de la EPA: localice y repare la fuga."},
  {"id":175,"sec":"Service & Troubleshooting","q":"A capacitor must be discharged before testing/handling because it:","opts":["Is always safe","Holds refrigerant","Can store a dangerous electrical charge even when power is off","Contains gas"],"correct":2,"re":"Run/start capacitors store energy; touching terminals can deliver a shock. Discharge through a proper resistor before handling.","rr":"Рабочие/пусковые конденсаторы хранят энергию; касание клемм может ударить током. Разряжайте через подходящий резистор перед работой.","qr":"Конденсатор нужно разрядить перед проверкой/работой, потому что он:","optsr":["Всегда безопасен","Содержит хладагент","Может хранить опасный электрозаряд даже при снятом питании","Содержит газ"],"qs":"Un capacitor debe descargarse antes de probarlo/manipularlo porque:","optss":["Siempre es seguro","Contiene refrigerante","Puede almacenar una carga eléctrica peligrosa incluso con la energía apagada","Contiene gas"],"rs":"Los capacitores de marcha/arranque almacenan energía; tocar las terminales puede provocar una descarga. Descárguelo a través de una resistencia adecuada antes de manipularlo."},
  {"id":176,"sec":"Service & Troubleshooting","q":"Low suction pressure with normal-to-high superheat in cooling often points to:","opts":["Dirty condenser only","Overcharge","High voltage","Low charge or restricted liquid line / low airflow"],"correct":3,"re":"Starved evaporator from low charge, a liquid-line restriction, or low indoor airflow lowers suction pressure and raises superheat.","rr":"Обеднённый испаритель из-за недозаправки, засора жидкостной линии или малого внутреннего расхода снижает давление всасывания и повышает superheat.","qr":"Низкое давление всасывания при нормальном-высоком superheat в охлаждении часто указывает на:","optsr":["Только грязный конденсатор","Перезаправку","Высокое напряжение","Недозаправку, засор жидкостной линии или низкий расход воздуха"],"qs":"Una baja presión de succión con sobrecalentamiento de normal a alto en enfriamiento a menudo apunta a:","optss":["Solo condensador sucio","Sobrecarga","Voltaje alto","Carga baja o línea de líquido restringida / bajo flujo de aire"],"rs":"Un evaporador hambriento por carga baja, una restricción en la línea de líquido o bajo flujo de aire interior reduce la presión de succión y aumenta el sobrecalentamiento."},
  {"id":177,"sec":"Service & Troubleshooting","q":"A contactor coil that won't pull in, with 24 V present at the coil, indicates:","opts":["Good coil","Refrigerant leak","Dirty filter","An open (burned-out) coil — replace the contactor"],"correct":3,"re":"If rated control voltage is present but the contactor doesn't energize, the coil is open/failed and the contactor must be replaced.","rr":"Если номинальное управляющее напряжение есть, а контактор не срабатывает — катушка в обрыве/отказала, контактор меняют.","qr":"Катушка контактора не притягивается при наличии 24 В на ней — это указывает на:","optsr":["Исправную катушку","Утечку хладагента","Грязный фильтр","Обрыв (перегорела) катушки — заменить контактор"],"qs":"Una bobina de contactor que no acciona, con 24 V presentes en la bobina, indica:","optss":["Bobina en buen estado","Fuga de refrigerante","Filtro sucio","Una bobina abierta (quemada): reemplace el contactor"],"rs":"Si el voltaje de control nominal está presente pero el contactor no se energiza, la bobina está abierta/fallada y el contactor debe reemplazarse."},
  {"id":178,"sec":"Service & Troubleshooting","q":"An evaporator coil that is clean but the system still ices up, with correct charge, suggests checking the:","opts":["Gas valve","Reversing valve","Indoor airflow (blower speed, duct restriction)","Flame sensor"],"correct":2,"re":"With good charge and a clean coil, persistent icing usually traces to low airflow — wrong blower tap/speed, restricted return, or blocked ducts.","rr":"При верной заправке и чистом испарителе устойчивое обмерзание обычно из-за малого расхода — неверная скорость вентилятора, забитая обратка или дакты.","qr":"Испаритель чист, заправка верна, но система всё равно обмерзает — стоит проверить:","optsr":["Газовый клапан","Реверс-клапан","Внутренний расход воздуха (скорость вентилятора, засор дакта)","Датчик пламени"],"qs":"Un serpentín de evaporador que está limpio pero el sistema aún se congela, con la carga correcta, sugiere revisar el/la:","optss":["Válvula de gas","Válvula reversora","Flujo de aire interior (velocidad del ventilador, restricción de ductos)","Sensor de llama"],"rs":"Con buena carga y un serpentín limpio, el congelamiento persistente usualmente se debe a bajo flujo de aire: derivación/velocidad incorrecta del ventilador, retorno restringido o ductos bloqueados."},
  {"id":179,"sec":"Safety & Field Practices","q":"Under EPA Section 608, intentionally venting most refrigerants during service is:","opts":["Prohibited","Only allowed indoors","Allowed if small","Required"],"correct":0,"re":"Venting CFC, HCFC, HFC and their substitutes is illegal; refrigerant must be recovered. Only de minimis releases during normal recovery/loop-back are tolerated.","rr":"Стравливание CFC, HCFC, HFC и их заменителей незаконно; хладагент откачивают. Допускаются лишь de minimis выбросы при штатной откачке/прокачке.","qr":"Согласно EPA Section 608, намеренное стравливание большинства хладагентов при обслуживании:","optsr":["Запрещено","Разрешено только внутри помещений","Разрешено, если немного","Обязательно"],"qs":"Bajo la Sección 608 de la EPA, ventilar intencionalmente la mayoría de los refrigerantes durante el servicio está:","optss":["Prohibido","Permitido solo en interiores","Permitido si es poco","Requerido"],"rs":"Ventilar CFC, HCFC, HFC y sus sustitutos es ilegal; el refrigerante debe recuperarse. Solo se toleran las liberaciones mínimas (de minimis) durante la recuperación/recirculación normal."},
  {"id":180,"sec":"Safety & Field Practices","q":"EPA Section 608 certification 'Type II' covers technicians working on:","opts":["Only auto AC","Small appliances","Disposal only","High-pressure appliances (e.g., split AC, heat pumps)"],"correct":3,"re":"Type I = small appliances; Type II = high-pressure systems; Type III = low-pressure; Universal = all. Most HVAC field work needs Type II or Universal.","rr":"Type I — малые приборы; Type II — высоконапорные системы; Type III — низконапорные; Universal — все. Большинству HVAC-работ нужен Type II или Universal.","qr":"Сертификат EPA Section 608 «Type II» охватывает техников, работающих с:","optsr":["Только авто-кондиционерами","Малыми приборами","Только утилизацией","Высоконапорным оборудованием (сплит-системы, тепловые насосы)"],"qs":"La certificación 'Tipo II' de la Sección 608 de la EPA cubre a los técnicos que trabajan en:","optss":["Solo AC automotriz","Electrodomésticos pequeños","Solo disposición","Aparatos de alta presión (por ejemplo, AC tipo split, bombas de calor)"],"rs":"Tipo I = electrodomésticos pequeños; Tipo II = sistemas de alta presión; Tipo III = baja presión; Universal = todos. La mayoría del trabajo de campo de HVAC requiere Tipo II o Universal."},
  {"id":181,"sec":"Safety & Field Practices","q":"A disposable (non-refillable) refrigerant cylinder must never be:","opts":["Kept below 125°F","Stored upright","Recycled when empty","Refilled"],"correct":3,"re":"Refilling a DOT disposable cylinder is illegal and dangerous (overpressure/rupture risk); recover into refillable, DOT-rated recovery cylinders only.","rr":"Перезаправка одноразового DOT-баллона незаконна и опасна (риск перенаддува/разрыва); откачивают только в перезаправляемые recovery-баллоны с допуском DOT.","qr":"Одноразовый (не перезаправляемый) баллон хладагента нельзя:","optsr":["Держать ниже 125°F","Хранить вертикально","Сдавать пустым в переработку","Перезаправлять"],"qs":"Un cilindro de refrigerante desechable (no recargable) nunca debe:","optss":["Mantenerse por debajo de 125°F","Almacenarse en posición vertical","Reciclarse cuando esté vacío","Recargarse"],"rs":"Recargar un cilindro desechable del DOT es ilegal y peligroso (riesgo de sobrepresión/ruptura); recupere únicamente en cilindros de recuperación recargables clasificados por el DOT."},
  {"id":182,"sec":"Safety & Field Practices","q":"A recovery cylinder should be filled to no more than ___ of its capacity to allow for liquid expansion:","opts":["80%","50%","100%","95%"],"correct":0,"re":"The 80% fill rule leaves vapor space for thermal expansion of liquid refrigerant, preventing hydrostatic overpressure as temperature rises.","rr":"Правило 80% оставляет паровое пространство для теплового расширения жидкого хладагента, предотвращая гидростатический перенаддув при росте температуры.","qr":"Recovery-баллон заполняют не более чем на ___ ёмкости, чтобы оставить место для расширения жидкости:","optsr":["80%","50%","100%","95%"],"qs":"Un cilindro de recuperación debe llenarse a no más del ___ de su capacidad para permitir la expansión del líquido:","optss":["80%","50%","100%","95%"],"rs":"La regla de llenado del 80% deja espacio de vapor para la expansión térmica del refrigerante líquido, previniendo la sobrepresión hidrostática a medida que sube la temperatura."},
  {"id":183,"sec":"Safety & Field Practices","q":"Refrigerant cylinders should be stored:","opts":["Near open flame","In a cool, ventilated area away from heat, secured upright","On a hot roof in summer","Next to a furnace"],"correct":1,"re":"Heat raises cylinder pressure dangerously; store in a cool, well-ventilated place, secured from falling, away from ignition sources.","rr":"Жар опасно повышает давление в баллоне; хранят в прохладном, хорошо проветриваемом месте, закреплёнными от падения, вдали от источников возгорания.","qr":"Баллоны с хладагентом следует хранить:","optsr":["У открытого огня","В прохладном проветриваемом месте, вдали от тепла, закреплёнными вертикально","На горячей крыше летом","Рядом с печью"],"qs":"Los cilindros de refrigerante deben almacenarse:","optss":["Cerca de una llama abierta","En un área fresca y ventilada, lejos del calor, asegurados en posición vertical","En un techo caliente en verano","Junto a un horno"],"rs":"El calor eleva peligrosamente la presión del cilindro; almacénelos en un lugar fresco y bien ventilado, asegurados contra caídas y lejos de fuentes de ignición."},
  {"id":184,"sec":"Safety & Field Practices","q":"A2L refrigerants (e.g., R-32, R-454B) differ from older HFCs in that they are:","opts":["Inert like nitrogen","Mildly flammable, requiring leak detection and charge limits","Non-toxic and non-flammable","Heavier than mercury"],"correct":1,"re":"A2L refrigerants are lower-GWP but mildly flammable; equipment uses leak detection, ventilation interlocks, and charge limits per code (UL 60335-2-40).","rr":"A2L имеют ниже GWP, но слабогорючи; оборудование использует детекцию утечки, вентиляционные блокировки и лимиты заправки по нормам (UL 60335-2-40).","qr":"Хладагенты A2L (например R-32, R-454B) отличаются от старых HFC тем, что они:","optsr":["Инертны как азот","Слабогорючи, требуют контроля утечки и лимитов заправки","Нетоксичны и негорючи","Тяжелее ртути"],"qs":"Los refrigerantes A2L (por ejemplo, R-32, R-454B) se diferencian de los HFC más antiguos en que son:","optss":["Inertes como el nitrógeno","Ligeramente inflamables, lo que requiere detección de fugas y límites de carga","No tóxicos y no inflamables","Más pesados que el mercurio"],"rs":"Los refrigerantes A2L tienen menor GWP pero son ligeramente inflamables; los equipos usan detección de fugas, enclavamientos de ventilación y límites de carga según el código (UL 60335-2-40)."},
  {"id":185,"sec":"Safety & Field Practices","q":"Before working inside an electrical panel on equipment, the technician must:","opts":["Lock out and tag out (LOTO) the disconnect and verify zero voltage","Increase the breaker size","Add refrigerant","Open the gas valve"],"correct":0,"re":"LOTO de-energizes the circuit, locks the disconnect, tags it, and a meter verifies zero voltage before work — preventing electrocution from unexpected startup.","rr":"LOTO обесточивает цепь, блокирует и маркирует разъединитель, а мультиметр подтверждает отсутствие напряжения до работы — защита от поражения при внезапном пуске.","qr":"Перед работой внутри электрощита оборудования техник обязан:","optsr":["Выполнить LOTO разъединителя и проверить отсутствие напряжения","Увеличить номинал автомата","Добавить хладагент","Открыть газовый клапан"],"qs":"Antes de trabajar dentro de un panel eléctrico del equipo, el técnico debe:","optss":["Bloquear y etiquetar (LOTO) la desconexión y verificar voltaje cero","Aumentar el tamaño del interruptor","Agregar refrigerante","Abrir la válvula de gas"],"rs":"El LOTO desenergiza el circuito, bloquea la desconexión, la etiqueta, y un medidor verifica voltaje cero antes de trabajar, previniendo la electrocución por un arranque inesperado."},
  {"id":186,"sec":"Safety & Field Practices","q":"A refrigerant leak in a low, poorly ventilated space (basement or pit) is dangerous mainly because most refrigerant vapors are:","opts":["Safe to breathe","Flammable like gasoline","Heavier than air and collect low, displacing oxygen","Lighter than air and rise out"],"correct":2,"re":"Most refrigerant vapors are denser than air, so they pool in low areas and can displace oxygen, causing asphyxiation. Ventilate low spaces and monitor oxygen before entry.","rr":"Пары большинства хладагентов плотнее воздуха, скапливаются в низких зонах и вытесняют кислород, вызывая удушье. Проветривайте низкие помещения и контролируйте кислород перед входом.","qr":"Утечка хладагента в низком, плохо проветриваемом помещении (подвал, приямок) опасна главным образом потому, что пары большинства хладагентов:","optsr":["Безопасны для дыхания","Горючи как бензин","Тяжелее воздуха, скапливаются внизу и вытесняют кислород","Легче воздуха и уходят вверх"],"qs":"Una fuga de refrigerante en un espacio bajo y mal ventilado (sótano o foso) es peligrosa principalmente porque la mayoría de los vapores de refrigerante son:","optss":["Seguros para respirar","Inflamables como la gasolina","Más pesados que el aire y se acumulan abajo, desplazando el oxígeno","Más ligeros que el aire y se elevan hacia afuera"],"rs":"La mayoría de los vapores de refrigerante son más densos que el aire, por lo que se acumulan en áreas bajas y pueden desplazar el oxígeno, causando asfixia. Ventile los espacios bajos y monitoree el oxígeno antes de entrar."},
  {"id":187,"sec":"Safety & Field Practices","q":"Fall protection is generally required on a roof or elevated work surface in construction when working at heights above:","opts":["2 feet","20 feet","6 feet (general construction trigger)","No requirement"],"correct":2,"re":"OSHA construction fall-protection generally triggers at 6 feet; Cal/OSHA and the work type may impose additional requirements — use guardrails, PFAS, or covers.","rr":"Защита от падения в строительстве OSHA обычно срабатывает на 6 футах; Cal/OSHA и вид работ могут добавлять требования — ограждения, страховочные системы, перекрытия.","qr":"Защита от падения на крыше или возвышении в строительстве обычно требуется при работе на высоте выше:","optsr":["2 футов","20 футов","6 футов (общий триггер в строительстве)","Не требуется"],"qs":"La protección contra caídas generalmente se requiere en un techo o superficie de trabajo elevada en construcción cuando se trabaja a alturas superiores a:","optss":["2 pies","20 pies","6 pies (umbral general de construcción)","Sin requisito"],"rs":"La protección contra caídas de OSHA en construcción generalmente se activa a los 6 pies; Cal/OSHA y el tipo de trabajo pueden imponer requisitos adicionales: use barandales, PFAS o cubiertas."},
  {"id":188,"sec":"Safety & Field Practices","q":"When entering an attic or vault that may have a hazardous atmosphere, the technician should treat it as a:","opts":["Refrigerant storage","Break room","Normal room","Possible confined space requiring evaluation/permit"],"correct":3,"re":"Spaces with limited entry/exit and potential hazardous atmosphere are confined spaces; evaluate, ventilate, test air, and follow permit procedures.","rr":"Пространства с ограниченным входом/выходом и возможной опасной атмосферой — замкнутые; оценивают, вентилируют, проверяют воздух и соблюдают процедуры допуска.","qr":"Входя на чердак или в приямок с возможной опасной атмосферой, техник должен рассматривать его как:","optsr":["Склад хладагента","Комнату отдыха","Обычную комнату","Возможное замкнутое пространство, требующее оценки/допуска"],"qs":"Al entrar a un ático o bóveda que pueda tener una atmósfera peligrosa, el técnico debe tratarlo como un/una:","optss":["Almacenamiento de refrigerante","Sala de descanso","Habitación normal","Posible espacio confinado que requiere evaluación/permiso"],"rs":"Los espacios con entrada/salida limitada y una atmósfera potencialmente peligrosa son espacios confinados; evalúe, ventile, pruebe el aire y siga los procedimientos de permiso."},
  {"id":189,"sec":"Safety & Field Practices","q":"A Class C fire extinguisher is rated for fires involving:","opts":["Combustible metals","Wood and paper","Cooking oils","Energized electrical equipment"],"correct":3,"re":"Class A = ordinary combustibles, B = flammable liquids, C = energized electrical, D = metals, K = cooking media. Use Class C (or ABC) near live electrical.","rr":"Класс A — обычные горючие, B — горючие жидкости, C — электрика под напряжением, D — металлы, K — кулинарные среды. У живой электрики применяют C (или ABC).","qr":"Огнетушитель класса C предназначен для пожаров с участием:","optsr":["Горючих металлов","Дерева и бумаги","Кулинарных масел","Электрооборудования под напряжением"],"qs":"Un extintor de incendios Clase C está clasificado para incendios que involucran:","optss":["Metales combustibles","Madera y papel","Aceites de cocina","Equipo eléctrico energizado"],"rs":"Clase A = combustibles ordinarios, B = líquidos inflamables, C = eléctrico energizado, D = metales, K = medios de cocina. Use Clase C (o ABC) cerca de equipo eléctrico vivo."},
  {"id":190,"sec":"Safety & Field Practices","q":"Nitrogen used for pressure testing is dangerous in a confined space mainly because it can:","opts":["Catch fire","Freeze the pipes","Explode","Displace oxygen and cause asphyxiation"],"correct":3,"re":"Nitrogen is inert but displaces oxygen; a leak in an enclosed space can lower O₂ to suffocating levels without warning. Ventilate and monitor.","rr":"Азот инертен, но вытесняет кислород; утечка в закрытом помещении может снизить O₂ до удушающего уровня без предупреждения. Вентилируйте и контролируйте.","qr":"Азот для опрессовки опасен в замкнутом пространстве главным образом тем, что может:","optsr":["Воспламениться","Заморозить трубы","Взорваться","Вытеснить кислород и вызвать удушье"],"qs":"El nitrógeno utilizado para pruebas de presión es peligroso en un espacio confinado principalmente porque puede:","optss":["Incendiarse","Congelar las tuberías","Explotar","Desplazar el oxígeno y causar asfixia"],"rs":"El nitrógeno es inerte pero desplaza el oxígeno; una fuga en un espacio cerrado puede reducir el O₂ a niveles asfixiantes sin advertencia. Ventile y monitoree."},
  {"id":191,"sec":"Safety & Field Practices","q":"A regulator must always be used on a nitrogen cylinder because cylinder pressure can exceed:","opts":["2000 psig (far above system test pressure)","14 psig","50 psig","100 psig"],"correct":0,"re":"Full nitrogen cylinders hold ~2000+ psig; without a regulator that pressure can rupture lines/components. Set the regulator to the required test pressure.","rr":"Полный азотный баллон держит ~2000+ psig; без редуктора это давление разорвёт линии/компоненты. Редуктор выставляют на нужное испытательное давление.","qr":"На азотном баллоне всегда ставят редуктор, потому что давление в баллоне может превышать:","optsr":["2000 psig (намного выше испытательного)","14 psig","50 psig","100 psig"],"qs":"Siempre debe usarse un regulador en un cilindro de nitrógeno porque la presión del cilindro puede exceder:","optss":["2000 psig (muy por encima de la presión de prueba del sistema)","14 psig","50 psig","100 psig"],"rs":"Los cilindros de nitrógeno llenos contienen ~2000+ psig; sin un regulador, esa presión puede romper líneas/componentes. Ajuste el regulador a la presión de prueba requerida."},
  {"id":192,"sec":"Safety & Field Practices","q":"Carbon monoxide (CO) is hazardous because it:","opts":["Only affects equipment","Is heavier than refrigerant","Has a strong odor","Is colorless and odorless and binds hemoglobin, blocking oxygen"],"correct":3,"re":"CO is an odorless, colorless gas that binds to hemoglobin far more readily than oxygen, causing poisoning; combustion safety checks and CO alarms are essential.","rr":"CO — газ без запаха и цвета, связывается с гемоглобином гораздо охотнее кислорода, вызывая отравление; проверки горения и CO-сигнализаторы обязательны.","qr":"Угарный газ (CO) опасен тем, что он:","optsr":["Влияет только на оборудование","Тяжелее хладагента","Имеет резкий запах","Бесцветен и без запаха, связывает гемоглобин, блокируя кислород"],"qs":"El monóxido de carbono (CO) es peligroso porque:","optss":["Solo afecta al equipo","Es más pesado que el refrigerante","Tiene un olor fuerte","Es incoloro e inodoro y se une a la hemoglobina, bloqueando el oxígeno"],"rs":"El CO es un gas inodoro e incoloro que se une a la hemoglobina con mucha más facilidad que el oxígeno, causando envenenamiento; las verificaciones de seguridad de combustión y las alarmas de CO son esenciales."},
  {"id":193,"sec":"Safety & Field Practices","q":"When brazing, eye protection (shaded glasses) is needed because the flame produces:","opts":["Static electricity","Bright light and the work involves hot metal/flux spatter","Cold","Refrigerant"],"correct":1,"re":"Brazing flames are intense; shaded safety glasses protect against glare, UV/IR, and flux/metal spatter, while gloves protect from burns.","rr":"Пламя пайки интенсивно; затемнённые защитные очки защищают от блеска, УФ/ИК и брызг флюса/металла, а перчатки — от ожогов.","qr":"При пайке нужна защита глаз (затемнённые очки), потому что пламя даёт:","optsr":["Статическое электричество","Яркий свет, и работа связана с горячим металлом/брызгами флюса","Холод","Хладагент"],"qs":"Al soldar con bronce, se necesita protección ocular (lentes con tono) porque la llama produce:","optss":["Electricidad estática","Luz brillante y el trabajo involucra metal caliente/salpicaduras de fundente","Frío","Refrigerante"],"rs":"Las llamas de soldadura con bronce son intensas; los lentes de seguridad con tono protegen contra el deslumbramiento, los rayos UV/IR y las salpicaduras de fundente/metal, mientras que los guantes protegen de las quemaduras."},
  {"id":194,"sec":"Safety & Field Practices","q":"A 'worst-case depressurization' test on a combustion appliance checks for:","opts":["Flue-gas spillage/backdrafting when exhaust fans depressurize the space","SEER","Refrigerant leaks","Duct size"],"correct":0,"re":"Running exhaust fans can depressurize a house and cause an atmospheric appliance to backdraft CO indoors; the test verifies safe venting under worst case.","rr":"Работа вытяжек может создать разрежение в доме и вызвать обратную тягу CO внутрь у атмосферного прибора; тест подтверждает безопасное дымоудаление в худшем случае.","qr":"Тест «worst-case depressurization» на топливном приборе проверяет:","optsr":["Обратную тягу/выход дымовых газов при разрежении вытяжкой","SEER","Утечки хладагента","Размер дакта"],"qs":"Una prueba de 'despresurización en el peor de los casos' en un aparato de combustión verifica:","optss":["El derrame de gases de combustión/contratiro cuando los ventiladores de extracción despresurizan el espacio","El SEER","Las fugas de refrigerante","El tamaño del ducto"],"rs":"Hacer funcionar los ventiladores de extracción puede despresurizar una casa y causar que un aparato atmosférico genere contratiro de CO al interior; la prueba verifica la ventilación segura en el peor de los casos."},
  {"id":195,"sec":"Safety & Field Practices","q":"Personal protective equipment (PPE) for electrical work near live parts includes:","opts":["Nothing","Only a hard hat","Insulated gloves/tools and appropriate arc-rated protection","Refrigerant goggles"],"correct":2,"re":"Live electrical work requires insulated tools/gloves, eye protection, and arc-rated PPE matched to the hazard; de-energizing first is always preferred.","rr":"Работы под напряжением требуют изолированного инструмента/перчаток, защиты глаз и СИЗ с дуговым рейтингом по уровню риска; предпочтительнее сначала обесточить.","qr":"Средства индивидуальной защиты (СИЗ) для электроработ у частей под напряжением включают:","optsr":["Ничего","Только каску","Изолированные перчатки/инструмент и защиту с дуговым рейтингом","Только очки от хладагента"],"qs":"El equipo de protección personal (PPE) para trabajo eléctrico cerca de partes vivas incluye:","optss":["Nada","Solo un casco","Guantes/herramientas aislados y protección con clasificación de arco apropiada","Gafas para refrigerante"],"rs":"El trabajo eléctrico vivo requiere herramientas/guantes aislados, protección ocular y PPE con clasificación de arco acorde al peligro; desenergizar primero siempre es preferible."},
  {"id":196,"sec":"Safety & Field Practices","q":"A GFCI receptacle protects a worker by:","opts":["Boosting amperage","Tripping quickly when it detects current leakage to ground","Adding refrigerant","Increasing voltage"],"correct":1,"re":"A GFCI senses an imbalance between hot and neutral (leakage to ground, e.g., through a person) and trips in milliseconds to prevent electrocution.","rr":"GFCI улавливает дисбаланс между фазой и нейтралью (утечку на землю, например через человека) и отключается за миллисекунды, предотвращая поражение.","qr":"Розетка GFCI защищает работника тем, что:","optsr":["Повышает силу тока","Быстро отключается при обнаружении утечки тока на землю","Добавляет хладагент","Повышает напряжение"],"qs":"Un receptáculo GFCI protege al trabajador al:","optss":["Aumentar el amperaje","Dispararse rápidamente cuando detecta una fuga de corriente a tierra","Agregar refrigerante","Aumentar el voltaje"],"rs":"Un GFCI detecta un desequilibrio entre la fase y el neutro (fuga a tierra, por ejemplo, a través de una persona) y se dispara en milisegundos para prevenir la electrocución."},
  {"id":197,"sec":"Safety & Field Practices","q":"The Safety Data Sheet (SDS) for a refrigerant or chemical provides:","opts":["Hazards, handling, first aid, and PPE information","The price","The duct size","The SEER rating"],"correct":0,"re":"An SDS lists physical/health hazards, safe handling and storage, exposure controls/PPE, first-aid, and spill response — required to be accessible on the job.","rr":"SDS перечисляет физические/санитарные опасности, безопасное обращение и хранение, меры защиты/СИЗ, первую помощь и действия при проливе — должен быть доступен на объекте.","qr":"Паспорт безопасности (SDS) на хладагент или химикат содержит:","optsr":["Опасности, обращение, первую помощь и сведения о СИЗ","Цену","Размер дакта","Рейтинг SEER"],"qs":"La Hoja de Datos de Seguridad (SDS) de un refrigerante o producto químico proporciona:","optss":["Información de peligros, manejo, primeros auxilios y PPE","El precio","El tamaño del ducto","La clasificación SEER"],"rs":"Una SDS enumera los peligros físicos/para la salud, el manejo y almacenamiento seguros, los controles de exposición/PPE, los primeros auxilios y la respuesta ante derrames; debe estar accesible en el trabajo."},
  {"id":198,"sec":"Safety & Field Practices","q":"Ladders used to access rooftop equipment must be:","opts":["Rated for the load and set at a safe angle, extended above the roof edge","Made of aluminum near power lines","Any length, leaned at any angle","Left unsecured"],"correct":0,"re":"Use a duty-rated ladder at ~4:1 angle, extended ~3 ft above the landing, secured; avoid metal ladders near electrical lines.","rr":"Используйте лестницу под нагрузку под углом ~4:1, с выступом ~3 фута над площадкой, закреплённую; избегайте металлических лестниц у электролиний.","qr":"Лестницы для доступа к оборудованию на крыше должны быть:","optsr":["Рассчитаны на нагрузку, под безопасным углом, выступать над краем крыши","Алюминиевыми у ЛЭП","Любой длины и под любым углом","Незакреплёнными"],"qs":"Las escaleras utilizadas para acceder a equipos en azoteas deben:","optss":["Estar clasificadas para la carga y colocadas en un ángulo seguro, extendidas por encima del borde del techo","Ser de aluminio cerca de líneas eléctricas","Tener cualquier longitud, apoyadas en cualquier ángulo","Dejarse sin asegurar"],"rs":"Use una escalera clasificada para servicio a un ángulo de ~4:1, extendida ~3 ft por encima del punto de apoyo, asegurada; evite escaleras metálicas cerca de líneas eléctricas."},
  {"id":199,"sec":"Safety & Field Practices","q":"Proper lifting technique to avoid back injury when moving equipment is to:","opts":["Lift with the legs, keep the load close, avoid twisting","Bend at the waist and twist","Use the fastest motion","Always lift alone"],"correct":0,"re":"Bend the knees, keep the back straight and load near the body, and pivot the feet instead of twisting; get help or use equipment for heavy units.","rr":"Сгибайте колени, держите спину прямо и груз близко к телу, поворачивайтесь стопами, а не скручиванием; для тяжёлого зовите помощь или используйте технику.","qr":"Правильная техника подъёма для защиты спины при перемещении оборудования —","optsr":["Поднимать ногами, держать груз близко, не скручиваться","Согнуться в пояснице и скручиваться","Двигаться максимально быстро","Всегда поднимать в одиночку"],"qs":"La técnica adecuada de levantamiento para evitar lesiones de espalda al mover equipo es:","optss":["Levantar con las piernas, mantener la carga cerca, evitar girar el torso","Doblarse por la cintura y girar","Usar el movimiento más rápido","Levantar siempre solo"],"rs":"Doble las rodillas, mantenga la espalda recta y la carga cerca del cuerpo, y pivotee con los pies en lugar de girar el torso; busque ayuda o use equipo para unidades pesadas."},
  {"id":200,"sec":"Safety & Field Practices","q":"Before reconnecting power and leaving a job, the technician should confirm all safety devices (limits, pressure switches, flame sensor) are:","opts":["Removed","Bypassed for reliability","Painted","Functional and not jumpered/defeated"],"correct":3,"re":"Never leave safety controls jumpered or disabled; verify all limits, pressure switches, float switches, and flame proving operate so the system fails safe.","rr":"Никогда не оставляйте защиты зашунтированными или отключёнными; проверьте, что все лимиты, реле давления, поплавковые выключатели и контроль пламени работают, чтобы система отказывала безопасно.","qr":"Перед подачей питания и завершением работы техник должен убедиться, что все защитные устройства (лимиты, реле давления, датчик пламени):","optsr":["Сняты","Зашунтированы для надёжности","Покрашены","Исправны и не зашунтированы/не отключены"],"qs":"Antes de reconectar la energía y dejar un trabajo, el técnico debe confirmar que todos los dispositivos de seguridad (límites, interruptores de presión, sensor de llama) estén:","optss":["Retirados","Puenteados para mayor confiabilidad","Pintados","Funcionales y no puenteados/anulados"],"rs":"Nunca deje los controles de seguridad puenteados o deshabilitados; verifique que todos los límites, interruptores de presión, interruptores de flotador y la comprobación de llama operen para que el sistema falle de forma segura."},
  {"id":201,"sec":"Principles & Load Calculations","q":"One ton of refrigeration is equal to:","opts":["100,000 BTU/h","1,000 BTU/h","500 watts","12,000 BTU/h"],"correct":3,"re":"A ton of refrigeration = 12,000 BTU/h, the rate to melt one ton of ice in 24 hours (288,000 BTU ÷ 24 h).","rr":"Тонна холода = 12 000 BTU/ч — скорость плавления одной тонны льда за 24 часа (288 000 BTU ÷ 24 ч).","qr":"Одна тонна холода (ton of refrigeration) равна:","optsr":["100 000 BTU/ч","1 000 BTU/ч","500 ватт","12 000 BTU/ч"],"qs":"Una tonelada de refrigeración es igual a:","optss":["100,000 BTU/h","1,000 BTU/h","500 watts","12,000 BTU/h"],"rs":"Una tonelada de refrigeración = 12,000 BTU/h, la tasa para derretir una tonelada de hielo en 24 horas (288,000 BTU ÷ 24 h)."},
  {"id":202,"sec":"Principles & Load Calculations","q":"Latent heat of vaporization is the heat absorbed when a substance:","opts":["Loses pressure","Freezes","Rises in temperature","Changes from liquid to vapor with no temperature change"],"correct":3,"re":"Latent heat changes state (liquid↔vapor) at constant temperature; this phase change in the evaporator/condenser is how refrigeration moves heat.","rr":"Latent heat меняет состояние (жидкость↔пар) при постоянной температуре; этот фазовый переход в испарителе/конденсаторе и переносит тепло.","qr":"Скрытая теплота парообразования (latent heat) — это тепло, поглощаемое при:","optsr":["Падении давления","Замерзании","Росте температуры","Переходе жидкости в пар без изменения температуры"],"qs":"El calor latente de vaporización es el calor absorbido cuando una sustancia:","optss":["Pierde presión","Se congela","Aumenta su temperatura","Cambia de líquido a vapor sin cambio de temperatura"],"rs":"El calor latente cambia el estado (líquido↔vapor) a temperatura constante; este cambio de fase en el evaporador/condensador es como la refrigeración mueve el calor."},
  {"id":203,"sec":"Principles & Load Calculations","q":"In the basic refrigeration cycle, the component that raises refrigerant pressure and temperature is the:","opts":["Metering device","Condenser","Compressor","Evaporator"],"correct":2,"re":"The compressor raises the low-pressure vapor to high pressure/temperature so it can reject heat in the condenser.","rr":"Компрессор поднимает пар низкого давления до высокого давления/температуры, чтобы тот отдал тепло в конденсаторе.","qr":"В базовом холодильном цикле компонент, повышающий давление и температуру хладагента, — это:","optsr":["Дозатор","Конденсатор","Компрессор","Испаритель"],"qs":"En el ciclo básico de refrigeración, el componente que eleva la presión y la temperatura del refrigerante es el:","optss":["Dispositivo dosificador","Condensador","Compresor","Evaporador"],"rs":"El compresor eleva el vapor de baja presión a alta presión/temperatura para que pueda rechazar el calor en el condensador."},
  {"id":204,"sec":"Principles & Load Calculations","q":"The metering device (e.g., TXV or piston) in the cycle:","opts":["Compresses vapor","Drops pressure and meters liquid into the evaporator","Adds heat","Stores oil"],"correct":1,"re":"The metering device creates the pressure drop between high and low sides and controls liquid refrigerant flow into the evaporator.","rr":"Дозатор создаёт перепад давления между высокой и низкой сторонами и регулирует подачу жидкого хладагента в испаритель.","qr":"Дозатор (TXV или piston) в цикле:","optsr":["Сжимает пар","Снижает давление и дозирует жидкость в испаритель","Добавляет тепло","Хранит масло"],"qs":"El dispositivo dosificador (p. ej., TXV o pistón) en el ciclo:","optss":["Comprime el vapor","Reduce la presión y dosifica el líquido hacia el evaporador","Agrega calor","Almacena aceite"],"rs":"El dispositivo dosificador crea la caída de presión entre el lado de alta y el de baja, y controla el flujo de refrigerante líquido hacia el evaporador."},
  {"id":205,"sec":"Principles & Load Calculations","q":"In a cooling system, the evaporator:","opts":["Raises pressure","Absorbs heat from the indoor air","Stores liquid","Rejects heat to outdoors"],"correct":1,"re":"The evaporator absorbs indoor heat as refrigerant boils to vapor; the condenser rejects that heat outdoors.","rr":"Испаритель поглощает тепло помещения, пока хладагент кипит в пар; конденсатор отдаёт это тепло наружу.","qr":"В системе охлаждения испаритель:","optsr":["Повышает давление","Поглощает тепло из внутреннего воздуха","Хранит жидкость","Отдаёт тепло наружу"],"qs":"En un sistema de enfriamiento, el evaporador:","optss":["Eleva la presión","Absorbe el calor del aire interior","Almacena líquido","Rechaza el calor al exterior"],"rs":"El evaporador absorbe el calor interior a medida que el refrigerante hierve y se convierte en vapor; el condensador rechaza ese calor al exterior."},
  {"id":206,"sec":"Principles & Load Calculations","q":"The compression ratio of a refrigeration compressor is the ratio of:","opts":["Absolute discharge pressure to absolute suction pressure","Suction to discharge temperature","CFM to tonnage","Voltage to amperage"],"correct":0,"re":"Compression ratio = absolute discharge pressure / absolute suction pressure (psia, not psig). A higher ratio lowers volumetric efficiency and raises discharge temperature.","rr":"Compression ratio = абсолютное давление нагнетания / абсолютное давление всасывания (psia, не psig). Выше степень - ниже объёмный КПД и выше температура нагнетания.","qr":"Степень сжатия (compression ratio) холодильного компрессора - это отношение:","optsr":["Абсолютного давления нагнетания к абсолютному давлению всасывания","Температуры всасывания к нагнетанию","CFM к тоннажу","Напряжения к току"],"qs":"La relación de compresión de un compresor de refrigeración es la relación entre:","optss":["La presión absoluta de descarga y la presión absoluta de succión","La temperatura de succión y la de descarga","Los CFM y el tonelaje","El voltaje y el amperaje"],"rs":"Relación de compresión = presión absoluta de descarga / presión absoluta de succión (psia, no psig). Una relación más alta reduce la eficiencia volumétrica y eleva la temperatura de descarga."},
  {"id":207,"sec":"Principles & Load Calculations","q":"In a refrigeration system, the high side (discharge side) includes the components between the:","opts":["Two service valves only","Thermostat and the fuse","Compressor discharge and the metering device","Evaporator inlet and compressor inlet"],"correct":2,"re":"The high (discharge) side runs from the compressor outlet through the condenser to the metering device; the low (suction) side runs from the metering-device outlet through the evaporator back to the compressor.","rr":"Сторона высокого (нагнетания) идёт от выхода компрессора через конденсатор до дозатора; сторона низкого (всасывания) - от выхода дозатора через испаритель обратно к компрессору.","qr":"В холодильной системе сторона высокого давления (high side) включает компоненты между:","optsr":["Только двумя сервисными вентилями","Термостатом и предохранителем","Нагнетанием компрессора и дозатором","Входом испарителя и входом компрессора"],"qs":"En un sistema de refrigeración, el lado de alta (lado de descarga) incluye los componentes entre:","optss":["Únicamente las dos válvulas de servicio","El termostato y el fusible","La descarga del compresor y el dispositivo dosificador","La entrada del evaporador y la entrada del compresor"],"rs":"El lado de alta (descarga) va desde la salida del compresor, a través del condensador, hasta el dispositivo dosificador; el lado de baja (succión) va desde la salida del dispositivo dosificador, a través del evaporador, de vuelta al compresor."},
  {"id":208,"sec":"Principles & Load Calculations","q":"Compared with R-22, R-410A operates at:","opts":["Significantly higher pressures","Identical pressures","No pressure","Much lower pressures"],"correct":0,"re":"R-410A runs roughly 50–70% higher pressures than R-22, so it requires equipment, gauges, and components rated for the higher pressure.","rr":"R-410A работает примерно на 50–70% выше по давлению, чем R-22, поэтому нужны оборудование, манометры и компоненты под более высокое давление.","qr":"По сравнению с R-22, R-410A работает при:","optsr":["Значительно более высоком давлении","Точно таком же давлении","Без давления","Гораздо более низком давлении"],"qs":"En comparación con el R-22, el R-410A opera a:","optss":["Presiones significativamente más altas","Presiones idénticas","Sin presión","Presiones mucho más bajas"],"rs":"El R-410A funciona aproximadamente entre 50 y 70 % más de presión que el R-22, por lo que requiere equipos, manómetros y componentes calificados para la presión más alta."},
  {"id":209,"sec":"Principles & Load Calculations","q":"A zeotropic refrigerant blend (e.g., R-407C) exhibits 'temperature glide,' which means:","opts":["It has one boiling point","Its components boil/condense over a range of temperatures","It is an azeotrope","It cannot be used"],"correct":1,"re":"Zeotropic blends change phase over a temperature range (glide); to avoid fractionation they are charged as liquid, and glide is accounted for in superheat/subcooling.","rr":"Зеотропные смеси меняют фазу в диапазоне температур (glide); чтобы избежать фракционирования, их заправляют жидкостью, а glide учитывают в superheat/subcooling.","qr":"Зеотропная смесь хладагента (например R-407C) имеет «температурный глайд», то есть:","optsr":["Одну точку кипения","Её компоненты кипят/конденсируются в диапазоне температур","Это азеотроп","Её нельзя применять"],"qs":"Una mezcla de refrigerante zeotrópica (p. ej., R-407C) presenta 'deslizamiento de temperatura' (temperature glide), lo que significa que:","optss":["Tiene un solo punto de ebullición","Sus componentes hierven/condensan en un rango de temperaturas","Es un azeótropo","No se puede utilizar"],"rs":"Las mezclas zeotrópicas cambian de fase en un rango de temperatura (glide); para evitar el fraccionamiento se cargan como líquido, y el glide se toma en cuenta en el sobrecalentamiento/subenfriamiento."},
  {"id":210,"sec":"Principles & Load Calculations","q":"POE (polyolester) oil is required with which refrigerants?","opts":["R-22 (mineral oil)","HFCs such as R-410A","Only ammonia","No refrigerant needs oil"],"correct":1,"re":"HFC systems (R-410A, R-407C) use POE oil; R-22 used mineral oil. POE is hygroscopic, so keep it sealed and evacuate well.","rr":"Системы HFC (R-410A, R-407C) используют POE; R-22 — минеральное масло. POE гигроскопично, держите его закрытым и тщательно вакуумируйте.","qr":"Масло POE (polyolester) требуется с какими хладагентами?","optsr":["R-22 (минеральное масло)","HFC, например R-410A","Только с аммиаком","Хладагенту масло не нужно"],"qs":"¿Con cuáles refrigerantes se requiere el aceite POE (polioléster)?","optss":["R-22 (aceite mineral)","HFC como el R-410A","Solo amoníaco","Ningún refrigerante necesita aceite"],"rs":"Los sistemas con HFC (R-410A, R-407C) usan aceite POE; el R-22 usaba aceite mineral. El POE es higroscópico, así que manténgalo sellado y evacúe bien."},
  {"id":211,"sec":"Principles & Load Calculations","q":"The R-value of insulation is a measure of its:","opts":["Weight","Thermal resistance (higher = better insulator)","Cost","Color"],"correct":1,"re":"R-value quantifies resistance to heat flow; higher R means less heat transfer. U-value (overall conductance) is its reciprocal.","rr":"R-value — сопротивление тепловому потоку; больше R = меньше теплопередача. U-value (общая проводимость) — обратная величина.","qr":"R-value изоляции — это мера её:","optsr":["Веса","Термического сопротивления (больше = лучше изолятор)","Стоимости","Цвета"],"qs":"El valor R del aislamiento es una medida de su:","optss":["Peso","Resistencia térmica (mayor = mejor aislante)","Costo","Color"],"rs":"El valor R cuantifica la resistencia al flujo de calor; un valor R más alto significa menor transferencia de calor. El valor U (conductancia total) es su recíproco."},
  {"id":212,"sec":"Principles & Load Calculations","q":"Ohm's law states that voltage equals:","opts":["Power × time","Current ÷ resistance","Resistance ÷ current","Current × resistance (V = I × R)"],"correct":3,"re":"Ohm's law: V = I × R. It lets technicians calculate any one value (voltage, current, resistance) from the other two.","rr":"Закон Ома: V = I × R. Позволяет вычислить любую из величин (напряжение, ток, сопротивление) по двум другим.","qr":"Закон Ома гласит, что напряжение равно:","optsr":["Мощность × время","Ток ÷ сопротивление","Сопротивление ÷ ток","Ток × сопротивление (V = I × R)"],"qs":"La ley de Ohm establece que el voltaje es igual a:","optss":["Potencia × tiempo","Corriente ÷ resistencia","Resistencia ÷ corriente","Corriente × resistencia (V = I × R)"],"rs":"Ley de Ohm: V = I × R. Permite a los técnicos calcular cualquiera de los valores (voltaje, corriente, resistencia) a partir de los otros dos."},
  {"id":213,"sec":"Principles & Load Calculations","q":"For a resistive load, electrical power in watts equals:","opts":["Volts × amps","Volts ÷ amps","Amps ÷ ohms","Volts × ohms"],"correct":0,"re":"Power (W) = volts × amps (P = V × I) for resistive loads; this is used to size circuits and estimate electric-heat consumption.","rr":"Мощность (Вт) = вольты × амперы (P = V × I) для резистивной нагрузки; используется для подбора цепей и оценки потребления электронагрева.","qr":"Для резистивной нагрузки электрическая мощность в ваттах равна:","optsr":["Вольты × амперы","Вольты ÷ амперы","Амперы ÷ омы","Вольты × омы"],"qs":"Para una carga resistiva, la potencia eléctrica en watts es igual a:","optss":["Volts × amperes","Volts ÷ amperes","Amperes ÷ ohms","Volts × ohms"],"rs":"Potencia (W) = volts × amperes (P = V × I) para cargas resistivas; esto se usa para dimensionar circuitos y estimar el consumo de la calefacción eléctrica."},
  {"id":214,"sec":"Principles & Load Calculations","q":"The approximate heating value of natural gas is about:","opts":["100 BTU per cubic foot","1,000 BTU per cubic foot","1,000,000 BTU per cubic foot","10 BTU per cubic foot"],"correct":1,"re":"Natural gas is roughly 1,000 BTU per cubic foot; this is used with metered gas flow to find a furnace's input rate.","rr":"Природный газ — примерно 1 000 BTU на куб. фут; вместе с замером расхода газа даёт входную мощность печи.","qr":"Примерная теплотворность природного газа составляет около:","optsr":["100 BTU на куб. фут","1 000 BTU на куб. фут","1 000 000 BTU на куб. фут","10 BTU на куб. фут"],"qs":"El poder calorífico aproximado del gas natural es de alrededor de:","optss":["100 BTU por pie cúbico","1,000 BTU por pie cúbico","1,000,000 BTU por pie cúbico","10 BTU por pie cúbico"],"rs":"El gas natural es de aproximadamente 1,000 BTU por pie cúbico; esto se usa con el flujo de gas medido para hallar la tasa de entrada de un horno (furnace)."},
  {"id":215,"sec":"Principles & Load Calculations","q":"'Clocking the gas meter' lets a technician determine a furnace's:","opts":["Duct size","SEER","Input BTU/h (firing rate)","Refrigerant charge"],"correct":2,"re":"Timing the gas meter dial gives cubic feet per hour; multiplied by the heating value (~1,000 BTU/cf) it yields the input firing rate.","rr":"Замер времени по диску счётчика даёт куб. футы в час; умножив на теплотворность (~1 000 BTU/cf), получают входную мощность горения.","qr":"«Clocking the gas meter» (хронометраж счётчика газа) позволяет определить:","optsr":["Размер дакта","SEER","Входную мощность BTU/ч (firing rate)","Заправку хладагентом"],"qs":"'Cronometrar el medidor de gas' (clocking the gas meter) permite al técnico determinar de un horno (furnace) su:","optss":["Tamaño del ducto","SEER","BTU/h de entrada (tasa de quemado)","Carga de refrigerante"],"rs":"Cronometrar el dial del medidor de gas da los pies cúbicos por hora; multiplicado por el poder calorífico (~1,000 BTU/cf) arroja la tasa de quemado de entrada."},
  {"id":216,"sec":"Principles & Load Calculations","q":"The temperature rise across a gas furnace must fall within the range:","opts":["Set by the thermostat","Always 20°F","Listed on the furnace rating plate","Always 100°F"],"correct":2,"re":"Each furnace lists an allowable temperature-rise range on its rating plate; airflow is adjusted so the measured rise (return-to-supply) stays within it.","rr":"У каждой печи на шильдике указан допустимый диапазон temperature rise; расход воздуха подбирают так, чтобы измеренный подъём (обратка→подача) был в нём.","qr":"Температурный подъём (temperature rise) через газовую печь должен укладываться в диапазон:","optsr":["Заданный термостатом","Всегда 20°F","Указанный на шильдике печи","Всегда 100°F"],"qs":"El aumento de temperatura a través de un horno (furnace) de gas debe estar dentro del rango:","optss":["Establecido por el termostato","Siempre 20°F","Indicado en la placa de datos del horno (furnace)","Siempre 100°F"],"rs":"Cada horno (furnace) indica un rango permitido de aumento de temperatura en su placa de datos; el flujo de aire se ajusta para que el aumento medido (de retorno a suministro) se mantenga dentro de ese rango."},
  {"id":217,"sec":"Principles & Load Calculations","q":"Gas-furnace airflow can be calculated from the formula CFM = output BTU/h ÷ (1.08 × ___):","opts":["Temperature rise","Static pressure","Superheat","Voltage"],"correct":0,"re":"Rearranging Q = 1.08 × CFM × ΔT gives CFM = output ÷ (1.08 × temperature rise) — a field check of blower airflow on a furnace.","rr":"Преобразуя Q = 1.08 × CFM × ΔT, получаем CFM = output ÷ (1.08 × temperature rise) — полевая проверка расхода вентилятора на печи.","qr":"Расход воздуха печи можно найти по формуле CFM = output BTU/ч ÷ (1.08 × ___):","optsr":["Температурный подъём","Статическое давление","Superheat","Напряжение"],"qs":"El flujo de aire de un horno (furnace) de gas se puede calcular con la fórmula CFM = BTU/h de salida ÷ (1.08 × ___):","optss":["Aumento de temperatura","Presión estática","Sobrecalentamiento","Voltaje"],"rs":"Reordenando Q = 1.08 × CFM × ΔT se obtiene CFM = salida ÷ (1.08 × aumento de temperatura) — una verificación en campo del flujo de aire del soplador en un horno (furnace)."},
  {"id":218,"sec":"Principles & Load Calculations","q":"According to the fan laws, airflow (CFM) varies:","opts":["Not at all with RPM","Inversely with RPM","Directly (linearly) with blower RPM","With the square of blower RPM"],"correct":2,"re":"CFM is directly proportional to RPM; static pressure varies with RPM squared; horsepower varies with RPM cubed.","rr":"CFM прямо пропорционален RPM; статическое давление — квадрату RPM; мощность — кубу RPM.","qr":"Согласно законам вентилятора, расход (CFM) изменяется:","optsr":["Никак с оборотами","Обратно оборотам","Прямо (линейно) с оборотами вентилятора","Пропорционально квадрату оборотов"],"qs":"Según las leyes de los ventiladores (fan laws), el flujo de aire (CFM) varía:","optss":["Nada con las RPM","Inversamente con las RPM","Directamente (linealmente) con las RPM del soplador","Con el cuadrado de las RPM del soplador"],"rs":"El CFM es directamente proporcional a las RPM; la presión estática varía con las RPM al cuadrado; la potencia varía con las RPM al cubo."},
  {"id":219,"sec":"Principles & Load Calculations","q":"By the fan laws, static pressure varies with:","opts":["RPM","The cube of RPM","The square root of RPM","The square of RPM"],"correct":3,"re":"Static pressure rises with the square of speed, and required horsepower with the cube — why small speed increases sharply raise power and noise.","rr":"Статическое давление растёт с квадратом скорости, а потребная мощность — с кубом; поэтому малый рост оборотов резко повышает мощность и шум.","qr":"По законам вентилятора статическое давление изменяется с:","optsr":["Оборотами","Кубом оборотов","Корнем из оборотов","Квадратом оборотов"],"qs":"Según las leyes de los ventiladores (fan laws), la presión estática varía con:","optss":["Las RPM","El cubo de las RPM","La raíz cuadrada de las RPM","El cuadrado de las RPM"],"rs":"La presión estática aumenta con el cuadrado de la velocidad, y la potencia requerida con el cubo — por eso pequeños aumentos de velocidad elevan fuertemente la potencia y el ruido."},
  {"id":220,"sec":"Principles & Load Calculations","q":"Air velocity in a duct equals airflow (CFM) divided by:","opts":["The voltage","The duct length","The duct cross-sectional area (sq ft)","The static pressure"],"correct":2,"re":"Velocity (fpm) = CFM ÷ area (sq ft). Excessive velocity causes noise; too low causes poor air distribution.","rr":"Скорость (fpm) = CFM ÷ площадь (кв. футы). Избыточная скорость даёт шум; слишком малая — плохое распределение воздуха.","qr":"Скорость воздуха в воздуховоде равна расходу (CFM), делённому на:","optsr":["Напряжение","Длину дакта","Площадь поперечного сечения дакта (кв. футы)","Статическое давление"],"qs":"La velocidad del aire en un ducto es igual al flujo de aire (CFM) dividido entre:","optss":["El voltaje","La longitud del ducto","El área de la sección transversal del ducto (pies cuadrados)","La presión estática"],"rs":"Velocidad (fpm) = CFM ÷ área (pies cuadrados). Una velocidad excesiva causa ruido; una muy baja causa una distribución deficiente del aire."},
  {"id":221,"sec":"Principles & Load Calculations","q":"Three-phase power is commonly used for larger HVAC motors because it:","opts":["Requires no protection","Is cheaper to install everywhere","Delivers smoother power, allowing smaller, more efficient motors","Uses one wire"],"correct":2,"re":"Three-phase delivers more constant power, so motors are smaller, run cooler/more efficiently, and start without start components.","rr":"Трёхфазное даёт более постоянную мощность, поэтому двигатели меньше, работают холоднее/эффективнее и стартуют без пусковых элементов.","qr":"Трёхфазное питание часто применяют для крупных HVAC-двигателей, потому что оно:","optsr":["Не требует защиты","Везде дешевле в монтаже","Даёт более ровную мощность — двигатели меньше и эффективнее","Использует один провод"],"qs":"La energía trifásica se usa comúnmente para motores grandes de HVAC porque:","optss":["No requiere protección","Es más barata de instalar en todas partes","Entrega energía más uniforme, lo que permite motores más pequeños y eficientes","Usa un solo cable"],"rs":"La energía trifásica entrega potencia más constante, por lo que los motores son más pequeños, funcionan más fríos/eficientemente y arrancan sin componentes de arranque."},
  {"id":222,"sec":"Principles & Load Calculations","q":"An 'equivalent round' duct dimension is used to:","opts":["Convert a rectangular duct to the round size with equal friction/airflow","Set the thermostat","Measure refrigerant","Size the breaker"],"correct":0,"re":"Friction charts are based on round duct; the equivalent-round value lets you size rectangular ducts to the same friction loss for a given airflow.","rr":"Таблицы трения построены для круглого дакта; эквивалентно-круглое значение позволяет подобрать прямоугольный дакт под то же трение при заданном расходе.","qr":"Размер «эквивалентного круглого» воздуховода используется для:","optsr":["Перевода прямоугольного дакта в круглый с равным трением/расходом","Настройки термостата","Замера хладагента","Подбора автомата"],"qs":"Una dimensión de 'redondo equivalente' de un ducto se usa para:","optss":["Convertir un ducto rectangular al tamaño redondo con igual fricción/flujo de aire","Ajustar el termostato","Medir el refrigerante","Dimensionar el interruptor (breaker)"],"rs":"Las tablas de fricción se basan en ductos redondos; el valor de redondo equivalente permite dimensionar ductos rectangulares con la misma pérdida por fricción para un flujo de aire dado."},
  {"id":223,"sec":"Principles & Load Calculations","q":"An undersized return-air system will typically cause:","opts":["Lower energy use","High static pressure and reduced airflow (starved blower)","More cooling capacity","Lower static pressure"],"correct":1,"re":"Too little return area raises return-side static, starving the blower; airflow drops, harming capacity and risking coil freeze or furnace limit trips.","rr":"Малая площадь обратки повышает статическое на обратной стороне, обедняя вентилятор; расход падает, страдает производительность, риск обмерзания или срабатывания лимита печи.","qr":"Заниженная система обратного воздуха обычно вызывает:","optsr":["Меньше энергопотребления","Высокое статическое и сниженный расход (обеднённый вентилятор)","Больше холодопроизводительности","Снижение статического давления"],"qs":"Un sistema de aire de retorno subdimensionado normalmente causará:","optss":["Menor consumo de energía","Alta presión estática y flujo de aire reducido (soplador hambriento)","Mayor capacidad de enfriamiento","Menor presión estática"],"rs":"Muy poca área de retorno eleva la presión estática del lado de retorno, dejando hambriento al soplador; el flujo de aire baja, perjudicando la capacidad y arriesgando congelamiento de la bobina o disparos del límite del horno (furnace)."},
  {"id":224,"sec":"Principles & Load Calculations","q":"In estimating, 'margin' differs from 'markup' in that margin is profit expressed as a percentage of:","opts":["Labor only","The selling price","Material only","Cost"],"correct":1,"re":"Margin = profit ÷ selling price; markup = profit ÷ cost. The same dollar profit is a smaller margin % than markup %, a common pricing error.","rr":"Margin = прибыль ÷ цена продажи; markup = прибыль ÷ себестоимость. Та же сумма прибыли даёт меньший % margin, чем % markup — частая ошибка ценообразования.","qr":"В сметах «margin» отличается от «markup» тем, что margin — это прибыль в процентах от:","optsr":["Только труда","Цены продажи","Только материала","Себестоимости"],"qs":"En la estimación, el 'margen' difiere del 'recargo' (markup) en que el margen es la ganancia expresada como un porcentaje de:","optss":["Solo la mano de obra","El precio de venta","Solo el material","El costo"],"rs":"Margen = ganancia ÷ precio de venta; recargo (markup) = ganancia ÷ costo. La misma ganancia en dólares representa un porcentaje de margen menor que el porcentaje de recargo, un error común de fijación de precios."},
  {"id":225,"sec":"Principles & Load Calculations","q":"A change order is used to:","opts":["Schedule an inspection","Order refrigerant","Document added/changed scope and its cost beyond the original contract","Cancel the license"],"correct":2,"re":"A written change order records work added or changed after the contract, with the agreed price and signatures — protecting both parties.","rr":"Письменный change order фиксирует добавленную или изменённую после договора работу с согласованной ценой и подписями — защита обеих сторон.","qr":"Change order (изменение к договору) служит для:","optsr":["Назначения инспекции","Заказа хладагента","Фиксации добавленного/изменённого объёма и его стоимости сверх договора","Аннулирования лицензии"],"qs":"Una orden de cambio (change order) se usa para:","optss":["Programar una inspección","Pedir refrigerante","Documentar el alcance agregado/modificado y su costo más allá del contrato original","Cancelar la licencia"],"rs":"Una orden de cambio por escrito registra el trabajo agregado o modificado después del contrato, con el precio acordado y las firmas — protegiendo a ambas partes."},
  {"id":226,"sec":"Fabrication & Installation","q":"A 45° SAE flare connection is used to:","opts":["Seal ductwork","Braze copper to steel","Connect gas vents","Make a mechanical, gasket-free seal on soft copper (mini-splits, valves)"],"correct":3,"re":"A properly made 45° flare seats metal-to-metal under the flare nut, giving a serviceable refrigerant connection without brazing.","rr":"Правильный flare 45° садится металл-по-металлу под накидной гайкой, давая обслуживаемое холодильное соединение без пайки.","qr":"Развальцовка 45° SAE (flare) применяется для:","optsr":["Герметизации воздуховодов","Пайки меди к стали","Соединения газовых дымоходов","Механического соединения мягкой меди без прокладки (мини-сплиты, вентили)"],"qs":"Una conexión abocardada SAE de 45° se usa para:","optss":["Sellar ductos","Soldar con bronce cobre a acero","Conectar respiraderos de gas","Hacer un sello mecánico, sin empaque, en cobre blando (mini-splits, válvulas)"],"rs":"Un abocardado de 45° bien hecho asienta metal contra metal bajo la tuerca de abocardado, dando una conexión de refrigerante reparable sin soldadura de bronce."},
  {"id":227,"sec":"Fabrication & Installation","q":"After cutting copper tubing, the technician should ream/deburr the end to:","opts":["Harden the copper","Add flux","Remove burrs that cause turbulence and debris in the system","Increase diameter"],"correct":2,"re":"Burrs restrict flow, create turbulence, and can break loose to foul metering devices; ream the inside and deburr before assembly.","rr":"Заусенцы сужают поток, создают турбулентность и могут отколоться, засоряя дозаторы; снимайте внутренний заусенец и грат перед сборкой.","qr":"После резки медной трубы конец нужно развернуть/снять заусенцы (ream/deburr), чтобы:","optsr":["Закалить медь","Добавить флюс","Убрать заусенцы, дающие турбулентность и мусор в системе","Увеличить диаметр"],"qs":"Después de cortar tubería de cobre, el técnico debe escariar/desbarbar el extremo para:","optss":["Endurecer el cobre","Agregar fundente","Eliminar las rebabas que causan turbulencia y residuos en el sistema","Aumentar el diámetro"],"rs":"Las rebabas restringen el flujo, crean turbulencia y pueden desprenderse y ensuciar los dispositivos dosificadores; escarie el interior y desbarbe antes del ensamblaje."},
  {"id":228,"sec":"Fabrication & Installation","q":"Among silver brazing alloys, those with higher silver content generally:","opts":["Require no heat","Are weaker","Flow at lower temperatures","Cannot join copper"],"correct":2,"re":"Higher-silver alloys melt/flow at lower temperatures and wet well, useful on dissimilar metals; lower-silver BCuP is common copper-to-copper.","rr":"Сплавы с бо́льшим серебром плавятся/текут при более низкой температуре и хорошо смачивают; полезны на разнородных металлах; BCuP с меньшим серебром — типично медь-медь.","qr":"Среди серебряных припоев сплавы с бо́льшим содержанием серебра обычно:","optsr":["Не требуют нагрева","Слабее","Текут при более низкой температуре","Не соединяют медь"],"qs":"Entre las aleaciones de soldadura fuerte de plata, las de mayor contenido de plata generalmente:","optss":["No requieren calor","Son más débiles","Fluyen a temperaturas más bajas","No pueden unir cobre"],"rs":"Las aleaciones con mayor contenido de plata se funden/fluyen a temperaturas más bajas y mojan bien, útiles en metales distintos; el BCuP de menor contenido de plata es común para cobre con cobre."},
  {"id":229,"sec":"Fabrication & Installation","q":"Soft solder (e.g., 95/5) is acceptable for ___ but NOT for refrigerant joints:","opts":["Water/condensate lines","Gas piping","Electrical wire","High-pressure refrigerant lines"],"correct":0,"re":"Soft solder melts at low temperature and lacks the strength for refrigerant pressures; it's used on water/drain lines, while refrigerant joints are brazed.","rr":"Мягкий припой плавится при низкой температуре и не выдерживает холодильных давлений; его применяют на водяных/дренажных линиях, а холодильные соединения паяют твёрдым припоем.","qr":"Мягкий припой (например 95/5) допустим для ___, но НЕ для холодильных соединений:","optsr":["Водяных/дренажных линий","Газовых труб","Электропроводки","Холодильных линий высокого давления"],"qs":"La soldadura blanda (p. ej., 95/5) es aceptable para ___ pero NO para uniones de refrigerante:","optss":["Líneas de agua/condensado","Tubería de gas","Cable eléctrico","Líneas de refrigerante de alta presión"],"rs":"La soldadura blanda se funde a baja temperatura y carece de la resistencia para las presiones de refrigerante; se usa en líneas de agua/drenaje, mientras que las uniones de refrigerante se sueldan con bronce."},
  {"id":230,"sec":"Fabrication & Installation","q":"Molten brazing alloy is drawn into a properly fitted joint by:","opts":["Refrigerant pressure","Gravity only","Electrical attraction","Capillary action"],"correct":3,"re":"Capillary action pulls the molten filler into the small, even gap between tube and fitting, so correct clearance and cleanliness are essential.","rr":"Капиллярный эффект втягивает расплав в малый равномерный зазор между трубой и фитингом, поэтому важны правильный зазор и чистота.","qr":"Расплавленный припой втягивается в правильно подогнанный стык за счёт:","optsr":["Давления хладагента","Только силы тяжести","Электрического притяжения","Капиллярного эффекта"],"qs":"La aleación fundida de soldadura fuerte es atraída hacia una unión correctamente ajustada por:","optss":["La presión del refrigerante","Solo la gravedad","La atracción eléctrica","La acción capilar"],"rs":"La acción capilar atrae el material de aporte fundido hacia el espacio pequeño y uniforme entre el tubo y el accesorio, por lo que el huelgo y la limpieza correctos son esenciales."},
  {"id":231,"sec":"Fabrication & Installation","q":"Copper wire (60/75°C) ampacity is commonly: #14 = 15 A, #12 = 20 A, and #10 = ___:","opts":["10 A","100 A","50 A","30 A"],"correct":3,"re":"Common branch-circuit copper ampacities: 14 AWG=15 A, 12 AWG=20 A, 10 AWG=30 A, 8 AWG=40 A — always confirm with the code table and conditions.","rr":"Типовая ампачность ответвлений (медь): 14 AWG=15 A, 12 AWG=20 A, 10 AWG=30 A, 8 AWG=40 A — всегда сверяйтесь с таблицей норм и условиями.","qr":"Ампачность медного провода (60/75°C) обычно: #14 = 15 A, #12 = 20 A, а #10 = ___:","optsr":["10 A","100 A","50 A","30 A"],"qs":"La ampacidad del cable de cobre (60/75°C) es comúnmente: #14 = 15 A, #12 = 20 A, y #10 = ___:","optss":["10 A","100 A","50 A","30 A"],"rs":"Ampacidades comunes de cobre para circuitos ramales: 14 AWG=15 A, 12 AWG=20 A, 10 AWG=30 A, 8 AWG=40 A — siempre confirme con la tabla del código y las condiciones."},
  {"id":232,"sec":"Fabrication & Installation","q":"The equipment grounding conductor's main purpose is to:","opts":["Increase voltage","Provide a low-resistance fault path so the breaker trips on a ground fault","Improve SEER","Carry normal load current"],"correct":1,"re":"The ground conductor gives fault current a safe path back to the source, tripping the overcurrent device and keeping enclosures from becoming energized.","rr":"Заземляющий проводник даёт току КЗ безопасный путь к источнику, отключая защиту и не давая корпусам оказаться под напряжением.","qr":"Главная задача защитного заземляющего проводника:","optsr":["Повысить напряжение","Дать низкоомный путь тока КЗ, чтобы автомат отключился при замыкании на землю","Улучшить SEER","Нести нормальный рабочий ток"],"qs":"El propósito principal del conductor de puesta a tierra del equipo es:","optss":["Aumentar el voltaje","Proporcionar una trayectoria de falla de baja resistencia para que el interruptor (breaker) se dispare ante una falla a tierra","Mejorar el SEER","Conducir la corriente de carga normal"],"rs":"El conductor de tierra le da a la corriente de falla una trayectoria segura de regreso a la fuente, disparando el dispositivo de sobrecorriente y evitando que las cubiertas queden energizadas."},
  {"id":233,"sec":"Fabrication & Installation","q":"A hard-start kit (start capacitor with a potential relay or PTCR) is added to:","opts":["Boost starting torque on a hard-starting compressor","Remove refrigerant","Lower the voltage","Slow the compressor"],"correct":0,"re":"A hard-start device gives extra starting torque (and quick disconnect after start) to help a compressor that struggles to start, e.g., under high head.","rr":"Hard-start даёт дополнительный пусковой момент (и быстрое отключение после пуска), помогая компрессору, который трудно стартует, например при высоком напоре.","qr":"Hard-start kit (пусковой конденсатор с потенциальным реле или PTCR) добавляют, чтобы:","optsr":["Повысить пусковой момент у тяжело пускающегося компрессора","Удалить хладагент","Снизить напряжение","Замедлить компрессор"],"qs":"Un kit de arranque rápido (capacitor de arranque con un relé de potencial o PTCR) se agrega para:","optss":["Aumentar el torque de arranque en un compresor de arranque difícil","Retirar refrigerante","Reducir el voltaje","Frenar el compresor"],"rs":"Un dispositivo de arranque rápido da torque de arranque adicional (y se desconecta rápidamente tras el arranque) para ayudar a un compresor que tiene dificultad para arrancar, p. ej., bajo alta presión de cabeza."},
  {"id":234,"sec":"Fabrication & Installation","q":"A crankcase heater on a compressor is used to:","opts":["Cool the oil","Increase head pressure","Keep refrigerant from migrating/condensing into the compressor oil during the off cycle","Add refrigerant"],"correct":2,"re":"The crankcase heater keeps the oil warm so refrigerant doesn't condense into it during off cycles, preventing dilution and damaging slugging at startup.","rr":"Подогреватель картера держит масло тёплым, чтобы хладагент не конденсировался в него при простое, предотвращая разбавление и опасный гидроудар при пуске.","qr":"Подогреватель картера компрессора нужен, чтобы:","optsr":["Охлаждать масло","Поднять давление нагнетания","Не дать хладагенту мигрировать/конденсироваться в масло компрессора во время простоя","Добавить хладагент"],"qs":"Un calentador de cárter (crankcase heater) en un compresor se usa para:","optss":["Enfriar el aceite","Aumentar la presión de cabeza","Evitar que el refrigerante migre/condense hacia el aceite del compresor durante el ciclo de apagado","Agregar refrigerante"],"rs":"El calentador de cárter mantiene el aceite caliente para que el refrigerante no condense en él durante los ciclos de apagado, evitando la dilución y el dañino golpe de líquido (slugging) en el arranque."},
  {"id":235,"sec":"Fabrication & Installation","q":"Low-ambient head-pressure control (fan cycling or condenser flooding) is used so a system can:","opts":["Heat faster","Save refrigerant","Cool reliably in cold outdoor temperatures by keeping head pressure up","Skip the metering device"],"correct":2,"re":"In cold weather head pressure can fall too low for the metering device to feed properly; low-ambient controls maintain adequate head pressure for mechanical cooling.","rr":"В холод давление нагнетания может упасть слишком низко для нормальной подачи дозатором; low-ambient контроль удерживает достаточный напор для механического охлаждения.","qr":"Контроль давления нагнетания при низкой наружной температуре (fan cycling или затопление конденсатора) нужен, чтобы система могла:","optsr":["Быстрее греть","Экономить хладагент","Надёжно охлаждать в холод, удерживая давление нагнетания","Обойтись без дозатора"],"qs":"El control de presión de cabeza en baja temperatura ambiente (ciclado del ventilador o inundación del condensador) se usa para que un sistema pueda:","optss":["Calentar más rápido","Ahorrar refrigerante","Enfriar de manera confiable en temperaturas exteriores frías al mantener alta la presión de cabeza","Omitir el dispositivo dosificador"],"rs":"En clima frío la presión de cabeza puede caer demasiado para que el dispositivo dosificador alimente correctamente; los controles de baja temperatura ambiente mantienen una presión de cabeza adecuada para el enfriamiento mecánico."},
  {"id":236,"sec":"Fabrication & Installation","q":"A sequencer in an electric-heat furnace is used to:","opts":["Meter refrigerant","Open the gas valve","Cool the coil","Stagger the heating elements on/off to limit inrush current"],"correct":3,"re":"Sequencers energize electric heat strips in steps, so they don't all draw inrush current at once — reducing electrical stress and flicker.","rr":"Секвенсор включает ТЭНы ступенями, чтобы они не брали пусковой ток разом — снижая электрическую нагрузку и мерцание.","qr":"Секвенсор в электропечи нужен, чтобы:","optsr":["Дозировать хладагент","Открывать газовый клапан","Охлаждать испаритель","Поэтапно включать/выключать ТЭНы, ограничивая пусковой ток"],"qs":"Un secuenciador en un horno (furnace) de calefacción eléctrica se usa para:","optss":["Dosificar el refrigerante","Abrir la válvula de gas","Enfriar la bobina","Escalonar el encendido/apagado de los elementos calefactores para limitar la corriente de irrupción"],"rs":"Los secuenciadores energizan las resistencias de calefacción eléctrica por etapas, de modo que no todas tomen la corriente de irrupción a la vez — reduciendo el estrés eléctrico y el parpadeo."},
  {"id":237,"sec":"Fabrication & Installation","q":"Gas piping is sized based on required CFH, pipe length, and:","opts":["SEER","Duct gauge","Allowable pressure drop (per sizing tables)","Refrigerant type"],"correct":2,"re":"Pipe-sizing tables use the demand (CFH), the longest length, and the allowable pressure drop to pick a diameter that delivers enough gas to all appliances.","rr":"Таблицы подбора используют потребление (CFH), наибольшую длину и допустимый перепад давления, чтобы выбрать диаметр, дающий достаточно газа всем приборам.","qr":"Газовые трубы подбирают по требуемому CFH, длине трубы и:","optsr":["SEER","Толщине дакта","Допустимому перепаду давления (по таблицам)","Типу хладагента"],"qs":"La tubería de gas se dimensiona con base en los CFH requeridos, la longitud de la tubería y:","optss":["El SEER","El calibre del ducto","La caída de presión permitida (según las tablas de dimensionamiento)","El tipo de refrigerante"],"rs":"Las tablas de dimensionamiento de tubería usan la demanda (CFH), la longitud más larga y la caída de presión permitida para elegir un diámetro que entregue suficiente gas a todos los aparatos."},
  {"id":238,"sec":"Fabrication & Installation","q":"A sediment trap (drip leg) is installed near the gas valve to:","opts":["Vent flue gas","Increase pressure","Catch debris and moisture before it enters the gas valve","Add air"],"correct":2,"re":"The sediment trap collects rust, scale, and condensate so it doesn't reach and foul the gas valve/orifices.","rr":"Грязевик собирает ржавчину, накипь и конденсат, чтобы они не попали в газовый клапан/жиклёры и не засорили их.","qr":"Грязевик (sediment trap / drip leg) у газового клапана ставят, чтобы:","optsr":["Удалять дымовые газы","Повысить давление","Задержать мусор и влагу до входа в газовый клапан","Добавлять воздух"],"qs":"Una trampa de sedimentos (drip leg) se instala cerca de la válvula de gas para:","optss":["Ventilar el gas de combustión","Aumentar la presión","Atrapar residuos y humedad antes de que entren a la válvula de gas","Agregar aire"],"rs":"La trampa de sedimentos recoge óxido, sarro y condensado para que no lleguen ni ensucien la válvula de gas/orificios."},
  {"id":239,"sec":"Fabrication & Installation","q":"A manual gas shutoff valve must generally be installed:","opts":["Within 6 feet of the appliance and in the same room","Inside the burner","Anywhere in the house","At the meter only"],"correct":0,"re":"Code requires an accessible manual shutoff within about 6 ft of the appliance (same room) so gas can be quickly isolated for service.","rr":"Нормы требуют доступный ручной запор примерно в 6 футах от прибора (в том же помещении), чтобы быстро перекрыть газ для обслуживания.","qr":"Ручной газовый запорный вентиль обычно должен устанавливаться:","optsr":["В пределах 6 футов от прибора и в том же помещении","Внутри горелки","Где угодно в доме","Только у счётчика"],"qs":"Una válvula manual de cierre de gas generalmente debe instalarse:","optss":["A menos de 6 pies del aparato y en la misma habitación","Dentro del quemador","En cualquier parte de la casa","Solo en el medidor"],"rs":"El código requiere un cierre manual accesible a unos 6 pies del aparato (misma habitación) para que el gas pueda aislarse rápidamente para el servicio."},
  {"id":240,"sec":"Fabrication & Installation","q":"A Type B (double-wall) gas vent must maintain its listed clearance to combustibles, typically:","opts":["0 inches","36 inches","12 inches","About 1 inch"],"correct":3,"re":"Type B vent is listed for about 1 in clearance to combustibles; single-wall connectors require much larger clearances — always follow the listing.","rr":"Type B рассчитан примерно на 1 дюйм зазора до горючих; одностенные соединители требуют гораздо больших зазоров — всегда по листингу.","qr":"Газовый дымоход Type B (двустенный) должен сохранять нормированный зазор до горючих, обычно:","optsr":["0 дюймов","36 дюймов","12 дюймов","Около 1 дюйма"],"qs":"Un respiradero de gas Tipo B (doble pared) debe mantener su espacio libre indicado a los combustibles, típicamente:","optss":["0 pulgadas","36 pulgadas","12 pulgadas","Alrededor de 1 pulgada"],"rs":"El respiradero Tipo B está certificado para un espacio libre de aproximadamente 1 pulgada a los combustibles; los conectores de pared simple requieren espacios libres mucho mayores — siempre siga la certificación."},
  {"id":241,"sec":"Fabrication & Installation","q":"A vent connector for an atmospheric appliance should slope:","opts":["Upward toward the chimney (e.g., ≥1/4 in per foot)","Be perfectly level","Loop downward","Downward away from the chimney"],"correct":0,"re":"An upward slope toward the chimney promotes natural draft and prevents flue-gas/condensate pooling that would block venting.","rr":"Уклон вверх к дымоходу способствует естественной тяге и не даёт скапливаться дымовым газам/конденсату, что блокировало бы удаление.","qr":"Соединительный дымоход атмосферного прибора должен иметь уклон:","optsr":["Вверх к дымоходу (например ≥1/4 дюйма на фут)","Строго горизонтально","Петлёй вниз","Вниз от дымохода"],"qs":"Un conector de respiradero para un aparato atmosférico debe tener una inclinación:","optss":["Hacia arriba en dirección a la chimenea (p. ej., ≥1/4 pulg por pie)","Perfectamente nivelado","En bucle hacia abajo","Hacia abajo, alejándose de la chimenea"],"rs":"Una inclinación hacia arriba en dirección a la chimenea favorece el tiro natural y evita el estancamiento de gases de combustión/condensado que bloquearía la ventilación."},
  {"id":242,"sec":"Fabrication & Installation","q":"A Pittsburgh lock, drive cleats, and S-cleats are all used in:","opts":["Electrical conduit","Refrigerant piping","Sheet-metal duct seams and joints","Gas venting"],"correct":2,"re":"These are sheet-metal connections: the Pittsburgh lock forms a longitudinal seam, while drive and S cleats join duct sections transversely.","rr":"Это соединения листового металла: Pittsburgh lock образует продольный шов, а drive- и S-cleats соединяют секции дакта поперечно.","qr":"Pittsburgh lock, drive cleats и S-cleats применяются в:","optsr":["Электрических трубах","Холодильных трубах","Швах и стыках металлических воздуховодов","Газовом дымоудалении"],"qs":"Un cierre Pittsburgh (Pittsburgh lock), las grapas de arrastre (drive cleats) y las grapas en S (S-cleats) se usan todos en:","optss":["Conducto eléctrico","Tubería de refrigerante","Costuras y uniones de ductos de lámina metálica","Ventilación de gas"],"rs":"Estas son conexiones de lámina metálica: el cierre Pittsburgh forma una costura longitudinal, mientras que las grapas de arrastre y en S unen secciones de ducto transversalmente."},
  {"id":243,"sec":"Fabrication & Installation","q":"A hot-surface igniter (HSI) is best checked by measuring its:","opts":["Voltage only","Airflow","Resistance (ohms) when cold, compared to spec","Refrigerant charge"],"correct":2,"re":"A cold-resistance (ohms) reading outside the manufacturer's range indicates a cracked or aged igniter; visually inspect for cracks too.","rr":"Сопротивление в холодном состоянии вне диапазона производителя указывает на треснувший или состарившийся игнайтер; осмотрите и на трещины.","qr":"Hot-surface igniter (HSI) лучше всего проверять, измеряя его:","optsr":["Только напряжение","Расход воздуха","Сопротивление (омы) в холодном состоянии и сравнивая со спецификацией","Заправку хладагентом"],"qs":"Un encendedor de superficie caliente (HSI) se verifica mejor midiendo su:","optss":["Solo el voltaje","El flujo de aire","La resistencia (ohms) en frío, comparada con la especificación","La carga de refrigerante"],"rs":"Una lectura de resistencia en frío (ohms) fuera del rango del fabricante indica un encendedor agrietado o envejecido; inspeccione visualmente también en busca de grietas."},
  {"id":244,"sec":"Fabrication & Installation","q":"Combustion analysis at startup measures CO, stack temperature, and:","opts":["Voltage","Oxygen/CO₂ in the flue gas","Duct size","SEER"],"correct":1,"re":"A combustion analyzer reads O₂/CO₂, CO, and stack temperature to confirm complete, safe, efficient combustion and proper venting.","rr":"Газоанализатор читает O₂/CO₂, CO и температуру отходящих газов, подтверждая полное, безопасное, эффективное сгорание и нормальное дымоудаление.","qr":"Анализ горения при пуске измеряет CO, температуру дымовых газов и:","optsr":["Напряжение","Кислород/CO₂ в дымовых газах","Размер дакта","SEER"],"qs":"El análisis de combustión al arranque mide el CO, la temperatura de la chimenea y:","optss":["El voltaje","El oxígeno/CO₂ en el gas de combustión","El tamaño del ducto","El SEER"],"rs":"Un analizador de combustión lee el O₂/CO₂, el CO y la temperatura de la chimenea para confirmar una combustión completa, segura y eficiente, y una ventilación adecuada."},
  {"id":245,"sec":"Fabrication & Installation","q":"A flow hood (balometer) is used during startup to measure:","opts":["Flame temperature","Airflow (CFM) at a register or grille","Gas pressure","Refrigerant pressure"],"correct":1,"re":"A flow hood captures and reads the CFM delivered at a supply or return register, useful for air balancing and verifying design airflow.","rr":"Flow hood накрывает решётку и считывает CFM на подаче или обратке — полезно для балансировки и проверки расчётного расхода.","qr":"Flow hood (балометр) при пуске используют для измерения:","optsr":["Температуры пламени","Расхода воздуха (CFM) на решётке","Давления газа","Давления хладагента"],"qs":"Una campana de flujo (balometer) se usa durante el arranque para medir:","optss":["La temperatura de la llama","El flujo de aire (CFM) en una rejilla de suministro o de retorno","La presión de gas","La presión de refrigerante"],"rs":"Una campana de flujo captura y lee los CFM entregados en una rejilla de suministro o de retorno, útil para el balanceo de aire y para verificar el flujo de aire de diseño."},
  {"id":246,"sec":"Fabrication & Installation","q":"When charging a ductless mini-split, the factory charge typically covers a set line length, and the tech must:","opts":["Use water","Always remove refrigerant","Skip evacuation","Add refrigerant for line length beyond the included amount"],"correct":3,"re":"Mini-splits ship pre-charged for a base line length (e.g., 15–25 ft); longer line sets require adding the per-foot amount from the install manual.","rr":"Мини-сплиты заправлены на базовую длину линий (например 15–25 футов); более длинные требуют долива по норме на фут из инструкции.","qr":"При заправке бесканального мини-сплита заводская заправка обычно рассчитана на заданную длину линий, и техник должен:","optsr":["Использовать воду","Всегда удалять хладагент","Пропустить вакуумирование","Добавить хладагент за длину линий сверх включённой"],"qs":"Al cargar un mini-split sin ductos, la carga de fábrica normalmente cubre una longitud de línea establecida, y el técnico debe:","optss":["Usar agua","Siempre retirar refrigerante","Omitir la evacuación","Agregar refrigerante por la longitud de línea que exceda la cantidad incluida"],"rs":"Los mini-splits vienen precargados para una longitud de línea base (p. ej., 15–25 pies); los juegos de líneas más largos requieren agregar la cantidad por pie indicada en el manual de instalación."},
  {"id":247,"sec":"Fabrication & Installation","q":"In a triple evacuation, dry nitrogen is introduced between vacuum pulls to:","opts":["Add refrigerant","Pressurize for leak test","Break the vacuum and help sweep out remaining moisture","Cool the pump"],"correct":2,"re":"Breaking vacuum with dry nitrogen dilutes and carries off residual moisture; repeating the pull/sweep reaches a dry system more reliably.","rr":"Срыв вакуума сухим азотом разбавляет и уносит остаточную влагу; повтор откачки/продувки надёжнее доводит систему до сухого состояния.","qr":"При тройном вакуумировании между откачками вводят сухой азот, чтобы:","optsr":["Добавить хладагент","Опрессовать для теста утечки","Сорвать вакуум и помочь вымести остаточную влагу","Охладить насос"],"qs":"En una evacuación triple, se introduce nitrógeno seco entre los tirones de vacío para:","optss":["Agregar refrigerante","Presurizar para la prueba de fugas","Romper el vacío y ayudar a barrer la humedad restante","Enfriar la bomba"],"rs":"Romper el vacío con nitrógeno seco diluye y arrastra la humedad residual; repetir el tirón/barrido alcanza un sistema seco de manera más confiable."},
  {"id":248,"sec":"Fabrication & Installation","q":"For an accurate vacuum reading, the micron gauge should be placed:","opts":["On the system, as far from the pump as practical","Inside the compressor","At the vacuum pump inlet","On the gas line"],"correct":0,"re":"Reading at the pump shows the pump's vacuum, not the system's; mount the micron gauge on the system (e.g., opposite end) to confirm the whole system is evacuated.","rr":"Измерение у насоса показывает вакуум насоса, а не системы; ставьте микронный датчик на систему (например на дальнем конце), чтобы подтвердить вакуум всей системы.","qr":"Для точного измерения вакуума микронный вакуумметр следует ставить:","optsr":["На системе, как можно дальше от насоса","Внутри компрессора","На входе вакуумного насоса","На газовой линии"],"qs":"Para una lectura de vacío precisa, el medidor de micrones (micron gauge) debe colocarse:","optss":["En el sistema, lo más lejos posible de la bomba","Dentro del compresor","En la entrada de la bomba de vacío","En la línea de gas"],"rs":"Leer en la bomba muestra el vacío de la bomba, no el del sistema; monte el medidor de micrones en el sistema (p. ej., en el extremo opuesto) para confirmar que todo el sistema está evacuado."},
  {"id":249,"sec":"Fabrication & Installation","q":"A flexible 'whip' (sealtight) conduit between the disconnect and condenser is used to:","opts":["Vent gas","Drain condensate","Allow for vibration/movement while protecting the wiring","Carry refrigerant"],"correct":2,"re":"The flexible whip protects branch-circuit conductors at the unit while allowing for vibration and slight movement of the outdoor equipment.","rr":"Гибкий whip защищает проводники ответвления у блока, допуская вибрацию и небольшие перемещения наружного оборудования.","qr":"Гибкий «whip» (sealtight) между разъединителем и конденсатором служит, чтобы:","optsr":["Удалять газ","Сливать конденсат","Допустить вибрацию/движение, защищая проводку","Нести хладагент"],"qs":"Un 'whip' flexible (sealtight) entre el desconectador y el condensador se usa para:","optss":["Ventilar gas","Drenar el condensado","Permitir la vibración/movimiento mientras protege el cableado","Conducir refrigerante"],"rs":"El whip flexible protege los conductores del circuito ramal en la unidad mientras permite la vibración y el ligero movimiento del equipo exterior."},
  {"id":250,"sec":"Fabrication & Installation","q":"Condensate from a high-efficiency condensing furnace is mildly acidic, so a ___ is often required:","opts":["Bigger filter","Larger gas line","Condensate neutralizer","Hard-start kit"],"correct":2,"re":"Condensing-furnace condensate is acidic (low pH); a neutralizer kit protects metal drains and meets local discharge requirements.","rr":"Конденсат конденсационной печи кислый (низкий pH); нейтрализатор защищает металлические дренажи и отвечает местным требованиям к сбросу.","qr":"Конденсат высокоэффективной конденсационной печи слабокислый, поэтому часто требуется:","optsr":["Бо́льший фильтр","Бо́льшая газовая линия","Нейтрализатор конденсата","Hard-start kit"],"qs":"El condensado de un horno (furnace) condensante de alta eficiencia es ligeramente ácido, por lo que a menudo se requiere un ___:","optss":["Filtro más grande","Línea de gas más grande","Neutralizador de condensado","Kit de arranque rápido"],"rs":"El condensado de un horno (furnace) condensante es ácido (pH bajo); un kit neutralizador protege los drenajes metálicos y cumple con los requisitos locales de descarga."},
  {"id":251,"sec":"Fabrication & Installation","q":"A condensate safety float switch is wired:","opts":["In parallel with line voltage","To the compressor windings","To the gas valve only","In series with the control circuit to shut the unit off on high water"],"correct":3,"re":"The float switch opens the 24 V control circuit when the pan/line backs up, stopping the system before water overflows and causes damage.","rr":"Поплавок размыкает цепь управления 24 В при переполнении поддона/линии, останавливая систему до перелива воды и порчи.","qr":"Поплавковый аварийный выключатель конденсата подключают:","optsr":["Параллельно линейному напряжению","К обмоткам компрессора","Только к газовому клапану","Последовательно в цепь управления, чтобы отключить блок при высокой воде"],"qs":"Un interruptor de flotador de seguridad de condensado se conecta:","optss":["En paralelo con el voltaje de línea","A los devanados del compresor","Solo a la válvula de gas","En serie con el circuito de control para apagar la unidad ante un nivel alto de agua"],"rs":"El interruptor de flotador abre el circuito de control de 24 V cuando la bandeja/línea se acumula, deteniendo el sistema antes de que el agua se desborde y cause daños."},
  {"id":252,"sec":"Fabrication & Installation","q":"Service (king/queen) valves on a condenser are 'back-seated' to:","opts":["Isolate the gauge ports while leaving the system open to flow","Pump the system down","Vent refrigerant","Add oil"],"correct":0,"re":"Back-seating opens the system flow path and closes the service port; front-seating isolates the condenser (used in pump-down).","rr":"Back-seat открывает путь потока системы и закрывает сервисный порт; front-seat изолирует конденсатор (используется при pump-down).","qr":"Сервисные вентили (king/queen) конденсатора «back-seat» (заднее седло) ставят, чтобы:","optsr":["Изолировать сервисные порты, оставив систему открытой для потока","Откачать систему (pump down)","Стравить хладагент","Добавить масло"],"qs":"Las válvulas de servicio (king/queen) de un condensador se 'asientan hacia atrás' (back-seated) para:","optss":["Aislar los puertos de manómetro mientras se deja el sistema abierto al flujo","Hacer el vaciado (pump down) del sistema","Ventilar refrigerante","Agregar aceite"],"rs":"El asentamiento hacia atrás abre la trayectoria de flujo del sistema y cierra el puerto de servicio; el asentamiento hacia adelante (front-seating) aísla el condensador (se usa en el pump-down)."},
  {"id":253,"sec":"Fabrication & Installation","q":"'Pumping down' a system stores the refrigerant in the:","opts":["Evaporator","Compressor oil","Suction line","Condenser/receiver (by closing the liquid valve and running until low suction)"],"correct":3,"re":"Closing the liquid-line (king) valve and running the compressor pulls refrigerant into the condenser/receiver, isolating the low side for service.","rr":"Закрыв жидкостный (king) вентиль и запустив компрессор, хладагент собирают в конденсатор/ресивер, изолируя низкую сторону для обслуживания.","qr":"«Pump down» системы хранит хладагент в:","optsr":["Испарителе","Масле компрессора","Всасывающей линии","Конденсаторе/ресивере (закрыв жидкостный вентиль и работая до низкого всасывания)"],"qs":"El 'vaciado' (pump down) de un sistema almacena el refrigerante en el:","optss":["Evaporador","Aceite del compresor","Línea de succión","Condensador/receptor (cerrando la válvula de líquido y haciéndolo funcionar hasta baja succión)"],"rs":"Cerrar la válvula de la línea de líquido (king) y hacer funcionar el compresor atrae el refrigerante hacia el condensador/receptor, aislando el lado de baja para el servicio."},
  {"id":254,"sec":"Fabrication & Installation","q":"A liquid-line filter drier must be installed:","opts":["In any direction","Only on the suction line","Upside down","With its arrow pointing in the direction of refrigerant flow (toward the metering device)"],"correct":3,"re":"The drier's flow arrow must point toward the evaporator/metering device; reversed installation impairs filtering and drying.","rr":"Стрелка осушителя должна указывать к испарителю/дозатору; установка наоборот ухудшает фильтрацию и осушку.","qr":"Жидкостный фильтр-осушитель нужно устанавливать:","optsr":["В любом направлении","Только на всасывающую линию","Вверх ногами","Стрелкой по направлению потока хладагента (к дозатору)"],"qs":"Un filtro secador de línea de líquido debe instalarse:","optss":["En cualquier dirección","Solo en la línea de succión","Al revés","Con su flecha apuntando en la dirección del flujo de refrigerante (hacia el dispositivo dosificador)"],"rs":"La flecha de flujo del secador debe apuntar hacia el evaporador/dispositivo dosificador; una instalación invertida perjudica el filtrado y el secado."},
  {"id":255,"sec":"Service & Troubleshooting","q":"Moisture in a refrigeration system is harmful because it can:","opts":["Freeze at the metering device and form acids with the oil","Lower head pressure","Increase subcooling","Improve cooling"],"correct":0,"re":"Moisture can freeze at the metering device (intermittent restriction) and react with POE oil/refrigerant to form acids that corrode and cause burnout.","rr":"Влага может замерзать у дозатора (периодический засор) и реагировать с POE-маслом/хладагентом, образуя кислоты, которые корродируют и ведут к выгоранию.","qr":"Влага в холодильной системе вредна, потому что может:","optsr":["Замерзать у дозатора и образовывать кислоты с маслом","Снижать давление нагнетания","Повышать subcooling","Улучшить охлаждение"],"qs":"La humedad en un sistema de refrigeración es dañina porque puede:","optss":["Congelarse en el dispositivo dosificador y formar ácidos con el aceite","Reducir la presión de cabeza","Aumentar el subenfriamiento","Mejorar el enfriamiento"],"rs":"La humedad puede congelarse en el dispositivo dosificador (restricción intermitente) y reaccionar con el aceite POE/refrigerante para formar ácidos que corroen y causan quemadura (burnout)."},
  {"id":256,"sec":"Service & Troubleshooting","q":"Non-condensable gases (such as air) in a system cause:","opts":["Head pressure higher than normal for the ambient/condensing temperature","Better efficiency","Low superheat","Low head pressure"],"correct":0,"re":"Air doesn't condense, so it occupies condenser volume and raises head pressure above what the ambient temperature alone would produce.","rr":"Воздух не конденсируется, занимает объём конденсатора и поднимает давление нагнетания выше, чем дала бы одна наружная температура.","qr":"Неконденсируемые газы (например воздух) в системе вызывают:","optsr":["Давление нагнетания выше нормы для данной наружной/конденсационной температуры","Лучшую эффективность","Низкий superheat","Низкое давление нагнетания"],"qs":"Los gases no condensables (como el aire) en un sistema causan:","optss":["Presión de cabeza más alta de lo normal para la temperatura ambiente/de condensación","Mejor eficiencia","Bajo sobrecalentamiento","Baja presión de cabeza"],"rs":"El aire no condensa, por lo que ocupa volumen del condensador y eleva la presión de cabeza por encima de lo que produciría la temperatura ambiente por sí sola."},
  {"id":257,"sec":"Service & Troubleshooting","q":"Bubbles in the liquid-line sight glass (flash gas) usually indicate:","opts":["Low subcooling — undercharge or a restriction","Overcharge","High airflow","A clean filter"],"correct":0,"re":"Flash gas means the liquid isn't fully subcooled; common causes are undercharge or a liquid-line restriction (e.g., clogged drier).","rr":"Flash gas означает, что жидкость недостаточно переохлаждена; частые причины — недозаправка или засор жидкостной линии (например забитый осушитель).","qr":"Пузыри в смотровом стекле жидкостной линии (flash gas) обычно указывают на:","optsr":["Низкий subcooling — недозаправку или засор","Перезаправку","Высокий расход воздуха","Чистый фильтр"],"qs":"Las burbujas en la mirilla de la línea de líquido (gas de revaporización/flash gas) usualmente indican:","optss":["Bajo subenfriamiento — carga insuficiente o una restricción","Sobrecarga","Alto flujo de aire","Un filtro limpio"],"rs":"El flash gas significa que el líquido no está completamente subenfriado; las causas comunes son la carga insuficiente o una restricción en la línea de líquido (p. ej., secador obstruido)."},
  {"id":258,"sec":"Service & Troubleshooting","q":"A TXV stuck closed (or with a lost bulb charge) produces:","opts":["No change","High superheat, low suction, low capacity","Overcharge symptoms","Low superheat, high suction"],"correct":1,"re":"A closed/under-feeding TXV starves the evaporator: superheat climbs, suction pressure drops, and capacity falls.","rr":"Закрытый/недоподающий TXV обедняет испаритель: superheat растёт, давление всасывания падает, производительность снижается.","qr":"TXV, заклинивший закрытым (или с потерей заряда колбы), даёт:","optsr":["Без изменений","Высокий superheat, низкое всасывание, малую производительность","Симптомы перезаправки","Низкий superheat, высокое всасывание"],"qs":"Una TXV atascada cerrada (o con la carga del bulbo perdida) produce:","optss":["Ningún cambio","Alto sobrecalentamiento, baja succión, baja capacidad","Síntomas de sobrecarga","Bajo sobrecalentamiento, alta succión"],"rs":"Una TXV cerrada/que subalimenta deja hambriento al evaporador: el sobrecalentamiento sube, la presión de succión baja y la capacidad disminuye."},
  {"id":259,"sec":"Service & Troubleshooting","q":"A TXV stuck open (overfeeding) produces:","opts":["Low suction","Low superheat, high suction, and risk of liquid floodback","High superheat","No symptoms"],"correct":1,"re":"An overfeeding valve floods the evaporator: superheat falls toward zero, suction rises, and liquid can return to the compressor (slugging risk).","rr":"Переподающий клапан затапливает испаритель: superheat падает к нулю, всасывание растёт, жидкость может вернуться в компрессор (риск гидроудара).","qr":"TXV, заклинивший открытым (переподаёт), даёт:","optsr":["Низкое всасывание","Низкий superheat, высокое всасывание и риск возврата жидкости","Высокий superheat","Без симптомов"],"qs":"Una TXV atascada abierta (sobrealimentando) produce:","optss":["Baja succión","Bajo sobrecalentamiento, alta succión y riesgo de retorno de líquido (floodback)","Alto sobrecalentamiento","Ningún síntoma"],"rs":"Una válvula que sobrealimenta inunda el evaporador: el sobrecalentamiento cae hacia cero, la succión sube y el líquido puede regresar al compresor (riesgo de slugging)."},
  {"id":260,"sec":"Service & Troubleshooting","q":"Liquid refrigerant returning to the compressor (floodback/slugging) is dangerous because liquid:","opts":["Improves lubrication","Lowers amps","Does not compress and can break valves/bearings","Compresses easily"],"correct":2,"re":"Liquid is essentially incompressible; slugging hammers the valves and washes oil from bearings, causing mechanical failure.","rr":"Жидкость практически несжимаема; гидроудар бьёт по клапанам и смывает масло с подшипников, вызывая механический отказ.","qr":"Возврат жидкого хладагента в компрессор (floodback/гидроудар) опасен тем, что жидкость:","optsr":["Улучшает смазку","Снижает ток","Не сжимается и может разрушить клапаны/подшипники","Легко сжимается"],"qs":"El retorno de refrigerante líquido al compresor (floodback/slugging) es peligroso porque el líquido:","optss":["Mejora la lubricación","Reduce los amperes","No se comprime y puede romper válvulas/cojinetes","Se comprime fácilmente"],"rs":"El líquido es esencialmente incompresible; el slugging golpea las válvulas y arrastra el aceite de los cojinetes, causando falla mecánica."},
  {"id":261,"sec":"Service & Troubleshooting","q":"On a single-phase compressor, the highest resistance reading is normally between:","opts":["Start and Run terminals","Terminal and ground","Common and Run","Common and Start"],"correct":0,"re":"C-R is lowest, C-S higher, and S-R is the sum (highest). Continuity to the shell/ground indicates a grounded (failed) compressor.","rr":"C-R наименьшее, C-S больше, а S-R — сумма (наибольшее). Проводимость на корпус/землю указывает на пробитый (неисправный) компрессор.","qr":"У однофазного компрессора наибольшее сопротивление обычно между:","optsr":["Клеммами Start и Run","Клеммой и землёй","Common и Run","Common и Start"],"qs":"En un compresor monofásico, la lectura de resistencia más alta normalmente está entre:","optss":["Las terminales de Arranque (Start) y Marcha (Run)","La terminal y tierra","Común (Common) y Marcha (Run)","Común (Common) y Arranque (Start)"],"rs":"C-R es la más baja, C-S es más alta y S-R es la suma (la más alta). La continuidad a la carcasa/tierra indica un compresor a tierra (con falla)."},
  {"id":262,"sec":"Service & Troubleshooting","q":"A compressor winding that reads infinite (OL) resistance indicates:","opts":["A good winding","A grounded winding","An open winding (or open internal overload)","A shorted winding"],"correct":2,"re":"Infinite resistance means the circuit is broken — an open winding or an open internal thermal overload (may reset when cooled).","rr":"Бесконечное сопротивление = разрыв цепи — обрыв обмотки или разомкнутая внутренняя тепловая защита (может вернуться при остывании).","qr":"Обмотка компрессора с бесконечным (OL) сопротивлением указывает на:","optsr":["Исправную обмотку","Пробой обмотки","Обрыв обмотки (или разомкнутую внутреннюю защиту)","Замкнутую обмотку"],"qs":"Un devanado de compresor que lee resistencia infinita (OL) indica:","optss":["Un devanado en buen estado","Un devanado a tierra","Un devanado abierto (o una sobrecarga interna abierta)","Un devanado en cortocircuito"],"rs":"La resistencia infinita significa que el circuito está roto — un devanado abierto o una sobrecarga térmica interna abierta (puede reiniciarse al enfriarse)."},
  {"id":263,"sec":"Service & Troubleshooting","q":"A three-phase motor that loses one phase ('single-phasing') will typically:","opts":["Speed up","Run cooler","Overheat, hum, and trip on overload","Improve efficiency"],"correct":2,"re":"With one phase lost, the motor can't develop normal torque; current rises in the remaining windings and it overheats/trips. Check fuses, contacts, and supply.","rr":"С потерей фазы двигатель не развивает нормальный момент; ток в оставшихся обмотках растёт, он перегревается/выбивает. Проверьте предохранители, контакты, питание.","qr":"Трёхфазный двигатель, потерявший одну фазу («single-phasing»), обычно:","optsr":["Ускоряется","Работает холоднее","Перегревается, гудит и выбивает по перегрузке","Повышает КПД"],"qs":"Un motor trifásico que pierde una fase ('single-phasing') normalmente:","optss":["Se acelera","Funciona más frío","Se sobrecalienta, zumba y se dispara por sobrecarga","Mejora la eficiencia"],"rs":"Con una fase perdida, el motor no puede desarrollar el torque normal; la corriente sube en los devanados restantes y se sobrecalienta/dispara. Revise fusibles, contactos y suministro."},
  {"id":264,"sec":"Service & Troubleshooting","q":"A compressor with worn/leaking valves typically shows:","opts":["Low suction, high head","Normal performance","Reduced capacity with high suction and low discharge pressure","High subcooling"],"correct":2,"re":"Internal valve leakage lets gas recirculate, so the compressor can't build normal discharge or pull down suction — capacity drops despite running.","rr":"Внутренняя утечка через клапаны даёт рециркуляцию газа: компрессор не создаёт нормальное нагнетание и не опускает всасывание — производительность падает при работе.","qr":"Компрессор с изношенными/негерметичными клапанами обычно показывает:","optsr":["Низкое всасывание, высокий напор","Нормальную работу","Снижение производительности при высоком всасывании и низком нагнетании","Высокий subcooling"],"qs":"Un compresor con válvulas desgastadas/con fugas normalmente muestra:","optss":["Baja succión, alta presión de cabeza","Desempeño normal","Capacidad reducida con alta succión y baja presión de descarga","Alto subenfriamiento"],"rs":"La fuga interna de las válvulas permite que el gas recircule, por lo que el compresor no puede generar la descarga normal ni bajar la succión — la capacidad cae a pesar de estar funcionando."},
  {"id":265,"sec":"Service & Troubleshooting","q":"Before condemning an ECM blower motor, the technician should first check:","opts":["The gas pressure","The condensate trap","The refrigerant charge","Supply power, the control/PWM signal, and connections/programming"],"correct":3,"re":"ECM modules are often blamed wrongly; verify line/low-voltage power, the thermostat/board demand signal, motor harness, and proper programming first.","rr":"ECM-модули часто винят зря; сначала проверьте питание (линия/низкое напряжение), сигнал запроса от термостата/платы, разъёмы и правильную программу.","qr":"Прежде чем менять ECM-двигатель вентилятора, техник сначала проверяет:","optsr":["Давление газа","Сифон конденсата","Заправку хладагентом","Питание, управляющий/PWM-сигнал и соединения/программирование"],"qs":"Antes de condenar un motor de soplador ECM, el técnico debe revisar primero:","optss":["La presión de gas","La trampa de condensado","La carga de refrigerante","La alimentación, la señal de control/PWM y las conexiones/programación"],"rs":"A menudo se culpa erróneamente a los módulos ECM; verifique primero la alimentación de línea/bajo voltaje, la señal de demanda del termostato/tablero, el arnés del motor y la programación correcta."},
  {"id":266,"sec":"Service & Troubleshooting","q":"A gas furnace whose pressure switch won't close after the inducer starts will:","opts":["Overheat","Fire normally","Cool the house","Fail to ignite (no proof of draft)"],"correct":3,"re":"The pressure switch must prove inducer draft before ignition; if it won't close (weak inducer, blocked flue/condensate, cracked hose), the sequence halts safely.","rr":"Реле давления должно подтвердить тягу инжектора до розжига; если оно не замкнётся (слабый инжектор, забитый дымоход/конденсат, треснувший шланг), последовательность безопасно останавливается.","qr":"Газовая печь, у которой реле давления не замыкается после старта инжектора, будет:","optsr":["Перегреваться","Зажигаться нормально","Охлаждать дом","Не зажигаться (нет подтверждения тяги)"],"qs":"Un horno (furnace) de gas cuyo interruptor de presión no cierra después de que arranca el inductor:","optss":["Se sobrecalienta","Enciende normalmente","Enfría la casa","No logra encender (sin prueba de tiro)"],"rs":"El interruptor de presión debe comprobar el tiro del inductor antes del encendido; si no cierra (inductor débil, chimenea/condensado bloqueado, manguera agrietada), la secuencia se detiene de forma segura."},
  {"id":267,"sec":"Service & Troubleshooting","q":"Delayed ignition causing a small 'puff' or rollout at the burners is often due to:","opts":["Too much airflow","High SEER","Dirty burners, low gas pressure, or a weak ignition source","Overcharge"],"correct":2,"re":"When gas accumulates before igniting, it lights with a puff; causes include dirty/clogged burners, low manifold pressure, or a weak igniter/flame path.","rr":"Когда газ накапливается до воспламенения, он зажигается с хлопком; причины — грязные/забитые горелки, низкое давление на манифольде или слабый розжиг.","qr":"Запоздалый розжиг с лёгким «хлопком» или выбросом пламени у горелок часто из-за:","optsr":["Слишком большого расхода воздуха","Высокого SEER","Грязных горелок, низкого давления газа или слабого источника розжига","Перезаправки"],"qs":"El encendido retardado que causa un pequeño 'soplido' (puff) o salida de llama (rollout) en los quemadores se debe a menudo a:","optss":["Demasiado flujo de aire","Alto SEER","Quemadores sucios, baja presión de gas o una fuente de encendido débil","Sobrecarga"],"rs":"Cuando el gas se acumula antes de encender, se enciende con un soplido; las causas incluyen quemadores sucios/obstruidos, baja presión de manifold o un encendedor/trayectoria de llama débil."},
  {"id":268,"sec":"Service & Troubleshooting","q":"No 24 V at the gas valve during a heat call (with a good valve) points to a problem:","opts":["In the condenser","Upstream in the control circuit (board, limit, flame sense, transformer)","In the refrigerant circuit","In the duct"],"correct":1,"re":"If the valve coil is good but receives no 24 V on a call, trace upstream — open limit/rollout, failed board, no flame proof, or transformer/fuse issue.","rr":"Если катушка клапана цела, но 24 В при запросе нет — ищите выше: разомкнутый лимит/rollout, отказ платы, нет подтверждения пламени, или трансформатор/предохранитель.","qr":"Отсутствие 24 В на газовом клапане при запросе тепла (клапан исправен) указывает на проблему:","optsr":["В конденсаторе","Выше по цепи управления (плата, лимит, контроль пламени, трансформатор)","В контуре хладагента","В воздуховоде"],"qs":"La ausencia de 24 V en la válvula de gas durante una demanda de calefacción (con una válvula en buen estado) apunta a un problema:","optss":["En el condensador","Aguas arriba en el circuito de control (tablero, límite, sensor de llama, transformador)","En el circuito de refrigerante","En el ducto"],"rs":"Si la bobina de la válvula está en buen estado pero no recibe 24 V durante una demanda, rastree aguas arriba — límite/rollout abierto, tablero con falla, sin prueba de llama, o problema de transformador/fusible."},
  {"id":269,"sec":"Service & Troubleshooting","q":"In cooling, low suction pressure together with high head pressure most likely indicates:","opts":["Low load","Dirty filter only","Overcharge","A restriction in the liquid line or metering device"],"correct":3,"re":"A restriction backs up refrigerant (high head) while starving the evaporator (low suction); look for a plugged drier or stuck metering device.","rr":"Засор подпирает хладагент (высокий напор), обедняя испаритель (низкое всасывание); ищите забитый осушитель или заклинивший дозатор.","qr":"В охлаждении низкое давление всасывания вместе с высоким давлением нагнетания скорее всего указывает на:","optsr":["Малую нагрузку","Только грязный фильтр","Перезаправку","Засор в жидкостной линии или дозаторе"],"qs":"En enfriamiento, una baja presión de succión junto con una alta presión de cabeza muy probablemente indica:","optss":["Baja carga","Solo filtro sucio","Sobrecarga","Una restricción en la línea de líquido o el dispositivo dosificador"],"rs":"Una restricción acumula el refrigerante (alta presión de cabeza) mientras deja hambriento al evaporador (baja succión); busque un secador obstruido o un dispositivo dosificador atascado."},
  {"id":270,"sec":"Service & Troubleshooting","q":"In cooling, high suction pressure together with high head pressure suggests:","opts":["Low airflow at evaporator","A closed TXV","Undercharge or restriction","Overcharge, a dirty/blocked condenser, or excessive load"],"correct":3,"re":"Both pressures high points to too much refrigerant, poor condenser heat rejection (dirty coil/failed fan), or a very high load.","rr":"Оба давления высокие — это избыток хладагента, плохой теплоотвод конденсатора (грязная батарея/отказ вентилятора) или очень высокая нагрузка.","qr":"В охлаждении высокое всасывание вместе с высоким нагнетанием указывает на:","optsr":["Низкий расход у испарителя","Закрытый TXV","Недозаправку или засор","Перезаправку, грязный/заблокированный конденсатор или избыточную нагрузку"],"qs":"En enfriamiento, una alta presión de succión junto con una alta presión de cabeza sugiere:","optss":["Bajo flujo de aire en el evaporador","Una TXV cerrada","Carga insuficiente o restricción","Sobrecarga, un condensador sucio/bloqueado o carga excesiva"],"rs":"Ambas presiones altas apuntan a demasiado refrigerante, un mal rechazo de calor del condensador (bobina sucia/ventilador con falla) o una carga muy alta."},
  {"id":271,"sec":"Service & Troubleshooting","q":"In cooling, high suction pressure with low head pressure most often indicates:","opts":["Overcharge","An inefficient compressor (worn valves)","Dirty condenser","A restriction"],"correct":1,"re":"When the compressor can't pump effectively, suction stays high and head stays low — classic worn-valve/inefficient compressor signature.","rr":"Когда компрессор плохо качает, всасывание остаётся высоким, а нагнетание низким — классическая картина изношенных клапанов/неэффективного компрессора.","qr":"В охлаждении высокое всасывание при низком нагнетании чаще всего указывает на:","optsr":["Перезаправку","Неэффективный компрессор (изношенные клапаны)","Грязный конденсатор","Засор"],"qs":"En enfriamiento, una alta presión de succión con una baja presión de cabeza con mayor frecuencia indica:","optss":["Sobrecarga","Un compresor ineficiente (válvulas desgastadas)","Condensador sucio","Una restricción"],"rs":"Cuando el compresor no puede bombear eficazmente, la succión se mantiene alta y la presión de cabeza baja — la firma clásica de un compresor ineficiente/de válvulas desgastadas."},
  {"id":272,"sec":"Service & Troubleshooting","q":"A reversing valve that buzzes but won't shift may be caused by:","opts":["A clean filter","Low refrigerant charge (insufficient pressure differential) or a failed solenoid","A new thermostat","High airflow"],"correct":1,"re":"The valve needs adequate pressure difference to shift; low charge or a failed solenoid coil/stuck slide can leave it buzzing without changing modes.","rr":"Клапану нужен достаточный перепад давления для переключения; малая заправка или отказ катушки соленоида/заклинивший золотник оставляют его гудящим без смены режима.","qr":"Реверс-клапан, который гудит, но не переключается, может быть из-за:","optsr":["Чистого фильтра","Малой заправки (недостаточный перепад давления) или отказа соленоида","Нового термостата","Высокого расхода воздуха"],"qs":"Una válvula reversible que zumba pero no cambia puede deberse a:","optss":["Un filtro limpio","Baja carga de refrigerante (diferencial de presión insuficiente) o un solenoide con falla","Un termostato nuevo","Alto flujo de aire"],"rs":"La válvula necesita una diferencia de presión adecuada para cambiar; una carga baja o una bobina de solenoide con falla/corredera atascada puede dejarla zumbando sin cambiar de modo."},
  {"id":273,"sec":"Service & Troubleshooting","q":"A heat pump low on charge in heating mode typically shows:","opts":["No symptoms","High head only","High suction, high capacity","Low suction pressure, reduced heating capacity, and possible outdoor-coil icing"],"correct":3,"re":"Undercharge in heating starves the outdoor (evaporator) coil: low suction, weak heat output, and abnormal frosting/icing.","rr":"Недозаправка в нагреве обедняет наружный (испарительный) змеевик: низкое всасывание, слабый нагрев и ненормальное инееобразование/обмерзание.","qr":"Тепловой насос с недостатком заправки в режиме нагрева обычно показывает:","optsr":["Без симптомов","Только высокий напор","Высокое всасывание, высокую отдачу","Низкое давление всасывания, сниженную теплоотдачу и возможное обмерзание наружного змеевика"],"qs":"Una bomba de calor con poca carga en modo calefacción normalmente muestra:","optss":["Ningún síntoma","Solo alta presión de cabeza","Alta succión, alta capacidad","Baja presión de succión, capacidad de calefacción reducida y posible formación de hielo en la bobina exterior"],"rs":"La carga insuficiente en calefacción deja hambrienta a la bobina exterior (evaporador): baja succión, salida de calor débil y escarcha/hielo anormal."},
  {"id":274,"sec":"Service & Troubleshooting","q":"A repeatedly blown 24 V control (low-voltage) fuse most often indicates:","opts":["A short to ground in the thermostat/control wiring","High head pressure","A dirty filter","A refrigerant leak"],"correct":0,"re":"A grounded/shorted low-voltage wire (e.g., a chafed thermostat cable) draws excess current and blows the control fuse; inspect and isolate the wiring.","rr":"Замкнутый на землю низковольтный провод (например протёртый кабель термостата) тянет лишний ток и жжёт предохранитель управления; осмотрите и изолируйте проводку.","qr":"Постоянно перегорающий управляющий предохранитель 24 В (низкое напряжение) чаще всего указывает на:","optsr":["Замыкание на землю в проводке термостата/управления","Высокий напор","Грязный фильтр","Утечку хладагента"],"qs":"Un fusible de control (bajo voltaje) de 24 V que se quema repetidamente con mayor frecuencia indica:","optss":["Un cortocircuito a tierra en el termostato/cableado de control","Alta presión de cabeza","Un filtro sucio","Una fuga de refrigerante"],"rs":"Un cable de bajo voltaje a tierra/en cortocircuito (p. ej., un cable de termostato rozado) toma corriente excesiva y quema el fusible de control; inspeccione y aísle el cableado."},
  {"id":275,"sec":"Service & Troubleshooting","q":"A dirty condenser coil in cooling typically causes:","opts":["High head pressure, high discharge temperature, and higher amp draw","Better efficiency","Low head pressure","Low suction only"],"correct":0,"re":"Restricted condenser airflow reduces heat rejection, raising head pressure, discharge temperature, and current — with poor cooling and possible high-pressure trips.","rr":"Ухудшённый обдув конденсатора снижает теплоотвод, поднимая напор, температуру нагнетания и ток — плохое охлаждение и возможные срабатывания по высокому давлению.","qr":"Грязный конденсатор в охлаждении обычно вызывает:","optsr":["Высокий напор, высокую температуру нагнетания и больший ток","Лучшую эффективность","Низкое давление нагнетания","Только низкое всасывание"],"qs":"Una bobina de condensador sucia en enfriamiento normalmente causa:","optss":["Alta presión de cabeza, alta temperatura de descarga y mayor consumo de amperes","Mejor eficiencia","Baja presión de cabeza","Solo baja succión"],"rs":"El flujo de aire restringido del condensador reduce el rechazo de calor, elevando la presión de cabeza, la temperatura de descarga y la corriente — con un enfriamiento deficiente y posibles disparos por alta presión."},
  {"id":276,"sec":"Service & Troubleshooting","q":"After thawing a frozen evaporator coil, the technician must:","opts":["Find and correct the cause (low airflow or low charge) before returning to service","Replace the compressor","Immediately recharge","Add oil"],"correct":0,"re":"Thawing only restores flow temporarily; unless the airflow restriction or undercharge is corrected, the coil will freeze again.","rr":"Разморозка лишь временно восстанавливает поток; без устранения сужения расхода или недозаправки змеевик обмёрзнет снова.","qr":"После разморозки обмёрзшего испарителя техник обязан:","optsr":["Найти и устранить причину (низкий расход или недозаправка) до возврата в работу","Заменить компрессор","Сразу дозаправить","Добавить масло"],"qs":"Después de descongelar una bobina de evaporador congelada, el técnico debe:","optss":["Encontrar y corregir la causa (bajo flujo de aire o baja carga) antes de volver a poner en servicio","Reemplazar el compresor","Recargar de inmediato","Agregar aceite"],"rs":"Descongelar solo restablece el flujo temporalmente; a menos que se corrija la restricción de flujo de aire o la carga insuficiente, la bobina se volverá a congelar."},
  {"id":277,"sec":"Service & Troubleshooting","q":"Contactor chatter (rapid pull-in/drop-out) is commonly caused by:","opts":["High SEER","Overcharge","Low control voltage or a weak transformer/loose connection","Dirty condenser"],"correct":2,"re":"If the coil can't hold in (low 24 V, weak transformer, loose/high-resistance connection), the contactor chatters; correct the control voltage/connection.","rr":"Если катушка не удерживается (низкие 24 В, слабый трансформатор, слабый/высокоомный контакт), контактор дребезжит; исправьте управляющее напряжение/контакт.","qr":"Дребезг контактора (быстрое включение/отпускание) обычно вызван:","optsr":["Высоким SEER","Перезаправкой","Низким управляющим напряжением или слабым трансформатором/слабым контактом","Грязным конденсатором"],"qs":"El chasquido del contactor (entrada/salida rápida) comúnmente es causado por:","optss":["Alto SEER","Sobrecarga","Bajo voltaje de control o un transformador débil/conexión floja","Condensador sucio"],"rs":"Si la bobina no puede mantenerse (bajo 24 V, transformador débil, conexión floja/de alta resistencia), el contactor chasquea; corrija el voltaje/conexión de control."},
  {"id":278,"sec":"Service & Troubleshooting","q":"A standing-pressure leak test (with dry nitrogen) confirms tightness by:","opts":["Pressurizing and watching for a pressure drop over time (temperature-corrected)","Pulling a vacuum","Adding refrigerant","Measuring superheat"],"correct":0,"re":"After pressurizing with nitrogen, a held pressure (accounting for temperature change) indicates no leak; a drop reveals one to locate with soap/detector.","rr":"После опрессовки азотом удержание давления (с учётом изменения температуры) означает отсутствие утечки; падение выявляет её — ищут мылом/детектором.","qr":"Опрессовка под стоячим давлением (сухим азотом) подтверждает герметичность путём:","optsr":["Подачи давления и наблюдения за его падением во времени (с поправкой на температуру)","Создания вакуума","Добавления хладагента","Измерения superheat"],"qs":"Una prueba de fuga de presión estática (con nitrógeno seco) confirma la hermeticidad al:","optss":["Presurizar y observar una caída de presión en el tiempo (corregida por temperatura)","Hacer vacío","Agregar refrigerante","Medir el sobrecalentamiento"],"rs":"Después de presurizar con nitrógeno, una presión mantenida (considerando el cambio de temperatura) indica que no hay fuga; una caída revela una para localizarla con jabón/detector."},
  {"id":279,"sec":"Safety & Field Practices","q":"Cal/OSHA (Title 8) requires every employer to establish a written:","opts":["Marketing plan","Injury and Illness Prevention Program (IIPP)","SEER report","Refrigerant log only"],"correct":1,"re":"California employers must have a written IIPP covering hazard identification, training, inspections, and correction of unsafe conditions.","rr":"Работодатели Калифорнии обязаны иметь письменную IIPP, охватывающую выявление опасностей, обучение, инспекции и устранение небезопасных условий.","qr":"Cal/OSHA (Title 8) требует от каждого работодателя иметь письменную:","optsr":["Маркетинговый план","Программу предотвращения травм и заболеваний (IIPP)","Отчётность по SEER","Только журнал хладагента"],"qs":"Cal/OSHA (Título 8) requiere que todo empleador establezca por escrito un:","optss":["Plan de marketing","Programa de Prevención de Lesiones y Enfermedades (IIPP)","Reporte de SEER","Solo un registro de refrigerante"],"rs":"Los empleadores de California deben tener un IIPP por escrito que cubra la identificación de peligros, capacitación, inspecciones y corrección de condiciones inseguras."},
  {"id":280,"sec":"Safety & Field Practices","q":"The Hazard Communication standard (GHS) requires that hazardous chemicals on a jobsite have:","opts":["No labeling","A patent","Proper labels and accessible Safety Data Sheets (SDS)","Only a price tag"],"correct":2,"re":"HazCom/GHS requires standardized labels and SDS so workers know the hazards, safe handling, and first aid for chemicals they may contact.","rr":"HazCom/GHS требует стандартные этикетки и SDS, чтобы работники знали опасности, безопасное обращение и первую помощь для химикатов, с которыми контактируют.","qr":"Стандарт информирования об опасностях (GHS) требует, чтобы опасные химикаты на объекте имели:","optsr":["Без маркировки","Патент","Правильные этикетки и доступные паспорта безопасности (SDS)","Только ценник"],"qs":"El estándar de Comunicación de Peligros (GHS) requiere que los productos químicos peligrosos en un sitio de trabajo tengan:","optss":["Ningún etiquetado","Una patente","Etiquetas adecuadas y Hojas de Datos de Seguridad (SDS) accesibles","Solo una etiqueta de precio"],"rs":"HazCom/GHS requiere etiquetas estandarizadas y SDS para que los trabajadores conozcan los peligros, el manejo seguro y los primeros auxilios de los químicos con los que puedan tener contacto."},
  {"id":281,"sec":"Safety & Field Practices","q":"Under EPA rules, recovered refrigerant that will be reused by a different owner must generally be:","opts":["Vented","Reclaimed to purity standards (or recycled on-site for the same owner)","Burned","Mixed with oil"],"correct":1,"re":"Refrigerant changing ownership must be reclaimed to AHRI-700 purity by a certified reclaimer; on-site recycling is limited to the same owner's equipment.","rr":"Хладагент, меняющий владельца, должен быть восстановлен до чистоты AHRI-700 сертифицированным реклаймером; переработка на месте — только для оборудования того же владельца.","qr":"По правилам EPA, откачанный хладагент для повторного использования другим владельцем обычно должен быть:","optsr":["Стравлен","Восстановлен до стандартов чистоты (или переработан на месте для того же владельца)","Сожжён","Смешан с маслом"],"qs":"Según las reglas de la EPA, el refrigerante recuperado que será reutilizado por un propietario diferente generalmente debe ser:","optss":["Ventilado","Reclamado a estándares de pureza (o reciclado en sitio para el mismo propietario)","Quemado","Mezclado con aceite"],"rs":"El refrigerante que cambia de propietario debe ser reclamado a la pureza AHRI-700 por un reclamador certificado; el reciclaje en sitio se limita al equipo del mismo propietario."},
  {"id":282,"sec":"Safety & Field Practices","q":"Oxygen must never be used to pressurize a refrigeration system because:","opts":["It can react explosively with compressor oil","It is too heavy","It is too expensive","It freezes the lines"],"correct":0,"re":"Oxygen under pressure can combust violently with hydrocarbon oils; only dry nitrogen is used for pressure/leak testing.","rr":"Кислород под давлением может бурно воспламениться с углеводородными маслами; для опрессовки/поиска утечек применяют только сухой азот.","qr":"Кислород нельзя применять для опрессовки холодильной системы, потому что он:","optsr":["Может взрывоопасно реагировать с маслом компрессора","Слишком тяжёл","Слишком дорог","Замораживает линии"],"qs":"El oxígeno nunca debe usarse para presurizar un sistema de refrigeración porque:","optss":["Puede reaccionar explosivamente con el aceite del compresor","Es demasiado pesado","Es demasiado caro","Congela las líneas"],"rs":"El oxígeno bajo presión puede combustionar violentamente con los aceites de hidrocarburos; solo se usa nitrógeno seco para las pruebas de presión/fugas."},
  {"id":283,"sec":"Safety & Field Practices","q":"An appliance with a known cracked heat exchanger should be:","opts":["Left as-is","Run at higher gas pressure","Shut down and red-tagged until repaired/replaced","Run with more airflow"],"correct":2,"re":"A cracked heat exchanger can leak CO into supply air; the appliance must be shut off (red-tagged) until the heat exchanger is repaired or replaced.","rr":"Треснувший теплообменник может пропускать CO в приточный воздух; прибор выключают (red-tag) до ремонта или замены теплообменника.","qr":"Прибор с заведомо треснувшим теплообменником следует:","optsr":["Оставить как есть","Запускать на повышенном давлении газа","Выключить и пометить red-tag до ремонта/замены","Запускать с бо́льшим расходом воздуха"],"qs":"Un aparato con un intercambiador de calor agrietado conocido debe ser:","optss":["Dejado tal como está","Operado a mayor presión de gas","Apagado y etiquetado con rojo (red-tagged) hasta su reparación/reemplazo","Operado con más flujo de aire"],"rs":"Un intercambiador de calor agrietado puede filtrar CO al aire de suministro; el aparato debe apagarse (red-tagged) hasta que el intercambiador de calor se repare o reemplace."},
  {"id":284,"sec":"Safety & Field Practices","q":"A CO alarm and combustion test protect occupants because carbon monoxide poisoning first causes:","opts":["Skin rash","Improved breathing","Loud noise","Headache, nausea, and dizziness (often mistaken for flu)"],"correct":3,"re":"Early CO symptoms are headache, nausea, dizziness, and fatigue; because CO is odorless, alarms and combustion testing are essential safeguards.","rr":"Ранние симптомы CO — головная боль, тошнота, головокружение, усталость; поскольку CO без запаха, сигнализаторы и анализ горения — ключевая защита.","qr":"CO-сигнализатор и анализ горения защищают жильцов, потому что отравление угарным газом сначала вызывает:","optsr":["Сыпь","Улучшение дыхания","Громкий шум","Головную боль, тошноту и головокружение (часто принимают за грипп)"],"qs":"Una alarma de CO y una prueba de combustión protegen a los ocupantes porque el envenenamiento por monóxido de carbono causa primero:","optss":["Sarpullido en la piel","Mejor respiración","Ruido fuerte","Dolor de cabeza, náuseas y mareos (a menudo confundidos con gripe)"],"rs":"Los primeros síntomas del CO son dolor de cabeza, náuseas, mareos y fatiga; como el CO es inodoro, las alarmas y la prueba de combustión son salvaguardas esenciales."},
  {"id":285,"sec":"Safety & Field Practices","q":"Pipe or duct insulation in a building constructed before about 1980 may contain asbestos, so the technician should:","opts":["Cut it freely","Vacuum it with a shop vac","Burn it off","Not disturb it and use a certified abatement contractor if removal is needed"],"correct":3,"re":"Disturbing asbestos releases hazardous fibers; suspect materials in older buildings should be left intact and handled only by certified abatement professionals.","rr":"Повреждение асбеста высвобождает опасные волокна; подозрительные материалы в старых зданиях не трогают, удаляют только сертифицированные специалисты по abatement.","qr":"Изоляция труб или воздуховодов в здании постройки примерно до 1980 года может содержать асбест, поэтому техник должен:","optsr":["Свободно резать её","Пропылесосить обычным пылесосом","Выжечь её","Не трогать её и при необходимости удаления привлечь сертифицированного abatement-подрядчика"],"qs":"El aislamiento de tubería o ducto en un edificio construido antes de aproximadamente 1980 puede contener asbesto, por lo que el técnico debe:","optss":["Cortarlo libremente","Aspirarlo con una aspiradora de taller","Quemarlo","No perturbarlo y usar un contratista de remediación certificado si se requiere su remoción"],"rs":"Perturbar el asbesto libera fibras peligrosas; los materiales sospechosos en edificios antiguos deben dejarse intactos y ser manejados solo por profesionales de remediación certificados."},
  {"id":286,"sec":"Safety & Field Practices","q":"After a chemical splash to the eyes, an emergency eyewash should flush the eyes for at least about:","opts":["1 minute","15 minutes","No flushing needed","10 seconds"],"correct":1,"re":"Standard practice is flushing affected eyes/skin for ~15 minutes and seeking medical care; check the chemical's SDS for specifics.","rr":"Стандарт — промывать поражённые глаза/кожу около 15 минут и обратиться за медпомощью; уточняйте по SDS химиката.","qr":"После попадания химиката в глаза аварийный душ для глаз должен промывать их не менее примерно:","optsr":["1 минуты","15 минут","Промывание не нужно","10 секунд"],"qs":"Después de una salpicadura química en los ojos, una estación de lavado de ojos de emergencia debe enjuagar los ojos durante al menos aproximadamente:","optss":["1 minuto","15 minutos","No se necesita enjuague","10 segundos"],"rs":"La práctica estándar es enjuagar los ojos/piel afectados durante ~15 minutos y buscar atención médica; consulte la SDS del químico para detalles específicos."},
  {"id":287,"sec":"Safety & Field Practices","q":"The 'PASS' method for using a portable fire extinguisher stands for:","opts":["Push, Add, Stop, Spray","Pull, Aim, Squeeze, Sweep","Press, Alarm, Shut, Step","Pump, Adjust, Set, Slide"],"correct":1,"re":"PASS = Pull the pin, Aim at the base of the fire, Squeeze the handle, Sweep side to side — only on a small, contained fire with an exit behind you.","rr":"PASS = выдернуть чеку (Pull), навести на основание огня (Aim), нажать рычаг (Squeeze), водить из стороны в сторону (Sweep) — только на малый очаг при наличии выхода за спиной.","qr":"Метод «PASS» при использовании переносного огнетушителя означает:","optsr":["Push, Add, Stop, Spray","Pull, Aim, Squeeze, Sweep (выдернуть, навести, нажать, водить)","Press, Alarm, Shut, Step","Pump, Adjust, Set, Slide"],"qs":"El método 'PASS' para usar un extintor de incendios portátil significa:","optss":["Push, Add, Stop, Spray (Empujar, Agregar, Detener, Rociar)","Pull, Aim, Squeeze, Sweep (Jalar, Apuntar, Apretar, Barrer)","Press, Alarm, Shut, Step (Presionar, Alarmar, Cerrar, Pisar)","Pump, Adjust, Set, Slide (Bombear, Ajustar, Fijar, Deslizar)"],"rs":"PASS = Pull (jalar el pasador), Aim (apuntar a la base del fuego), Squeeze (apretar la manija), Sweep (barrer de lado a lado) — solo en un fuego pequeño y contenido con una salida detrás de usted."},
  {"id":288,"sec":"Safety & Field Practices","q":"Performing hot work (brazing/cutting) near combustibles requires:","opts":["No precautions","More refrigerant","Higher voltage","A fire watch and an extinguisher present, with combustibles cleared/protected"],"correct":3,"re":"Hot work needs the area cleared or shielded, an extinguisher at hand, and a fire watch during and after the work to catch smoldering ignition.","rr":"Огневые работы требуют убрать/закрыть горючие, держать огнетушитель под рукой и обеспечить пожарное наблюдение во время и после работ для перехвата тления.","qr":"Огневые работы (пайка/резка) рядом с горючими требуют:","optsr":["Никаких мер","Больше хладагента","Более высокого напряжения","Пожарного наблюдателя и огнетушителя рядом, с уборкой/защитой горючих"],"qs":"Realizar trabajo en caliente (soldadura con bronce/corte) cerca de combustibles requiere:","optss":["Ninguna precaución","Más refrigerante","Mayor voltaje","Una vigilancia de incendios y un extintor presente, con los combustibles retirados/protegidos"],"rs":"El trabajo en caliente requiere el área despejada o protegida, un extintor a la mano y una vigilancia de incendios durante y después del trabajo para detectar una ignición latente."},
  {"id":289,"sec":"Safety & Field Practices","q":"Lockout/tagout is applied to a blower or rotating equipment before service to:","opts":["Lower static pressure","Prevent unexpected start-up that could injure the technician","Add refrigerant","Increase airflow"],"correct":1,"re":"LOTO de-energizes and secures the equipment so it can't start unexpectedly (e.g., on a thermostat call) while hands are near moving parts.","rr":"LOTO обесточивает и блокирует оборудование, чтобы оно не запустилось внезапно (например по запросу термостата), когда руки рядом с движущимися частями.","qr":"Lockout/tagout применяют к вентилятору или вращающемуся оборудованию перед обслуживанием, чтобы:","optsr":["Снизить статическое давление","Предотвратить внезапный пуск, который может травмировать техника","Добавить хладагент","Увеличить расход воздуха"],"qs":"El bloqueo/etiquetado (lockout/tagout) se aplica a un soplador o equipo rotativo antes del servicio para:","optss":["Reducir la presión estática","Evitar un arranque inesperado que pudiera lesionar al técnico","Agregar refrigerante","Aumentar el flujo de aire"],"rs":"El LOTO desenergiza y asegura el equipo para que no pueda arrancar inesperadamente (p. ej., ante una demanda del termostato) mientras las manos están cerca de las partes móviles."},
  {"id":290,"sec":"Safety & Field Practices","q":"Belt and pulley guards on air handlers are required to:","opts":["Prevent entanglement and contact injuries from moving parts","Hold refrigerant","Reduce voltage","Improve airflow"],"correct":0,"re":"Machine guarding keeps hands, clothing, and tools out of rotating belts/pulleys; never operate equipment with guards removed.","rr":"Защитные ограждения держат руки, одежду и инструмент вдали от вращающихся ремней/шкивов; не работайте со снятыми ограждениями.","qr":"Ограждения ремней и шкивов на воздухообрабатывающих агрегатах нужны, чтобы:","optsr":["Предотвратить затягивание и травмы от движущихся частей","Удерживать хладагент","Снизить напряжение","Улучшить расход воздуха"],"qs":"Las guardas de bandas y poleas en los manejadores de aire se requieren para:","optss":["Evitar el enredo y las lesiones por contacto con las partes móviles","Contener refrigerante","Reducir el voltaje","Mejorar el flujo de aire"],"rs":"El resguardo de máquinas mantiene las manos, la ropa y las herramientas fuera de las bandas/poleas rotativas; nunca opere el equipo con las guardas retiradas."},
  {"id":291,"sec":"Safety & Field Practices","q":"When testing the atmosphere of a confined space, the correct order to test for is:","opts":["Toxics, then oxygen, then flammables","Oxygen first, then flammable gases, then toxics","Order does not matter","Flammables first, then oxygen"],"correct":1,"re":"Test oxygen first (so flammable/toxic readings are valid), then flammable gases, then toxic gases — before entry and continuously as required.","rr":"Сначала кислород (чтобы показания горючих/токсичных были корректны), затем горючие газы, затем токсичные — до входа и далее по требованию.","qr":"При проверке атмосферы замкнутого пространства правильный порядок проверки:","optsr":["Токсичные, затем кислород, затем горючие","Сначала кислород, затем горючие газы, затем токсичные","Порядок не важен","Сначала горючие, затем кислород"],"qs":"Al probar la atmósfera de un espacio confinado, el orden correcto para hacer las pruebas es:","optss":["Tóxicos, luego oxígeno, luego inflamables","Oxígeno primero, luego gases inflamables, luego tóxicos","El orden no importa","Inflamables primero, luego oxígeno"],"rs":"Pruebe el oxígeno primero (para que las lecturas de inflamables/tóxicos sean válidas), luego los gases inflamables, luego los gases tóxicos — antes de entrar y de forma continua según se requiera."},
  {"id":292,"sec":"Safety & Field Practices","q":"In permit-required confined-space entry, the attendant's role is to:","opts":["Run the compressor","Enter and work alongside","Remain outside, monitor conditions, and maintain communication with the entrant","Test the refrigerant"],"correct":2,"re":"The attendant stays outside, watches for hazards, keeps communication, and initiates rescue procedures — never entering to attempt rescue alone.","rr":"Наблюдатель остаётся снаружи, следит за опасностями, держит связь и инициирует спасательные процедуры — не входит сам для спасения.","qr":"При входе в замкнутое пространство по допуску роль наблюдателя (attendant):","optsr":["Запускать компрессор","Войти и работать рядом","Оставаться снаружи, контролировать условия и поддерживать связь со входящим","Проверять хладагент"],"qs":"En la entrada a un espacio confinado que requiere permiso, la función del vigilante (attendant) es:","optss":["Hacer funcionar el compresor","Entrar y trabajar al lado","Permanecer afuera, monitorear las condiciones y mantener la comunicación con quien entra","Probar el refrigerante"],"rs":"El vigilante permanece afuera, está atento a los peligros, mantiene la comunicación e inicia los procedimientos de rescate — sin entrar nunca a intentar un rescate por su cuenta."},
  {"id":293,"sec":"Safety & Field Practices","q":"Extension cords used for power tools on a jobsite must be:","opts":["Rated for the load and inspected for damage; GFCI-protected outdoors/wet areas","Run through water","Daisy-chained for length","Spliced with tape"],"correct":0,"re":"Use undamaged, properly rated cords, avoid daisy-chaining, and provide GFCI protection in wet/outdoor locations to prevent shock and fire.","rr":"Используйте неповреждённые удлинители нужного номинала, не соединяйте цепочкой и обеспечьте GFCI во влажных/уличных зонах для защиты от удара и пожара.","qr":"Удлинители для электроинструмента на объекте должны быть:","optsr":["Рассчитаны на нагрузку и проверены на повреждения; с GFCI на улице/во влажных зонах","Проложены через воду","Соединены цепочкой для длины","Срощены изолентой"],"qs":"Los cables de extensión usados para herramientas eléctricas en un sitio de trabajo deben:","optss":["Estar calificados para la carga e inspeccionados por daños; con protección GFCI en exteriores/áreas húmedas","Pasarse por el agua","Conectarse en cadena para alargarse","Empalmarse con cinta"],"rs":"Use cables sin daños, debidamente calificados, evite la conexión en cadena y proporcione protección GFCI en lugares húmedos/exteriores para evitar choques e incendios."},
  {"id":294,"sec":"Safety & Field Practices","q":"For energized electrical work that cannot be avoided, NFPA 70E requires:","opts":["No special gear","Maintaining arc-flash boundaries and wearing arc-rated PPE","Only cotton gloves","Working faster"],"correct":1,"re":"When de-energizing isn't feasible, 70E requires risk assessment, approach/arc-flash boundaries, and arc-rated PPE matched to the incident energy.","rr":"Когда обесточить нельзя, 70E требует оценку риска, границы приближения/дугового разряда и СИЗ с дуговым рейтингом под энергию дуги.","qr":"Для неизбежных работ под напряжением NFPA 70E требует:","optsr":["Никакого спецснаряжения","Соблюдения границ дугового разряда и СИЗ с дуговым рейтингом","Только хлопковых перчаток","Работать быстрее"],"qs":"Para el trabajo eléctrico energizado que no se puede evitar, la NFPA 70E requiere:","optss":["Ningún equipo especial","Mantener los límites de arco eléctrico y usar EPP con clasificación de arco","Solo guantes de algodón","Trabajar más rápido"],"rs":"Cuando desenergizar no es factible, la 70E requiere una evaluación de riesgo, límites de aproximación/arco eléctrico y EPP con clasificación de arco acorde a la energía incidente."},
  {"id":295,"sec":"Safety & Field Practices","q":"Breathing a high concentration of refrigerant vapor in an enclosed area is dangerous because it can cause:","opts":["Dizziness, oxygen deprivation, and even cardiac sensitization","Better cooling","A pleasant odor","Improved alertness"],"correct":0,"re":"High refrigerant concentrations displace oxygen and can sensitize the heart to arrhythmia; leave the area, ventilate, and never work in an unventilated leak.","rr":"Высокие концентрации хладагента вытесняют кислород и могут сенсибилизировать сердце к аритмии; покиньте зону, проветрите и не работайте в непроветриваемой утечке.","qr":"Вдыхание высокой концентрации паров хладагента в закрытом помещении опасно, потому что может вызвать:","optsr":["Головокружение, кислородное голодание и даже сердечную сенсибилизацию","Лучшее охлаждение","Приятный запах","Повышение бдительности"],"qs":"Respirar una alta concentración de vapor de refrigerante en un área cerrada es peligroso porque puede causar:","optss":["Mareos, privación de oxígeno e incluso sensibilización cardíaca","Mejor enfriamiento","Un olor agradable","Mayor estado de alerta"],"rs":"Las altas concentraciones de refrigerante desplazan el oxígeno y pueden sensibilizar el corazón a la arritmia; salga del área, ventile y nunca trabaje en una fuga sin ventilación."},
  {"id":296,"sec":"Safety & Field Practices","q":"Before disassembling a unit, capacitors should be discharged because they:","opts":["Can store a dangerous electrical charge after power is removed","Hold refrigerant","Are always safe to touch","Contain oil"],"correct":0,"re":"Run/start capacitors retain a charge that can shock; discharge through a proper resistor (not a direct short) before handling terminals.","rr":"Рабочие/пусковые конденсаторы хранят заряд, способный ударить током; разряжайте через подходящий резистор (не прямым замыканием) до работы с клеммами.","qr":"Перед разборкой блока конденсаторы нужно разрядить, потому что они:","optsr":["Могут хранить опасный электрозаряд после снятия питания","Содержат хладагент","Всегда безопасны для касания","Содержат масло"],"qs":"Antes de desarmar una unidad, los capacitores deben descargarse porque:","optss":["Pueden almacenar una carga eléctrica peligrosa después de quitar la energía","Contienen refrigerante","Siempre es seguro tocarlos","Contienen aceite"],"rs":"Los capacitores de marcha/arranque retienen una carga que puede provocar un choque; descárguelos a través de una resistencia adecuada (no con un cortocircuito directo) antes de manipular las terminales."},
  {"id":297,"sec":"Safety & Field Practices","q":"A respirator used for a dust or vapor hazard must be:","opts":["Made of cloth only","Optional in all cases","Selected for the specific hazard and properly fit-tested","Any mask"],"correct":2,"re":"Respiratory protection must match the contaminant (e.g., N95 vs cartridge), and tight-fitting respirators require fit testing and a written program.","rr":"Респираторная защита должна соответствовать загрязнителю (например N95 или с картриджем), а плотноприлегающие респираторы требуют fit-test и письменной программы.","qr":"Респиратор для защиты от пыли или паров должен быть:","optsr":["Только тканевым","Необязателен во всех случаях","Подобран под конкретную опасность и правильно подогнан (fit-test)","Любой маской"],"qs":"Un respirador usado para un peligro de polvo o vapor debe:","optss":["Estar hecho solo de tela","Ser opcional en todos los casos","Estar seleccionado para el peligro específico y con prueba de ajuste adecuada","Ser cualquier mascarilla"],"rs":"La protección respiratoria debe coincidir con el contaminante (p. ej., N95 vs cartucho), y los respiradores de ajuste hermético requieren prueba de ajuste y un programa por escrito."},
  {"id":298,"sec":"Safety & Field Practices","q":"Working from an aerial lift or scaffold requires:","opts":["Only one worker without checks","Removing guardrails","No training","Fall protection and trained/authorized operation"],"correct":3,"re":"Aerial lifts and scaffolds require trained operators, inspections, fall protection (e.g., harness in a boom lift), and adherence to capacity limits.","rr":"Автовышки и леса требуют обученных операторов, проверок, защиты от падения (например страховку в стреловом подъёмнике) и соблюдения лимитов нагрузки.","qr":"Работа с автовышки или строительных лесов требует:","optsr":["Одного работника без проверок","Снятия ограждений","Без обучения","Защиты от падения и обученной/допущенной эксплуатации"],"qs":"Trabajar desde un elevador aéreo o andamio requiere:","optss":["Solo un trabajador sin verificaciones","Retirar las barandillas","Ninguna capacitación","Protección contra caídas y operación capacitada/autorizada"],"rs":"Los elevadores aéreos y andamios requieren operadores capacitados, inspecciones, protección contra caídas (p. ej., arnés en un elevador de pluma) y cumplimiento de los límites de capacidad."},
  {"id":299,"sec":"Safety & Field Practices","q":"To blow debris out of a line or component, a technician should use:","opts":["Pure oxygen","System refrigerant vented to atmosphere","Compressed acetylene","Dry nitrogen (never refrigerant or oxygen)"],"correct":3,"re":"Use regulated dry nitrogen for purging/blowing lines; venting refrigerant is illegal and oxygen is dangerously reactive with oils.","rr":"Для продувки/выдувания линий применяют сухой азот через редуктор; стравливание хладагента незаконно, а кислород опасно реагирует с маслами.","qr":"Чтобы выдуть мусор из линии или компонента, техник должен использовать:","optsr":["Чистый кислород","Хладагент системы, стравленный в атмосферу","Сжатый ацетилен","Сухой азот (никогда хладагент или кислород)"],"qs":"Para soplar residuos de una línea o componente, un técnico debe usar:","optss":["Oxígeno puro","Refrigerante del sistema ventilado a la atmósfera","Acetileno comprimido","Nitrógeno seco (nunca refrigerante ni oxígeno)"],"rs":"Use nitrógeno seco regulado para purgar/soplar líneas; ventilar refrigerante es ilegal y el oxígeno es peligrosamente reactivo con los aceites."},
  {"id":300,"sec":"Safety & Field Practices","q":"If a safety control (limit, pressure switch, rollout) keeps tripping, the technician should:","opts":["Jumper it out and continue","Remove the control","Increase the gas pressure","Find and correct the underlying cause, never bypass the safety"],"correct":3,"re":"Repeated trips signal a real hazard (overheating, blocked flue, high pressure); diagnose and fix the cause — bypassing a safety can cause fire, CO, or equipment damage.","rr":"Повторные срабатывания сигналят о реальной опасности (перегрев, забитый дымоход, высокое давление); диагностируйте и устраните причину — обход защиты грозит пожаром, CO или поломкой.","qr":"Если защитный орган (лимит, реле давления, rollout) постоянно срабатывает, техник должен:","optsr":["Зашунтировать его и продолжить","Снять орган управления","Повысить давление газа","Найти и устранить первопричину, никогда не обходя защиту"],"qs":"Si un control de seguridad (límite, interruptor de presión, rollout) sigue disparándose, el técnico debe:","optss":["Puentearlo y continuar","Retirar el control","Aumentar la presión de gas","Encontrar y corregir la causa subyacente, nunca puentear la seguridad"],"rs":"Los disparos repetidos señalan un peligro real (sobrecalentamiento, chimenea bloqueada, alta presión); diagnostique y corrija la causa — puentear una seguridad puede causar incendio, CO o daño al equipo."},
  {"id":301,"sec":"Principles & Load Calculations","q":"Heat transfer by direct contact between molecules of a solid is called:","opts":["Infiltration","Radiation","Conduction","Convection"],"correct":2,"re":"Conduction is heat moving through a material by molecular contact; convection moves heat by fluid motion; radiation transfers heat as electromagnetic waves with no medium.","rr":"Conduction - тепло идёт через материал контактом молекул; convection - движением жидкости/газа; radiation - электромагнитными волнами без среды.","qr":"Передача тепла прямым контактом молекул в твёрдом теле называется:","optsr":["Инфильтрация","Излучение","Теплопроводность (conduction)","Конвекция"],"qs":"La transferencia de calor por contacto directo entre las moleculas de un solido se llama:","optss":["Infiltracion","Radiacion","Conduccion","Conveccion"],"rs":"La conduccion es el calor que se mueve a traves de un material por contacto molecular; la conveccion mueve el calor por el movimiento de un fluido; la radiacion transfiere el calor como ondas electromagneticas sin necesidad de un medio."},
  {"id":302,"sec":"Principles & Load Calculations","q":"The total-heat (enthalpy) formula for an air-conditioning load uses the constant:","opts":["1.08","0.68","4.5","3.41"],"correct":2,"re":"Total heat (BTU/h) = 4.5 x CFM x change in enthalpy (delta-h, BTU/lb). 1.08 is sensible, 0.68 is latent, 3.41 converts watts to BTU/h.","rr":"Полное тепло (BTU/ч) = 4.5 x CFM x изменение enthalpy (delta-h, BTU/фунт). 1.08 - явное, 0.68 - скрытое, 3.41 - перевод ватт в BTU/ч.","qr":"Формула полного тепла (enthalpy) для нагрузки кондиционирования использует коэффициент:","optsr":["1.08","0.68","4.5","3.41"],"qs":"La formula de calor total (entalpia) para una carga de aire acondicionado utiliza la constante:","optss":["1.08","0.68","4.5","3.41"],"rs":"Calor total (BTU/h) = 4.5 x CFM x cambio de entalpia (delta-h, BTU/lb). 1.08 es sensible, 0.68 es latente, 3.41 convierte watts a BTU/h."},
  {"id":303,"sec":"Principles & Load Calculations","q":"The latent-heat load formula uses the constant 0.68 multiplied by CFM and the change in:","opts":["Voltage","Grains of moisture (humidity ratio)","Dry-bulb temperature","Velocity"],"correct":1,"re":"Latent heat (BTU/h) = 0.68 x CFM x change in grains of moisture per pound of air. It accounts for moisture (latent) removal, not temperature change.","rr":"Latent (BTU/ч) = 0.68 x CFM x изменение гран влаги на фунт воздуха. Учитывает удаление влаги (latent), а не изменение температуры.","qr":"Формула скрытой (latent) нагрузки использует коэффициент 0.68, умноженный на CFM и изменение:","optsr":["Напряжения","Граны влаги (humidity ratio)","Температуры по сухому термометру","Скорости"],"qs":"La formula de carga de calor latente utiliza la constante 0.68 multiplicada por los CFM y el cambio en:","optss":["Voltaje","Granos de humedad (relacion de humedad)","Temperatura de bulbo seco","Velocidad"],"rs":"Calor latente (BTU/h) = 0.68 x CFM x cambio en granos de humedad por libra de aire. Toma en cuenta la eliminacion de humedad (latente), no el cambio de temperatura."},
  {"id":304,"sec":"Principles & Load Calculations","q":"The U-factor of a building assembly is related to its R-value by:","opts":["U = R + 1","U = R","U = 1 / R","U = R squared"],"correct":2,"re":"U-factor is the reciprocal of total R-value (U = 1/R). A higher R means a lower U, meaning less heat transfer through the assembly.","rr":"U-фактор - обратная величина суммарного R-value (U = 1/R). Больше R - меньше U, то есть меньше теплопередача через конструкцию.","qr":"U-фактор конструкции связан с её R-value как:","optsr":["U = R + 1","U = R","U = 1 / R","U = R в квадрате"],"qs":"El factor U de un ensamblaje de edificio se relaciona con su valor R mediante:","optss":["U = R + 1","U = R","U = 1 / R","U = R al cuadrado"],"rs":"El factor U es el reciproco del valor R total (U = 1/R). Un valor R mas alto significa un factor U mas bajo, lo que significa menor transferencia de calor a traves del ensamblaje."},
  {"id":305,"sec":"Principles & Load Calculations","q":"The Solar Heat Gain Coefficient (SHGC) of a window describes:","opts":["The fraction of solar radiation it admits as heat","Its color only","Its weight","Its thickness"],"correct":0,"re":"SHGC is the fraction of incident solar energy transmitted as heat; a lower SHGC reduces cooling load from sunlit glass.","rr":"SHGC - доля падающей солнечной энергии, пропущенной как тепло; меньший SHGC снижает охлаждающую нагрузку от освещённого солнцем стекла.","qr":"Коэффициент солнечного теплопритока (SHGC) окна описывает:","optsr":["Долю солнечной радиации, пропускаемую как тепло","Только цвет","Его вес","Его толщину"],"qs":"El Coeficiente de Ganancia de Calor Solar (SHGC) de una ventana describe:","optss":["La fraccion de radiacion solar que admite como calor","Solo su color","Su peso","Su espesor"],"rs":"El SHGC es la fraccion de energia solar incidente que se transmite como calor; un SHGC mas bajo reduce la carga de enfriamiento del vidrio expuesto al sol."},
  {"id":306,"sec":"Principles & Load Calculations","q":"To convert an electrical lighting load in watts to heat gain in BTU/h, multiply watts by:","opts":["1.08","4.5","3.41","0.293"],"correct":2,"re":"1 watt = 3.41 BTU/h. Lighting and plug loads add sensible heat to the cooling calculation at this conversion.","rr":"1 ватт = 3.41 BTU/ч. Освещение и розеточная нагрузка добавляют явное тепло в расчёт охлаждения по этому коэффициенту.","qr":"Чтобы перевести электрическую нагрузку освещения из ватт в теплоприток BTU/ч, умножьте ватты на:","optsr":["1.08","4.5","3.41","0.293"],"qs":"Para convertir una carga electrica de iluminacion en watts a ganancia de calor en BTU/h, multiplique los watts por:","optss":["1.08","4.5","3.41","0.293"],"rs":"1 watt = 3.41 BTU/h. Las cargas de iluminacion y de tomacorrientes agregan calor sensible al calculo de enfriamiento con esta conversion."},
  {"id":307,"sec":"Principles & Load Calculations","q":"In a load calculation, each occupant is typically counted as contributing:","opts":["Only latent heat","No heat","Only sensible heat","Both sensible and latent heat"],"correct":3,"re":"People add sensible heat (body warmth) and latent heat (respiration/perspiration); Manual J tables give per-person values by activity level.","rr":"Люди добавляют явное тепло (тепло тела) и скрытое (дыхание/потоотделение); таблицы Manual J дают значения на человека по уровню активности.","qr":"В расчёте нагрузки каждый человек обычно учитывается как источник:","optsr":["Только скрытого тепла","Никакого тепла","Только явного тепла","И явного, и скрытого тепла"],"qs":"En un calculo de carga, cada ocupante normalmente se cuenta como aporte de:","optss":["Solo calor latente","Nada de calor","Solo calor sensible","Calor sensible y latente a la vez"],"rs":"Las personas agregan calor sensible (calor corporal) y calor latente (respiracion/transpiracion); las tablas del Manual J dan valores por persona segun el nivel de actividad."},
  {"id":308,"sec":"Principles & Load Calculations","q":"Air changes per hour (ACH) is a way to express:","opts":["Compressor speed","The infiltration/ventilation rate of a space","Duct gauge","Refrigerant flow"],"correct":1,"re":"ACH = how many times the air volume of a space is replaced per hour; it is used to estimate infiltration and ventilation loads.","rr":"ACH - сколько раз объём воздуха помещения сменяется за час; используется для оценки нагрузок инфильтрации и вентиляции.","qr":"Воздухообмен в час (ACH) - способ выразить:","optsr":["Скорость компрессора","Кратность инфильтрации/вентиляции помещения","Толщину дакта","Поток хладагента"],"qs":"Los cambios de aire por hora (ACH) son una forma de expresar:","optss":["La velocidad del compresor","La tasa de infiltracion/ventilacion de un espacio","El calibre del ducto","El flujo de refrigerante"],"rs":"ACH = cuantas veces se reemplaza el volumen de aire de un espacio por hora; se usa para estimar las cargas de infiltracion y ventilacion."},
  {"id":309,"sec":"Principles & Load Calculations","q":"In a duct system, total pressure equals static pressure plus:","opts":["Atmospheric pressure","Gas pressure","Velocity pressure","Refrigerant pressure"],"correct":2,"re":"Total pressure = static pressure + velocity pressure. Static acts in all directions; velocity pressure relates to air movement (and is always positive in the flow direction).","rr":"Полное давление = статическое + скоростное. Статическое действует во все стороны; velocity pressure связано с движением воздуха (всегда положительно по потоку).","qr":"В системе воздуховодов полное давление равно статическому давлению плюс:","optsr":["Атмосферное давление","Давление газа","Скоростное давление (velocity pressure)","Давление хладагента"],"qs":"En un sistema de ductos, la presion total es igual a la presion estatica mas:","optss":["La presion atmosferica","La presion del gas","La presion de velocidad","La presion del refrigerante"],"rs":"Presion total = presion estatica + presion de velocidad. La estatica actua en todas las direcciones; la presion de velocidad se relaciona con el movimiento del aire (y siempre es positiva en la direccion del flujo)."},
  {"id":310,"sec":"Principles & Load Calculations","q":"A high duct aspect ratio (very wide and flat rectangular duct) generally:","opts":["Eliminates the need for sealing","Has no effect","Increases friction loss and material/cost for the same area","Reduces friction"],"correct":2,"re":"For equal cross-sectional area, a high aspect ratio increases surface area and friction, raising static pressure and sheet-metal cost; near-square ducts are more efficient.","rr":"При равной площади сечения высокое соотношение сторон увеличивает площадь поверхности и трение, поднимая статическое давление и стоимость металла; близкие к квадрату дакты эффективнее.","qr":"Высокое соотношение сторон воздуховода (очень широкий плоский прямоугольный) обычно:","optsr":["Убирает необходимость герметизации","Не влияет","Повышает потери на трение и расход/стоимость материала при той же площади","Снижает трение"],"qs":"Una alta relacion de aspecto en un ducto (ducto rectangular muy ancho y plano) por lo general:","optss":["Elimina la necesidad de sellado","No tiene efecto","Aumenta la perdida por friccion y el material/costo para la misma area","Reduce la friccion"],"rs":"Para una misma area de seccion transversal, una alta relacion de aspecto aumenta el area superficial y la friccion, elevando la presion estatica y el costo de la lamina; los ductos casi cuadrados son mas eficientes."},
  {"id":311,"sec":"Principles & Load Calculations","q":"Manual T (ACCA) addresses the selection and location of:","opts":["Air distribution devices (registers, grilles, diffusers)","Gas piping","Compressors","Refrigerant"],"correct":0,"re":"Manual T covers air-distribution: selecting supply registers/diffusers and return grilles for proper throw, spread, and noise (NC) at the design airflow.","rr":"Manual T - о воздухораспределении: подбор приточных решёток/диффузоров и обратных решёток по дальнобойности, рассеиванию и шуму (NC) при расчётном расходе.","qr":"Manual T (ACCA) рассматривает подбор и расположение:","optsr":["Воздухораспределителей (решёток, диффузоров)","Газовых труб","Компрессоров","Хладагента"],"qs":"El Manual T (ACCA) trata sobre la seleccion y ubicacion de:","optss":["Dispositivos de distribucion de aire (registros, rejillas, difusores)","Tuberia de gas","Compresores","Refrigerante"],"rs":"El Manual T cubre la distribucion de aire: la seleccion de registros/difusores de suministro y rejillas de retorno para lograr el alcance (throw), la dispersion (spread) y el ruido (NC) adecuados con el flujo de aire de diseno."},
  {"id":312,"sec":"Principles & Load Calculations","q":"A duct-leakage test reported as 'CFM25' measures leakage at a reference pressure of:","opts":["25 microns","25 inches WC","25 Pascals","25 psig"],"correct":2,"re":"Duct leakage is measured with the system pressurized to 25 Pascals; CFM25 is the leakage airflow at that reference, used for code/HERS verification.","rr":"Утечку воздуховодов измеряют при давлении системы 25 паскалей; CFM25 - расход утечки при этом эталоне, используется для проверки по нормам/HERS.","qr":"Тест герметичности воздуховодов с результатом 'CFM25' измеряет утечку при эталонном давлении:","optsr":["25 микрон","25 дюймов WC","25 паскалей","25 psig"],"qs":"Una prueba de fuga de ductos reportada como 'CFM25' mide la fuga a una presion de referencia de:","optss":["25 micrones","25 pulgadas WC","25 Pascales","25 psig"],"rs":"La fuga de ductos se mide con el sistema presurizado a 25 Pascales; CFM25 es el flujo de aire de fuga a esa referencia, usado para la verificacion de codigo/HERS."},
  {"id":313,"sec":"Principles & Load Calculations","q":"An extended-plenum duct system differs from a radial system in that it:","opts":["Has no trunk","Uses a main trunk of constant size with branch takeoffs","Cannot be used in homes","Needs no registers"],"correct":1,"re":"An extended plenum uses a constant-size main trunk feeding branch runs; a reducing-plenum trunk steps down in size; radial systems run branches directly from the air handler.","rr":"Extended plenum - магистральный ствол постоянного сечения с ответвлениями; reducing-plenum ствол сужается; радиальная - ветви идут прямо от воздухообрабатывающего блока.","qr":"Система с расширенным плёнумом отличается от радиальной тем, что:","optsr":["Не имеет ствола","Использует магистральный ствол постоянного сечения с ответвлениями","Непригодна для домов","Не нуждается в решётках"],"qs":"Un sistema de ductos de plenum extendido se diferencia de un sistema radial en que:","optss":["No tiene tronco principal","Usa un tronco principal de tamano constante con derivaciones de ramales","No se puede usar en viviendas","No necesita registros"],"rs":"Un plenum extendido usa un tronco principal de tamano constante que alimenta los ramales; un tronco de plenum reductor disminuye de tamano en pasos; los sistemas radiales llevan los ramales directamente desde el manejador de aire."},
  {"id":314,"sec":"Principles & Load Calculations","q":"Equivalent length (EL) of a duct fitting is used in design to:","opts":["Measure refrigerant","Set the gas pressure","Account for the fitting's friction as an added length of straight duct","Size the breaker"],"correct":2,"re":"Each elbow, takeoff, or boot adds resistance equal to a length of straight duct; total effective length = measured straight length + sum of fitting equivalent lengths.","rr":"Каждое колено, врезка или башмак добавляют сопротивление, равное длине прямого дакта; полная эффективная длина = измеренная прямая + сумма эквив. длин фитингов.","qr":"Эквивалентная длина (EL) фитинга воздуховода в проектировании нужна, чтобы:","optsr":["Измерить хладагент","Задать давление газа","Учесть трение фитинга как добавочную длину прямого дакта","Подобрать автомат"],"qs":"La longitud equivalente (EL) de un accesorio de ducto se usa en el diseno para:","optss":["Medir el refrigerante","Ajustar la presion del gas","Tomar en cuenta la friccion del accesorio como una longitud adicional de ducto recto","Dimensionar el breaker"],"rs":"Cada codo, derivacion o bota agrega una resistencia igual a una longitud de ducto recto; la longitud efectiva total = longitud recta medida + suma de las longitudes equivalentes de los accesorios."},
  {"id":315,"sec":"Principles & Load Calculations","q":"In California, a permitted residential changeout commonly triggers Title 24 HERS verification of:","opts":["The TikTok account","The thermostat brand","Refrigerant charge, airflow, and duct leakage","Paint color"],"correct":2,"re":"California's Energy Code (Title 24) often requires an independent HERS rater to verify refrigerant charge/fan airflow and duct leakage on alterations, depending on the measure.","rr":"Энергокодекс Калифорнии (Title 24) часто требует независимого HERS-оценщика для проверки заправки/расхода вентилятора и утечки воздуховодов при переделках, в зависимости от меры.","qr":"В Калифорнии замена по разрешению на жильё обычно влечёт HERS-проверку по Title 24 для:","optsr":["Аккаунта TikTok","Бренда термостата","Заправки хладагентом, расхода воздуха и утечки воздуховодов","Цвета краски"],"qs":"En California, un reemplazo residencial con permiso comunmente activa la verificacion HERS del Titulo 24 de:","optss":["La cuenta de TikTok","La marca del termostato","La carga de refrigerante, el flujo de aire y la fuga de ductos","El color de la pintura"],"rs":"El Codigo de Energia de California (Titulo 24) a menudo requiere que un evaluador HERS independiente verifique la carga de refrigerante/flujo de aire del ventilador y la fuga de ductos en las alteraciones, segun la medida."},
  {"id":316,"sec":"Principles & Load Calculations","q":"'Diversity' in a commercial load calculation accounts for the fact that:","opts":["All loads peak at once","Ducts leak","Refrigerant varies","Not all loads (people, lights, equipment) peak simultaneously"],"correct":3,"re":"Diversity reduces the calculated peak because occupancy, lighting, and equipment loads rarely all reach maximum at the same moment, avoiding oversizing.","rr":"Diversity снижает расчётный пик, т.к. заполненность, освещение и оборудование редко достигают максимума одновременно, что предотвращает завышение.","qr":"'Диверсификация' (diversity) в коммерческом расчёте нагрузки учитывает, что:","optsr":["Все нагрузки пикуют одновременно","Дакты текут","Хладагент меняется","Не все нагрузки (люди, свет, оборудование) пикуют одновременно"],"qs":"La 'diversidad' en un calculo de carga comercial toma en cuenta el hecho de que:","optss":["Todas las cargas llegan a su pico al mismo tiempo","Los ductos tienen fugas","El refrigerante varia","No todas las cargas (personas, luces, equipos) llegan a su pico simultaneamente"],"rs":"La diversidad reduce el pico calculado porque las cargas de ocupacion, iluminacion y equipos rara vez alcanzan su maximo en el mismo momento, evitando el sobredimensionamiento."},
  {"id":317,"sec":"Principles & Load Calculations","q":"A 'square-foot per ton' rule of thumb for sizing AC is:","opts":["Used for gas sizing","A rough estimate that often oversizes equipment","Required by code","More accurate than Manual J"],"correct":1,"re":"Rules of thumb (e.g., 500-600 sq ft/ton) ignore insulation, windows, and orientation and usually oversize; a Manual J calculation is the correct method.","rr":"Эмпирические правила (например 500-600 кв.фт/тонна) игнорируют утепление, окна и ориентацию и обычно завышают; правильный метод - расчёт Manual J.","qr":"Эмпирическое правило 'квадратных футов на тонну' для подбора AC:","optsr":["Применяется для подбора газа","Грубая оценка, часто завышающая оборудование","Требуется нормами","Точнее, чем Manual J"],"qs":"Una regla empirica de 'pies cuadrados por tonelada' para dimensionar el aire acondicionado es:","optss":["Usada para dimensionar el gas","Una estimacion aproximada que a menudo sobredimensiona el equipo","Requerida por el codigo","Mas precisa que el Manual J"],"rs":"Las reglas empiricas (por ejemplo, 500-600 pies cuadrados/tonelada) ignoran el aislamiento, las ventanas y la orientacion y por lo general sobredimensionan; un calculo del Manual J es el metodo correcto."},
  {"id":318,"sec":"Principles & Load Calculations","q":"To achieve a 40% gross margin, a job with $600 cost must be priced at:","opts":["$660","$840","$1000","$960"],"correct":2,"re":"Margin is profit as a percent of price: price = cost / (1 - margin) = 600 / 0.60 = $1000. (A 40% markup on cost would only be $840.)","rr":"Маржа - прибыль в процентах от цены: цена = себестоимость / (1 - маржа) = 600 / 0.60 = $1000. (Наценка 40% на себестоимость дала бы лишь $840.)","qr":"Чтобы получить 40% валовой маржи, работа стоимостью $600 должна продаваться за:","optsr":["$660","$840","$1000","$960"],"qs":"Para lograr un margen bruto del 40%, un trabajo con un costo de $600 debe cotizarse en:","optss":["$660","$840","$1000","$960"],"rs":"El margen es la ganancia como porcentaje del precio: precio = costo / (1 - margen) = 600 / 0.60 = $1000. (Un sobreprecio del 40% sobre el costo solo seria $840.)"},
  {"id":319,"sec":"Principles & Load Calculations","q":"Labor burden added to a worker's base wage includes:","opts":["Payroll taxes, workers' comp, and benefits","Permit fees","Material cost","Only the hourly wage"],"correct":0,"re":"Labor burden is the extra cost above wages - employer payroll taxes, workers' compensation, insurance, and benefits - and must be in the estimated labor rate.","rr":"Labor burden - дополнительные затраты сверх зарплаты: налоги работодателя с ФОТ, страхование от травм, страховка и льготы - и должны входить в расчётную ставку труда.","qr":"Трудовая надбавка (labor burden) сверх базовой зарплаты работника включает:","optsr":["Налоги с ФОТ, workers' comp и льготы","Пошлины за разрешение","Стоимость материала","Только почасовую оплату"],"qs":"El recargo laboral (labor burden) agregado al salario base de un trabajador incluye:","optss":["Impuestos sobre la nomina, compensacion al trabajador y prestaciones","Cuotas de permisos","Costo de materiales","Solo el salario por hora"],"rs":"El recargo laboral es el costo adicional sobre los salarios - impuestos patronales sobre la nomina, compensacion al trabajador, seguros y prestaciones - y debe estar incluido en la tarifa de mano de obra estimada."},
  {"id":320,"sec":"Principles & Load Calculations","q":"A flue/chimney for an atmospheric appliance is sized primarily on the appliance input (BTU/h) and the:","opts":["Vent height and connector configuration","Refrigerant type","Duct color","Wire size"],"correct":0,"re":"Venting tables size the flue from total input, vent height, lateral length, and number of connectors so the appliance vents safely (per the venting tables/code).","rr":"Таблицы дымоудаления подбирают дымоход по суммарному input, высоте, длине горизонтали и числу соединителей, чтобы прибор безопасно вентилировался (по таблицам/нормам).","qr":"Дымоход для атмосферного прибора подбирается прежде всего по входной мощности прибора (BTU/ч) и:","optsr":["Высоте дымохода и конфигурации соединителя","Типу хладагента","Цвету дакта","Сечению провода"],"qs":"Un conducto de humos/chimenea para un aparato atmosferico se dimensiona principalmente segun la entrada del aparato (BTU/h) y:","optss":["La altura del venteo y la configuracion del conector","El tipo de refrigerante","El color del ducto","El calibre del cable"],"rs":"Las tablas de ventilacion dimensionan el conducto de humos a partir de la entrada total, la altura del venteo, la longitud lateral y el numero de conectores para que el aparato ventee con seguridad (segun las tablas de ventilacion/codigo)."},
  {"id":321,"sec":"Principles & Load Calculations","q":"The 'design temperature' used for sizing should come from:","opts":["Published ASHRAE/Manual J design data for the location","A guess","The thermostat setting","The hottest/coldest day ever recorded"],"correct":0,"re":"Use the location's published 1%/99% ASHRAE design temperatures (in Manual J), not record extremes, to avoid chronic oversizing.","rr":"Используйте опубликованные расчётные температуры 1%/99% ASHRAE для местности (в Manual J), а не рекорды, чтобы не завышать систему хронически.","qr":"'Расчётная температура' для подбора должна браться из:","optsr":["Опубликованных расчётных данных ASHRAE/Manual J для местности","Догадки","Уставки термостата","Самого жаркого/холодного дня в истории"],"qs":"La 'temperatura de diseno' usada para el dimensionamiento debe provenir de:","optss":["Datos de diseno publicados de ASHRAE/Manual J para la ubicacion","Una suposicion","El ajuste del termostato","El dia mas caluroso/frio jamas registrado"],"rs":"Use las temperaturas de diseno publicadas de ASHRAE al 1%/99% de la ubicacion (en el Manual J), no los extremos historicos, para evitar el sobredimensionamiento cronico."},
  {"id":322,"sec":"Principles & Load Calculations","q":"Required ventilation (outdoor) air for a commercial space is generally based on occupancy and:","opts":["Floor area / use category per code (e.g., ASHRAE 62.1)","Refrigerant charge","Compressor size","Duct color"],"correct":0,"re":"ASHRAE 62.1 sets outdoor-air rates from people (cfm/person) plus area (cfm/sq ft) by occupancy category to maintain indoor air quality.","rr":"ASHRAE 62.1 задаёт расход наружного воздуха от людей (cfm/чел) плюс площади (cfm/кв.фт) по категории помещения для качества воздуха.","qr":"Требуемый объём наружного (вентиляционного) воздуха для коммерческого помещения обычно зависит от заполненности и:","optsr":["Площади / категории использования по нормам (например ASHRAE 62.1)","Заправки хладагентом","Размера компрессора","Цвета дакта"],"qs":"El aire de ventilacion (exterior) requerido para un espacio comercial generalmente se basa en la ocupacion y:","optss":["El area de piso / categoria de uso segun el codigo (por ejemplo, ASHRAE 62.1)","La carga de refrigerante","El tamano del compresor","El color del ducto"],"rs":"ASHRAE 62.1 establece las tasas de aire exterior a partir de las personas (cfm/persona) mas el area (cfm/pie cuadrado) por categoria de ocupacion para mantener la calidad del aire interior."},
  {"id":323,"sec":"Principles & Load Calculations","q":"Heating degree days (HDD) are used to estimate:","opts":["Seasonal heating energy use","Duct size","Peak cooling load","Refrigerant charge"],"correct":0,"re":"Degree days sum how far daily average temperatures fall below a base (e.g., 65F); HDD estimates seasonal heating energy/fuel use, not peak sizing.","rr":"Градусо-сутки суммируют, насколько средние дневные температуры ниже базовой (например 65F); HDD оценивает сезонный расход энергии/топлива на отопление, а не пиковый подбор.","qr":"Градусо-сутки отопления (HDD) применяют для оценки:","optsr":["Сезонного расхода энергии на отопление","Размера дакта","Пиковой охлаждающей нагрузки","Заправки хладагентом"],"qs":"Los grados-dia de calefaccion (HDD) se usan para estimar:","optss":["El consumo de energia de calefaccion estacional","El tamano del ducto","La carga pico de enfriamiento","La carga de refrigerante"],"rs":"Los grados-dia suman cuanto caen las temperaturas promedio diarias por debajo de una base (por ejemplo, 65F); los HDD estiman el consumo de energia/combustible de calefaccion estacional, no el dimensionamiento pico."},
  {"id":324,"sec":"Principles & Load Calculations","q":"When two stages of cooling are specified, the equipment selection should ensure the first stage:","opts":["Handles part-load conditions efficiently for better comfort/humidity control","Meets the entire peak load","Runs only in winter","Is oversized"],"correct":0,"re":"Two-stage (or variable) equipment runs at low capacity most of the time, improving runtime, dehumidification, and comfort; full capacity is reserved for design extremes.","rr":"Двухступенчатое (или инверторное) оборудование большую часть времени работает на низкой мощности, улучшая длительность работы, осушение и комфорт; полная мощность - для расчётных экстремумов.","qr":"Когда задано двухступенчатое охлаждение, подбор оборудования должен обеспечить, чтобы первая ступень:","optsr":["Эффективно работала при частичной нагрузке ради комфорта/влажности","Покрывала всю пиковую нагрузку","Работала только зимой","Была завышена"],"qs":"Cuando se especifican dos etapas de enfriamiento, la seleccion del equipo debe asegurar que la primera etapa:","optss":["Maneje las condiciones de carga parcial de manera eficiente para un mejor confort/control de humedad","Cubra toda la carga pico","Funcione solo en invierno","Este sobredimensionada"],"rs":"El equipo de dos etapas (o variable) funciona a baja capacidad la mayor parte del tiempo, mejorando el tiempo de funcionamiento, la deshumidificacion y el confort; la capacidad total se reserva para los extremos de diseno."},
  {"id":325,"sec":"Principles & Load Calculations","q":"A reducing-trunk (reducing-plenum) duct design keeps air velocity more constant by:","opts":["Adding refrigerant","Keeping the trunk one size","Stepping the trunk down in size after branch takeoffs","Removing all branches"],"correct":2,"re":"As branches remove air, a reducing trunk steps down in size to maintain velocity and balanced static pressure along the run.","rr":"Поскольку ветви отбирают воздух, сужающийся ствол ступенчато уменьшается в размере, удерживая скорость и сбалансированное статическое давление вдоль трассы.","qr":"Проект с сужающимся стволом (reducing-plenum) поддерживает скорость воздуха более постоянной за счёт:","optsr":["Добавления хладагента","Сохранения одного размера ствола","Ступенчатого сужения ствола после ответвлений","Удаления всех ветвей"],"qs":"Un diseno de ductos con tronco reductor (plenum reductor) mantiene la velocidad del aire mas constante al:","optss":["Agregar refrigerante","Mantener el tronco de un solo tamano","Disminuir el tamano del tronco en pasos despues de las derivaciones de ramales","Eliminar todos los ramales"],"rs":"A medida que los ramales extraen aire, un tronco reductor disminuye de tamano en pasos para mantener la velocidad y la presion estatica balanceada a lo largo del recorrido."},
  {"id":326,"sec":"Fabrication & Installation","q":"For a long line set, the liquid line is sized smaller than the suction line mainly to:","opts":["Save money only","Reduce subcooling","Maintain refrigerant velocity and minimize charge in the liquid line","Increase noise"],"correct":2,"re":"Liquid refrigerant is dense, so a smaller liquid line keeps velocity adequate and limits the added charge; the suction (vapor) line is larger to limit pressure drop.","rr":"Жидкий хладагент плотный, поэтому меньшая жидкостная линия держит достаточную скорость и ограничивает добавочный заряд; всасывающая (паровая) больше для снижения перепада давления.","qr":"На длинной трассе жидкостную линию делают меньше всасывающей главным образом чтобы:","optsr":["Только сэкономить","Снизить subcooling","Сохранить скорость хладагента и уменьшить заряд в жидкостной линии","Увеличить шум"],"qs":"Para un line set largo, la linea de liquido se dimensiona mas pequena que la linea de succion principalmente para:","optss":["Solo ahorrar dinero","Reducir el subenfriamiento","Mantener la velocidad del refrigerante y minimizar la carga en la linea de liquido","Aumentar el ruido"],"rs":"El refrigerante liquido es denso, por lo que una linea de liquido mas pequena mantiene una velocidad adecuada y limita la carga adicional; la linea de succion (vapor) es mas grande para limitar la caida de presion."},
  {"id":327,"sec":"Fabrication & Installation","q":"When the line set exceeds the factory-charge length, the technician must:","opts":["Add nitrogen","Add refrigerant per the manufacturer's per-foot adjustment","Ignore it","Remove refrigerant"],"correct":1,"re":"Manufacturers pre-charge for a set line length; beyond it, add refrigerant by the specified amount per additional foot of liquid line.","rr":"Производитель заправляет под заданную длину; сверх неё добавляют хладагент по указанной норме на каждый дополнительный фут жидкостной линии.","qr":"Когда длина трассы превышает заводскую заправку, техник должен:","optsr":["Добавить азот","Добавить хладагент по поправке производителя на фут","Игнорировать","Убрать хладагент"],"qs":"Cuando el line set excede la longitud de la carga de fabrica, el tecnico debe:","optss":["Agregar nitrogeno","Agregar refrigerante segun el ajuste por pie del fabricante","Ignorarlo","Quitar refrigerante"],"rs":"Los fabricantes precargan para una longitud de linea determinada; mas alla de esa longitud, agregue refrigerante segun la cantidad especificada por cada pie adicional de linea de liquido."},
  {"id":328,"sec":"Fabrication & Installation","q":"Charging by weight (using a scale) is the most accurate method when:","opts":["Doing a quick check","Topping off a leak","Guessing","Installing a system with a known total charge or a mini-split"],"correct":3,"re":"Weigh-in charging to the nameplate total (adjusted for line length) is most accurate on evacuated systems and ductless installs where the full charge is known.","rr":"Заправка по весу до полного значения с шильдика (с поправкой на длину) наиболее точна на отвакуумированных системах и ductless-монтаже, где полный заряд известен.","qr":"Заправка по весу (по весам) наиболее точна, когда:","optsr":["Делают быструю проверку","Доливают в текущую систему","Гадают","Ставят систему с известным полным зарядом или мини-сплит"],"qs":"La carga por peso (usando una bascula) es el metodo mas preciso cuando:","optss":["Se hace una revision rapida","Se completa la carga por una fuga","Se adivina","Se instala un sistema con una carga total conocida o un mini-split"],"rs":"La carga por peso hasta el total de la placa de datos (ajustada por la longitud de la linea) es la mas precisa en sistemas evacuados e instalaciones sin ductos donde se conoce la carga total."},
  {"id":329,"sec":"Fabrication & Installation","q":"Removing the Schrader valve cores during evacuation:","opts":["Adds moisture","Slows evacuation","Is never allowed","Speeds evacuation by removing a flow restriction"],"correct":3,"re":"Schrader cores restrict conductance; using a core-removal tool greatly speeds deep evacuation. Reinstall cores before charging.","rr":"Золотники Schrader ограничивают проводимость; инструмент для их съёма заметно ускоряет глубокое вакуумирование. Перед заправкой золотники ставят обратно.","qr":"Снятие золотников Schrader при вакуумировании:","optsr":["Добавляет влагу","Замедляет откачку","Запрещено","Ускоряет откачку, убирая сужение потока"],"qs":"Retirar los nucleos de las valvulas Schrader durante la evacuacion:","optss":["Agrega humedad","Retrasa la evacuacion","Nunca esta permitido","Acelera la evacuacion al eliminar una restriccion de flujo"],"rs":"Los nucleos Schrader restringen la conductancia; usar una herramienta para retirar nucleos acelera enormemente la evacuacion profunda. Reinstale los nucleos antes de cargar."},
  {"id":330,"sec":"Fabrication & Installation","q":"Vacuum-pump oil should be changed:","opts":["Only when it leaks","Never","Regularly, because moisture/contaminants degrade it and reduce vacuum depth","Only yearly regardless"],"correct":2,"re":"Contaminated pump oil cannot reach a deep vacuum; change it frequently (especially after wet systems) to keep the pump pulling below 500 microns.","rr":"Загрязнённое масло насоса не даёт глубокого вакуума; меняйте часто (особенно после влажных систем), чтобы насос тянул ниже 500 микрон.","qr":"Масло вакуумного насоса следует менять:","optsr":["Только при течи","Никогда","Регулярно, т.к. влага/загрязнения ухудшают его и снижают глубину вакуума","Только раз в год независимо ни от чего"],"qs":"El aceite de la bomba de vacio debe cambiarse:","optss":["Solo cuando tiene fugas","Nunca","Con regularidad, porque la humedad/contaminantes lo degradan y reducen la profundidad del vacio","Solo anualmente sin importar nada"],"rs":"El aceite de bomba contaminado no puede alcanzar un vacio profundo; cambielo con frecuencia (especialmente despues de sistemas humedos) para mantener la bomba jalando por debajo de 500 micrones."},
  {"id":331,"sec":"Fabrication & Installation","q":"A typical leak-test (standing) pressure for an R-410A system using dry nitrogen is in the range of about:","opts":["2000 psig","0 psig","Several hundred psig per the equipment's test rating","10-15 psig"],"correct":2,"re":"Pressure-test with dry nitrogen to the manufacturer's specified test pressure (often a few hundred psig for R-410A equipment); never exceed component ratings, and never use oxygen.","rr":"Опрессовку ведут сухим азотом до указанного производителем давления (часто несколько сотен psig для R-410A); не превышайте рейтинги компонентов и не применяйте кислород.","qr":"Типовое испытательное (на удержание) давление для системы R-410A сухим азотом находится в диапазоне около:","optsr":["2000 psig","0 psig","Несколько сотен psig по испытательному рейтингу оборудования","10-15 psig"],"qs":"Una presion tipica de prueba de fuga (estatica) para un sistema R-410A usando nitrogeno seco esta en el rango de aproximadamente:","optss":["2000 psig","0 psig","Varios cientos de psig segun la clasificacion de prueba del equipo","10-15 psig"],"rs":"Pruebe la presion con nitrogeno seco hasta la presion de prueba especificada por el fabricante (a menudo unos pocos cientos de psig para equipos R-410A); nunca exceda las clasificaciones de los componentes, y nunca use oxigeno."},
  {"id":332,"sec":"Fabrication & Installation","q":"Brazing copper to a steel or brass component (dissimilar metals) requires:","opts":["No flux ever","Plain water","A silver alloy (BAg) with the proper flux","Soft solder only"],"correct":2,"re":"Copper-to-steel/brass joints need flux and a silver-bearing (BAg) filler; self-fluxing BCuP is only for copper-to-copper.","rr":"Стыки медь-сталь/латунь требуют флюс и припой с серебром (BAg); самофлюсующийся BCuP - только для медь-медь.","qr":"Пайка меди к стальному или латунному компоненту (разнородные металлы) требует:","optsr":["Без флюса вообще","Простой воды","Серебряного сплава (BAg) с подходящим флюсом","Только мягкого припоя"],"qs":"Soldar con laton (brazing) cobre a un componente de acero o laton (metales disimiles) requiere:","optss":["Nunca usar fundente","Agua simple","Una aleacion de plata (BAg) con el fundente adecuado","Solo soldadura blanda"],"rs":"Las uniones de cobre a acero/laton necesitan fundente y un material de aporte con plata (BAg); el BCuP autofundente solo es para cobre a cobre."},
  {"id":333,"sec":"Fabrication & Installation","q":"Vibration-isolation pads are placed under an outdoor condenser to:","opts":["Increase airflow","Add refrigerant","Reduce transmitted noise/vibration and protect the slab/connections","Raise the SEER"],"correct":2,"re":"Isolation pads dampen compressor vibration, lowering noise and reducing fatigue on line connections and the mounting surface.","rr":"Изоляционные подушки гасят вибрацию компрессора, снижая шум и усталостную нагрузку на соединения линий и опорную поверхность.","qr":"Виброизолирующие подушки ставят под наружный конденсатор, чтобы:","optsr":["Увеличить расход воздуха","Добавить хладагент","Снизить передаваемый шум/вибрацию и защитить площадку/соединения","Поднять SEER"],"qs":"Las almohadillas de aislamiento de vibracion se colocan debajo de un condensador exterior para:","optss":["Aumentar el flujo de aire","Agregar refrigerante","Reducir el ruido/vibracion transmitidos y proteger la losa/conexiones","Elevar el SEER"],"rs":"Las almohadillas de aislamiento amortiguan la vibracion del compresor, reduciendo el ruido y disminuyendo la fatiga en las conexiones de las lineas y la superficie de montaje."},
  {"id":334,"sec":"Fabrication & Installation","q":"An auxiliary (secondary) drain pan under an attic air handler is required to:","opts":["Improve airflow","Support the unit","Hold refrigerant","Catch condensate overflow and protect the ceiling below"],"correct":3,"re":"Equipment above a finished space needs a secondary pan (with its own drain or float switch) to catch overflow if the primary drain clogs.","rr":"Оборудование над жилым помещением требует вторичный поддон (со своим дренажом или поплавковым выключателем), чтобы поймать перелив при засоре основного дренажа.","qr":"Вспомогательный (вторичный) дренажный поддон под чердачным воздухообрабатывающим блоком нужен, чтобы:","optsr":["Улучшить расход воздуха","Поддерживать блок","Хранить хладагент","Ловить перелив конденсата и защитить потолок снизу"],"qs":"Una charola de drenaje auxiliar (secundaria) debajo de un manejador de aire en el atico se requiere para:","optss":["Mejorar el flujo de aire","Sostener la unidad","Contener refrigerante","Capturar el desborde de condensado y proteger el techo de abajo"],"rs":"El equipo que esta sobre un espacio acabado necesita una charola secundaria (con su propio drenaje o interruptor de flotador) para capturar el desborde si el drenaje primario se obstruye."},
  {"id":335,"sec":"Fabrication & Installation","q":"A thermostat should be located:","opts":["Above a heat source","On an interior wall away from drafts, supply registers, and sunlight","On an exterior wall in direct sun","Inside a closet"],"correct":1,"re":"Mount the thermostat about 5 ft up on an interior wall in a representative location, away from drafts, supply air, sun, and heat sources, for accurate sensing.","rr":"Термостат ставят примерно на высоте 5 футов на внутренней стене в репрезентативном месте, вдали от сквозняков, приточного воздуха, солнца и источников тепла - для точного измерения.","qr":"Термостат следует размещать:","optsr":["Над источником тепла","На внутренней стене вдали от сквозняков, приточных решёток и солнца","На наружной стене под прямым солнцем","Внутри шкафа"],"qs":"Un termostato debe ubicarse:","optss":["Sobre una fuente de calor","En una pared interior alejada de corrientes de aire, registros de suministro y luz solar","En una pared exterior bajo luz solar directa","Dentro de un closet"],"rs":"Monte el termostato a unos 5 pies de altura en una pared interior en una ubicacion representativa, alejado de corrientes de aire, aire de suministro, sol y fuentes de calor, para una deteccion precisa."},
  {"id":336,"sec":"Fabrication & Installation","q":"A modern Wi-Fi/smart thermostat usually requires a 'C' wire to:","opts":["Provide continuous 24 V common for power","Call for heat","Open the gas valve","Run the compressor"],"correct":0,"re":"Smart thermostats draw continuous power; the C (common) wire completes the 24 V circuit so the thermostat runs without 'power stealing' that can cause faults.","rr":"Умные термостаты потребляют постоянное питание; провод C (общий) замыкает цепь 24 В, чтобы термостат работал без 'воровства питания', вызывающего сбои.","qr":"Современный Wi-Fi/умный термостат обычно требует провод 'C', чтобы:","optsr":["Обеспечить постоянный общий 24 В для питания","Вызвать нагрев","Открыть газовый клапан","Запустить компрессор"],"qs":"Un termostato moderno Wi-Fi/inteligente generalmente requiere un cable 'C' para:","optss":["Proporcionar el comun continuo de 24 V para la alimentacion","Solicitar calefaccion","Abrir la valvula de gas","Hacer funcionar el compresor"],"rs":"Los termostatos inteligentes consumen energia de forma continua; el cable C (comun) completa el circuito de 24 V para que el termostato funcione sin 'robo de energia' (power stealing) que puede causar fallas."},
  {"id":337,"sec":"Fabrication & Installation","q":"On a heat-pump thermostat, the 'E' terminal controls:","opts":["Evaporator fan","Emergency (auxiliary) heat","Economizer","Exhaust"],"correct":1,"re":"E energizes emergency heat (typically electric strips) directly, bypassing the compressor - used if the heat pump fails or in emergency-heat mode.","rr":"E напрямую запитывает аварийный нагрев (обычно ТЭНы) в обход компрессора - используется при отказе насоса или в режиме emergency heat.","qr":"На термостате теплового насоса клемма 'E' управляет:","optsr":["Вентилятором испарителя","Аварийным (auxiliary) нагревом","Экономайзером","Вытяжкой"],"qs":"En un termostato de bomba de calor, la terminal 'E' controla:","optss":["El ventilador del evaporador","El calor de emergencia (auxiliar)","El economizador","El escape"],"rs":"La E energiza el calor de emergencia (normalmente resistencias electricas) directamente, omitiendo el compresor; se usa si la bomba de calor falla o en modo de calor de emergencia."},
  {"id":338,"sec":"Fabrication & Installation","q":"Adequate service clearance around an outdoor condenser is needed to:","opts":["Reduce wire size","Allow airflow across the coil and room to service the unit","Hold refrigerant","Increase SEER rating"],"correct":1,"re":"Manufacturers specify minimum clearances so the condenser gets adequate airflow (preventing high head pressure) and the unit can be serviced safely.","rr":"Производитель задаёт минимальные зазоры, чтобы конденсатор получал достаточный обдув (без высокого давления нагнетания) и блок можно было безопасно обслуживать.","qr":"Достаточный сервисный зазор вокруг наружного конденсатора нужен, чтобы:","optsr":["Уменьшить сечение провода","Обеспечить обдув батареи и место для обслуживания блока","Хранить хладагент","Повысить рейтинг SEER"],"qs":"Se necesita un espacio libre de servicio adecuado alrededor de un condensador exterior para:","optss":["Reducir el calibre del cable","Permitir el flujo de aire a traves del serpentin y espacio para dar servicio a la unidad","Contener refrigerante","Aumentar la clasificacion SEER"],"rs":"Los fabricantes especifican espacios libres minimos para que el condensador reciba flujo de aire adecuado (evitando alta presion de descarga) y la unidad pueda recibir servicio de manera segura."},
  {"id":339,"sec":"Fabrication & Installation","q":"Blower speed taps are often set differently for heating and cooling because:","opts":["Refrigerant differs","The thermostat requires it","Voltage changes","Cooling needs higher airflow per ton and heating needs a proper temperature rise"],"correct":3,"re":"Cooling typically uses ~400 CFM/ton; heating airflow is set to keep the furnace temperature rise within the rated range - so the taps usually differ.","rr":"Охлаждение обычно использует ~400 CFM/тонна; расход на нагреве задают так, чтобы temperature rise печи был в номинальном диапазоне - поэтому скорости обычно разные.","qr":"Скорости вентилятора часто настраивают по-разному для нагрева и охлаждения, потому что:","optsr":["Хладагент другой","Этого требует термостат","Меняется напряжение","Охлаждению нужен больший расход на тонну, а нагреву - правильный temperature rise"],"qs":"Las tomas de velocidad del soplador a menudo se ajustan de manera diferente para calefaccion y enfriamiento porque:","optss":["El refrigerante es diferente","El termostato lo requiere","El voltaje cambia","El enfriamiento necesita mayor flujo de aire por tonelada y la calefaccion necesita una elevacion de temperatura adecuada"],"rs":"El enfriamiento normalmente usa ~400 CFM/tonelada; el flujo de aire de calefaccion se ajusta para mantener la elevacion de temperatura del horno dentro del rango nominal, por lo que las tomas suelen ser diferentes."},
  {"id":340,"sec":"Fabrication & Installation","q":"Converting a furnace from natural gas to LP (propane) requires:","opts":["No changes","Adding refrigerant","Changing the burner orifices and adjusting gas pressure per the kit","Replacing the blower"],"correct":2,"re":"LP has higher heating value and pressure, so a conversion kit with smaller orifices/spuds and a manifold-pressure adjustment is required; never run a gas-mismatched furnace.","rr":"У LP выше теплотворность и давление, поэтому нужен комплект с меньшими жиклёрами и настройкой давления на манифольде; печь с несоответствующим газом эксплуатировать нельзя.","qr":"Перевод печи с природного газа на LP (пропан) требует:","optsr":["Без изменений","Добавления хладагента","Замены жиклёров горелки и настройки давления газа по комплекту","Замены вентилятора"],"qs":"Convertir un horno de gas natural a LP (propano) requiere:","optss":["Ningun cambio","Agregar refrigerante","Cambiar los orificios del quemador y ajustar la presion del gas segun el kit","Reemplazar el soplador"],"rs":"El LP tiene mayor valor calorifico y presion, por lo que se requiere un kit de conversion con orificios/inyectores mas pequenos y un ajuste de la presion del multiple; nunca haga funcionar un horno con un tipo de gas incorrecto."},
  {"id":341,"sec":"Fabrication & Installation","q":"Combustion-air openings to the outdoors for a furnace in a confined space are sized based on:","opts":["The duct color","Refrigerant charge","The total input BTU/h and the method (direct/indirect) per code","The SEER"],"correct":2,"re":"Code sizes combustion-air openings/ducts from total appliance input and whether air comes from inside, outside, or via ducts - ensuring complete combustion.","rr":"Нормы подбирают отверстия/каналы воздуха горения по суммарному input прибора и тому, откуда берётся воздух (изнутри, снаружи, по каналам) - для полного сгорания.","qr":"Отверстия для воздуха горения наружу для печи в тесном помещении подбирают по:","optsr":["Цвету дакта","Заправке хладагентом","Суммарному input BTU/ч и методу (прямой/непрямой) по нормам","SEER"],"qs":"Las aberturas de aire de combustion hacia el exterior para un horno en un espacio confinado se dimensionan segun:","optss":["El color del ducto","La carga de refrigerante","La entrada total en BTU/h y el metodo (directo/indirecto) segun el codigo","El SEER"],"rs":"El codigo dimensiona las aberturas/ductos de aire de combustion a partir de la entrada total del aparato y de si el aire proviene del interior, del exterior o mediante ductos, asegurando una combustion completa."},
  {"id":342,"sec":"Fabrication & Installation","q":"When making a flare on a mini-split, using a torque wrench to the specified value prevents:","opts":["High SEER","Low voltage","Under- or over-tightening that causes leaks or cracked flares","Excess airflow"],"correct":2,"re":"Mini-split flare nuts have specified torque values; too loose leaks, too tight cracks the flare. A torque wrench ensures a reliable, leak-free joint.","rr":"Гайки flare на мини-сплитах имеют заданный момент; слабо - течёт, сильно - трескается раздача. Динамометрический ключ обеспечивает надёжный герметичный стык.","qr":"При раздаче (flare) на мини-сплите динамометрический ключ на заданное значение предотвращает:","optsr":["Высокий SEER","Низкое напряжение","Недо- или перетяжку, ведущую к утечкам или трещинам раздачи","Избыточный расход воздуха"],"qs":"Al hacer un abocardado (flare) en un mini-split, usar una llave de torque con el valor especificado evita:","optss":["Un SEER alto","Bajo voltaje","Un apriete insuficiente o excesivo que cause fugas o abocardados agrietados","Exceso de flujo de aire"],"rs":"Las tuercas de abocardado de los mini-split tienen valores de torque especificados; muy flojas tienen fugas, muy apretadas agrietan el abocardado. Una llave de torque asegura una union confiable y sin fugas."},
  {"id":343,"sec":"Fabrication & Installation","q":"Closed-cell refrigerant line insulation should be:","opts":["Removed in summer","Replaced with tape only","Sealed at seams/ends to prevent condensation under the insulation","Left with open seams"],"correct":2,"re":"Unsealed seams let humid air reach the cold line, causing hidden condensation, dripping, and corrosion; glue/seal all joints and ends.","rr":"Негерметичные швы пропускают влажный воздух к холодной линии, вызывая скрытый конденсат, капель и коррозию; клейте/герметизируйте все стыки и торцы.","qr":"Закрытопористую изоляцию линий хладагента следует:","optsr":["Снимать летом","Заменять только лентой","Герметизировать по швам/торцам, чтобы не было конденсата под изоляцией","Оставлять с открытыми швами"],"qs":"El aislamiento de celda cerrada para lineas de refrigerante debe:","optss":["Retirarse en verano","Reemplazarse solo con cinta","Sellarse en las uniones/extremos para evitar la condensacion debajo del aislamiento","Dejarse con las uniones abiertas"],"rs":"Las uniones sin sellar dejan que el aire humedo llegue a la linea fria, causando condensacion oculta, goteo y corrosion; pegue/selle todas las uniones y extremos."},
  {"id":344,"sec":"Fabrication & Installation","q":"A 125 V service receptacle is commonly required near rooftop/attic HVAC equipment to:","opts":["Charge refrigerant","Power the compressor","Replace the disconnect","Provide convenience power for service tools"],"correct":3,"re":"Electrical code requires a service receptacle within a set distance of the equipment so technicians can power tools and lights for maintenance.","rr":"Электрические нормы требуют сервисную розетку в пределах заданного расстояния от оборудования, чтобы техники могли питать инструмент и свет при обслуживании.","qr":"Сервисная розетка 125 В обычно требуется рядом с HVAC-оборудованием на крыше/чердаке, чтобы:","optsr":["Заправлять хладагент","Питать компрессор","Заменить разъединитель","Обеспечить вспомогательное питание для сервисного инструмента"],"qs":"Comunmente se requiere un tomacorriente de servicio de 125 V cerca del equipo HVAC de azotea/atico para:","optss":["Cargar refrigerante","Alimentar el compresor","Reemplazar el desconectador","Proporcionar energia de conveniencia para las herramientas de servicio"],"rs":"El codigo electrico requiere un tomacorriente de servicio dentro de una distancia determinada del equipo para que los tecnicos puedan alimentar herramientas y luces para el mantenimiento."},
  {"id":345,"sec":"Fabrication & Installation","q":"At startup of a cooling system, a normal indoor temperature split (return vs supply dry-bulb) is about:","opts":["Zero","16-22 F","40-50 F","2-5 F"],"correct":1,"re":"A properly charged system with correct airflow usually shows ~16-22 F drop across the evaporator (varies with indoor wet-bulb); too small or too large signals airflow/charge issues.","rr":"Правильно заправленная система с верным расходом обычно даёт перепад ~16-22 F на испарителе (зависит от indoor wet-bulb); слишком малый или большой - сигнал проблем расхода/заправки.","qr":"При запуске охлаждения нормальный внутренний temperature split (обратка против подачи по сухому термометру) составляет около:","optsr":["Ноль","16-22 F","40-50 F","2-5 F"],"qs":"Al arrancar un sistema de enfriamiento, un split de temperatura interior normal (bulbo seco de retorno vs suministro) es de aproximadamente:","optss":["Cero","16-22 F","40-50 F","2-5 F"],"rs":"Un sistema correctamente cargado con el flujo de aire adecuado normalmente muestra una caida de ~16-22 F a traves del evaporador (varia con el bulbo humedo interior); un valor muy pequeno o muy grande indica problemas de flujo de aire/carga."},
  {"id":346,"sec":"Fabrication & Installation","q":"A condensate pump is used when:","opts":["The system is heating only","There is no condensate","The equipment is below the drain and condensate must be lifted","The drain can slope to gravity"],"correct":2,"re":"When gravity drainage is impossible (basement/below-grade), a condensate pump lifts the water to a drain; it usually has a safety switch to stop the system if it fails.","rr":"Когда самотёк невозможен (подвал/ниже уровня), конденсатный насос поднимает воду к дренажу; обычно имеет защитный выключатель для останова системы при отказе.","qr":"Конденсатный насос применяют, когда:","optsr":["Система только на нагрев","Конденсата нет","Оборудование ниже дренажа и конденсат нужно поднимать","Дренаж можно вести самотёком"],"qs":"Se usa una bomba de condensado cuando:","optss":["El sistema es solo de calefaccion","No hay condensado","El equipo esta por debajo del drenaje y el condensado debe elevarse","El drenaje puede tener pendiente por gravedad"],"rs":"Cuando el drenaje por gravedad es imposible (sotano/bajo nivel), una bomba de condensado eleva el agua hasta un drenaje; normalmente tiene un interruptor de seguridad para detener el sistema si falla."},
  {"id":347,"sec":"Fabrication & Installation","q":"A 'whip' (liquid-tight flexible conduit) at the condenser is used so that:","opts":["The unit gets more refrigerant","The SEER increases","Vibration is not transmitted to rigid conduit and connections flex safely","The gas line is shorter"],"correct":2,"re":"A short liquid-tight flex whip absorbs compressor vibration and allows a flexible, weatherproof connection between the disconnect and the unit.","rr":"Короткая герметичная гибкая подводка гасит вибрацию компрессора и обеспечивает гибкое, влагозащищённое соединение между разъединителем и блоком.","qr":"Гибкая герметичная подводка ('whip') у конденсатора нужна, чтобы:","optsr":["Блок получил больше хладагента","Вырос SEER","Вибрация не передавалась на жёсткую трубу и соединение гибко/безопасно работало","Газовая линия была короче"],"qs":"Un 'whip' (conducto flexible hermetico a los liquidos) en el condensador se usa para que:","optss":["La unidad reciba mas refrigerante","El SEER aumente","La vibracion no se transmita al conducto rigido y las conexiones flexionen de forma segura","La linea de gas sea mas corta"],"rs":"Un whip flexible corto y hermetico a los liquidos absorbe la vibracion del compresor y permite una conexion flexible y resistente a la intemperie entre el desconectador y la unidad."},
  {"id":348,"sec":"Fabrication & Installation","q":"Supporting refrigerant line sets at proper intervals prevents:","opts":["High SEER","Excess subcooling","Low voltage","Sagging, stress on joints, and chafing/vibration damage"],"correct":3,"re":"Unsupported lines sag and vibrate, stressing brazed joints and chafing through insulation; secure them at regular intervals and where they penetrate walls.","rr":"Неподдержанные линии провисают и вибрируют, нагружая паяные стыки и протирая изоляцию; крепите их через равные интервалы и в местах прохода через стены.","qr":"Поддержка линий хладагента через нужные интервалы предотвращает:","optsr":["Высокий SEER","Избыточный subcooling","Низкое напряжение","Провисание, нагрузку на стыки и истирание/виброповреждение"],"qs":"Soportar los line sets de refrigerante a intervalos adecuados evita:","optss":["Un SEER alto","Exceso de subenfriamiento","Bajo voltaje","Pandeo, esfuerzo en las uniones y dano por roce/vibracion"],"rs":"Las lineas sin soporte se pandean y vibran, esforzando las uniones soldadas y desgastando el aislamiento por roce; asegurelas a intervalos regulares y donde penetren las paredes."},
  {"id":349,"sec":"Fabrication & Installation","q":"Before energizing a newly installed system, the installer should verify line voltage is:","opts":["Always 480 V","Any value","Within the unit's rated voltage range on the data plate","Below 24 V"],"correct":2,"re":"Operating outside the rated voltage range (e.g., low voltage) causes overheating and component failure; verify supply voltage matches the nameplate before startup.","rr":"Работа вне номинального диапазона (например низкое напряжение) вызывает перегрев и отказ компонентов; сверьте напряжение питания с шильдиком до запуска.","qr":"Перед подачей питания на новый монтаж установщик должен убедиться, что линейное напряжение:","optsr":["Всегда 480 В","Любое","В пределах номинального диапазона блока на шильдике","Ниже 24 В"],"qs":"Antes de energizar un sistema recien instalado, el instalador debe verificar que el voltaje de linea este:","optss":["Siempre en 480 V","En cualquier valor","Dentro del rango de voltaje nominal de la unidad en la placa de datos","Por debajo de 24 V"],"rs":"Operar fuera del rango de voltaje nominal (por ejemplo, bajo voltaje) causa sobrecalentamiento y falla de componentes; verifique que el voltaje de suministro coincida con la placa de datos antes del arranque."},
  {"id":350,"sec":"Fabrication & Installation","q":"When installing flexible duct, the inner liner should be:","opts":["Filled with refrigerant","Cut shorter than needed","Left loose and kinked","Stretched taut and connected/sealed to the collar, with the insulation/jacket secured"],"correct":3,"re":"Pull the inner core tight onto the collar, secure with a clamp/strap, seal it, then pull the insulation and vapor jacket over and band them - avoiding compression and leaks.","rr":"Натяните внутренний рукав на патрубок, закрепите хомутом/стяжкой, загерметизируйте, затем натяните изоляцию и пароизоляционную оболочку и обвяжите - избегая сжатия и утечек.","qr":"При монтаже гибкого воздуховода внутренний рукав должен быть:","optsr":["Заполнен хладагентом","Обрезан короче нужного","Оставлен свободным и заломленным","Натянут и подсоединён/загерметизирован к патрубку, с закреплением изоляции/оболочки"],"qs":"Al instalar ducto flexible, el forro interior debe:","optss":["Llenarse con refrigerante","Cortarse mas corto de lo necesario","Dejarse suelto y doblado","Estirarse tenso y conectarse/sellarse al collar, con el aislamiento/forro asegurado"],"rs":"Jale el nucleo interior tenso sobre el collar, asegurelo con una abrazadera/correa, sellelo, luego jale el aislamiento y el forro de vapor por encima y suncha­los, evitando la compresion y las fugas."},
  {"id":351,"sec":"Fabrication & Installation","q":"A reversing valve on a heat pump is energized by:","opts":["A 24 V solenoid coil","Line voltage compressor power","Refrigerant pressure only","The gas valve"],"correct":0,"re":"The reversing valve's pilot is shifted by a 24 V solenoid coil; the main valve is moved by refrigerant pressure differential once the pilot ports switch.","rr":"Пилот реверс-клапана переключается соленоидной катушкой 24 В; основной клапан сдвигается перепадом давления хладагента после переключения пилотных каналов.","qr":"Реверс-клапан теплового насоса запитывается:","optsr":["Соленоидной катушкой 24 В","Сетевым питанием компрессора","Только давлением хладагента","Газовым клапаном"],"qs":"La valvula reversora (reversing valve) de una bomba de calor se energiza mediante:","optss":["Una bobina solenoide de 24 V","La alimentacion de voltaje de linea del compresor","Solo la presion del refrigerante","La valvula de gas"],"rs":"El piloto de la valvula reversora se desplaza mediante una bobina solenoide de 24 V; la valvula principal se mueve por el diferencial de presion del refrigerante una vez que cambian los puertos del piloto."},
  {"id":352,"sec":"Fabrication & Installation","q":"After brazing in a new filter drier, it should be installed with the arrow:","opts":["It does not matter","Pointing against flow","Sideways","Pointing in the direction of refrigerant flow"],"correct":3,"re":"The drier's arrow must point in the direction of flow (usually liquid line toward the metering device) so it filters and dries correctly.","rr":"Стрелка осушителя должна указывать по потоку (обычно по жидкостной линии к дозатору), чтобы он правильно фильтровал и осушал.","qr":"После впайки нового фильтра-осушителя его стрелка должна указывать:","optsr":["Неважно","Против потока","Вбок","В направлении потока хладагента"],"qs":"Despues de soldar con laton un nuevo filtro deshidratador, debe instalarse con la flecha:","optss":["No importa","Apuntando en contra del flujo","De lado","Apuntando en la direccion del flujo del refrigerante"],"rs":"La flecha del deshidratador debe apuntar en la direccion del flujo (normalmente de la linea de liquido hacia el dispositivo de medicion) para que filtre y seque correctamente."},
  {"id":353,"sec":"Fabrication & Installation","q":"When two indoor coils share a heat-pump outdoor unit are not involved, a properly sized suction line on a tall riser may use a double riser to:","opts":["Add refrigerant","Increase noise","Maintain oil return at both full and reduced capacity","Lower the SEER"],"correct":2,"re":"On modulating systems with tall risers, a double (large + small) suction riser keeps velocity high enough for oil return at part load while limiting pressure drop at full load.","rr":"На модулируемых системах с высокими стояками двойной (большой + малый) всасывающий стояк держит достаточную скорость для возврата масла при частичной нагрузке, ограничивая перепад на полной.","qr":"На высоком стояке всасывающей линии правильно подобранный двойной стояк применяют, чтобы:","optsr":["Добавить хладагент","Увеличить шум","Сохранить возврат масла и на полной, и на сниженной мощности","Снизить SEER"],"qs":"Cuando no estan involucrados dos serpentines interiores que comparten una unidad exterior de bomba de calor, una linea de succion correctamente dimensionada en un montante alto puede usar un montante doble para:","optss":["Agregar refrigerante","Aumentar el ruido","Mantener el retorno de aceite tanto a capacidad total como reducida","Bajar el SEER"],"rs":"En sistemas modulantes con montantes altos, un montante de succion doble (grande + pequeno) mantiene la velocidad lo suficientemente alta para el retorno de aceite a carga parcial, limitando a la vez la caida de presion a plena carga."},
  {"id":354,"sec":"Fabrication & Installation","q":"Documenting startup readings (pressures, temps, superheat/subcool, static, amps) is important because it:","opts":["Is illegal","Wastes time","Verifies correct operation and provides a baseline for future service","Voids the warranty"],"correct":2,"re":"A commissioning record proves the system was set up correctly and gives a reference for diagnosing future problems and for warranty/HERS documentation.","rr":"Пусконаладочный протокол доказывает, что система настроена верно, и даёт точку отсчёта для диагностики будущих проблем и для гарантии/HERS-документации.","qr":"Документирование пусковых показаний (давления, температуры, superheat/subcool, статическое, токи) важно, потому что:","optsr":["Незаконно","Это трата времени","Подтверждает правильную работу и даёт базовую точку для будущего сервиса","Аннулирует гарантию"],"qs":"Documentar las lecturas de arranque (presiones, temperaturas, sobrecalentamiento/subenfriamiento, presion estatica, amperaje) es importante porque:","optss":["Es ilegal","Es una perdida de tiempo","Verifica el funcionamiento correcto y proporciona una referencia base para el servicio futuro","Anula la garantia"],"rs":"Un registro de puesta en marcha comprueba que el sistema se configuro correctamente y da una referencia para diagnosticar problemas futuros y para la documentacion de garantia/HERS."},
  {"id":355,"sec":"Service & Troubleshooting","q":"A cooling system with a very small temperature split (e.g., 8 F) and normal pressures most likely has:","opts":["A stuck reversing valve","Excessive airflow or a humidity-load condition","A cracked heat exchanger","Low charge"],"correct":1,"re":"Too much airflow (or very high latent load) reduces the dry-bulb split; check blower speed and conditions before assuming a refrigerant problem.","rr":"Слишком большой расход (или очень высокая latent-нагрузка) уменьшает перепад по сухому термометру; проверьте скорость вентилятора и условия, прежде чем винить хладагент.","qr":"Система охлаждения с очень малым temperature split (например 8 F) и нормальными давлениями скорее всего имеет:","optsr":["Заклинивший реверс-клапан","Избыточный расход воздуха или условие высокой влажностной нагрузки","Трещину теплообменника","Недозаправку"],"qs":"Un sistema de enfriamiento con un split de temperatura muy pequeno (por ejemplo, 8 F) y presiones normales lo mas probable es que tenga:","optss":["Una valvula reversora atascada","Flujo de aire excesivo o una condicion de carga de humedad","Un intercambiador de calor agrietado","Carga baja"],"rs":"Demasiado flujo de aire (o una carga latente muy alta) reduce el split de bulbo seco; revise la velocidad del soplador y las condiciones antes de asumir un problema de refrigerante."},
  {"id":356,"sec":"Service & Troubleshooting","q":"A condenser fan motor that fails (stops) while the compressor runs will cause:","opts":["Rapidly rising head pressure and a high-pressure trip","More subcooling","Lower amps","Low head pressure"],"correct":0,"re":"With no condenser airflow, heat cannot be rejected, so head pressure climbs fast and the high-pressure switch trips (or the compressor overheats). Check the fan motor and its capacitor.","rr":"Без обдува конденсатора тепло не отводится, давление нагнетания быстро растёт, и срабатывает реле высокого давления (или перегревается компрессор). Проверьте мотор вентилятора и его конденсатор.","qr":"Отказ (остановка) вентилятора конденсатора при работающем компрессоре вызывает:","optsr":["Быстро растущее давление нагнетания и срабатывание защиты по высокому давлению","Больше subcooling","Меньший ток","Низкое давление нагнетания"],"qs":"Un motor del ventilador del condensador que falla (se detiene) mientras el compresor funciona causara:","optss":["Una presion de descarga que sube rapidamente y un disparo por alta presion","Mas subenfriamiento","Menor amperaje","Baja presion de descarga"],"rs":"Sin flujo de aire en el condensador, el calor no puede rechazarse, por lo que la presion de descarga sube rapidamente y el interruptor de alta presion se dispara (o el compresor se sobrecalienta). Revise el motor del ventilador y su capacitor."},
  {"id":357,"sec":"Service & Troubleshooting","q":"A single run capacitor serving both the compressor and condenser fan is a 'dual run' capacitor; its three terminals are labeled:","opts":["C (common), HERM, FAN","L1, L2, L3","R, S, T","Y, G, W"],"correct":0,"re":"A dual-run capacitor has a common (C) terminal plus HERM (compressor) and FAN terminals; a weak section causes that motor to struggle or overheat.","rr":"Dual-run конденсатор имеет общую (C) клемму плюс HERM (компрессор) и FAN; слабая секция заставляет соответствующий мотор тяжело работать или перегреваться.","qr":"Один рабочий конденсатор, обслуживающий и компрессор, и вентилятор - это 'dual run' конденсатор; его три клеммы маркированы:","optsr":["C (общий), HERM, FAN","L1, L2, L3","R, S, T","Y, G, W"],"qs":"Un solo capacitor de marcha que sirve tanto al compresor como al ventilador del condensador es un capacitor de 'marcha dual'; sus tres terminales estan etiquetadas como:","optss":["C (comun), HERM, FAN","L1, L2, L3","R, S, T","Y, G, W"],"rs":"Un capacitor de marcha dual tiene una terminal comun (C) mas las terminales HERM (compresor) y FAN (ventilador); una seccion debil hace que ese motor batalle o se sobrecaliente."},
  {"id":358,"sec":"Service & Troubleshooting","q":"An ECM blower that won't run but has correct line voltage and a valid thermostat call should be checked for:","opts":["The low-voltage control signal and module connector before condemning the motor","Gas pressure","Refrigerant level","Duct color"],"correct":0,"re":"ECM motors need a proper control signal at the module; verify the 24 V/PWM command and connections - a missing signal mimics a failed motor.","rr":"ECM-моторам нужен корректный управляющий сигнал на модуле; проверьте команду 24 В/PWM и соединения - отсутствие сигнала имитирует отказ мотора.","qr":"ECM-вентилятор не крутится при верном линейном напряжении и корректном запросе термостата - проверяют:","optsr":["Низковольтный управляющий сигнал и разъём модуля до замены мотора","Давление газа","Уровень хладагента","Цвет дакта"],"qs":"Un soplador ECM que no funciona pero tiene el voltaje de linea correcto y una llamada valida del termostato debe revisarse en cuanto a:","optss":["La senal de control de bajo voltaje y el conector del modulo antes de condenar el motor","La presion del gas","El nivel de refrigerante","El color del ducto"],"rs":"Los motores ECM necesitan una senal de control adecuada en el modulo; verifique el comando de 24 V/PWM y las conexiones; una senal faltante imita un motor fallado."},
  {"id":359,"sec":"Service & Troubleshooting","q":"A furnace flame-rollout switch that has tripped usually indicates:","opts":["Too much airflow","A dirty filter only","High refrigerant","Blocked heat exchanger or flue causing flame to roll out of the burner box"],"correct":3,"re":"Rollout trips when flames spill from the burners (blocked HX passages, restricted venting, or poor combustion air); find and fix the cause - do not just reset.","rr":"Rollout срабатывает, когда пламя выходит из горелок (засор каналов HX, ограниченное дымоудаление или плохой воздух горения); найдите и устраните причину - не просто сбрасывайте.","qr":"Сработавший flame-rollout switch печи обычно указывает на:","optsr":["Слишком большой расход воздуха","Только грязный фильтр","Избыток хладагента","Засор теплообменника или дымохода, из-за чего пламя выбрасывается из горелочной камеры"],"qs":"Un interruptor de derrame de flama (flame-rollout) de un horno que se ha disparado normalmente indica:","optss":["Demasiado flujo de aire","Solo un filtro sucio","Refrigerante alto","Un intercambiador de calor o conducto de humos bloqueado que hace que la flama se derrame fuera de la camara de quemadores"],"rs":"El derrame se dispara cuando las flamas salen de los quemadores (pasos del intercambiador de calor bloqueados, ventilacion restringida o mala combustion de aire); encuentre y corrija la causa, no solo reinicie."},
  {"id":360,"sec":"Service & Troubleshooting","q":"A defrost board stuck so the heat pump stays in defrost too long will cause:","opts":["Lower head pressure","No effect","Cold air in heating and wasted energy as it keeps reversing to cooling","Higher heating capacity"],"correct":2,"re":"A failed defrost sensor/board can over-defrost, repeatedly reversing to cooling and running the aux heat, lowering efficiency and comfort.","rr":"Неисправный датчик/плата разморозки может пере-размораживать, постоянно реверсируя в охлаждение и гоняя aux-нагрев, снижая КПД и комфорт.","qr":"Зависшая плата разморозки, из-за которой тепловой насос слишком долго в defrost, вызывает:","optsr":["Меньшее давление нагнетания","Никакого эффекта","Холодный воздух в нагреве и перерасход энергии из-за постоянного реверса в охлаждение","Большую теплопроизводительность"],"qs":"Una tarjeta de descongelamiento (defrost) atascada de modo que la bomba de calor permanece en descongelamiento demasiado tiempo causara:","optss":["Menor presion de descarga","Ningun efecto","Aire frio en calefaccion y energia desperdiciada al seguir reversando a enfriamiento","Mayor capacidad de calefaccion"],"rs":"Un sensor/tarjeta de descongelamiento fallado puede sobre-descongelar, reversando repetidamente a enfriamiento y haciendo funcionar el calor auxiliar, reduciendo la eficiencia y el confort."},
  {"id":361,"sec":"Service & Troubleshooting","q":"After a compressor burnout, the system must be cleaned up, typically by installing a:","opts":["New thermostat","Suction-line (and liquid-line) acid-removal filter drier and following burnout procedure","Bigger duct","Larger condenser"],"correct":1,"re":"A burnout leaves acid and contaminants; install suction and liquid acid-cleanup driers, monitor/replace them, and test for acid until the system is clean.","rr":"Выгорание оставляет кислоту и загрязнения; ставят кислотные осушители на всасывание и жидкостную линию, контролируют/меняют их и проверяют на кислоту, пока система не чистая.","qr":"После выгорания компрессора систему нужно очистить, обычно установив:","optsr":["Новый термостат","Кислотопоглощающий фильтр-осушитель на всасывании (и жидкостной линии) по процедуре burnout","Больший дакт","Больший конденсатор"],"qs":"Despues de la quemadura de un compresor (burnout), el sistema debe limpiarse, normalmente instalando un:","optss":["Nuevo termostato","Filtro deshidratador para remocion de acido en la linea de succion (y de liquido) y siguiendo el procedimiento de quemadura","Ducto mas grande","Condensador mas grande"],"rs":"Una quemadura deja acido y contaminantes; instale deshidratadores de limpieza de acido de succion y de liquido, monitoreelos/reemplacelos, y pruebe la presencia de acido hasta que el sistema este limpio."},
  {"id":362,"sec":"Service & Troubleshooting","q":"A contactor whose contacts have welded closed will cause:","opts":["A blown fuse only","Low refrigerant","The unit to keep running even when the thermostat is satisfied","The unit to never start"],"correct":2,"re":"Welded contacts keep the high-voltage circuit closed, so the compressor/condenser runs continuously regardless of the control call - replace the contactor.","rr":"Приварившиеся контакты держат силовую цепь замкнутой, поэтому компрессор/конденсатор работает непрерывно независимо от запроса - контактор меняют.","qr":"Контактор с приварившимися контактами вызывает:","optsr":["Только перегорание предохранителя","Недозаправку","Что блок продолжает работать, даже когда термостат удовлетворён","Что блок никогда не запустится"],"qs":"Un contactor cuyos contactos se han soldado cerrados causara:","optss":["Solo un fusible quemado","Refrigerante bajo","Que la unidad siga funcionando incluso cuando el termostato esta satisfecho","Que la unidad nunca arranque"],"rs":"Los contactos soldados mantienen cerrado el circuito de alto voltaje, por lo que el compresor/condensador funciona continuamente sin importar la llamada de control; reemplace el contactor."},
  {"id":363,"sec":"Service & Troubleshooting","q":"Frost forming on the suction line all the way back to the compressor usually indicates:","opts":["Liquid floodback (low superheat) returning to the compressor","A dirty filter","Overheating","High head pressure"],"correct":0,"re":"Suction frost to the compressor signals very low superheat/floodback - causes include overcharge, a flooding TXV, or low load/airflow; correct before the compressor is damaged.","rr":"Иней до компрессора - сигнал очень низкого superheat/floodback; причины - перезаправка, переподающий TXV или малая нагрузка/расход; устраните до повреждения компрессора.","qr":"Иней на всасывающей линии вплоть до компрессора обычно указывает на:","optsr":["Возврат жидкости (низкий superheat) в компрессор","Грязный фильтр","Перегрев","Высокое давление нагнетания"],"qs":"La formacion de escarcha en la linea de succion hasta el compresor normalmente indica:","optss":["Retorno de liquido (bajo sobrecalentamiento) regresando al compresor","Un filtro sucio","Sobrecalentamiento","Alta presion de descarga"],"rs":"La escarcha de succion hasta el compresor indica un sobrecalentamiento muy bajo/retorno de liquido; las causas incluyen sobrecarga, una TXV que inunda, o baja carga/flujo de aire; corrija antes de que el compresor se dane."},
  {"id":364,"sec":"Service & Troubleshooting","q":"On a three-phase compressor, a significant voltage imbalance between legs (over ~2%) can cause:","opts":["Excess current and motor overheating","Better efficiency","Lower head pressure","More subcooling"],"correct":0,"re":"Voltage imbalance produces a much larger current imbalance and motor heating; investigate supply connections/utility, since prolonged imbalance shortens motor life.","rr":"Дисбаланс напряжения даёт куда больший дисбаланс тока и нагрев двигателя; проверьте соединения питания/сеть, т.к. длительный дисбаланс сокращает ресурс мотора.","qr":"На трёхфазном компрессоре значительный дисбаланс напряжения между фазами (более ~2%) может вызвать:","optsr":["Избыточный ток и перегрев двигателя","Лучший КПД","Меньшее давление нагнетания","Больше subcooling"],"qs":"En un compresor trifasico, un desequilibrio de voltaje significativo entre fases (mas de ~2%) puede causar:","optss":["Exceso de corriente y sobrecalentamiento del motor","Mejor eficiencia","Menor presion de descarga","Mas subenfriamiento"],"rs":"El desequilibrio de voltaje produce un desequilibrio de corriente mucho mayor y calentamiento del motor; investigue las conexiones de suministro/la compania electrica, ya que un desequilibrio prolongado acorta la vida del motor."},
  {"id":365,"sec":"Service & Troubleshooting","q":"A megohmmeter (insulation tester) is used on a compressor motor to:","opts":["Measure refrigerant","Detect breakdown of winding insulation to ground (motor 'meggering')","Check superheat","Set gas pressure"],"correct":1,"re":"A megger applies high DC voltage to read winding-to-ground insulation resistance in megohms; a low/declining value warns of impending motor failure.","rr":"Меггер подаёт высокое постоянное напряжение и измеряет сопротивление изоляции обмотка-земля в мегаомах; низкое/падающее значение предупреждает о скором отказе мотора.","qr":"Мегаомметр (тестер изоляции) применяют на двигателе компрессора, чтобы:","optsr":["Измерить хладагент","Выявить пробой изоляции обмотки на землю ('меггеровка' мотора)","Проверить superheat","Задать давление газа"],"qs":"Un megohmetro (probador de aislamiento) se usa en un motor de compresor para:","optss":["Medir el refrigerante","Detectar la ruptura del aislamiento del devanado a tierra (megado del motor)","Revisar el sobrecalentamiento","Ajustar la presion del gas"],"rs":"Un megger aplica alto voltaje de CC para leer la resistencia de aislamiento del devanado a tierra en megaohmios; un valor bajo/en descenso advierte de una falla inminente del motor."},
  {"id":366,"sec":"Service & Troubleshooting","q":"A blower runs but the gas furnace produces no heat. The first things to check include:","opts":["Gas supply, ignition sequence, and flame proving","Subcooling","Duct color","Refrigerant charge"],"correct":0,"re":"No heat with a running blower points to the gas/ignition side: gas valve, igniter/pilot, flame sensor, limits, and the control board sequence - not the refrigerant circuit.","rr":"Нет тепла при работающем вентиляторе - это газ/розжиг: газовый клапан, игнайтер/пилот, датчик пламени, лимиты и последовательность платы - не контур хладагента.","qr":"Вентилятор работает, но газовая печь не греет. В первую очередь проверяют:","optsr":["Подачу газа, последовательность розжига и контроль пламени","Subcooling","Цвет дакта","Заправку хладагентом"],"qs":"El soplador funciona pero el horno de gas no produce calor. Lo primero que hay que revisar incluye:","optss":["El suministro de gas, la secuencia de encendido y la comprobacion de flama","El subenfriamiento","El color del ducto","La carga de refrigerante"],"rs":"La falta de calor con el soplador funcionando apunta al lado del gas/encendido: valvula de gas, encendedor/piloto, sensor de flama, limites, y la secuencia de la tarjeta de control, no al circuito de refrigerante."},
  {"id":367,"sec":"Service & Troubleshooting","q":"A capacitor that tests well below its rated microfarads will cause a motor to:","opts":["Start hard, run hot, and draw high amps (or fail to start)","Increase SEER","Lower head pressure","Run cooler"],"correct":0,"re":"A weak capacitor reduces motor torque and phase shift, so the motor runs hot and over-amps; replace with the exact rated uF and voltage or higher voltage rating.","rr":"Слабый конденсатор уменьшает момент и фазовый сдвиг, мотор греется и перегружается по току; меняют на точный номинал uF и то же или большее напряжение.","qr":"Конденсатор, показывающий заметно ниже номинальных микрофарад, заставит мотор:","optsr":["Тяжело пускаться, греться и тянуть высокий ток (или не пускаться)","Повысить SEER","Снизить давление нагнетания","Работать холоднее"],"qs":"Un capacitor que prueba muy por debajo de sus microfaradios nominales causara que un motor:","optss":["Arranque con dificultad, funcione caliente y consuma alto amperaje (o no arranque)","Aumente el SEER","Baje la presion de descarga","Funcione mas frio"],"rs":"Un capacitor debil reduce el torque del motor y el desfase, por lo que el motor funciona caliente y con sobreamperaje; reemplacelo con el valor exacto de uF nominal y el voltaje igual o mayor."},
  {"id":368,"sec":"Service & Troubleshooting","q":"A repeatedly tripping high-limit on a furnace, with a clean filter and open registers, may indicate:","opts":["A failing blower motor/capacitor or a closed/blocked duct reducing airflow","A stuck reversing valve","Low subcooling","Overcharge"],"correct":0,"re":"If filters and registers are fine, low airflow may come from a weak blower (motor/cap), slipped belt, or blocked ducting - all overheat the heat exchanger and trip the limit.","rr":"Если фильтры и решётки в порядке, малый расход может быть от слабого вентилятора (мотор/конденсатор), проскользнувшего ремня или забитого дакта - всё перегревает теплообменник и выбивает лимит.","qr":"Многократное срабатывание верхнего лимита печи при чистом фильтре и открытых решётках может указывать на:","optsr":["Слабый мотор/конденсатор вентилятора или закрытый/забитый дакт, снижающий расход","Заклинивший реверс-клапан","Низкий subcooling","Перезаправку"],"qs":"Un limite alto (high-limit) que se dispara repetidamente en un horno, con un filtro limpio y los registros abiertos, puede indicar:","optss":["Un motor del soplador/capacitor que esta fallando o un ducto cerrado/bloqueado que reduce el flujo de aire","Una valvula reversora atascada","Bajo subenfriamiento","Sobrecarga"],"rs":"Si los filtros y registros estan bien, el bajo flujo de aire puede provenir de un soplador debil (motor/capacitor), una banda patinando o un ducto bloqueado, todo lo cual sobrecalienta el intercambiador de calor y dispara el limite."},
  {"id":369,"sec":"Service & Troubleshooting","q":"To distinguish a low refrigerant charge from a restricted metering device, the technician compares:","opts":["Superheat, subcooling, and pressures together against expected values","Only the voltage","The duct gauge","The thermostat brand"],"correct":0,"re":"Low charge shows high superheat AND low subcooling; a liquid-line restriction often shows high subcooling upstream with low evaporator pressure - reading the full set distinguishes them.","rr":"Недозаправка даёт высокий superheat И низкий subcooling; засор жидкостной линии часто даёт высокий subcooling до засора при низком давлении испарителя - полный набор показаний их различает.","qr":"Чтобы отличить недозаправку от засора дозатора, техник сравнивает:","optsr":["Superheat, subcooling и давления вместе с ожидаемыми значениями","Только напряжение","Толщину дакта","Бренд термостата"],"qs":"Para distinguir una carga baja de refrigerante de un dispositivo de medicion restringido, el tecnico compara:","optss":["El sobrecalentamiento, el subenfriamiento y las presiones en conjunto contra los valores esperados","Solo el voltaje","El calibre del ducto","La marca del termostato"],"rs":"La carga baja muestra alto sobrecalentamiento Y bajo subenfriamiento; una restriccion en la linea de liquido a menudo muestra alto subenfriamiento aguas arriba con baja presion del evaporador; leer el conjunto completo los distingue."},
  {"id":370,"sec":"Service & Troubleshooting","q":"A noisy compressor that knocks on startup and shows frost at the suction may be experiencing:","opts":["High SEER","Liquid slugging from refrigerant migration or overcharge","Low voltage only","Normal operation"],"correct":1,"re":"Knocking with suction frost suggests liquid entering the compressor (migration during off-cycle or overcharge); a crankcase heater and correct charge help prevent slugging.","rr":"Стук с инеем на всасывании указывает на попадание жидкости в компрессор (миграция в простое или перезаправка); подогрев картера и верный заряд помогают избежать гидроудара.","qr":"Шумный компрессор, стучащий при пуске и с инеем на всасывании, может испытывать:","optsr":["Высокий SEER","Гидроудар от миграции хладагента или перезаправки","Только низкое напряжение","Нормальную работу"],"qs":"Un compresor ruidoso que golpetea al arrancar y muestra escarcha en la succion puede estar experimentando:","optss":["Un SEER alto","Golpeteo de liquido (slugging) por migracion de refrigerante o sobrecarga","Solo bajo voltaje","Funcionamiento normal"],"rs":"El golpeteo con escarcha en la succion sugiere liquido entrando al compresor (migracion durante el ciclo de apagado o sobrecarga); un calentador de carter y la carga correcta ayudan a evitar el slugging."},
  {"id":371,"sec":"Service & Troubleshooting","q":"A maintenance check finds a 10 F+ approach across a clean condenser on a mild day; the next step is to:","opts":["Add refrigerant blindly","Change the thermostat","Verify charge (subcooling) and condenser airflow before any correction","Replace the compressor"],"correct":2,"re":"Diagnose with measurements: confirm subcooling, airflow, and ambient before adjusting charge; never add refrigerant without verifying it is actually low.","rr":"Диагностируйте измерениями: подтвердите subcooling, обдув и наружную температуру до правки заряда; не добавляйте хладагент, не убедившись, что его реально мало.","qr":"При ТО обнаружен большой 'approach' (10+ F) на чистом конденсаторе в мягкий день; следующий шаг:","optsr":["Доливать хладагент вслепую","Сменить термостат","Проверить заправку (subcooling) и обдув конденсатора до любых правок","Заменить компрессор"],"qs":"Una revision de mantenimiento encuentra un acercamiento (approach) de mas de 10 F en un condensador limpio en un dia templado; el siguiente paso es:","optss":["Agregar refrigerante a ciegas","Cambiar el termostato","Verificar la carga (subenfriamiento) y el flujo de aire del condensador antes de cualquier correccion","Reemplazar el compresor"],"rs":"Diagnostique con mediciones: confirme el subenfriamiento, el flujo de aire y la temperatura ambiente antes de ajustar la carga; nunca agregue refrigerante sin verificar que realmente este baja."},
  {"id":372,"sec":"Service & Troubleshooting","q":"A dirty air filter that is left unchanged over time most directly causes:","opts":["Higher refrigerant cost","More subcooling","Reduced airflow, lower capacity, and possible coil freezing or limit trips","Higher voltage"],"correct":2,"re":"A clogged filter starves airflow, dropping capacity and efficiency; in cooling it can freeze the coil, in heating it can trip the limit - routine filter changes prevent this.","rr":"Забитый фильтр душит расход, снижая производительность и КПД; в охлаждении может заморозить испаритель, в нагреве - выбить лимит; регулярная замена фильтра это предотвращает.","qr":"Грязный воздушный фильтр, который долго не меняют, напрямую вызывает:","optsr":["Рост стоимости хладагента","Больше subcooling","Снижение расхода, падение производительности и возможное обмерзание или срабатывание лимита","Высокое напряжение"],"qs":"Un filtro de aire sucio que se deja sin cambiar con el tiempo causa de manera mas directa:","optss":["Mayor costo de refrigerante","Mas subenfriamiento","Reduccion del flujo de aire, menor capacidad, y posible congelamiento del serpentin o disparos del limite","Mayor voltaje"],"rs":"Un filtro obstruido restringe el flujo de aire, reduciendo la capacidad y la eficiencia; en enfriamiento puede congelar el serpentin, en calefaccion puede disparar el limite; los cambios rutinarios de filtro lo evitan."},
  {"id":373,"sec":"Service & Troubleshooting","q":"When the thermostat calls for cooling but nothing runs, a logical first check is:","opts":["Flame sensor","Refrigerant subcooling","Duct leakage","24 V at the contactor coil and proper line voltage/disconnect"],"correct":3,"re":"Trace the circuit: confirm power/disconnect, then 24 V control signal to the contactor; no control voltage points upstream (thermostat, transformer, safeties), not the refrigerant side.","rr":"Прослеживайте цепь: подтвердите питание/разъединитель, затем сигнал 24 В на контактор; нет управляющего напряжения - проблема выше (термостат, трансформатор, защиты), а не в хладагенте.","qr":"Когда термостат запрашивает охлаждение, но ничего не работает, логичная первая проверка:","optsr":["Датчик пламени","Subcooling хладагента","Утечка воздуховодов","24 В на катушке контактора и нормальное линейное напряжение/разъединитель"],"qs":"Cuando el termostato solicita enfriamiento pero nada funciona, una primera revision logica es:","optss":["El sensor de flama","El subenfriamiento del refrigerante","La fuga de ductos","24 V en la bobina del contactor y el voltaje de linea/desconectador adecuado"],"rs":"Rastree el circuito: confirme la energia/desconectador, luego la senal de control de 24 V al contactor; la ausencia de voltaje de control apunta aguas arriba (termostato, transformador, seguridades), no al lado del refrigerante."},
  {"id":374,"sec":"Service & Troubleshooting","q":"A heat pump providing weak heat with low suction pressure and a frosted outdoor coil that won't clear suggests:","opts":["A cracked heat exchanger","A defrost problem and/or low charge in heating","Overcharge","Too much airflow"],"correct":1,"re":"In heating the outdoor coil is the evaporator; if defrost fails or charge is low, ice builds and heating capacity falls - check the defrost control and charge.","rr":"В нагреве наружная батарея - испаритель; при отказе разморозки или недозаправке нарастает лёд и падает теплопроизводительность - проверьте управление defrost и заряд.","qr":"Тепловой насос слабо греет, низкое давление всасывания, наружная батарея обмерзла и не оттаивает - это указывает на:","optsr":["Трещину теплообменника","Проблему разморозки и/или недозаправку в нагреве","Перезаправку","Слишком большой расход воздуха"],"qs":"Una bomba de calor que da calor debil con baja presion de succion y un serpentin exterior escarchado que no se despeja sugiere:","optss":["Un intercambiador de calor agrietado","Un problema de descongelamiento y/o carga baja en calefaccion","Sobrecarga","Demasiado flujo de aire"],"rs":"En calefaccion el serpentin exterior es el evaporador; si el descongelamiento falla o la carga es baja, se acumula hielo y la capacidad de calefaccion cae; revise el control de descongelamiento y la carga."},
  {"id":375,"sec":"Service & Troubleshooting","q":"During maintenance, tightening electrical lugs/terminals is important because loose connections cause:","opts":["Higher SEER","Lower amps","Heat, voltage drop, and burnt connections/component failure","More refrigerant"],"correct":2,"re":"Loose connections add resistance, generating heat and voltage drop that burns terminals and damages contactors/wiring; check and tighten during service.","rr":"Слабые соединения добавляют сопротивление, создавая нагрев и падение напряжения, что жжёт клеммы и повреждает контакторы/проводку; проверяйте и подтягивайте при обслуживании.","qr":"При ТО затяжка электрических наконечников/клемм важна, потому что слабые соединения вызывают:","optsr":["Высокий SEER","Меньший ток","Нагрев, падение напряжения и подгоревшие соединения/отказ компонентов","Больше хладагента"],"qs":"Durante el mantenimiento, apretar los lugs/terminales electricos es importante porque las conexiones flojas causan:","optss":["Mayor SEER","Menor amperaje","Calor, caida de voltaje y conexiones quemadas/falla de componentes","Mas refrigerante"],"rs":"Las conexiones flojas agregan resistencia, generando calor y caida de voltaje que quema las terminales y dana los contactores/cableado; revise y apriete durante el servicio."},
  {"id":376,"sec":"Service & Troubleshooting","q":"A 24 V control fuse that blows the instant power is restored indicates a:","opts":["Bad duct","Short in the low-voltage wiring or a shorted component (e.g., contactor coil)","Low refrigerant condition","Dirty filter"],"correct":1,"re":"An immediately blown control fuse means a dead short in the 24 V circuit - chafed thermostat wire, shorted coil, or pinched cable; find and clear it before re-fusing.","rr":"Мгновенно сгорающий управляющий предохранитель - это короткое в цепи 24 В: протёртый провод термостата, замкнутая катушка или зажатый кабель; найдите и устраните до замены предохранителя.","qr":"Управляющий предохранитель 24 В, перегорающий сразу при подаче питания, указывает на:","optsr":["Плохой дакт","Короткое в низковольтной проводке или замкнутый компонент (например катушку контактора)","Недозаправку","Грязный фильтр"],"qs":"Un fusible de control de 24 V que se quema en el instante en que se restablece la energia indica:","optss":["Un ducto en mal estado","Un corto en el cableado de bajo voltaje o un componente en corto (por ejemplo, la bobina del contactor)","Una condicion de refrigerante bajo","Un filtro sucio"],"rs":"Un fusible de control que se quema de inmediato significa un corto franco en el circuito de 24 V: cable del termostato desgastado, bobina en corto o cable pellizcado; encuentrelo y corrijalo antes de volver a colocar el fusible."},
  {"id":377,"sec":"Service & Troubleshooting","q":"Annual maintenance on a gas furnace should include cleaning the flame sensor and:","opts":["Disabling the rollout switch","Removing the limit switch","Adding refrigerant","Inspecting the heat exchanger and verifying safe combustion/venting"],"correct":3,"re":"Maintenance includes flame-sensor cleaning, heat-exchanger inspection, combustion/venting check, and confirming all safeties function - never disable a safety control.","rr":"ТО включает чистку датчика пламени, осмотр теплообменника, проверку сгорания/дымоудаления и подтверждение работы всех защит - защитное устройство отключать нельзя.","qr":"Ежегодное ТО газовой печи должно включать чистку датчика пламени и:","optsr":["Отключение rollout-выключателя","Снятие лимитного выключателя","Добавление хладагента","Осмотр теплообменника и проверку безопасного сгорания/дымоудаления"],"qs":"El mantenimiento anual de un horno de gas debe incluir la limpieza del sensor de flama y:","optss":["Deshabilitar el interruptor de derrame de flama","Quitar el interruptor de limite","Agregar refrigerante","Inspeccionar el intercambiador de calor y verificar la combustion/ventilacion segura"],"rs":"El mantenimiento incluye la limpieza del sensor de flama, la inspeccion del intercambiador de calor, la revision de la combustion/ventilacion y la confirmacion de que todas las seguridades funcionan; nunca deshabilite un control de seguridad."},
  {"id":378,"sec":"Service & Troubleshooting","q":"Comparing measured compressor running amps to the nameplate RLA helps determine whether the compressor is:","opts":["The right color","A heat pump","Overloaded, undersized for conditions, or operating normally","Out of refrigerant by itself"],"correct":2,"re":"Running amps near RLA at design conditions is normal; well over RLA suggests high head/overcharge/mechanical issues, far below may indicate undercharge or unloading - interpret with the pressures.","rr":"Ток около RLA при расчётных условиях нормален; заметно выше RLA - высокое давление/перезаправка/механика, заметно ниже - недозаправка или разгрузка; трактуйте вместе с давлениями.","qr":"Сравнение измеренного рабочего тока компрессора с RLA на шильдике помогает определить, что компрессор:","optsr":["Правильного цвета","Тепловой насос","Перегружен, недогружен по условиям или работает нормально","Сам по себе без хладагента"],"qs":"Comparar el amperaje de marcha medido del compresor con la RLA de la placa de datos ayuda a determinar si el compresor esta:","optss":["Del color correcto","Una bomba de calor","Sobrecargado, subdimensionado para las condiciones, u operando normalmente","Sin refrigerante por si solo"],"rs":"El amperaje de marcha cercano a la RLA en condiciones de diseno es normal; muy por encima de la RLA sugiere alta presion de descarga/sobrecarga/problemas mecanicos, muy por debajo puede indicar carga baja o descarga (unloading); interpretelo junto con las presiones."},
  {"id":379,"sec":"Safety & Field Practices","q":"Refrigerant cylinders transported in a vehicle should be:","opts":["Laid on their side near the engine","Secured upright, valve protected, in a ventilated area (not the passenger cabin)","Loose in the passenger cabin","Heated for pressure"],"correct":1,"re":"Secure cylinders upright with valve caps on, in a ventilated cargo area away from occupants and heat, to prevent leaks, rolling, and asphyxiation hazards.","rr":"Закрепляйте баллоны вертикально с колпачками на вентилях, в проветриваемом грузовом отсеке вдали от людей и тепла - чтобы избежать утечек, перекатывания и удушья.","qr":"Баллоны с хладагентом при перевозке в автомобиле должны быть:","optsr":["Лежать на боку у двигателя","Закреплены вертикально, с защитой вентиля, в проветриваемой зоне (не в салоне)","Свободно в салоне","Подогреты для давления"],"qs":"Los cilindros de refrigerante transportados en un vehiculo deben:","optss":["Acostarse de lado cerca del motor","Asegurarse en posicion vertical, con la valvula protegida, en un area ventilada (no en la cabina de pasajeros)","Sueltos en la cabina de pasajeros","Calentarse para generar presion"],"rs":"Asegure los cilindros en posicion vertical con las tapas de valvula puestas, en un area de carga ventilada lejos de los ocupantes y del calor, para evitar fugas, rodamientos y peligros de asfixia."},
  {"id":380,"sec":"Safety & Field Practices","q":"In a permit-required confined space, a safe oxygen level is generally:","opts":["19.5% to 23.5%","Above 30%","Exactly 50%","Below 15%"],"correct":0,"re":"Normal/safe oxygen is 19.5-23.5%; below 19.5% is oxygen-deficient (asphyxiation risk) and above 23.5% is oxygen-enriched (fire risk). Test before entry.","rr":"Нормальный/безопасный кислород 19.5-23.5%; ниже 19.5% - кислородное голодание (удушье), выше 23.5% - переобогащение (пожароопасно). Проверяйте до входа.","qr":"В замкнутом пространстве с допуском безопасный уровень кислорода обычно:","optsr":["19.5% - 23.5%","Выше 30%","Ровно 50%","Ниже 15%"],"qs":"En un espacio confinado que requiere permiso, un nivel de oxigeno seguro generalmente es:","optss":["19.5% a 23.5%","Por encima del 30%","Exactamente 50%","Por debajo del 15%"],"rs":"El oxigeno normal/seguro es 19.5-23.5%; por debajo del 19.5% es deficiente en oxigeno (riesgo de asfixia) y por encima del 23.5% es enriquecido en oxigeno (riesgo de incendio). Pruebe antes de entrar."},
  {"id":381,"sec":"Safety & Field Practices","q":"Old thermostats containing a mercury bulb must be:","opts":["Disposed of as universal/hazardous waste (mercury recovery)","Thrown in regular trash","Burned","Buried on site"],"correct":0,"re":"Mercury is toxic; mercury-switch thermostats are universal waste and must be recycled through approved programs, never landfilled or incinerated.","rr":"Ртуть токсична; ртутные термостаты - universal waste, их сдают через одобренные программы переработки, не на свалку и не на сжигание.","qr":"Старые термостаты с ртутной колбой необходимо:","optsr":["Утилизировать как universal/опасные отходы (сбор ртути)","Выбросить в обычный мусор","Сжечь","Закопать на месте"],"qs":"Los termostatos viejos que contienen un bulbo de mercurio deben:","optss":["Desecharse como residuo universal/peligroso (recuperacion de mercurio)","Tirarse a la basura comun","Quemarse","Enterrarse en el sitio"],"rs":"El mercurio es toxico; los termostatos con interruptor de mercurio son residuos universales y deben reciclarse mediante programas aprobados, nunca en vertederos ni incinerados."},
  {"id":382,"sec":"Safety & Field Practices","q":"Old fluorescent ballasts or capacitors may contain PCBs, which require:","opts":["Handling and disposal as hazardous waste","Regular trash disposal","No precautions","Burning on site"],"correct":0,"re":"PCB-containing ballasts/capacitors are hazardous waste; handle to avoid leaks and dispose through proper hazardous-waste channels.","rr":"Балласты/конденсаторы с PCB - опасные отходы; обращайтесь так, чтобы избежать течи, и утилизируйте через надлежащие каналы опасных отходов.","qr":"Старые люминесцентные балласты или конденсаторы могут содержать PCB (ПХБ), что требует:","optsr":["Обращения и утилизации как опасные отходы","Выброса в обычный мусор","Никаких мер","Сжигания на месте"],"qs":"Los balastros o capacitores fluorescentes viejos pueden contener PCB, lo que requiere:","optss":["Manejo y eliminacion como residuo peligroso","Eliminacion en la basura comun","Ninguna precaucion","Quemarse en el sitio"],"rs":"Los balastros/capacitores que contienen PCB son residuos peligrosos; manejelos para evitar fugas y desechelos a traves de los canales adecuados de residuos peligrosos."},
  {"id":383,"sec":"Safety & Field Practices","q":"The first action when someone is being shocked and cannot let go of an energized circuit is to:","opts":["Wait and watch","De-energize the circuit (kill power) before touching them","Pour water on them","Pull them with bare hands"],"correct":1,"re":"Never touch a person in contact with live current; shut off the power/disconnect first (or use a non-conductive means), then call for help and give aid.","rr":"Никогда не касайтесь человека в контакте с током; сначала отключите питание/разъединитель (или используйте непроводящее средство), затем зовите помощь и оказывайте её.","qr":"Первое действие, когда человека бьёт током и он не может оторваться от цепи под напряжением:","optsr":["Ждать и наблюдать","Обесточить цепь (снять питание) до прикосновения к нему","Облить водой","Тянуть его голыми руками"],"qs":"La primera accion cuando alguien esta recibiendo una descarga y no puede soltar un circuito energizado es:","optss":["Esperar y observar","Desenergizar el circuito (cortar la energia) antes de tocarlo","Echarle agua","Jalarlo con las manos descubiertas"],"rs":"Nunca toque a una persona en contacto con corriente viva; corte primero la energia/desconectador (o use un medio no conductor), luego pida ayuda y brinde auxilio."},
  {"id":384,"sec":"Safety & Field Practices","q":"First aid for inhaling a high concentration of refrigerant vapor is to:","opts":["Have them keep working","Move the person to fresh air immediately and seek medical help","Apply heat","Give the person caffeine"],"correct":1,"re":"Refrigerant vapor displaces oxygen and can cause dizziness/asphyxiation; get the person to fresh air at once, monitor breathing, and get medical attention per the SDS.","rr":"Пары хладагента вытесняют кислород и вызывают головокружение/удушье; немедленно выведите человека на свежий воздух, контролируйте дыхание и обратитесь за медпомощью по SDS.","qr":"Первая помощь при вдыхании высокой концентрации паров хладагента:","optsr":["Заставить продолжать работу","Немедленно вывести человека на свежий воздух и обратиться за медпомощью","Приложить тепло","Дать кофеин"],"qs":"Los primeros auxilios por inhalar una alta concentracion de vapor de refrigerante son:","optss":["Hacer que siga trabajando","Llevar a la persona al aire fresco de inmediato y buscar ayuda medica","Aplicar calor","Darle cafeina a la persona"],"rs":"El vapor de refrigerante desplaza el oxigeno y puede causar mareos/asfixia; lleve a la persona al aire fresco de inmediato, vigile la respiracion y obtenga atencion medica segun la SDS."},
  {"id":385,"sec":"Safety & Field Practices","q":"A respirator selected for a specific dust or vapor must be:","opts":["Any mask available","Matched to the hazard, fit-tested, and used within a respiratory-protection program","A surgical mask","Optional always"],"correct":1,"re":"Respirator choice (e.g., N95/P100 for particulates, cartridges for vapors) must match the hazard, be fit-tested, and follow Cal/OSHA's respiratory-protection requirements.","rr":"Выбор респиратора (например N95/P100 для частиц, картриджи для паров) должен соответствовать опасности, пройти fit-test и следовать требованиям Cal/OSHA по защите дыхания.","qr":"Респиратор, выбранный под конкретную пыль или пар, должен быть:","optsr":["Любой имеющейся маской","Подобран под опасность, проверен на прилегание (fit-test) и использован в программе защиты органов дыхания","Хирургической маской","Всегда необязателен"],"qs":"Un respirador seleccionado para un polvo o vapor especifico debe:","optss":["Ser cualquier mascarilla disponible","Estar acorde al peligro, tener prueba de ajuste y usarse dentro de un programa de proteccion respiratoria","Ser una mascarilla quirurgica","Ser siempre opcional"],"rs":"La eleccion del respirador (por ejemplo, N95/P100 para particulas, cartuchos para vapores) debe coincidir con el peligro, tener prueba de ajuste y seguir los requisitos de proteccion respiratoria de Cal/OSHA."},
  {"id":386,"sec":"Safety & Field Practices","q":"Heat stroke differs from heat exhaustion in that heat stroke:","opts":["Only causes thirst","Needs no action","Is a medical emergency (high body temp, confusion) requiring immediate cooling and 911","Is minor"],"correct":2,"re":"Heat exhaustion (heavy sweating, weakness) is serious; heat stroke (hot dry skin or confusion, very high temperature) is life-threatening - cool rapidly and call 911 immediately.","rr":"Тепловое истощение (сильное потоотделение, слабость) серьёзно; тепловой удар (горячая сухая кожа или спутанность, очень высокая температура) опасен для жизни - быстро охлаждайте и звоните 911.","qr":"Тепловой удар отличается от теплового истощения тем, что тепловой удар:","optsr":["Вызывает только жажду","Не требует действий","Это неотложное состояние (высокая температура тела, спутанность), требующее немедленного охлаждения и 911","Незначителен"],"qs":"El golpe de calor se diferencia del agotamiento por calor en que el golpe de calor:","optss":["Solo causa sed","No necesita ninguna accion","Es una emergencia medica (temperatura corporal alta, confusion) que requiere enfriamiento inmediato y 911","Es menor"],"rs":"El agotamiento por calor (sudoracion intensa, debilidad) es serio; el golpe de calor (piel caliente y seca o confusion, temperatura muy alta) es mortal; enfrie rapidamente y llame al 911 de inmediato."},
  {"id":387,"sec":"Safety & Field Practices","q":"Under Cal/OSHA's heat illness standard, new or returning workers in high heat should be:","opts":["Sent to the roof alone","Denied water","Acclimatized gradually and closely observed","Worked at full pace immediately"],"correct":2,"re":"Acclimatization (gradually building heat tolerance over days) and close observation of new/returning workers reduce heat-illness risk during heat waves.","rr":"Акклиматизация (постепенное наращивание переносимости жары за несколько дней) и пристальное наблюдение за новыми/вернувшимися работниками снижают риск тепловых болезней в жару.","qr":"По стандарту Cal/OSHA о тепловых болезнях новые или вернувшиеся работники в сильную жару должны:","optsr":["Отправлены на крышу в одиночку","Быть лишены воды","Постепенно акклиматизироваться и быть под пристальным наблюдением","Сразу работать в полном темпе"],"qs":"Bajo la norma de enfermedad por calor de Cal/OSHA, los trabajadores nuevos o que regresan en condiciones de alto calor deben:","optss":["Enviarse solos a la azotea","Negarseles agua","Aclimatarse gradualmente y observarse de cerca","Trabajar a ritmo completo de inmediato"],"rs":"La aclimatacion (desarrollar gradualmente la tolerancia al calor durante varios dias) y la observacion cercana de los trabajadores nuevos/que regresan reducen el riesgo de enfermedad por calor durante las olas de calor."},
  {"id":388,"sec":"Safety & Field Practices","q":"An extension ladder used on the job should have a duty rating that:","opts":["Meets or exceeds the combined weight of worker plus tools/materials","Does not matter","Is the cheapest available","Is always Type III"],"correct":0,"re":"Choose a ladder duty rating (e.g., Type IA = 300 lb) at or above the total load; overloading a ladder risks structural failure and falls.","rr":"Выбирайте нагрузочный рейтинг лестницы (например Type IA = 300 фунтов) не ниже полной нагрузки; перегрузка лестницы грозит разрушением и падением.","qr":"Раздвижная лестница на работе должна иметь нагрузочный рейтинг, который:","optsr":["Соответствует или превышает суммарный вес работника плюс инструмент/материалы","Неважен","Самый дешёвый из доступных","Всегда Type III"],"qs":"Una escalera de extension usada en el trabajo debe tener una clasificacion de carga (duty rating) que:","optss":["Cumpla o exceda el peso combinado del trabajador mas las herramientas/materiales","No importa","Sea la mas barata disponible","Sea siempre Tipo III"],"rs":"Elija una clasificacion de carga de escalera (por ejemplo, Tipo IA = 300 lb) igual o superior a la carga total; sobrecargar una escalera arriesga fallas estructurales y caidas."},
  {"id":389,"sec":"Safety & Field Practices","q":"Before touching a circuit you believe is de-energized, the safest practice is to:","opts":["Test before touch: verify zero voltage with a meter proven on a known live source","Touch it quickly","Wear gloves only","Assume it is off"],"correct":0,"re":"'Test before touch' (live-dead-live): confirm your meter works on a known live source, verify the circuit reads zero, then re-confirm the meter - this catches LOTO errors.","rr":"'Проверь до касания' (живое-мёртвое-живое): убедитесь, что прибор работает на заведомо живом источнике, проверьте нуль на цепи, затем перепроверьте прибор - это ловит ошибки LOTO.","qr":"Перед прикосновением к цепи, которую считаете обесточенной, безопаснее всего:","optsr":["Проверить до касания: убедиться в нуле напряжения мультиметром, проверенным на заведомо живом источнике","Быстро коснуться","Только надеть перчатки","Предположить, что она выключена"],"qs":"Antes de tocar un circuito que cree que esta desenergizado, la practica mas segura es:","optss":["Probar antes de tocar: verificar voltaje cero con un medidor comprobado en una fuente viva conocida","Tocarlo rapidamente","Usar solo guantes","Asumir que esta apagado"],"rs":"'Probar antes de tocar' (vivo-muerto-vivo): confirme que su medidor funciona en una fuente viva conocida, verifique que el circuito lea cero, luego vuelva a confirmar el medidor; esto detecta errores de LOTO."},
  {"id":390,"sec":"Safety & Field Practices","q":"Portable fire extinguishers on a jobsite must be:","opts":["Used only by managers","Left empty","Inspected/maintained and charged, with the right class for the hazard","Painted any color"],"correct":2,"re":"Extinguishers must be accessible, inspected, fully charged, and of the correct class (ABC for general HVAC work near electrical) to be effective.","rr":"Огнетушители должны быть доступны, проверены, полностью заряжены и нужного класса (ABC для общих HVAC-работ у электрики), чтобы быть эффективными.","qr":"Переносные огнетушители на объекте должны быть:","optsr":["Использоваться только руководителями","Оставлены пустыми","Проверены/обслужены и заряжены, нужного класса под опасность","Покрашены в любой цвет"],"qs":"Los extintores portatiles de incendios en un sitio de trabajo deben:","optss":["Ser usados solo por los gerentes","Dejarse vacios","Estar inspeccionados/mantenidos y cargados, con la clase correcta para el peligro","Pintarse de cualquier color"],"rs":"Los extintores deben estar accesibles, inspeccionados, totalmente cargados y de la clase correcta (ABC para trabajo general de HVAC cerca de equipos electricos) para ser eficaces."},
  {"id":391,"sec":"Safety & Field Practices","q":"Hearing protection should be worn when:","opts":["Only indoors","Noise levels are high enough to require it (e.g., near loud equipment/power tools)","Only at night","Never on HVAC jobs"],"correct":1,"re":"Sustained high noise damages hearing; wear earplugs/muffs when working around loud blowers, compressors, or power tools per the noise exposure limits.","rr":"Длительный высокий шум повреждает слух; надевайте беруши/наушники у громких вентиляторов, компрессоров или электроинструмента согласно лимитам шумового воздействия.","qr":"Защиту слуха следует носить, когда:","optsr":["Только в помещении","Уровень шума достаточно высок (например рядом с громким оборудованием/электроинструментом)","Только ночью","Никогда на HVAC-работах"],"qs":"La proteccion auditiva debe usarse cuando:","optss":["Solo en interiores","Los niveles de ruido son lo suficientemente altos como para requerirla (por ejemplo, cerca de equipos ruidosos/herramientas electricas)","Solo de noche","Nunca en trabajos de HVAC"],"rs":"El ruido alto sostenido dana la audicion; use tapones/orejeras cuando trabaje cerca de sopladores, compresores o herramientas electricas ruidosas, segun los limites de exposicion al ruido."},
  {"id":392,"sec":"Safety & Field Practices","q":"A compressed-gas cylinder (refrigerant or nitrogen) in use or storage should be:","opts":["Left in walkways","Laid on its side unsecured","Used as a roller","Secured upright (chained/strapped) so it cannot fall"],"correct":3,"re":"Cylinders must be secured upright so they cannot tip; a falling cylinder can shear the valve and become a dangerous projectile.","rr":"Баллоны крепят вертикально, чтобы не опрокинулись; падающий баллон может срезать вентиль и стать опасным снарядом.","qr":"Баллон со сжатым газом (хладагент или азот) при использовании или хранении должен быть:","optsr":["Оставлен в проходах","Лежать на боку незакреплённым","Использоваться как каток","Закреплён вертикально (цепью/ремнём), чтобы не упасть"],"qs":"Un cilindro de gas comprimido (refrigerante o nitrogeno) en uso o almacenamiento debe:","optss":["Dejarse en los pasillos","Acostarse de lado sin asegurar","Usarse como rodillo","Asegurarse en posicion vertical (encadenado/sunchado) para que no pueda caerse"],"rs":"Los cilindros deben asegurarse en posicion vertical para que no puedan volcarse; un cilindro que cae puede cortar la valvula y convertirse en un proyectil peligroso."},
  {"id":393,"sec":"Safety & Field Practices","q":"When charging or recovering, a recovery cylinder must never be overfilled because:","opts":["It adds moisture","It lowers efficiency","It changes the color","Hydrostatic pressure from liquid expansion can rupture it"],"correct":3,"re":"Filling past 80% leaves no room for liquid expansion; as temperature rises, hydrostatic pressure can burst the cylinder - use a scale and never overfill.","rr":"Заполнение свыше 80% не оставляет места для расширения жидкости; при росте температуры гидростатическое давление может разорвать баллон - используйте весы и не переполняйте.","qr":"При заправке или откачке recovery-баллон нельзя переполнять, потому что:","optsr":["Это добавляет влагу","Это снижает КПД","Это меняет цвет","Гидростатическое давление от расширения жидкости может его разорвать"],"qs":"Al cargar o recuperar, un cilindro de recuperacion nunca debe llenarse en exceso porque:","optss":["Agrega humedad","Reduce la eficiencia","Cambia el color","La presion hidrostatica por la expansion del liquido puede romperlo"],"rs":"Llenar mas alla del 80% no deja espacio para la expansion del liquido; a medida que sube la temperatura, la presion hidrostatica puede reventar el cilindro; use una bascula y nunca lo llene en exceso."},
  {"id":394,"sec":"Safety & Field Practices","q":"Before performing hot work (brazing) in an occupied building, a technician should:","opts":["Disable smoke alarms permanently","Clear/protect combustibles, have an extinguisher and fire watch ready","Use more flux","Skip notifying anyone"],"correct":1,"re":"Hot work requires removing or shielding combustibles, a charged extinguisher at hand, and a fire watch during and after the work to catch smoldering ignition.","rr":"Огневые работы требуют убрать или прикрыть горючее, держать заряженный огнетушитель под рукой и вести пожарный надзор во время и после работы, чтобы поймать тлеющее возгорание.","qr":"Перед огневыми работами (пайкой) в занятом здании техник должен:","optsr":["Навсегда отключить дымовые извещатели","Убрать/защитить горючие материалы, иметь под рукой огнетушитель и пожарный надзор","Использовать больше флюса","Никого не предупреждать"],"qs":"Antes de realizar trabajo en caliente (brazing) en un edificio ocupado, un tecnico debe:","optss":["Deshabilitar las alarmas de humo permanentemente","Despejar/proteger los combustibles, tener un extintor y una vigilancia de incendios listos","Usar mas fundente","Omitir notificar a alguien"],"rs":"El trabajo en caliente requiere retirar o proteger los combustibles, un extintor cargado a la mano, y una vigilancia de incendios durante y despues del trabajo para detectar una ignicion latente."},
  {"id":395,"sec":"Safety & Field Practices","q":"Eye protection rated for impact and brazing glare should be worn because:","opts":["It looks professional","Flux spatter, hot metal, and intense light can injure unprotected eyes","It is only for managers","It increases SEER"],"correct":1,"re":"Brazing produces glare and spatter; impact/shade-rated eyewear protects against burns, flying particles, and harmful light during fabrication.","rr":"Пайка даёт блеск и брызги; очки с рейтингом на удар/затемнение защищают от ожогов, летящих частиц и вредного света при изготовлении.","qr":"Защита глаз с рейтингом на удар и блеск пайки нужна, потому что:","optsr":["Это выглядит профессионально","Брызги флюса, горячий металл и яркий свет травмируют незащищённые глаза","Это только для руководителей","Это повышает SEER"],"qs":"Debe usarse proteccion ocular clasificada para impacto y para el resplandor del brazing porque:","optss":["Se ve profesional","Las salpicaduras de fundente, el metal caliente y la luz intensa pueden lesionar los ojos desprotegidos","Es solo para los gerentes","Aumenta el SEER"],"rs":"El brazing produce resplandor y salpicaduras; los lentes clasificados para impacto/con sombra protegen contra quemaduras, particulas voladoras y luz danina durante la fabricacion."},
  {"id":396,"sec":"Safety & Field Practices","q":"Cal/OSHA's written Injury and Illness Prevention Program (IIPP) must include:","opts":["A marketing plan","Hazard identification, correction, training, and communication procedures","Refrigerant prices","Only a logo"],"correct":1,"re":"Every California employer must maintain an IIPP that identifies and corrects hazards, trains employees, and documents safety communication and responsibility.","rr":"Каждый работодатель Калифорнии обязан вести IIPP, которая выявляет и устраняет опасности, обучает работников и документирует информирование и ответственность по безопасности.","qr":"Письменная программа предотвращения травм и болезней (IIPP) Cal/OSHA должна включать:","optsr":["Маркетинговый план","Выявление и устранение опасностей, обучение и процедуры информирования","Цены на хладагент","Только логотип"],"qs":"El Programa escrito de Prevencion de Lesiones y Enfermedades (IIPP) de Cal/OSHA debe incluir:","optss":["Un plan de marketing","Procedimientos de identificacion de peligros, correccion, capacitacion y comunicacion","Precios de refrigerante","Solo un logotipo"],"rs":"Todo empleador de California debe mantener un IIPP que identifique y corrija peligros, capacite a los empleados, y documente la comunicacion y la responsabilidad de seguridad."},
  {"id":397,"sec":"Safety & Field Practices","q":"A ladder set up to access a roof should extend above the roof edge by about:","opts":["About 3 feet (36 in) for a safe handhold","0 inches","It should be below the edge","10 feet"],"correct":0,"re":"Extend the ladder ~3 ft above the landing/roof edge and secure the top so the worker has a stable handhold when stepping on and off.","rr":"Выпускайте лестницу на ~3 фута над площадкой/краем крыши и закрепляйте верх, чтобы у работника был устойчивый хват при заходе и сходе.","qr":"Лестница для выхода на крышу должна выступать над краем крыши примерно на:","optsr":["Около 3 футов (36 дюймов) для безопасного хвата","0 дюймов","Ниже края","10 футов"],"qs":"Una escalera colocada para acceder a una azotea debe extenderse por encima del borde del techo aproximadamente:","optss":["Aproximadamente 3 pies (36 in) para un agarre seguro","0 pulgadas","Debe estar por debajo del borde","10 pies"],"rs":"Extienda la escalera ~3 pies por encima del descanso/borde del techo y asegure la parte superior para que el trabajador tenga un agarre estable al subir y bajar."},
  {"id":398,"sec":"Safety & Field Practices","q":"When entering an attic that may exceed safe temperatures in summer, the technician should:","opts":["Limit exposure, hydrate, ventilate, and watch for heat-illness symptoms","Work as long as possible","Wear heavy clothing","Skip water breaks"],"correct":0,"re":"Attics can reach dangerous heat; limit time, take water/rest breaks, ventilate if possible, and stop at the first signs of heat illness.","rr":"Чердаки могут достигать опасной жары; ограничьте время, делайте перерывы на воду/отдых, проветривайте при возможности и прекращайте при первых признаках теплового удара.","qr":"При входе на чердак, который летом может превышать безопасную температуру, техник должен:","optsr":["Ограничить пребывание, пить воду, проветривать и следить за симптомами теплового удара","Работать как можно дольше","Надеть тёплую одежду","Пропускать перерывы на воду"],"qs":"Al entrar en un atico que puede exceder temperaturas seguras en verano, el tecnico debe:","optss":["Limitar la exposicion, hidratarse, ventilar y vigilar los sintomas de enfermedad por calor","Trabajar el mayor tiempo posible","Usar ropa pesada","Omitir las pausas para tomar agua"],"rs":"Los aticos pueden alcanzar un calor peligroso; limite el tiempo, tome pausas para agua/descanso, ventile si es posible, y deten­gase ante los primeros signos de enfermedad por calor."},
  {"id":399,"sec":"Safety & Field Practices","q":"Recovered refrigerant and used compressor oil must be:","opts":["Mixed and burned","Poured down a drain","Managed and disposed of properly (oil as hazardous waste; refrigerant recovered/reclaimed)","Vented outdoors"],"correct":2,"re":"Never dump refrigerant or oil; recover refrigerant for reuse/reclaim and manage used oil as hazardous waste through approved disposal/recycling.","rr":"Никогда не сливайте хладагент или масло; хладагент откачивают для повторного использования/регенерации, а отработанное масло сдают как опасные отходы через одобренную утилизацию/переработку.","qr":"Откачанный хладагент и отработанное масло компрессора нужно:","optsr":["Смешать и сжечь","Слить в канализацию","Правильно собрать и утилизировать (масло как опасные отходы; хладагент - откачать/регенерировать)","Стравить наружу"],"qs":"El refrigerante recuperado y el aceite usado del compresor deben:","optss":["Mezclarse y quemarse","Verterse por un drenaje","Manejarse y desecharse adecuadamente (el aceite como residuo peligroso; el refrigerante recuperado/reciclado)","Ventilarse al exterior"],"rs":"Nunca tire refrigerante ni aceite; recupere el refrigerante para su reutilizacion/reciclaje y maneje el aceite usado como residuo peligroso mediante eliminacion/reciclaje aprobados."},
  {"id":400,"sec":"Safety & Field Practices","q":"The safest overall approach when any unfamiliar or hazardous condition is found on a job is to:","opts":["Remove the safety devices","Proceed quickly and hope","Ignore safety to save time","Stop, assess the hazard, follow the SDS/codes, and use proper PPE and procedures"],"correct":3,"re":"A stop-and-assess approach - reading the SDS, following code, and using correct PPE/lockout - prevents injuries; production never justifies bypassing safety.","rr":"Подход 'остановись и оцени' - чтение SDS, соблюдение норм и правильные СИЗ/блокировки - предотвращает травмы; выработка никогда не оправдывает обход безопасности.","qr":"Самый безопасный общий подход при обнаружении незнакомого или опасного условия на работе:","optsr":["Снять защитные устройства","Быстро действовать и надеяться","Игнорировать безопасность ради времени","Остановиться, оценить опасность, следовать SDS/нормам и применять нужные СИЗ и процедуры"],"qs":"El enfoque general mas seguro cuando se encuentra cualquier condicion desconocida o peligrosa en un trabajo es:","optss":["Retirar los dispositivos de seguridad","Proceder rapidamente y confiar en la suerte","Ignorar la seguridad para ahorrar tiempo","Detenerse, evaluar el peligro, seguir la SDS/codigos, y usar el EPP y los procedimientos adecuados"],"rs":"Un enfoque de detenerse y evaluar -leyendo la SDS, siguiendo el codigo, y usando el EPP/bloqueo correcto- previene lesiones; la produccion nunca justifica saltarse la seguridad."},
  {"id":401,"sec":"Principles & Load Calculations","q":"A pressure-temperature (P-T) chart is used by a technician to:","opts":["Size ductwork","Find the saturation temperature of a refrigerant at a measured pressure","Calculate wire size","Set the gas pressure"],"correct":1,"re":"A P-T chart lists the saturation (boiling/condensing) temperature of each refrigerant at a given pressure - essential for figuring superheat and subcooling.","rr":"P-T таблица даёт температуру насыщения (кипения/конденсации) каждого хладагента при заданном давлении - нужна для расчёта superheat и subcooling.","qr":"Таблицу давление-температура (P-T) техник использует, чтобы:","optsr":["Подбирать воздуховоды","Найти температуру насыщения хладагента при измеренном давлении","Рассчитать сечение провода","Задать давление газа"],"qs":"Un tecnico utiliza una tabla de presion-temperatura (P-T) para:","optss":["Dimensionar ductos","Encontrar la temperatura de saturacion de un refrigerante a una presion medida","Calcular el calibre del cable","Ajustar la presion del gas"],"rs":"Una tabla P-T indica la temperatura de saturacion (ebullicion/condensacion) de cada refrigerante a una presion dada, esencial para calcular el sobrecalentamiento y el subenfriamiento."},
  {"id":402,"sec":"Principles & Load Calculations","q":"Absolute pressure (psia) is equal to gauge pressure (psig) plus approximately:","opts":["100","14.7","32","0"],"correct":1,"re":"psia = psig + 14.7 (atmospheric pressure at sea level). Absolute pressure is used for compression-ratio and vacuum (micron) work.","rr":"psia = psig + 14.7 (атмосферное давление на уровне моря). Абсолютное давление используют для compression ratio и вакуума (микроны).","qr":"Абсолютное давление (psia) равно манометрическому (psig) плюс приблизительно:","optsr":["100","14.7","32","0"],"qs":"La presion absoluta (psia) es igual a la presion manometrica (psig) mas aproximadamente:","optss":["100","14.7","32","0"],"rs":"psia = psig + 14.7 (presion atmosferica al nivel del mar). La presion absoluta se usa para trabajos de relacion de compresion y de vacio (micrones)."},
  {"id":403,"sec":"Principles & Load Calculations","q":"The saturation temperature of a refrigerant is the temperature at which it:","opts":["Boils/condenses (changes state) at a given pressure","Reaches room temperature","Loses all heat","Freezes solid"],"correct":0,"re":"At saturation the refrigerant is changing state (liquid<->vapor) at the corresponding pressure; superheat and subcooling are measured relative to this temperature.","rr":"При насыщении хладагент меняет состояние (жидкость<->пар) при соответствующем давлении; superheat и subcooling отсчитывают от этой температуры.","qr":"Температура насыщения хладагента - это температура, при которой он:","optsr":["Кипит/конденсируется (меняет состояние) при данном давлении","Достигает комнатной температуры","Теряет всё тепло","Замерзает в твёрдое тело"],"qs":"La temperatura de saturacion de un refrigerante es la temperatura a la cual este:","optss":["Hierve/condensa (cambia de estado) a una presion dada","Alcanza la temperatura ambiente","Pierde todo el calor","Se congela por completo"],"rs":"En la saturacion el refrigerante esta cambiando de estado (liquido<->vapor) a la presion correspondiente; el sobrecalentamiento y el subenfriamiento se miden respecto a esta temperatura."},
  {"id":404,"sec":"Principles & Load Calculations","q":"Specific heat is the amount of heat needed to raise the temperature of one pound of a substance by:","opts":["10 degrees","1 degree F","Any amount","100 degrees"],"correct":1,"re":"Specific heat is BTU per pound per degree F. Water is the reference at 1.0 BTU/lb/F; air is about 0.24.","rr":"Удельная теплоёмкость - BTU на фунт на градус F. Вода - эталон 1.0 BTU/фунт/F; воздух около 0.24.","qr":"Удельная теплоёмкость - это количество тепла для нагрева одного фунта вещества на:","optsr":["10 градусов","1 градус F","Любую величину","100 градусов"],"qs":"El calor especifico es la cantidad de calor necesaria para elevar la temperatura de una libra de una sustancia en:","optss":["10 grados","1 grado F","Cualquier cantidad","100 grados"],"rs":"El calor especifico es BTU por libra por grado F. El agua es la referencia con 1.0 BTU/lb/F; el aire es aproximadamente 0.24."},
  {"id":405,"sec":"Principles & Load Calculations","q":"During a change of state (e.g., boiling), heat added to a refrigerant:","opts":["Changes its state at a constant temperature (latent heat)","Is lost entirely","Lowers its pressure","Raises its temperature rapidly"],"correct":0,"re":"Latent heat changes state without a temperature change; sensible heat changes temperature. In the evaporator, latent absorption does the cooling work.","rr":"Latent heat меняет состояние без изменения температуры; sensible heat меняет температуру. В испарителе именно latent-поглощение даёт охлаждение.","qr":"Во время смены состояния (например кипения) тепло, добавленное хладагенту:","optsr":["Меняет его состояние при постоянной температуре (latent heat)","Полностью теряется","Снижает его давление","Быстро повышает его температуру"],"qs":"Durante un cambio de estado (por ejemplo, la ebullicion), el calor agregado a un refrigerante:","optss":["Cambia su estado a temperatura constante (calor latente)","Se pierde por completo","Reduce su presion","Eleva su temperatura rapidamente"],"rs":"El calor latente cambia el estado sin un cambio de temperatura; el calor sensible cambia la temperatura. En el evaporador, la absorcion latente realiza el trabajo de enfriamiento."},
  {"id":406,"sec":"Principles & Load Calculations","q":"HSPF is a rating that measures a heat pump's:","opts":["Cooling efficiency","Seasonal heating efficiency","Refrigerant charge","Duct leakage"],"correct":1,"re":"HSPF (Heating Seasonal Performance Factor) rates heating-mode efficiency over a season; SEER/SEER2 rates cooling. Higher HSPF means more efficient heating.","rr":"HSPF (Heating Seasonal Performance Factor) оценивает эффективность в режиме нагрева за сезон; SEER/SEER2 - охлаждение. Выше HSPF - эффективнее нагрев.","qr":"HSPF - это рейтинг, измеряющий у теплового насоса:","optsr":["Эффективность охлаждения","Сезонную эффективность нагрева","Заправку хладагентом","Утечку воздуховодов"],"qs":"El HSPF es una clasificacion que mide, en una bomba de calor, su:","optss":["Eficiencia de enfriamiento","Eficiencia estacional de calefaccion","Carga de refrigerante","Fuga de aire en los ductos"],"rs":"El HSPF (Heating Seasonal Performance Factor) clasifica la eficiencia en modo calefaccion durante una temporada; el SEER/SEER2 clasifica el enfriamiento. Un HSPF mas alto significa calefaccion mas eficiente."},
  {"id":407,"sec":"Principles & Load Calculations","q":"The newer SEER2/EER2 efficiency ratings differ from SEER/EER mainly because they are tested at:","opts":["Colder outdoor temps","No airflow","A higher external static pressure (more realistic duct conditions)","Lower voltage"],"correct":2,"re":"SEER2/EER2 (effective 2023) use higher external static pressure in testing to better reflect real installed duct systems, so the numbers run a bit lower than old SEER.","rr":"SEER2/EER2 (с 2023) испытывают при более высоком внешнем статическом давлении, ближе к реальным дактам, поэтому значения чуть ниже старого SEER.","qr":"Новые рейтинги SEER2/EER2 отличаются от SEER/EER главным образом тем, что испытываются при:","optsr":["Более холодной улице","Нулевом расходе","Более высоком внешнем статическом давлении (реалистичнее условия дактов)","Меньшем напряжении"],"qs":"Las clasificaciones de eficiencia mas recientes SEER2/EER2 difieren del SEER/EER principalmente porque se prueban a:","optss":["Temperaturas exteriores mas frias","Sin flujo de aire","Una presion estatica externa mas alta (condiciones de ductos mas realistas)","Menor voltaje"],"rs":"El SEER2/EER2 (vigente desde 2023) usa una presion estatica externa mas alta en las pruebas para reflejar mejor los sistemas de ductos realmente instalados, por lo que los numeros resultan un poco mas bajos que el antiguo SEER."},
  {"id":408,"sec":"Principles & Load Calculations","q":"A gas furnace installed at high altitude typically must be derated by roughly:","opts":["About 4% per 1000 ft above ~2000 ft elevation","No change","Doubled","50% always"],"correct":0,"re":"Thinner air at altitude reduces combustion air; most manufacturers derate input about 4% per 1000 ft above 2000 ft (follow the rating-plate/manufacturer instructions).","rr":"Разрежённый воздух на высоте уменьшает воздух горения; большинство производителей снижают input около 4% на 1000 футов выше 2000 футов (по шильдику/инструкции).","qr":"Газовая печь на большой высоте обычно должна быть derate (снижение мощности) примерно на:","optsr":["Около 4% на 1000 футов выше ~2000 футов высоты","Без изменений","Удвоена","Всегда 50%"],"qs":"Un calefactor (furnace) de gas instalado a gran altitud normalmente debe reducirse en su capacidad (derate) en aproximadamente:","optss":["Cerca de 4% por cada 1000 ft sobre ~2000 ft de elevacion","Sin cambio","Al doble","50% siempre"],"rs":"El aire mas delgado a la altitud reduce el aire de combustion; la mayoria de los fabricantes reducen la entrada (input) cerca de 4% por cada 1000 ft sobre 2000 ft (siga la placa de clasificacion/instrucciones del fabricante)."},
  {"id":409,"sec":"Principles & Load Calculations","q":"The equal-friction method of duct design sizes ducts to maintain a constant:","opts":["Air temperature","Refrigerant pressure","Friction loss per 100 ft of duct","Voltage"],"correct":2,"re":"Equal-friction design keeps the friction rate (e.g., 0.1 in WC per 100 ft) constant throughout, sizing each section to that target for the required CFM.","rr":"Equal-friction держит friction rate (например 0.1 in WC на 100 футов) постоянным по всей системе, подбирая каждый участок под этот таргет для нужного CFM.","qr":"Метод равного трения (equal-friction) при проектировании воздуховодов поддерживает постоянным:","optsr":["Температуру воздуха","Давление хладагента","Потери на трение на 100 футов дакта","Напряжение"],"qs":"El metodo de friccion igual (equal-friction) para el diseno de ductos los dimensiona para mantener constante un valor de:","optss":["Temperatura del aire","Presion del refrigerante","Perdida por friccion por cada 100 ft de ducto","Voltaje"],"rs":"El diseno de friccion igual mantiene constante la tasa de friccion (por ejemplo, 0.1 in WC por cada 100 ft) en todo el sistema, dimensionando cada seccion a ese objetivo para el CFM requerido."},
  {"id":410,"sec":"Principles & Load Calculations","q":"Standard air used in HVAC calculations is assumed to have a density of about:","opts":["14.7 lb/ft3","0.0 lb/ft3","0.075 lb/ft3","1.0 lb/ft3"],"correct":2,"re":"Standard air is ~0.075 lb/ft3 (70 F, sea level, 50% RH). The 1.08 and 4.5 constants are based on this; high altitude/temperature requires correction.","rr":"Стандартный воздух ~0.075 фунт/фт3 (70 F, уровень моря, 50% RH). Коэффициенты 1.08 и 4.5 основаны на этом; высота/температура требуют поправки.","qr":"Стандартный воздух в расчётах HVAC принимают с плотностью около:","optsr":["14.7 фунт/фт3","0.0 фунт/фт3","0.075 фунт/фт3","1.0 фунт/фт3"],"qs":"Se supone que el aire estandar usado en los calculos de HVAC tiene una densidad de aproximadamente:","optss":["14.7 lb/ft3","0.0 lb/ft3","0.075 lb/ft3","1.0 lb/ft3"],"rs":"El aire estandar es ~0.075 lb/ft3 (70 F, nivel del mar, 50% RH). Las constantes 1.08 y 4.5 se basan en esto; la gran altitud/temperatura requiere correccion."},
  {"id":411,"sec":"Principles & Load Calculations","q":"An air-side economizer saves energy by:","opts":["Using cool outdoor air for free cooling when conditions allow","Closing all dampers","Running the heat","Adding refrigerant"],"correct":0,"re":"When outdoor air is cool/dry enough, an economizer brings in outside air to cool the space instead of running the compressor, reducing energy use.","rr":"Когда наружный воздух достаточно прохладный/сухой, экономайзер впускает его для охлаждения помещения вместо работы компрессора, снижая расход энергии.","qr":"Воздушный экономайзер экономит энергию, используя:","optsr":["Прохладный наружный воздух для бесплатного охлаждения, когда условия позволяют","Закрытие всех заслонок","Нагрев","Добавление хладагента"],"qs":"Un economizador del lado del aire (air-side economizer) ahorra energia al:","optss":["Usar aire exterior frio para enfriamiento gratuito cuando las condiciones lo permiten","Cerrar todas las compuertas","Encender la calefaccion","Agregar refrigerante"],"rs":"Cuando el aire exterior es lo suficientemente frio/seco, un economizador introduce aire del exterior para enfriar el espacio en lugar de operar el compresor, reduciendo el consumo de energia."},
  {"id":412,"sec":"Principles & Load Calculations","q":"An ERV (energy recovery ventilator) is used to:","opts":["Replace the furnace","Increase head pressure","Recover heat (and moisture) from exhaust air to precondition incoming fresh air","Add refrigerant"],"correct":2,"re":"An ERV transfers heat and moisture between exhaust and intake air, providing fresh-air ventilation while reducing the heating/cooling load of that ventilation.","rr":"ERV передаёт тепло и влагу между вытяжкой и притоком, обеспечивая вентиляцию свежим воздухом и снижая нагрузку отопления/охлаждения от этой вентиляции.","qr":"ERV (рекуператор энергии) применяют, чтобы:","optsr":["Заменить печь","Поднять давление нагнетания","Возвращать тепло (и влагу) из вытяжного воздуха для подготовки притока","Добавить хладагент"],"qs":"Un ERV (ventilador de recuperacion de energia) se utiliza para:","optss":["Reemplazar el calefactor (furnace)","Aumentar la presion de descarga (head pressure)","Recuperar calor (y humedad) del aire de escape para preacondicionar el aire fresco entrante","Agregar refrigerante"],"rs":"Un ERV transfiere calor y humedad entre el aire de escape y el de entrada, proporcionando ventilacion de aire fresco mientras reduce la carga de calefaccion/enfriamiento de esa ventilacion."},
  {"id":413,"sec":"Principles & Load Calculations","q":"Make-up air must be provided when a building has large exhaust fans in order to:","opts":["Increase the SEER","Replace exhausted air and prevent negative pressure/backdrafting","Lower the gas pressure","Add refrigerant"],"correct":1,"re":"Without make-up air, big exhaust fans depressurize the building, which can backdraft combustion appliances and pull in unconditioned air. Provide balanced make-up air.","rr":"Без make-up воздуха мощные вытяжки создают разрежение, что вызывает обратную тягу у топливных приборов и подсос неподготовленного воздуха. Обеспечьте сбалансированный приток.","qr":"Подпиточный (make-up) воздух нужен, когда в здании мощные вытяжки, чтобы:","optsr":["Повысить SEER","Заменить удаляемый воздух и не допустить разрежения/обратной тяги","Снизить давление газа","Добавить хладагент"],"qs":"Se debe proporcionar aire de reposicion (make-up air) cuando un edificio tiene grandes ventiladores de escape con el fin de:","optss":["Aumentar el SEER","Reemplazar el aire extraido y prevenir la presion negativa/contratiro (backdrafting)","Reducir la presion del gas","Agregar refrigerante"],"rs":"Sin aire de reposicion, los grandes ventiladores de escape despresurizan el edificio, lo que puede causar contratiro en los aparatos de combustion y atraer aire no acondicionado. Proporcione aire de reposicion balanceado."},
  {"id":414,"sec":"Principles & Load Calculations","q":"A bypass damper in a zoned system is used to:","opts":["Increase the load","Relieve excess air pressure when only a few zones call","Add refrigerant","Close the gas valve"],"correct":1,"re":"When only small zones are open, a bypass damper relieves excess airflow to prevent high static pressure and noise, though proper zone design limits its need.","rr":"Когда открыты лишь малые зоны, bypass-заслонка сбрасывает избыток воздуха, предотвращая высокое статическое давление и шум, хотя грамотная зональность снижает её необходимость.","qr":"Перепускная (bypass) заслонка в зональной системе нужна, чтобы:","optsr":["Увеличить нагрузку","Сбросить избыточное давление воздуха, когда открыто мало зон","Добавить хладагент","Закрыть газовый клапан"],"qs":"Una compuerta de derivacion (bypass damper) en un sistema zonificado se utiliza para:","optss":["Aumentar la carga","Aliviar el exceso de presion de aire cuando solo unas pocas zonas estan activas","Agregar refrigerante","Cerrar la valvula de gas"],"rs":"Cuando solo hay zonas pequenas abiertas, una compuerta de derivacion alivia el exceso de flujo de aire para evitar alta presion estatica y ruido, aunque un diseno de zonas adecuado limita su necesidad."},
  {"id":415,"sec":"Principles & Load Calculations","q":"In a home with central returns, a door undercut or transfer grille is provided so that:","opts":["Gas can vent","Air can return from closed rooms back to the return (pressure balance)","Refrigerant flows","The duct gets smaller"],"correct":1,"re":"Closed-door rooms need a return path (undercut/transfer grille/jump duct); without it, supply air pressurizes the room and starves return airflow.","rr":"Комнатам с закрытой дверью нужен путь возврата (подрез/transfer-решётка/jump-дакт); без него приток создаёт избыточное давление в комнате и душит обратку.","qr":"В доме с центральной обраткой подрез двери или transfer-решётку делают, чтобы:","optsr":["Газ выходил","Воздух мог вернуться из закрытых комнат к обратке (баланс давления)","Тёк хладагент","Дакт стал меньше"],"qs":"En una vivienda con retornos centrales, se proporciona un corte inferior de puerta (door undercut) o una rejilla de transferencia para que:","optss":["El gas pueda ventilarse","El aire pueda retornar desde las habitaciones cerradas de vuelta al retorno (balance de presion)","Fluya el refrigerante","El ducto se haga mas pequeno"],"rs":"Las habitaciones con la puerta cerrada necesitan una trayectoria de retorno (corte inferior/rejilla de transferencia/jump duct); sin ella, el aire de suministro presuriza la habitacion y restringe el flujo de aire de retorno."},
  {"id":416,"sec":"Principles & Load Calculations","q":"To convert electrical power in kilowatts to BTU/h, multiply kW by approximately:","opts":["12000","3412","100","746"],"correct":1,"re":"1 kW = 3412 BTU/h. This converts electric-heat or equipment kW into heat output/load (e.g., a 5 kW strip heater = ~17,060 BTU/h).","rr":"1 кВт = 3412 BTU/ч. Так переводят электронагрев или оборудование в кВт в теплоотдачу/нагрузку (например ТЭН 5 кВт = ~17 060 BTU/ч).","qr":"Чтобы перевести электрическую мощность из киловатт в BTU/ч, умножьте кВт примерно на:","optsr":["12000","3412","100","746"],"qs":"Para convertir la potencia electrica en kilovatios a BTU/h, multiplique los kW por aproximadamente:","optss":["12000","3412","100","746"],"rs":"1 kW = 3412 BTU/h. Esto convierte los kW de calefaccion electrica o de equipos en salida de calor/carga (por ejemplo, un calentador de resistencia de 5 kW = ~17,060 BTU/h)."},
  {"id":417,"sec":"Principles & Load Calculations","q":"For natural-gas billing/sizing, one therm equals about:","opts":["3412 BTU","100,000 BTU","12,000 BTU","1000 BTU"],"correct":1,"re":"A therm is 100,000 BTU of gas energy. Knowing therms and meter clocking lets a tech relate fuel use to furnace input.","rr":"Therm - это 100 000 BTU энергии газа. Зная термы и clocking счётчика, техник связывает расход топлива с input печи.","qr":"Для учёта/подбора природного газа один therm равен примерно:","optsr":["3412 BTU","100 000 BTU","12 000 BTU","1000 BTU"],"qs":"Para la facturacion/dimensionamiento de gas natural, un therm equivale a aproximadamente:","optss":["3412 BTU","100,000 BTU","12,000 BTU","1000 BTU"],"rs":"Un therm es 100,000 BTU de energia de gas. Conocer los therms y la lectura del medidor permite a un tecnico relacionar el uso de combustible con la entrada (input) del calefactor."},
  {"id":418,"sec":"Principles & Load Calculations","q":"EER and COP are related by the expression:","opts":["EER = COP / 100","EER = COP","EER = COP x 3.412","EER = COP + 12"],"correct":2,"re":"EER (BTU/h per watt) = COP x 3.412, since 1 watt = 3.412 BTU/h. COP is the dimensionless ratio of heat moved to energy input.","rr":"EER (BTU/ч на ватт) = COP x 3.412, т.к. 1 ватт = 3.412 BTU/ч. COP - безразмерное отношение перемещённого тепла к затраченной энергии.","qr":"EER и COP связаны выражением:","optsr":["EER = COP / 100","EER = COP","EER = COP x 3.412","EER = COP + 12"],"qs":"El EER y el COP se relacionan mediante la expresion:","optss":["EER = COP / 100","EER = COP","EER = COP x 3.412","EER = COP + 12"],"rs":"EER (BTU/h por vatio) = COP x 3.412, ya que 1 vatio = 3.412 BTU/h. El COP es la relacion adimensional entre el calor desplazado y la energia consumida."},
  {"id":419,"sec":"Principles & Load Calculations","q":"In California Title 24, a CF1R (Certificate of Compliance) is generally completed at the:","opts":["Sale of the home","Final inspection only","Design/permit-application stage","Demolition"],"correct":2,"re":"CF1R documents the design meets Title 24; CF2R is the installation certificate by the contractor; CF3R is the HERS rater verification - each at its stage.","rr":"CF1R документирует соответствие проекта Title 24; CF2R - сертификат монтажа от подрядчика; CF3R - проверка HERS-оценщиком - каждая на своём этапе.","qr":"В Title 24 (Калифорния) форму CF1R (Certificate of Compliance) обычно заполняют на этапе:","optsr":["Продажи дома","Только финальной инспекции","Проектирования/подачи на разрешение","Сноса"],"qs":"En el Title 24 de California, un CF1R (Certificado de Cumplimiento) generalmente se completa en la etapa de:","optss":["Venta de la vivienda","Inspeccion final unicamente","Diseno/solicitud del permiso","Demolicion"],"rs":"El CF1R documenta que el diseno cumple con el Title 24; el CF2R es el certificado de instalacion del contratista; el CF3R es la verificacion del evaluador HERS, cada uno en su etapa."},
  {"id":420,"sec":"Principles & Load Calculations","q":"The Noise Criteria (NC) level matters when selecting registers/diffusers because:","opts":["It sets refrigerant charge","High air velocity through a register creates objectionable noise","It changes the voltage","It sizes the breaker"],"correct":1,"re":"Registers/diffusers are selected so face velocity stays below the noise threshold for the space (bedrooms need a lower NC); oversizing airflow causes whistling.","rr":"Решётки/диффузоры подбирают так, чтобы скорость на лицевой части была ниже порога шума для помещения (спальням нужен меньший NC); избыток расхода даёт свист.","qr":"Уровень Noise Criteria (NC) важен при подборе решёток/диффузоров, потому что:","optsr":["Он задаёт заправку хладагентом","Высокая скорость воздуха через решётку создаёт неприятный шум","Меняет напряжение","Подбирает автомат"],"qs":"El nivel de Criterio de Ruido (NC) importa al seleccionar registros/difusores porque:","optss":["Establece la carga de refrigerante","La alta velocidad del aire a traves de un registro genera ruido molesto","Cambia el voltaje","Dimensiona el interruptor (breaker)"],"rs":"Los registros/difusores se seleccionan para que la velocidad frontal se mantenga por debajo del umbral de ruido del espacio (los dormitorios necesitan un NC mas bajo); un flujo de aire sobredimensionado provoca silbidos."},
  {"id":421,"sec":"Principles & Load Calculations","q":"In a humid climate, designing for better dehumidification often means selecting airflow toward the ___ end of the range:","opts":["Maximum possible","Zero","Higher (450 CFM/ton)","Lower (about 350 CFM/ton)"],"correct":3,"re":"Lower airflow per ton lowers the coil temperature and increases moisture removal (latent capacity), improving comfort in humid conditions.","rr":"Меньший расход на тонну снижает температуру испарителя и усиливает удаление влаги (latent), повышая комфорт во влажных условиях.","qr":"Во влажном климате для лучшего осушения часто выбирают расход ближе к ___ краю диапазона:","optsr":["Максимально возможному","Нулю","Верхнему (450 CFM/тонна)","Нижнему (около 350 CFM/тонна)"],"qs":"En un clima humedo, disenar para una mejor deshumidificacion a menudo significa seleccionar el flujo de aire hacia el extremo ___ del rango:","optss":["Maximo posible","Cero","Mas alto (450 CFM/ton)","Mas bajo (alrededor de 350 CFM/ton)"],"rs":"Un menor flujo de aire por tonelada reduce la temperatura del serpentin y aumenta la eliminacion de humedad (capacidad latente), mejorando el confort en condiciones humedas."},
  {"id":422,"sec":"Principles & Load Calculations","q":"Adding a contingency to a bid is intended to:","opts":["Guarantee a loss","Replace the permit","Cover unforeseen conditions and risk so the job stays profitable","Lower the price below cost"],"correct":2,"re":"A contingency allowance buffers against surprises (hidden conditions, price changes); it protects margin without relying on guesswork during the job.","rr":"Резерв (contingency) защищает от сюрпризов (скрытые условия, рост цен); он сохраняет маржу без догадок по ходу работы.","qr":"Добавление резерва (contingency) в заявку призвано:","optsr":["Гарантировать убыток","Заменить разрешение","Покрыть непредвиденные условия и риск, чтобы работа осталась прибыльной","Снизить цену ниже себестоимости"],"qs":"Agregar una contingencia a una cotizacion tiene como fin:","optss":["Garantizar una perdida","Reemplazar el permiso","Cubrir condiciones imprevistas y riesgos para que el trabajo siga siendo rentable","Bajar el precio por debajo del costo"],"rs":"Una reserva de contingencia amortigua las sorpresas (condiciones ocultas, cambios de precio); protege el margen sin depender de suposiciones durante el trabajo."},
  {"id":423,"sec":"Principles & Load Calculations","q":"Under California energy code, ducts in unconditioned spaces generally must be insulated to at least about:","opts":["R-8","R-30","No insulation","R-2"],"correct":0,"re":"Title 24 typically requires about R-8 duct insulation in unconditioned spaces (attics) to limit conductive losses; verify the current code value for the climate zone.","rr":"Title 24 обычно требует около R-8 для дактов в неотапливаемых зонах (чердаках), чтобы ограничить теплопотери; сверьтесь с актуальным значением для климатической зоны.","qr":"По энергокодексу Калифорнии воздуховоды в неотапливаемых зонах обычно должны быть утеплены минимум примерно до:","optsr":["R-8","R-30","Без утепления","R-2"],"qs":"Segun el codigo de energia de California, los ductos en espacios no acondicionados generalmente deben aislarse al menos a aproximadamente:","optss":["R-8","R-30","Sin aislamiento","R-2"],"rs":"El Title 24 normalmente requiere alrededor de R-8 de aislamiento de ductos en espacios no acondicionados (aticos) para limitar las perdidas por conduccion; verifique el valor de codigo vigente para la zona climatica."},
  {"id":424,"sec":"Principles & Load Calculations","q":"A 'block load' calculation differs from a room-by-room calculation in that it:","opts":["Ignores the climate","Is only for gas","Sizes each register","Sizes the whole-building equipment but not individual room airflow"],"correct":3,"re":"Block load gives the total equipment size; a room-by-room (Manual J detailed) is still needed to size ducts and distribute airflow to each room.","rr":"Block load даёт общий размер оборудования; покомнатный (детальный Manual J) всё равно нужен для подбора дактов и распределения расхода по комнатам.","qr":"Расчёт 'block load' отличается от покомнатного тем, что он:","optsr":["Игнорирует климат","Только для газа","Подбирает каждую решётку","Подбирает оборудование на всё здание, но не расход по комнатам"],"qs":"Un calculo de 'carga en bloque' (block load) difiere de un calculo habitacion por habitacion en que:","optss":["Ignora el clima","Es solo para gas","Dimensiona cada registro","Dimensiona el equipo de todo el edificio pero no el flujo de aire de cada habitacion"],"rs":"La carga en bloque da el tamano total del equipo; aun se necesita un calculo habitacion por habitacion (Manual J detallado) para dimensionar los ductos y distribuir el flujo de aire a cada habitacion."},
  {"id":425,"sec":"Principles & Load Calculations","q":"Oversizing cooling equipment typically results in:","opts":["Short cycling, poor humidity control, and reduced comfort/efficiency","Longer run times","Better dehumidification","Lower noise"],"correct":0,"re":"Oversized AC satisfies the thermostat quickly (short cycles) before removing enough moisture, hurting comfort, efficiency, and equipment life - why Manual J/S sizing matters.","rr":"Завышенный AC быстро удовлетворяет термостат (короткие циклы), не успев убрать влагу, что вредит комфорту, КПД и ресурсу - поэтому важен подбор по Manual J/S.","qr":"Завышение охлаждающего оборудования обычно приводит к:","optsr":["Короткому циклированию, плохому контролю влажности и снижению комфорта/КПД","Более длинным циклам работы","Лучшему осушению","Меньшему шуму"],"qs":"El sobredimensionamiento del equipo de enfriamiento normalmente resulta en:","optss":["Ciclos cortos, mal control de humedad y menor confort/eficiencia","Tiempos de operacion mas largos","Mejor deshumidificacion","Menor ruido"],"rs":"Un aire acondicionado sobredimensionado satisface el termostato rapidamente (ciclos cortos) antes de eliminar suficiente humedad, perjudicando el confort, la eficiencia y la vida del equipo, por eso importa el dimensionamiento Manual J/S."},
  {"id":426,"sec":"Fabrication & Installation","q":"Before flaring copper tubing, the end should be deburred/reamed so that:","opts":["The wall is thinner","The flare forms evenly and seals without a leak path","Brazing is faster","The tube is shorter"],"correct":1,"re":"Burrs cause an uneven flare and leak paths; deburr lightly (without removing much wall) so the flare seats evenly against the fitting.","rr":"Заусенцы дают неровную раздачу и пути утечки; снимите заусенцы слегка (без съёма стенки), чтобы flare ровно сел на фитинг.","qr":"Перед раздачей (flare) медной трубки торец нужно зачистить от заусенцев, чтобы:","optsr":["Стенка стала тоньше","Раздача формировалась ровно и герметизировала без пути утечки","Пайка шла быстрее","Трубка стала короче"],"qs":"Antes de abocinar (flaring) tuberia de cobre, el extremo debe desbarbarse/escariarse para que:","optss":["La pared sea mas delgada","El abocinado se forme de manera uniforme y selle sin una via de fuga","El soldado fuerte (brazing) sea mas rapido","El tubo sea mas corto"],"rs":"Las rebabas provocan un abocinado desigual y vias de fuga; desbarbe ligeramente (sin remover mucha pared) para que el abocinado asiente uniformemente contra la conexion."},
  {"id":427,"sec":"Fabrication & Installation","q":"Swaging two pieces of copper tubing allows the technician to:","opts":["Add refrigerant","Bend without a tool","Join them without a separate coupling (one end expanded over the other)","Increase the SEER"],"correct":2,"re":"A swage tool expands one tube end to slip over the matching tube, forming a brazed joint without buying a coupling.","rr":"Инструмент для свагирования расширяет конец одной трубки, чтобы он наделся на ответную, образуя паяное соединение без покупки муфты.","qr":"Свагирование (swaging) двух кусков медной трубки позволяет технику:","optsr":["Добавить хладагент","Гнуть без инструмента","Соединить их без отдельной муфты (один конец расширен поверх другого)","Повысить SEER"],"qs":"El abocardado por expansion (swaging) de dos piezas de tuberia de cobre le permite al tecnico:","optss":["Agregar refrigerante","Doblar sin una herramienta","Unirlas sin un acople separado (un extremo expandido sobre el otro)","Aumentar el SEER"],"rs":"Una herramienta de expansion (swage) ensancha el extremo de un tubo para deslizarlo sobre el tubo correspondiente, formando una union soldada con soldadura fuerte sin comprar un acople."},
  {"id":428,"sec":"Fabrication & Installation","q":"To bend soft copper tubing without kinking it, the technician should use:","opts":["His foot","Pliers","A hammer","A tube bender (spring or lever) respecting the minimum radius"],"correct":3,"re":"A tube bender supports the wall through the bend; kinks restrict flow and weaken the tube. Stay above the minimum bend radius.","rr":"Трубогиб поддерживает стенку на изгибе; заломы сужают поток и ослабляют трубку. Соблюдайте минимальный радиус гиба.","qr":"Чтобы согнуть мягкую медную трубку без залома, техник должен использовать:","optsr":["Ногу","Плоскогубцы","Молоток","Трубогиб (пружинный или рычажный) с соблюдением минимального радиуса"],"qs":"Para doblar tuberia de cobre blando sin retorcerla, el tecnico debe usar:","optss":["Su pie","Pinzas","Un martillo","Un dobladora de tubos (de resorte o de palanca) respetando el radio minimo"],"rs":"Una dobladora de tubos soporta la pared durante el doblez; los pliegues restringen el flujo y debilitan el tubo. Mantengase por encima del radio minimo de doblez."},
  {"id":429,"sec":"Fabrication & Installation","q":"Press-type refrigerant fittings (e.g., RLS) are an alternative to brazing that:","opts":["Use solder","Require an open flame","Are only for water","Form a permanent joint with a press tool and an O-ring, no flame"],"correct":3,"re":"Press fittings make flameless refrigerant joints with a pressing tool - useful where a torch is hazardous; follow the listing and prep requirements.","rr":"Press-фитинги делают беспламенные соединения хладагента прессовым инструментом - полезно там, где горелка опасна; соблюдайте листинг и требования подготовки.","qr":"Press-фитинги для хладагента (например RLS) - это альтернатива пайке, которая:","optsr":["Использует припой","Требует открытого огня","Только для воды","Создаёт постоянное соединение прессом и уплотнением, без огня"],"qs":"Las conexiones de refrigerante de tipo prensado (press-type, por ejemplo RLS) son una alternativa al soldado fuerte (brazing) que:","optss":["Usan soldadura blanda","Requieren una llama abierta","Son solo para agua","Forman una union permanente con una herramienta de prensado y un O-ring, sin llama"],"rs":"Las conexiones prensadas hacen uniones de refrigerante sin llama con una herramienta de prensado, utiles donde una antorcha es peligrosa; siga el listado y los requisitos de preparacion."},
  {"id":430,"sec":"Fabrication & Installation","q":"A new gas-pipe connection is checked for leaks using:","opts":["Soap-bubble solution or an electronic gas detector","Refrigerant","An open flame","Plain water"],"correct":0,"re":"Never use a flame to find gas leaks. Apply leak-detection (soap) solution or use a combustible-gas detector with the line pressurized.","rr":"Никогда не ищите утечки газа пламенем. Нанесите мыльный раствор или используйте детектор горючего газа при наддутой линии.","qr":"Новое соединение газовой трубы проверяют на утечки с помощью:","optsr":["Мыльного раствора или электронного газового детектора","Хладагента","Открытого огня","Простой воды"],"qs":"Una nueva conexion de tuberia de gas se verifica en busca de fugas usando:","optss":["Solucion de pompas de jabon o un detector electronico de gas","Refrigerante","Una llama abierta","Agua simple"],"rs":"Nunca use una llama para encontrar fugas de gas. Aplique solucion de deteccion de fugas (jabon) o use un detector de gas combustible con la linea presurizada."},
  {"id":431,"sec":"Fabrication & Installation","q":"After connecting a new gas line, air must be purged from the piping to:","opts":["Ensure the appliance gets pure gas and lights reliably","Lower the voltage","Increase static pressure","Add refrigerant"],"correct":0,"re":"Trapped air causes ignition problems and unsafe combustion; purge the line (safely, to outdoors) until gas is present before lighting the appliance.","rr":"Запертый воздух вызывает проблемы розжига и небезопасное горение; стравите линию (безопасно, наружу), пока не пойдёт газ, до розжига прибора.","qr":"После подключения новой газовой линии воздух нужно стравить из трубопровода, чтобы:","optsr":["Прибор получал чистый газ и надёжно зажигался","Снизить напряжение","Повысить статическое давление","Добавить хладагент"],"qs":"Despues de conectar una nueva linea de gas, se debe purgar el aire de la tuberia para:","optss":["Asegurar que el aparato reciba gas puro y encienda de forma confiable","Reducir el voltaje","Aumentar la presion estatica","Agregar refrigerante"],"rs":"El aire atrapado causa problemas de ignicion y combustion insegura; purgue la linea (de forma segura, hacia el exterior) hasta que haya gas presente antes de encender el aparato."},
  {"id":432,"sec":"Fabrication & Installation","q":"CSST (corrugated stainless-steel gas tubing) generally requires:","opts":["No grounding","Refrigerant","Painting","Bonding to the grounding system (lightning protection)"],"correct":3,"re":"Code requires CSST to be bonded to reduce the risk of lightning-induced arcing perforating the thin tubing; follow the manufacturer's bonding instructions.","rr":"Нормы требуют bonding CSST для снижения риска дугообразования от молнии, прожигающего тонкую трубку; следуйте инструкции производителя по bonding.","qr":"Гофрированная нержавеющая газовая трубка (CSST) обычно требует:","optsr":["Без заземления","Хладагента","Покраски","Уравнивания с системой заземления (защита от молнии)"],"qs":"La CSST (tuberia de gas de acero inoxidable corrugado) generalmente requiere:","optss":["Sin conexion a tierra","Refrigerante","Pintura","Conexion equipotencial (bonding) al sistema de puesta a tierra (proteccion contra rayos)"],"rs":"El codigo requiere que la CSST este conectada equipotencialmente (bonded) para reducir el riesgo de que un arco inducido por un rayo perfore la tuberia delgada; siga las instrucciones de bonding del fabricante."},
  {"id":433,"sec":"Fabrication & Installation","q":"A time-delay (dual-element) fuse is often used on motor circuits because it:","opts":["Trips instantly on any current","Tolerates brief motor inrush current but protects against sustained overload","Increases voltage","Adds refrigerant"],"correct":1,"re":"Motors draw high starting (inrush) current briefly; a time-delay fuse rides through that surge while still protecting against a real, sustained overcurrent.","rr":"Двигатели кратко тянут большой пусковой ток; предохранитель с задержкой пропускает этот всплеск, но защищает от реальной длительной перегрузки.","qr":"Предохранитель с задержкой (dual-element) часто ставят на двигательные цепи, потому что он:","optsr":["Срабатывает мгновенно на любой ток","Терпит кратковременный пусковой ток, но защищает от длительной перегрузки","Повышает напряжение","Добавляет хладагент"],"qs":"Un fusible de retardo de tiempo (de doble elemento) se usa a menudo en circuitos de motor porque:","optss":["Se dispara instantaneamente ante cualquier corriente","Tolera la breve corriente de arranque (inrush) del motor pero protege contra sobrecarga sostenida","Aumenta el voltaje","Agrega refrigerante"],"rs":"Los motores consumen brevemente una alta corriente de arranque (inrush); un fusible de retardo de tiempo soporta ese pico mientras sigue protegiendo contra una sobrecorriente real y sostenida."},
  {"id":434,"sec":"Fabrication & Installation","q":"When terminating an aluminum conductor, the technician should:","opts":["Apply antioxidant compound and torque to the specified value","Use it like copper with no prep","Solder it","Leave it loose"],"correct":0,"re":"Aluminum oxidizes and creeps; use listed terminals, antioxidant paste where required, and torque to spec to prevent loose, overheating connections.","rr":"Алюминий окисляется и 'течёт'; используйте листингованные клеммы, антиокислительную пасту где требуется и момент по спецификации, чтобы избежать слабых перегревающихся соединений.","qr":"При оконцевании алюминиевого проводника техник должен:","optsr":["Нанести антиокислительный состав и затянуть на заданный момент","Использовать как медь без подготовки","Запаять","Оставить слабым"],"qs":"Al terminar un conductor de aluminio, el tecnico debe:","optss":["Aplicar compuesto antioxidante y aplicar el torque al valor especificado","Usarlo como el cobre sin preparacion","Soldarlo con soldadura blanda","Dejarlo suelto"],"rs":"El aluminio se oxida y fluye (creep); use terminales listadas, pasta antioxidante donde se requiera y aplique el torque a la especificacion para evitar conexiones sueltas y sobrecalentadas."},
  {"id":435,"sec":"Fabrication & Installation","q":"A 125 V receptacle installed outdoors or on a rooftop for service must be:","opts":["Removed in winter","Unprotected","GFCI-protected and in a weatherproof (in-use) cover","240 V only"],"correct":2,"re":"Outdoor/rooftop and other wet-location receptacles require GFCI protection and a weatherproof in-use cover for shock protection and weather resistance.","rr":"Розетки снаружи/на крыше и в других влажных местах требуют GFCI-защиты и погодозащищённой крышки in-use для защиты от удара током и погоды.","qr":"Розетка 125 В, установленная снаружи или на крыше для обслуживания, должна быть:","optsr":["Снята зимой","Без защиты","С GFCI-защитой и в погодозащищённой (in-use) крышке","Только 240 В"],"qs":"Un receptaculo de 125 V instalado en exteriores o en una azotea para servicio debe estar:","optss":["Retirado en invierno","Sin proteccion","Protegido por GFCI y con una cubierta a prueba de intemperie (de uso/in-use)","Solo a 240 V"],"rs":"Los receptaculos en exteriores/azoteas y otras ubicaciones humedas requieren proteccion GFCI y una cubierta a prueba de intemperie de uso (in-use) para proteccion contra descargas y resistencia a la intemperie."},
  {"id":436,"sec":"Fabrication & Installation","q":"A control transformer with multiple primary taps (e.g., 208/240) is wired by:","opts":["Ignoring voltage","Connecting the tap that matches the actual supply voltage","Shorting all taps","Using any tap"],"correct":1,"re":"Match the primary tap to the measured supply (208 vs 240) so the secondary delivers proper 24 V; using the wrong tap gives high/low control voltage and faults.","rr":"Подбирайте первичный отвод под измеренное питание (208 или 240), чтобы вторичка давала правильные 24 В; неверный отвод даёт высокое/низкое управляющее напряжение и сбои.","qr":"Управляющий трансформатор с несколькими первичными отводами (например 208/240) подключают:","optsr":["Игнорируя напряжение","Подключая отвод, соответствующий реальному напряжению питания","Закоротив все отводы","Используя любой отвод"],"qs":"Un transformador de control con multiples derivaciones (taps) primarias (por ejemplo, 208/240) se conecta:","optss":["Ignorando el voltaje","Conectando la derivacion (tap) que coincide con el voltaje de suministro real","Cortocircuitando todas las derivaciones","Usando cualquier derivacion"],"rs":"Haga coincidir la derivacion primaria con el suministro medido (208 vs 240) para que el secundario entregue los 24 V adecuados; usar la derivacion equivocada da un voltaje de control alto/bajo y fallas."},
  {"id":437,"sec":"Fabrication & Installation","q":"Class 2 low-voltage control wiring should generally be:","opts":["Separated from line-voltage conductors unless rated/divided per code","Run in the same conduit as line voltage","Spliced to line voltage","Left energized to ground"],"correct":0,"re":"Keep Class 2 (24 V) wiring separated from line-voltage conductors (or use barriers/rated cable) to avoid hazardous voltage transfer and interference.","rr":"Держите проводку Class 2 (24 В) отдельно от сетевых проводников (или используйте барьеры/листингованный кабель), чтобы избежать опасного переноса напряжения и помех.","qr":"Низковольтную управляющую проводку Class 2 обычно следует:","optsr":["Отделять от сетевых проводников, если нет рейтинга/разделения по нормам","Прокладывать в одном кабель-канале с сетевым напряжением","Сращивать с сетевым напряжением","Оставлять под напряжением на землю"],"qs":"El cableado de control de bajo voltaje Clase 2 generalmente debe estar:","optss":["Separado de los conductores de voltaje de linea a menos que este clasificado/dividido segun el codigo","Tendido en el mismo conducto que el voltaje de linea","Empalmado al voltaje de linea","Dejado energizado a tierra"],"rs":"Mantenga el cableado Clase 2 (24 V) separado de los conductores de voltaje de linea (o use barreras/cable clasificado) para evitar la transferencia de voltaje peligroso e interferencias."},
  {"id":438,"sec":"Fabrication & Installation","q":"Condensate that drains to a plumbing system must usually discharge through:","opts":["The refrigerant line","A direct hard connection","An indirect waste with an air gap","The gas line"],"correct":2,"re":"Codes require condensate to drain indirectly with an air gap to a suitable receptor, preventing sewer gas/back-siphonage into the equipment.","rr":"Нормы требуют отводить конденсат непрямо, с воздушным разрывом к подходящему приёмнику, предотвращая канализационные газы/обратный сифон в оборудование.","qr":"Конденсат, отводимый в канализацию, обычно должен сбрасываться через:","optsr":["Линию хладагента","Прямое жёсткое подключение","Непрямой слив с воздушным разрывом (air gap)","Газовую линию"],"qs":"El condensado que drena a un sistema de plomeria normalmente debe descargar a traves de:","optss":["La linea de refrigerante","Una conexion directa rigida","Un desague indirecto con un espacio de aire (air gap)","La linea de gas"],"rs":"Los codigos requieren que el condensado drene de forma indirecta con un espacio de aire (air gap) hacia un receptor adecuado, evitando el gas de alcantarilla/sifonaje inverso hacia el equipo."},
  {"id":439,"sec":"Fabrication & Installation","q":"A roof curb under a packaged rooftop unit (RTU) provides:","opts":["Extra voltage","A level, weatherproof support that also connects supply/return ducts","More SEER","Refrigerant storage"],"correct":1,"re":"The curb raises and supports the RTU, provides a weather seal, and aligns the supply/return duct openings - matching the curb to the unit is essential on changeouts.","rr":"Curb поднимает и поддерживает RTU, даёт погодное уплотнение и совмещает проёмы подачи/обратки - подбор curb под блок критичен при заменах.","qr":"Опорная рама (roof curb) под крышным моноблоком (RTU) обеспечивает:","optsr":["Дополнительное напряжение","Ровную, погодозащищённую опору, также соединяющую подачу/обратку","Больший SEER","Хранение хладагента"],"qs":"Una base de techo (roof curb) bajo una unidad empaquetada de azotea (RTU) proporciona:","optss":["Voltaje adicional","Un soporte nivelado y a prueba de intemperie que tambien conecta los ductos de suministro/retorno","Mas SEER","Almacenamiento de refrigerante"],"rs":"La base eleva y soporta la RTU, proporciona un sello contra la intemperie y alinea las aberturas de los ductos de suministro/retorno; hacer coincidir la base con la unidad es esencial en los cambios de equipo (changeouts)."},
  {"id":440,"sec":"Fabrication & Installation","q":"Where a refrigerant line set passes through an exterior wall, the penetration should be:","opts":["Filled with refrigerant","Widened for airflow","Sealed (and sleeved/protected) to keep out air, water, and pests and prevent chafing","Left open"],"correct":2,"re":"Seal and protect wall penetrations with a sleeve/grommet and approved sealant to stop air/water/pest intrusion and keep the tubing from abrading on the wall edge.","rr":"Герметизируйте и защищайте проход через стену гильзой/втулкой и одобренным герметиком, чтобы не пускать воздух/воду/вредителей и чтобы трубка не истиралась о край стены.","qr":"Там, где комплект линий хладагента проходит через наружную стену, проход должен быть:","optsr":["Заполнен хладагентом","Расширен для воздуха","Загерметизирован (и в гильзе/защите) от воздуха, воды и вредителей и от истирания","Оставлен открытым"],"qs":"Donde un juego de lineas de refrigerante (line set) atraviesa una pared exterior, la penetracion debe estar:","optss":["Rellena con refrigerante","Ensanchada para el flujo de aire","Sellada (y entubada/protegida) para impedir el paso de aire, agua y plagas y evitar el roce","Dejada abierta"],"rs":"Selle y proteja las penetraciones de pared con un manguito/ojal y sellador aprobado para detener la intrusion de aire/agua/plagas y evitar que la tuberia se desgaste contra el borde de la pared."},
  {"id":441,"sec":"Fabrication & Installation","q":"When commissioning a ductless mini-split, the technician must evacuate the lines and indoor coil and then:","opts":["Open the service valves to release the factory charge into the system","Leave the valves closed","Add nitrogen","Vent the charge"],"correct":1,"re":"The outdoor unit ships pre-charged with valves closed; only after a proper vacuum does the tech open the service (stem) valves to release the charge into the evacuated lines/coil.","rr":"Наружный блок поставляется заправленным с закрытыми вентилями; только после правильного вакуума техник открывает сервисные (штоковые) вентили, выпуская заряд в отвакуумированные линии/блок.","qr":"При пусконаладке мини-сплита техник вакуумирует линии и внутренний блок, а затем:","optsr":["Открывает сервисные вентили, выпуская заводской заряд в систему","Оставляет вентили закрытыми","Добавляет азот","Стравливает заряд"],"qs":"Al poner en marcha un mini-split sin ductos, el tecnico debe evacuar las lineas y el serpentin interior y luego:","optss":["Abrir las valvulas de servicio para liberar la carga de fabrica hacia el sistema","Dejar las valvulas cerradas","Agregar nitrogeno","Ventilar la carga"],"rs":"La unidad exterior se envia precargada con las valvulas cerradas; solo despues de un vacio adecuado el tecnico abre las valvulas de servicio (vastago) para liberar la carga hacia las lineas/serpentin evacuados."},
  {"id":442,"sec":"Fabrication & Installation","q":"The indoor head of a wall-mount mini-split must be installed so the condensate line:","opts":["Is sealed shut","Connects to the gas line","Maintains a continuous downward slope to drain by gravity","Runs uphill"],"correct":2,"re":"The condensate drain from the indoor head must slope continuously downward; a sag or uphill run causes water backup and leaks into the room.","rr":"Дренаж конденсата от внутреннего блока должен идти непрерывно вниз; провис или подъём вызывают застой воды и протечки в комнату.","qr":"Внутренний блок настенного мини-сплита монтируют так, чтобы линия конденсата:","optsr":["Была заглушена","Подключалась к газовой линии","Сохраняла непрерывный уклон вниз для самотёчного слива","Шла вверх"],"qs":"El cabezal interior de un mini-split de montaje en pared debe instalarse de modo que la linea de condensado:","optss":["Este sellada y cerrada","Se conecte a la linea de gas","Mantenga una pendiente descendente continua para drenar por gravedad","Vaya cuesta arriba"],"rs":"El drenaje de condensado del cabezal interior debe tener una pendiente descendente continua; un hundimiento o un tramo cuesta arriba causa acumulacion de agua y fugas hacia la habitacion."},
  {"id":443,"sec":"Fabrication & Installation","q":"On a three-phase scroll compressor, verifying correct phase rotation at startup matters because:","opts":["It changes the color","Reversed rotation makes a scroll run backward (loud, no pumping)","It lowers voltage","It adds refrigerant"],"correct":1,"re":"A scroll runs in only one direction; if phased backward it is noisy, doesn't pump, and can be damaged. Swap two legs to correct rotation.","rr":"Scroll работает только в одном направлении; при обратной фазировке он шумит, не качает и может повредиться. Поменяйте две фазы для исправления вращения.","qr":"На трёхфазном scroll-компрессоре проверка правильного порядка фаз при запуске важна, потому что:","optsr":["Это меняет цвет","Обратное вращение заставляет scroll работать задом наперёд (шум, нет перекачки)","Снижает напряжение","Это добавляет хладагент"],"qs":"En un compresor scroll trifasico, verificar la rotacion de fase correcta en el arranque importa porque:","optss":["Cambia el color","La rotacion invertida hace que un scroll funcione al reves (ruidoso, sin bombear)","Reduce el voltaje","Agrega refrigerante"],"rs":"Un scroll funciona en una sola direccion; si se conecta con la fase invertida es ruidoso, no bombea y puede danarse. Intercambie dos lineas (legs) para corregir la rotacion."},
  {"id":444,"sec":"Fabrication & Installation","q":"Subcooling is calculated by subtracting the measured liquid-line temperature from the:","opts":["Saturated condensing temperature (from liquid pressure)","Suction temperature","Outdoor air temperature","Return-air temperature"],"correct":0,"re":"Subcooling = saturated condensing temp (converted from liquid-line pressure via P-T) minus actual liquid-line temperature; it confirms charge on TXV systems.","rr":"Subcooling = температура насыщенной конденсации (из давления жидкостной линии по P-T) минус фактическая температура жидкостной линии; подтверждает заправку на системах с TXV.","qr":"Subcooling вычисляют, вычитая измеренную температуру жидкостной линии из:","optsr":["Температуры насыщенной конденсации (по давлению жидкости)","Температуры всасывания","Температуры наружного воздуха","Температуры обратного воздуха"],"qs":"El subenfriamiento se calcula restando la temperatura medida de la linea de liquido de la:","optss":["Temperatura de condensacion saturada (a partir de la presion de liquido)","Temperatura de succion","Temperatura del aire exterior","Temperatura del aire de retorno"],"rs":"Subenfriamiento = temperatura de condensacion saturada (convertida desde la presion de la linea de liquido mediante la tabla P-T) menos la temperatura real de la linea de liquido; confirma la carga en sistemas con TXV."},
  {"id":445,"sec":"Fabrication & Installation","q":"After installing a unit with a crankcase heater, the heater should be energized before starting the compressor for about:","opts":["Several hours (often 24 h) to boil refrigerant out of the oil","One minute","No time","One week"],"correct":0,"re":"Energizing the crankcase heater for the recommended period (often ~24 h) drives liquid refrigerant out of the oil, preventing a flooded start and slugging.","rr":"Включение подогрева картера на рекомендованный срок (часто ~24 ч) выгоняет жидкий хладагент из масла, предотвращая flooded start и гидроудар.","qr":"После установки блока с подогревом картера нагреватель включают до запуска компрессора примерно на:","optsr":["Несколько часов (часто 24 ч), чтобы выпарить хладагент из масла","Одну минуту","Нисколько","Одну неделю"],"qs":"Despues de instalar una unidad con calentador de carter (crankcase heater), el calentador debe energizarse antes de arrancar el compresor durante aproximadamente:","optss":["Varias horas (a menudo 24 h) para evaporar el refrigerante del aceite","Un minuto","Nada de tiempo","Una semana"],"rs":"Energizar el calentador de carter durante el periodo recomendado (a menudo ~24 h) expulsa el refrigerante liquido del aceite, evitando un arranque inundado y el golpe de liquido (slugging)."},
  {"id":446,"sec":"Fabrication & Installation","q":"The temperature-rise method at furnace startup is used to:","opts":["Measure refrigerant","Size the duct","Set the gas type","Verify airflow is within the rated rise range on the data plate"],"correct":3,"re":"Measure return and supply air temperatures; the rise must fall within the nameplate range. Too high = low airflow; too low = high airflow - adjust blower speed.","rr":"Измеряют температуры обратного и приточного воздуха; rise должен быть в диапазоне шильдика. Слишком высокий - малый расход; слишком низкий - большой; регулируйте скорость вентилятора.","qr":"Метод temperature-rise при запуске печи применяют, чтобы:","optsr":["Измерить хладагент","Подобрать дакт","Задать тип газа","Проверить, что расход в номинальном диапазоне rise на шильдике"],"qs":"El metodo de aumento de temperatura (temperature-rise) en el arranque del calefactor (furnace) se usa para:","optss":["Medir el refrigerante","Dimensionar el ducto","Establecer el tipo de gas","Verificar que el flujo de aire este dentro del rango de aumento clasificado en la placa de datos"],"rs":"Mida las temperaturas del aire de retorno y de suministro; el aumento debe quedar dentro del rango de la placa. Demasiado alto = bajo flujo de aire; demasiado bajo = alto flujo de aire; ajuste la velocidad del soplador."},
  {"id":447,"sec":"Fabrication & Installation","q":"In an unconditioned attic, supply ducts should be insulated to the code R-value primarily to:","opts":["Reduce noise","Add refrigerant","Increase static pressure","Limit conductive heat gain/loss between the air and the hot/cold attic"],"correct":3,"re":"Attics swing hot and cold; insulating ducts (e.g., R-8 per Title 24) limits energy lost or gained through the duct walls, protecting capacity and efficiency.","rr":"Чердаки то жаркие, то холодные; утепление дактов (например R-8 по Title 24) ограничивает энергию, теряемую/получаемую через стенки, сохраняя производительность и КПД.","qr":"В неотапливаемом чердаке приточные дакты утепляют до нормативного R-value прежде всего чтобы:","optsr":["Снизить шум","Добавить хладагент","Повысить статическое давление","Ограничить теплоприток/теплопотери между воздухом и жарким/холодным чердаком"],"qs":"En un atico no acondicionado, los ductos de suministro deben aislarse al valor R del codigo principalmente para:","optss":["Reducir el ruido","Agregar refrigerante","Aumentar la presion estatica","Limitar la ganancia/perdida de calor por conduccion entre el aire y el atico caliente/frio"],"rs":"Los aticos varian entre caliente y frio; aislar los ductos (por ejemplo, R-8 segun el Title 24) limita la energia perdida o ganada a traves de las paredes del ducto, protegiendo la capacidad y la eficiencia."},
  {"id":448,"sec":"Fabrication & Installation","q":"Supply boots and registers should be sealed to the drywall/floor opening to:","opts":["Increase the SEER","Prevent air leakage into wall/floor cavities (lost conditioned air)","Add refrigerant","Lower the voltage"],"correct":1,"re":"Unsealed boots leak conditioned air into cavities, wasting energy and reducing room airflow; seal the boot-to-opening connection with mastic/gasket.","rr":"Негерметичные башмаки пропускают кондиционированный воздух в полости, теряя энергию и снижая расход в комнату; герметизируйте стык башмак-проём мастикой/уплотнением.","qr":"Приточные башмаки (boots) и решётки герметизируют к проёму в гипсокартоне/полу, чтобы:","optsr":["Повысить SEER","Предотвратить утечку воздуха в полости стен/пола (потеря кондиционированного воздуха)","Добавить хладагент","Снизить напряжение"],"qs":"Las botas (boots) de suministro y los registros deben sellarse a la abertura del panel de yeso/piso para:","optss":["Aumentar el SEER","Evitar la fuga de aire hacia las cavidades de pared/piso (aire acondicionado perdido)","Agregar refrigerante","Reducir el voltaje"],"rs":"Las botas sin sellar dejan escapar aire acondicionado hacia las cavidades, desperdiciando energia y reduciendo el flujo de aire de la habitacion; selle la conexion de la bota a la abertura con mastique/empaque."},
  {"id":449,"sec":"Fabrication & Installation","q":"A direct-vent (sealed-combustion) furnace draws combustion air from outdoors through:","opts":["A dedicated intake pipe, exhausting through a separate/concentric vent","The refrigerant line","Room air only","The return duct"],"correct":0,"re":"Sealed-combustion units pipe outdoor air directly to the burner and vent flue gases outside (often a concentric pipe), isolating combustion from indoor air.","rr":"Sealed-combustion блоки подводят наружный воздух прямо к горелке и отводят дымовые газы наружу (часто коаксиальная труба), изолируя горение от воздуха помещения.","qr":"Печь с прямым дымоудалением (sealed-combustion) берёт воздух горения снаружи через:","optsr":["Выделенную приточную трубу, с отводом через отдельный/коаксиальный дымоход","Линию хладагента","Только воздух помещения","Обратный дакт"],"qs":"Un calefactor (furnace) de ventilacion directa (combustion sellada) toma el aire de combustion del exterior a traves de:","optss":["Una tuberia de admision dedicada, expulsando a traves de un ventilador separado/concentrico","La linea de refrigerante","Solo aire de la habitacion","El ducto de retorno"],"rs":"Las unidades de combustion sellada conducen el aire exterior directamente al quemador y ventilan los gases de combustion al exterior (a menudo una tuberia concentrica), aislando la combustion del aire interior."},
  {"id":450,"sec":"Fabrication & Installation","q":"When a high-efficiency furnace replaces an older one that shared a chimney with a water heater, the technician must verify the water heater's vent because:","opts":["The 'orphaned' water heater may be oversized for the chimney and backdraft","It needs refrigerant","The gas type changed","It now has more draft"],"correct":0,"re":"Removing the furnace from a shared (common) vent can leave the water heater 'orphaned' in an oversized chimney, risking poor draft/backdrafting - re-evaluate venting per code.","rr":"Удаление печи из общего дымохода оставляет водонагреватель 'осиротевшим' в слишком большом дымоходе, рискуя плохой тягой/обратной тягой - пересчитайте дымоудаление по нормам.","qr":"Когда высокоэффективная печь заменяет старую, делившую дымоход с водонагревателем, техник обязан проверить дымоудаление водонагревателя, потому что:","optsr":["'Осиротевший' водонагреватель может оказаться мал для дымохода и давать обратную тягу","Ему нужен хладагент","Сменился тип газа","Теперь у него больше тяги"],"qs":"Cuando un calefactor (furnace) de alta eficiencia reemplaza a uno mas antiguo que compartia una chimenea con un calentador de agua, el tecnico debe verificar la ventilacion del calentador de agua porque:","optss":["El calentador de agua 'huerfano' puede quedar sobredimensionado para la chimenea y tener contratiro (backdraft)","Necesita refrigerante","El tipo de gas cambio","Ahora tiene mas tiro"],"rs":"Retirar el calefactor de una ventilacion compartida (comun) puede dejar al calentador de agua 'huerfano' en una chimenea sobredimensionada, con riesgo de mal tiro/contratiro; reevalue la ventilacion segun el codigo."},
  {"id":451,"sec":"Fabrication & Installation","q":"On a new installation, the condensate trap should be primed (filled with water) so that:","opts":["The compressor starts","The trap seals immediately and air is not pulled through the empty drain","The SEER rises","The gas lights"],"correct":1,"re":"A dry trap lets the blower pull air through the drain (or block drainage); priming the trap establishes the water seal so condensate flows correctly at startup.","rr":"Сухой сифон даёт вентилятору подсасывать воздух через дренаж (или блокирует слив); заливка сифона создаёт водяной затвор, и конденсат течёт правильно при запуске.","qr":"На новом монтаже сифон конденсата нужно залить водой (prime), чтобы:","optsr":["Запустился компрессор","Сифон сразу герметизировал и воздух не подсасывался через пустой дренаж","Вырос SEER","Зажёгся газ"],"qs":"En una instalacion nueva, la trampa de condensado debe cebarse (llenarse con agua) para que:","optss":["El compresor arranque","La trampa selle de inmediato y no se aspire aire a traves del desague vacio","Suba el SEER","Encienda el gas"],"rs":"Una trampa seca permite que el soplador aspire aire a traves del desague (o bloquee el drenaje); cebar la trampa establece el sello de agua para que el condensado fluya correctamente en el arranque."},
  {"id":452,"sec":"Fabrication & Installation","q":"In California, HVAC equipment and water heaters often require seismic strapping/anchorage to:","opts":["Improve airflow","Raise the voltage","Prevent the unit from shifting or toppling during an earthquake","Add refrigerant"],"correct":2,"re":"Seismic anchorage (strapping water heaters, securing rooftop/attic units) keeps equipment in place during a quake, preventing gas-line/refrigerant-line damage and hazards.","rr":"Сейсмическая анкеровка (стяжка водонагревателей, крепление крышных/чердачных блоков) удерживает оборудование на месте при толчках, предотвращая повреждение газовых/хладагентных линий и опасности.","qr":"В Калифорнии HVAC-оборудование и водонагреватели часто требуют сейсмического крепления/анкеровки, чтобы:","optsr":["Улучшить расход воздуха","Поднять напряжение","Не дать блоку сдвинуться или опрокинуться при землетрясении","Добавить хладагент"],"qs":"En California, los equipos de HVAC y los calentadores de agua a menudo requieren amarre/anclaje sismico para:","optss":["Mejorar el flujo de aire","Elevar el voltaje","Evitar que la unidad se desplace o se vuelque durante un terremoto","Agregar refrigerante"],"rs":"El anclaje sismico (amarrar los calentadores de agua, asegurar las unidades de azotea/atico) mantiene el equipo en su lugar durante un sismo, evitando danos a las lineas de gas/refrigerante y peligros."},
  {"id":453,"sec":"Fabrication & Installation","q":"At installation, electrical lugs and terminals should be tightened to:","opts":["As tight as possible","No particular value","Hand-tight only","The manufacturer's specified torque value"],"correct":3,"re":"Both under- and over-torquing cause problems; use a torque screwdriver/wrench to the specified value for low-resistance, reliable connections that won't loosen or overheat.","rr":"И недотяжка, и перетяжка вредны; используйте динамометрическую отвёртку/ключ на заданный момент для надёжных соединений с малым сопротивлением, которые не ослабнут и не перегреются.","qr":"При монтаже электрические наконечники и клеммы следует затягивать до:","optsr":["Максимально туго","Без конкретного значения","Только от руки","Заданного производителем момента затяжки"],"qs":"En la instalacion, los bornes (lugs) y terminales electricos deben apretarse a:","optss":["Lo mas apretado posible","Ningun valor en particular","Solo apretado a mano","El valor de torque especificado por el fabricante"],"rs":"Tanto el torque insuficiente como el excesivo causan problemas; use un destornillador/llave de torque al valor especificado para obtener conexiones de baja resistencia y confiables que no se aflojen ni se sobrecalienten."},
  {"id":454,"sec":"Fabrication & Installation","q":"Circuit breakers and disconnects serving HVAC equipment should be:","opts":["Bypassed","Clearly labeled to identify the equipment they serve","Left unlabeled","Painted over"],"correct":1,"re":"Proper labeling lets technicians and occupants quickly identify and de-energize the right circuit for service and emergencies, improving safety.","rr":"Правильная маркировка позволяет техникам и жильцам быстро найти и обесточить нужную цепь при обслуживании и в аварии, повышая безопасность.","qr":"Автоматы и разъединители, питающие HVAC-оборудование, должны быть:","optsr":["Зашунтированы","Чётко промаркированы с указанием обслуживаемого оборудования","Без подписи","Закрашены"],"qs":"Los interruptores (breakers) y desconectadores que sirven a los equipos de HVAC deben estar:","optss":["Puenteados","Claramente etiquetados para identificar el equipo al que sirven","Dejados sin etiqueta","Cubiertos con pintura"],"rs":"Un etiquetado adecuado permite a los tecnicos y ocupantes identificar y desenergizar rapidamente el circuito correcto para servicio y emergencias, mejorando la seguridad."},
  {"id":455,"sec":"Service & Troubleshooting","q":"A three-phase scroll compressor that is loud and produces little or no cooling right after a service may be:","opts":["Low on oil","Wired for reverse rotation (two phases swapped)","Overcharged","Out of filters"],"correct":1,"re":"Reversed phase rotation makes a scroll spin backward - noisy, no pumping, and no cooling. Swapping any two line phases restores correct rotation.","rr":"Обратный порядок фаз заставляет scroll крутиться назад - шум, нет перекачки и охлаждения. Перестановка любых двух фаз восстанавливает правильное вращение.","qr":"Трёхфазный scroll-компрессор, который шумит и почти не охлаждает сразу после обслуживания, может быть:","optsr":["Без масла","Подключён на обратное вращение (поменяны две фазы)","Перезаправлен","Без фильтров"],"qs":"Un compresor scroll trifasico que esta ruidoso y produce poco o ningun enfriamiento justo despues de un servicio puede estar:","optss":["Bajo de aceite","Conectado para rotacion inversa (dos fases intercambiadas)","Sobrecargado","Sin filtros"],"rs":"La rotacion de fase invertida hace que un scroll gire al reves: ruidoso, sin bombeo y sin enfriamiento. Intercambiar dos fases de linea cualesquiera restablece la rotacion correcta."},
  {"id":456,"sec":"Service & Troubleshooting","q":"A moisture-indicating sight glass that has turned yellow (instead of green) indicates:","opts":["Moisture in the system (replace the drier and evacuate)","Correct charge","High voltage","Overcharge"],"correct":0,"re":"The indicator changes color with moisture content (green = dry, yellow = wet). A wet reading calls for a new filter drier and proper evacuation.","rr":"Индикатор меняет цвет по содержанию влаги (зелёный = сухо, жёлтый = влажно). Влажный показатель требует нового фильтра-осушителя и правильного вакуума.","qr":"Смотровое стекло с индикатором влаги, ставшее жёлтым (вместо зелёного), указывает на:","optsr":["Влагу в системе (заменить осушитель и отвакуумировать)","Правильную заправку","Высокое напряжение","Перезаправку"],"qs":"Un visor (sight glass) indicador de humedad que se ha vuelto amarillo (en lugar de verde) indica:","optss":["Humedad en el sistema (reemplace el secador y evacue)","Carga correcta","Alto voltaje","Sobrecarga"],"rs":"El indicador cambia de color con el contenido de humedad (verde = seco, amarillo = humedo). Una lectura humeda exige un nuevo filtro secador y una evacuacion adecuada."},
  {"id":457,"sec":"Service & Troubleshooting","q":"An abnormally high compressor discharge temperature is commonly caused by:","opts":["Low voltage only","A high compression ratio (low suction/high head), low charge, or high superheat","Overcharge only","A clean filter"],"correct":1,"re":"High discharge temp results from a high compression ratio and high return-gas superheat (often from undercharge or restriction); excessive heat breaks down oil and damages valves.","rr":"Высокая температура нагнетания - от высокой степени сжатия и высокого superheat обратного газа (часто недозаправка или засор); избыток тепла разлагает масло и повреждает клапаны.","qr":"Аномально высокая температура нагнетания компрессора обычно вызвана:","optsr":["Только низким напряжением","Высокой степенью сжатия (низкое всасывание/высокое нагнетание), недозаправкой или высоким superheat","Только перезаправкой","Чистым фильтром"],"qs":"Una temperatura de descarga del compresor anormalmente alta es causada comunmente por:","optss":["Solo bajo voltaje","Una alta relacion de compresion (baja succion/alta descarga), carga baja o alto sobrecalentamiento","Solo sobrecarga","Un filtro limpio"],"rs":"La alta temperatura de descarga resulta de una alta relacion de compresion y un alto sobrecalentamiento del gas de retorno (a menudo por baja carga o restriccion); el calor excesivo descompone el aceite y dana las valvulas."},
  {"id":458,"sec":"Service & Troubleshooting","q":"An oil acid test that reads positive after a compressor failure means the technician should:","opts":["Just recharge","Perform a burnout cleanup (acid driers) until the system tests clean","Ignore it","Add more oil"],"correct":1,"re":"Acidic oil indicates contamination from a burnout; install suction/liquid acid-removal driers, run, retest, and replace driers until the acid test is clean.","rr":"Кислое масло указывает на загрязнение от выгорания; ставьте кислотные осушители на всасывание/жидкостную, гоняйте, перепроверяйте и меняйте, пока кислотный тест не чист.","qr":"Положительный кислотный тест масла после отказа компрессора означает, что техник должен:","optsr":["Просто дозаправить","Провести очистку после burnout (кислотные осушители), пока система не станет чистой","Игнорировать","Долить масла"],"qs":"Una prueba de acidez del aceite que da positiva despues de una falla del compresor significa que el tecnico debe:","optss":["Solo recargar","Realizar una limpieza por quemadura (burnout) con secadores de acido hasta que el sistema de una prueba limpia","Ignorarlo","Agregar mas aceite"],"rs":"El aceite acido indica contaminacion por una quemadura (burnout); instale secadores de eliminacion de acido en succion/liquido, opere, vuelva a probar y reemplace los secadores hasta que la prueba de acidez este limpia."},
  {"id":459,"sec":"Service & Troubleshooting","q":"A gas furnace pressure switch that will not close after the inducer starts is often caused by:","opts":["Too much airflow","High refrigerant","A blocked vent or a pressure-switch hose plugged with condensate","A clean filter"],"correct":2,"re":"The switch proves inducer draft; a blocked flue, cracked/plugged hose, or condensate in the port keeps it open, halting ignition for safety.","rr":"Реле подтверждает тягу inducer; засор дымохода, треснувший/забитый шланг или конденсат в штуцере держат его разомкнутым, останавливая розжиг ради безопасности.","qr":"Реле давления газовой печи, которое не замыкается после запуска inducer, часто вызвано:","optsr":["Слишком большим расходом","Избытком хладагента","Засором дымохода или шлангом реле, забитым конденсатом","Чистым фильтром"],"qs":"Un interruptor de presion (pressure switch) de un calefactor (furnace) de gas que no cierra despues de que arranca el inductor a menudo es causado por:","optss":["Demasiado flujo de aire","Alto refrigerante","Una ventilacion bloqueada o una manguera del interruptor de presion tapada con condensado","Un filtro limpio"],"rs":"El interruptor comprueba el tiro del inductor; un conducto (flue) bloqueado, una manguera agrietada/tapada o condensado en el puerto lo mantiene abierto, deteniendo la ignicion por seguridad."},
  {"id":460,"sec":"Service & Troubleshooting","q":"A reversing valve with an internal (bypass) leak will cause:","opts":["Poor heating/cooling with suction and discharge pressures closer than normal","Low voltage","Perfect operation","A blown fuse"],"correct":0,"re":"An internally leaking reversing valve bleeds hot discharge gas to the suction side, equalizing pressures and reducing capacity even though the solenoid works.","rr":"Внутренне текущий реверс-клапан перепускает горячий газ нагнетания на сторону всасывания, выравнивая давления и снижая производительность, хотя соленоид исправен.","qr":"Реверс-клапан с внутренней (перепускной) утечкой вызывает:","optsr":["Плохой нагрев/охлаждение, давления всасывания и нагнетания ближе нормы","Низкое напряжение","Идеальную работу","Перегорание предохранителя"],"qs":"Una valvula reversora (reversing valve) con una fuga interna (bypass) causara:","optss":["Mala calefaccion/enfriamiento con las presiones de succion y descarga mas cercanas de lo normal","Bajo voltaje","Operacion perfecta","Un fusible quemado"],"rs":"Una valvula reversora con fuga interna deja pasar gas de descarga caliente al lado de succion, igualando las presiones y reduciendo la capacidad aunque el solenoide funcione."},
  {"id":461,"sec":"Service & Troubleshooting","q":"A suction-line accumulator protects the compressor by:","opts":["Filtering air","Trapping liquid refrigerant and metering it back as vapor (preventing slugging)","Adding refrigerant","Raising head pressure"],"correct":1,"re":"The accumulator (common on heat pumps) holds liquid that returns during heating/defrost and feeds it back slowly so the compressor isn't slugged with liquid.","rr":"Accumulator (часто на тепловых насосах) удерживает жидкость, возвращающуюся при нагреве/разморозке, и медленно подаёт её, чтобы компрессор не получал гидроудар.","qr":"Накопитель (accumulator) на всасывающей линии защищает компрессор тем, что:","optsr":["Фильтрует воздух","Удерживает жидкий хладагент и дозирует его обратно паром (предотвращая гидроудар)","Добавляет хладагент","Поднимает давление нагнетания"],"qs":"Un acumulador de linea de succion (suction-line accumulator) protege el compresor al:","optss":["Filtrar el aire","Atrapar el refrigerante liquido y dosificarlo de vuelta como vapor (evitando el golpe de liquido)","Agregar refrigerante","Elevar la presion de descarga (head pressure)"],"rs":"El acumulador (comun en bombas de calor) retiene el liquido que retorna durante la calefaccion/descongelacion y lo realimenta lentamente para que el compresor no reciba golpe de liquido (slugging)."},
  {"id":462,"sec":"Service & Troubleshooting","q":"A bi-flow filter drier or a check valve installed backward in a heat pump will:","opts":["Restrict flow in one mode, causing poor performance in heating or cooling","Add refrigerant","Improve efficiency","Lower the discharge temp"],"correct":0,"re":"Heat pumps reverse flow; a directional drier/check valve installed wrong restricts one mode. Use a bi-flow drier or correct the arrow direction.","rr":"Тепловые насосы реверсируют поток; направленный осушитель/обратный клапан наоборот ограничивает один режим. Ставьте bi-flow осушитель или верное направление стрелки.","qr":"Bi-flow фильтр-осушитель или обратный клапан, установленный наоборот в тепловом насосе:","optsr":["Ограничит поток в одном режиме, ухудшив нагрев или охлаждение","Добавит хладагент","Улучшит эффективность","Снизит температуру нагнетания"],"qs":"Un filtro secador de doble flujo (bi-flow) o una valvula de retencion (check valve) instalada al reves en una bomba de calor:","optss":["Restringira el flujo en un modo, causando mal desempeno en calefaccion o enfriamiento","Agregara refrigerante","Mejorara la eficiencia","Reducira la temperatura de descarga"],"rs":"Las bombas de calor invierten el flujo; un secador/valvula de retencion direccional instalado mal restringe un modo. Use un secador de doble flujo (bi-flow) o corrija la direccion de la flecha."},
  {"id":463,"sec":"Service & Troubleshooting","q":"A plugged TXV external equalizer line will typically cause the valve to:","opts":["Increase subcooling only","Add refrigerant","Control poorly, usually starving the evaporator (high superheat)","Overfeed badly"],"correct":2,"re":"The external equalizer senses evaporator outlet pressure; if plugged, the TXV misreads and commonly underfeeds, producing high superheat and low capacity.","rr":"Внешний эквалайзер измеряет давление на выходе испарителя; при засоре TXV ошибается и обычно недоподаёт, давая высокий superheat и низкую производительность.","qr":"Забитая линия внешнего эквалайзера TXV обычно заставляет клапан:","optsr":["Только увеличивать subcooling","Добавлять хладагент","Плохо регулировать, обычно обедняя испаритель (высокий superheat)","Сильно переподавать"],"qs":"Una linea del ecualizador externo de un TXV tapada normalmente causara que la valvula:","optss":["Solo aumente el subenfriamiento","Agregue refrigerante","Controle deficientemente, generalmente restringiendo el evaporador (alto sobrecalentamiento)","Sobrealimente gravemente"],"rs":"El ecualizador externo detecta la presion de salida del evaporador; si se tapa, el TXV lee mal y comunmente subalimenta, produciendo alto sobrecalentamiento y baja capacidad."},
  {"id":464,"sec":"Service & Troubleshooting","q":"A frequently overlooked cause of low airflow on a maintenance call is:","opts":["A dirty blower wheel packed with debris","A clean coil","High voltage","Overcharge"],"correct":0,"re":"Dirt loads the blower wheel blades, drastically cutting airflow even with a clean filter; inspect and clean the wheel as part of airflow troubleshooting.","rr":"Грязь облепляет лопасти колеса вентилятора, резко срезая расход даже при чистом фильтре; осматривайте и чистите колесо при диагностике расхода.","qr":"Часто упускаемая причина низкого расхода воздуха при ТО - это:","optsr":["Грязное колесо вентилятора, забитое мусором","Чистый испаритель","Высокое напряжение","Перезаправка"],"qs":"Una causa frecuentemente pasada por alto de bajo flujo de aire en una visita de mantenimiento es:","optss":["Una rueda del soplador sucia llena de residuos","Un serpentin limpio","Alto voltaje","Sobrecarga"],"rs":"La suciedad carga las aspas de la rueda del soplador, reduciendo drasticamente el flujo de aire incluso con un filtro limpio; inspeccione y limpie la rueda como parte del diagnostico de flujo de aire."},
  {"id":465,"sec":"Service & Troubleshooting","q":"In cooling, a dirty evaporator (air side) and a dirty condenser produce different symptoms: a dirty evaporator most directly reduces:","opts":["Airflow and evaporator capacity (low suction, possible icing)","Head pressure","Voltage","Subcooling only"],"correct":0,"re":"A dirty evaporator restricts airflow, lowering suction pressure and risking ice; a dirty condenser raises head pressure. Reading both pressures locates the fault.","rr":"Грязный испаритель ограничивает расход, снижая давление всасывания и риск льда; грязный конденсатор поднимает давление нагнетания. Чтение обоих давлений локализует неисправность.","qr":"В охлаждении грязный испаритель (со стороны воздуха) и грязный конденсатор дают разные симптомы: грязный испаритель напрямую снижает:","optsr":["Расход воздуха и производительность испарителя (низкое всасывание, риск обмерзания)","Давление нагнетания","Напряжение","Только subcooling"],"qs":"En enfriamiento, un evaporador sucio (lado del aire) y un condensador sucio producen sintomas diferentes: un evaporador sucio reduce mas directamente:","optss":["El flujo de aire y la capacidad del evaporador (baja succion, posible formacion de hielo)","La presion de descarga (head pressure)","El voltaje","Solo el subenfriamiento"],"rs":"Un evaporador sucio restringe el flujo de aire, bajando la presion de succion y arriesgando hielo; un condensador sucio eleva la presion de descarga. Leer ambas presiones localiza la falla."},
  {"id":466,"sec":"Service & Troubleshooting","q":"On a pump-down system, a liquid-line solenoid valve that fails to close will cause:","opts":["High SEER","Normal pump down","The system to fail to pump down (refrigerant keeps flowing to the low side)","A blown fuse"],"correct":2,"re":"Pump-down relies on the solenoid closing so the compressor evacuates the low side into the condenser/receiver; a stuck-open valve defeats pump-down.","rr":"Pump-down зависит от закрытия соленоида, чтобы компрессор откачал низкую сторону в конденсатор/ресивер; зависший открытым клапан срывает pump-down.","qr":"В системе с pump-down соленоидный клапан жидкостной линии, не закрывающийся, вызовет:","optsr":["Высокий SEER","Нормальный pump down","Невозможность откачать систему (хладагент продолжает идти на низкую сторону)","Перегорание предохранителя"],"qs":"En un sistema con bombeo de vaciado (pump-down), una valvula solenoide de linea de liquido que no logra cerrar causara:","optss":["Alto SEER","Bombeo de vaciado normal","Que el sistema no logre el bombeo de vaciado (el refrigerante sigue fluyendo al lado de baja)","Un fusible quemado"],"rs":"El bombeo de vaciado depende de que el solenoide cierre para que el compresor evacue el lado de baja hacia el condensador/recibidor; una valvula atascada abierta anula el pump-down."},
  {"id":467,"sec":"Service & Troubleshooting","q":"A defrost-termination sensor that fails can cause a heat pump to:","opts":["Increase subcooling","Stop the compressor permanently","Never defrost or stay in defrost too long","Run more efficiently"],"correct":3,"re":"The termination sensor ends defrost at the right coil temperature; if it fails, the unit may not clear ice or may waste energy over-defrosting - check the sensor/board.","rr":"Датчик завершения прекращает defrost при нужной температуре змеевика; при отказе блок может не очищать лёд или перерасходовать энергию на пере-разморозку - проверьте датчик/плату.","qr":"Отказ датчика завершения разморозки может заставить тепловой насос:","optsr":["Увеличить subcooling","Навсегда остановить компрессор","Никогда не размораживаться или слишком долго быть в defrost","Работать эффективнее"],"qs":"Un sensor de terminacion de descongelacion (defrost-termination) que falla puede causar que una bomba de calor:","optss":["Aumente el subenfriamiento","Detenga el compresor permanentemente","Nunca descongele o permanezca demasiado tiempo en descongelacion","Funcione con mayor eficiencia"],"rs":"El sensor de terminacion finaliza la descongelacion a la temperatura correcta del serpentin; si falla, la unidad puede no eliminar el hielo o puede desperdiciar energia descongelando en exceso; revise el sensor/tarjeta."},
  {"id":468,"sec":"Service & Troubleshooting","q":"A hard-start kit using a potential (start) relay drops the start capacitor out of the circuit based on:","opts":["Refrigerant pressure","Time only","The back-EMF voltage as the motor nears running speed","Outdoor temperature"],"correct":2,"re":"A potential relay senses the rising back-EMF (start-winding voltage) and opens to remove the start cap once the motor is up to speed; a bad relay leaves the cap in or out wrongly.","rr":"Потенциальное реле улавливает растущую противо-ЭДС (напряжение пусковой обмотки) и размыкается, убирая пусковой конденсатор при выходе мотора на скорость; неисправное реле оставляет конденсатор неверно.","qr":"Hard-start комплект с потенциальным (пусковым) реле выводит пусковой конденсатор из цепи на основе:","optsr":["Давления хладагента","Только времени","Напряжения противо-ЭДС, когда мотор приближается к рабочей скорости","Наружной температуры"],"qs":"Un kit de arranque forzado (hard-start) que usa un relevador de potencial (start relay) retira el capacitor de arranque del circuito segun:","optss":["La presion del refrigerante","Solo el tiempo","El voltaje de fuerza contraelectromotriz (back-EMF) a medida que el motor se acerca a la velocidad de operacion","La temperatura exterior"],"rs":"Un relevador de potencial detecta la creciente back-EMF (voltaje del devanado de arranque) y abre para retirar el capacitor de arranque una vez que el motor alcanza su velocidad; un relevador defectuoso deja el capacitor dentro o fuera de forma incorrecta."},
  {"id":469,"sec":"Service & Troubleshooting","q":"A TXV sensing bulb that is loose or poorly insulated from the suction line tends to make the valve:","opts":["Close completely","Overfeed the evaporator (it senses warm air instead of true line temperature)","Have no effect","Starve the evaporator"],"correct":1,"re":"A bulb reading ambient air instead of the colder suction line senses a false high temperature and overfeeds, lowering superheat and risking floodback; mount and insulate the bulb properly.","rr":"Колба, читающая окружающий воздух вместо более холодной всасывающей линии, чувствует ложно высокую температуру и переподаёт, снижая superheat и рискуя floodback; крепите и изолируйте колбу правильно.","qr":"Колба-сенсор TXV, слабо закреплённая или плохо изолированная от всасывающей линии, обычно заставляет клапан:","optsr":["Полностью закрыться","Переподавать в испаритель (чувствует тёплый воздух вместо реальной температуры линии)","Не влиять","Обеднять испаритель"],"qs":"Un bulbo sensor de un TXV que esta suelto o mal aislado de la linea de succion tiende a hacer que la valvula:","optss":["Cierre por completo","Sobrealimente el evaporador (detecta aire caliente en lugar de la verdadera temperatura de la linea)","No tenga efecto","Restrinja el evaporador"],"rs":"Un bulbo que lee el aire ambiente en lugar de la linea de succion mas fria detecta una falsa temperatura alta y sobrealimenta, bajando el sobrecalentamiento y arriesgando retorno de liquido (floodback); monte y aisle el bulbo correctamente."},
  {"id":470,"sec":"Service & Troubleshooting","q":"A weak condenser-fan capacitor will cause the fan to:","opts":["Lower the SEER only","Run slow or stall and overheat, raising head pressure","Add refrigerant","Spin faster"],"correct":1,"re":"The fan motor needs its rated capacitor for torque; a weak cap makes it run slow/hot or fail to start, cutting condenser airflow and raising head pressure.","rr":"Мотору вентилятора нужен номинальный конденсатор для момента; слабый даёт медленную/горячую работу или незапуск, срезая обдув конденсатора и поднимая давление нагнетания.","qr":"Слабый конденсатор вентилятора конденсатора заставит вентилятор:","optsr":["Только снизить SEER","Работать медленно или встать и перегреться, подняв давление нагнетания","Добавить хладагент","Крутиться быстрее"],"qs":"Un capacitor debil del ventilador del condensador causara que el ventilador:","optss":["Solo reduzca el SEER","Funcione lento o se detenga y se sobrecaliente, elevando la presion de descarga (head pressure)","Agregue refrigerante","Gire mas rapido"],"rs":"El motor del ventilador necesita su capacitor clasificado para el par (torque); un capacitor debil lo hace funcionar lento/caliente o no arrancar, reduciendo el flujo de aire del condensador y elevando la presion de descarga."},
  {"id":471,"sec":"Service & Troubleshooting","q":"A hissing or 'gurgling' sound at the TXV often indicates:","opts":["Correct charge","Flash gas at the valve from undercharge or a liquid-line restriction","Overcharge","High voltage"],"correct":1,"re":"Vapor (flash gas) entering the TXV instead of solid liquid makes a hissing/gurgling noise and reduces capacity - check for undercharge or a restriction upstream.","rr":"Пар (flash gas), входящий в TXV вместо сплошной жидкости, даёт шипение/бульканье и снижает производительность - проверьте недозаправку или засор выше по течению.","qr":"Шипящий или 'булькающий' звук у TXV часто указывает на:","optsr":["Правильную заправку","Flash gas у клапана из-за недозаправки или засора жидкостной линии","Перезаправку","Высокое напряжение"],"qs":"Un sonido de silbido o 'gorgoteo' en el TXV a menudo indica:","optss":["Carga correcta","Gas instantaneo (flash gas) en la valvula por baja carga o una restriccion en la linea de liquido","Sobrecarga","Alto voltaje"],"rs":"El vapor (flash gas) que entra al TXV en lugar de liquido solido produce un ruido de silbido/gorgoteo y reduce la capacidad; revise si hay baja carga o una restriccion aguas arriba."},
  {"id":472,"sec":"Service & Troubleshooting","q":"High compressor amp draw together with high head pressure most likely points to:","opts":["Undercharge","Low voltage","A dirty filter","Overcharge or a condenser problem (dirty coil/failed fan)"],"correct":3,"re":"High head makes the compressor work harder (high amps); causes include overcharge, dirty condenser, failed condenser fan, or non-condensables - verify before correcting.","rr":"Высокое нагнетание заставляет компрессор работать тяжелее (высокий ток); причины - перезаправка, грязный конденсатор, отказ вентилятора или неконденсируемые - проверьте до правки.","qr":"Высокий ток компрессора вместе с высоким давлением нагнетания скорее всего указывает на:","optsr":["Недозаправку","Низкое напряжение","Грязный фильтр","Перезаправку или проблему конденсатора (грязь/отказ вентилятора)"],"qs":"Un alto consumo de amperaje del compresor junto con alta presion de descarga (head pressure) lo mas probable es que apunte a:","optss":["Baja carga","Bajo voltaje","Un filtro sucio","Sobrecarga o un problema del condensador (serpentin sucio/ventilador averiado)"],"rs":"La alta descarga hace que el compresor trabaje mas duro (alto amperaje); las causas incluyen sobrecarga, condensador sucio, ventilador del condensador averiado o no condensables; verifique antes de corregir."},
  {"id":473,"sec":"Service & Troubleshooting","q":"Reducing indoor airflow in cooling (e.g., a closed-up duct) will tend to:","opts":["Raise the voltage","Lower suction pressure and evaporator temperature, risking coil freeze","Have no effect","Raise suction pressure"],"correct":1,"re":"Less airflow over the coil drops evaporator pressure/temperature; left unchecked it freezes the coil. Restore airflow before assuming a refrigerant fault.","rr":"Меньший обдув испарителя снижает давление/температуру испарителя; без устранения он обмерзает. Восстановите расход до выводов о хладагенте.","qr":"Снижение внутреннего расхода воздуха в охлаждении (например пережатый дакт) обычно:","optsr":["Повышает напряжение","Снижает давление всасывания и температуру испарителя, рискуя обмерзанием","Не влияет","Повышает давление всасывания"],"qs":"Reducir el flujo de aire interior en enfriamiento (por ejemplo, un ducto cerrado) tendera a:","optss":["Elevar el voltaje","Bajar la presion de succion y la temperatura del evaporador, arriesgando la congelacion del serpentin","No tener efecto","Elevar la presion de succion"],"rs":"Menos flujo de aire sobre el serpentin baja la presion/temperatura del evaporador; si no se corrige, congela el serpentin. Restablezca el flujo de aire antes de suponer una falla de refrigerante."},
  {"id":474,"sec":"Service & Troubleshooting","q":"On older thermostats, the heat anticipator setting that is too low causes:","opts":["Longer burner cycles and possible overshoot of the set temperature","Refrigerant loss","Higher SEER","No cycling"],"correct":0,"re":"The anticipator tunes cycle length; set too low it lengthens cycles and overshoots, too high it short-cycles. Modern thermostats use electronic cycle-rate settings instead.","rr":"Anticipator настраивает длину цикла; слишком низко - длинные циклы и перегрев, слишком высоко - короткие циклы. Современные термостаты вместо этого используют электронную настройку cycle-rate.","qr":"На старых термостатах слишком низкая уставка heat anticipator вызывает:","optsr":["Более длинные циклы горелки и возможный перегрев сверх уставки","Потерю хладагента","Более высокий SEER","Отсутствие циклирования"],"qs":"En termostatos antiguos, un ajuste del anticipador de calor (heat anticipator) demasiado bajo causa:","optss":["Ciclos del quemador mas largos y posible sobrepaso de la temperatura ajustada","Perdida de refrigerante","Mayor SEER","Sin ciclos"],"rs":"El anticipador ajusta la duracion del ciclo; demasiado bajo alarga los ciclos y sobrepasa, demasiado alto provoca ciclos cortos. Los termostatos modernos usan ajustes electronicos de tasa de ciclo en su lugar."},
  {"id":475,"sec":"Service & Troubleshooting","q":"A compressor that runs, then trips and restarts only after cooling down for a while, likely has:","opts":["A bad duct","A clean filter","An internal overload opening on heat (often from high amps/temperature)","A wrong thermostat"],"correct":2,"re":"The internal overload protects the motor by opening when too hot and resetting when cool; recurring trips signal high current/heat - investigate charge, airflow, voltage, capacitor.","rr":"Внутренняя защита бережёт мотор, размыкаясь при перегреве и сбрасываясь при остывании; повторные срабатывания - сигнал высокого тока/нагрева; проверьте заряд, расход, напряжение, конденсатор.","qr":"Компрессор, который работает, затем выключается и перезапускается лишь остыв, вероятно имеет:","optsr":["Плохой дакт","Чистый фильтр","Срабатывающую по нагреву внутреннюю защиту (часто от высокого тока/температуры)","Неверный термостат"],"qs":"Un compresor que funciona, luego se dispara y solo reinicia despues de enfriarse un rato, probablemente tiene:","optss":["Un ducto defectuoso","Un filtro limpio","Una proteccion de sobrecarga interna que abre por calor (a menudo por alto amperaje/temperatura)","Un termostato equivocado"],"rs":"La proteccion de sobrecarga interna protege el motor abriendo cuando esta demasiado caliente y restableciendose al enfriarse; los disparos recurrentes senalan alta corriente/calor; investigue carga, flujo de aire, voltaje, capacitor."},
  {"id":476,"sec":"Service & Troubleshooting","q":"A run capacitor that is visibly bulged or leaking should be:","opts":["Reused","Filed flat","Replaced with one of the same uF and equal-or-higher voltage rating","Filled with oil"],"correct":2,"re":"A bulged/leaking capacitor has failed; replace it with the exact microfarad rating and the same or higher voltage rating - never a lower voltage rating.","rr":"Вздутый/текущий конденсатор отказал; замените на точный номинал микрофарад и то же или большее напряжение - никогда не меньше.","qr":"Рабочий конденсатор с видимым вздутием или течью следует:","optsr":["Использовать повторно","Подпилить","Заменить на такой же uF и равным-или-выше напряжением","Залить маслом"],"qs":"Un capacitor de operacion (run capacitor) que esta visiblemente abultado o con fugas debe:","optss":["Reutilizarse","Limarse plano","Reemplazarse por uno con los mismos uF y una clasificacion de voltaje igual o superior","Rellenarse con aceite"],"rs":"Un capacitor abultado/con fugas ha fallado; reemplacelo con la clasificacion exacta de microfaradios y la misma clasificacion de voltaje o superior, nunca una clasificacion de voltaje inferior."},
  {"id":477,"sec":"Service & Troubleshooting","q":"Pitted, high-resistance contactor contacts can cause a compressor to receive:","opts":["Low voltage (voltage drop) and heat, leading to hard starts or failure","More refrigerant","Higher SEER","Cleaner air"],"correct":0,"re":"Worn contacts add resistance and voltage drop, starving the compressor of voltage and generating heat; replace the contactor rather than filing the contacts.","rr":"Изношенные контакты добавляют сопротивление и падение напряжения, лишая компрессор напряжения и создавая нагрев; меняйте контактор, а не опиливайте контакты.","qr":"Изъеденные контакты контактора с высоким сопротивлением могут давать компрессору:","optsr":["Низкое напряжение (падение напряжения) и нагрев, ведущие к тяжёлым пускам или отказу","Больше хладагента","Более высокий SEER","Более чистый воздух"],"qs":"Los contactos picados y de alta resistencia de un contactor pueden causar que un compresor reciba:","optss":["Bajo voltaje (caida de voltaje) y calor, lo que provoca arranques forzados o falla","Mas refrigerante","Mayor SEER","Aire mas limpio"],"rs":"Los contactos desgastados agregan resistencia y caida de voltaje, privando al compresor de voltaje y generando calor; reemplace el contactor en lugar de limar los contactos."},
  {"id":478,"sec":"Service & Troubleshooting","q":"The most logical no-cooling diagnostic sequence is to verify:","opts":["Only the filter","Only the thermostat","Refrigerant first, always","Power/disconnect, then 24 V control to the contactor, then the compressor and finally the refrigerant circuit"],"correct":3,"re":"Work the circuit in order: confirm line power and disconnect, then the 24 V control signal, then contactor/compressor operation, and only then evaluate refrigerant pressures.","rr":"Идите по цепи по порядку: подтвердите сетевое питание и разъединитель, затем сигнал 24 В, затем работу контактора/компрессора и лишь потом давления хладагента.","qr":"Самая логичная последовательность диагностики отсутствия охлаждения - проверять:","optsr":["Только фильтр","Только термостат","Сначала всегда хладагент","Питание/разъединитель, затем 24 В на контактор, затем компрессор и лишь потом контур хладагента"],"qs":"La secuencia de diagnostico mas logica ante una falta de enfriamiento es verificar:","optss":["Solo el filtro","Solo el termostato","El refrigerante primero, siempre","La alimentacion/desconectador, luego los 24 V de control al contactor, despues el compresor y finalmente el circuito de refrigerante"],"rs":"Recorra el circuito en orden: confirme la alimentacion de linea y el desconectador, luego la senal de control de 24 V, despues la operacion del contactor/compresor, y solo entonces evalue las presiones del refrigerante."},
  {"id":479,"sec":"Safety & Field Practices","q":"When working on a system charged with an A2L (mildly flammable) refrigerant, the technician should:","opts":["Use any open flame nearby","Eliminate ignition sources, ventilate, and use tools/practices rated for flammable refrigerant","Vent it indoors","Smoke while working"],"correct":1,"re":"A2L refrigerants can ignite at high concentration; remove ignition sources, ventilate the area, use a listed leak detector, and follow the equipment's A2L service procedures.","rr":"A2L могут воспламениться при высокой концентрации; уберите источники искр, проветрите зону, используйте листингованный течеискатель и соблюдайте сервисные процедуры A2L для оборудования.","qr":"При работе с системой на хладагенте A2L (слабогорючем) техник должен:","optsr":["Использовать рядом открытый огонь","Устранить источники возгорания, проветрить и применять инструмент/практики под горючий хладагент","Стравить его в помещении","Курить во время работы"],"qs":"Al trabajar en un sistema cargado con un refrigerante A2L (ligeramente inflamable), el tecnico debe:","optss":["Usar cualquier llama abierta cerca","Eliminar las fuentes de ignicion, ventilar y usar herramientas/practicas clasificadas para refrigerante inflamable","Ventilarlo en interiores","Fumar mientras trabaja"],"rs":"Los refrigerantes A2L pueden encenderse a alta concentracion; elimine las fuentes de ignicion, ventile el area, use un detector de fugas listado y siga los procedimientos de servicio A2L del equipo."},
  {"id":480,"sec":"Safety & Field Practices","q":"For A2L refrigerants, the maximum allowable charge in a space is limited based on:","opts":["The SEER","The duct color","The wire size","The room floor area (to keep any leak below the flammable concentration)"],"correct":3,"re":"Standards (e.g., UL 60335-2-40) cap charge by room area so that a full leak cannot reach a flammable concentration; larger charges require larger rooms or mitigation.","rr":"Стандарты (например UL 60335-2-40) ограничивают заряд по площади помещения, чтобы полная утечка не достигла горючей концентрации; больший заряд требует большего помещения или мер защиты.","qr":"Для хладагентов A2L максимально допустимый заряд в помещении ограничивается на основе:","optsr":["SEER","Цвета дакта","Сечения провода","Площади пола помещения (чтобы любая утечка осталась ниже горючей концентрации)"],"qs":"Para los refrigerantes A2L, la carga maxima permitida en un espacio se limita en funcion de:","optss":["El SEER","El color del ducto","El calibre del cable","El area del piso de la habitacion (para mantener cualquier fuga por debajo de la concentracion inflamable)"],"rs":"Las normas (por ejemplo, UL 60335-2-40) limitan la carga segun el area de la habitacion para que una fuga total no pueda alcanzar una concentracion inflamable; cargas mayores requieren habitaciones mas grandes o mitigacion."},
  {"id":481,"sec":"Safety & Field Practices","q":"Detecting a leak in a flammable (A2L) refrigerant system requires:","opts":["A leak detector listed/rated for flammable refrigerants","Your nose only","Spraying water","A lit match"],"correct":0,"re":"Use only a leak detector approved for flammable refrigerants; an ignition source like a halide torch or flame is dangerous with A2L systems.","rr":"Используйте только течеискатель, одобренный для горючих хладагентов; источник возгорания вроде галоидной горелки или пламени опасен с системами A2L.","qr":"Обнаружение утечки в системе с горючим (A2L) хладагентом требует:","optsr":["Течеискателя, листингованного/рассчитанного на горючие хладагенты","Только носа","Распыления воды","Зажжённой спички"],"qs":"Detectar una fuga en un sistema de refrigerante inflamable (A2L) requiere:","optss":["Un detector de fugas listado/clasificado para refrigerantes inflamables","Solo su nariz","Rociar agua","Un cerillo encendido"],"rs":"Use unicamente un detector de fugas aprobado para refrigerantes inflamables; una fuente de ignicion como una antorcha de haluro o una llama es peligrosa con los sistemas A2L."},
  {"id":482,"sec":"Safety & Field Practices","q":"Before connecting to a refrigerant cylinder, the technician should confirm the refrigerant type by:","opts":["Its temperature","The label and color code, to avoid mixing incompatible refrigerants","The cylinder's weight","Shaking it"],"correct":1,"re":"Cylinders are labeled and color-coded; mixing refrigerants ruins the charge and the recovered refrigerant. Always verify the label before connecting.","rr":"Баллоны имеют этикетку и цветовой код; смешивание хладагентов портит заряд и откачанный хладагент. Всегда проверяйте этикетку перед подключением.","qr":"Перед подключением к баллону с хладагентом техник должен подтвердить тип хладагента по:","optsr":["Его температуре","Этикетке и цветовому коду, чтобы не смешать несовместимые хладагенты","Весу баллона","Встряхиванию"],"qs":"Antes de conectarse a un cilindro de refrigerante, el tecnico debe confirmar el tipo de refrigerante mediante:","optss":["Su temperatura","La etiqueta y el codigo de color, para evitar mezclar refrigerantes incompatibles","El peso del cilindro","Agitandolo"],"rs":"Los cilindros estan etiquetados y codificados por color; mezclar refrigerantes arruina la carga y el refrigerante recuperado. Verifique siempre la etiqueta antes de conectarse."},
  {"id":483,"sec":"Safety & Field Practices","q":"Acetylene used for brazing must never be used above a working pressure of about:","opts":["5 psig","250 psig","100 psig","15 psig"],"correct":3,"re":"Acetylene is unstable above ~15 psig and can decompose explosively; never set the regulator higher. Use proper oxy-acetylene safety practices.","rr":"Ацетилен нестабилен выше ~15 psig и может взрывоопасно разлагаться; не выставляйте редуктор выше. Соблюдайте правила безопасности oxy-acetylene.","qr":"Ацетилен для пайки нельзя использовать при рабочем давлении выше примерно:","optsr":["5 psig","250 psig","100 psig","15 psig"],"qs":"El acetileno usado para soldadura fuerte (brazing) nunca debe usarse por encima de una presion de trabajo de aproximadamente:","optss":["5 psig","250 psig","100 psig","15 psig"],"rs":"El acetileno es inestable por encima de ~15 psig y puede descomponerse de forma explosiva; nunca ajuste el regulador mas alto. Use practicas de seguridad adecuadas de oxiacetileno."},
  {"id":484,"sec":"Safety & Field Practices","q":"Flashback arrestors on an oxy-fuel torch set are installed to:","opts":["Prevent a flame from traveling back into the hoses/cylinders","Save gas","Increase flame size","Add refrigerant"],"correct":0,"re":"Flashback arrestors/check valves stop a flame or reverse gas flow from reaching the hoses and cylinders, preventing a dangerous explosion.","rr":"Огнепреградители/обратные клапаны не дают пламени или обратному потоку газа дойти до шлангов и баллонов, предотвращая опасный взрыв.","qr":"Обратные клапаны/огнепреградители (flashback arrestors) на oxy-fuel горелке ставят, чтобы:","optsr":["Не дать пламени уйти обратно в шланги/баллоны","Сэкономить газ","Увеличить пламя","Добавить хладагент"],"qs":"Los arrestallamas (flashback arrestors) en un equipo de antorcha de oxicombustible se instalan para:","optss":["Evitar que una llama viaje de regreso hacia las mangueras/cilindros","Ahorrar gas","Aumentar el tamano de la llama","Agregar refrigerante"],"rs":"Los arrestallamas/valvulas de retencion detienen una llama o el flujo inverso de gas para que no lleguen a las mangueras y cilindros, evitando una explosion peligrosa."},
  {"id":485,"sec":"Safety & Field Practices","q":"Acetylene cylinders should be stored and used:","opts":["On their side","Horizontally in the sun","Upright (the acetone inside requires it) and secured","Upside down"],"correct":2,"re":"Acetylene is dissolved in acetone inside the cylinder; storing/using it upright keeps the acetone from being drawn into the hose. Secure cylinders from tipping.","rr":"Ацетилен растворён в ацетоне внутри баллона; вертикальное хранение/использование не даёт ацетону уйти в шланг. Крепите баллоны от опрокидывания.","qr":"Ацетиленовые баллоны следует хранить и использовать:","optsr":["На боку","Горизонтально на солнце","Вертикально (ацетон внутри этого требует) и закреплёнными","Вверх дном"],"qs":"Los cilindros de acetileno deben almacenarse y usarse:","optss":["De costado","Horizontalmente bajo el sol","En posicion vertical (la acetona del interior lo requiere) y asegurados","Boca abajo"],"rs":"El acetileno esta disuelto en acetona dentro del cilindro; almacenarlo/usarlo en posicion vertical evita que la acetona sea arrastrada hacia la manguera. Asegure los cilindros para que no se vuelquen."},
  {"id":486,"sec":"Safety & Field Practices","q":"A brazing/oxy-fuel torch should be lit using:","opts":["An open candle","A cigarette lighter","A striker (spark lighter), not matches or a lighter","Another torch"],"correct":2,"re":"Use a friction striker to keep hands away from the igniting flame; matches/lighters put fingers at the torch tip and risk burns.","rr":"Используйте искровой запальник, чтобы держать руки вдали от вспыхивающего пламени; спички/зажигалки подводят пальцы к соплу и грозят ожогами.","qr":"Горелку для пайки/oxy-fuel следует зажигать с помощью:","optsr":["Открытой свечи","Зажигалки","Кремнёвого искрового запальника (striker), а не спичек или зажигалки","Другой горелки"],"qs":"Una antorcha de soldadura fuerte/oxicombustible debe encenderse usando:","optss":["Una vela encendida","Un encendedor de cigarrillos","Un chispero (encendedor de chispa), no cerillos ni un encendedor","Otra antorcha"],"rs":"Use un chispero de friccion para mantener las manos alejadas de la llama que se enciende; los cerillos/encendedores ponen los dedos en la punta de la antorcha y arriesgan quemaduras."},
  {"id":487,"sec":"Safety & Field Practices","q":"After completing hot work near combustibles, a fire watch should continue for at least about:","opts":["No time","5 seconds","30 minutes (to catch smoldering ignition)","1 week"],"correct":2,"re":"Smoldering can ignite minutes after brazing/cutting; maintain a fire watch for at least 30 minutes (longer if conditions warrant) and keep an extinguisher ready.","rr":"Тление может вспыхнуть через минуты после пайки/резки; ведите пожарный надзор минимум 30 минут (дольше при необходимости) и держите огнетушитель наготове.","qr":"После завершения огневых работ рядом с горючим пожарный надзор должен продолжаться минимум примерно:","optsr":["Нисколько","5 секунд","30 минут (чтобы поймать тлеющее возгорание)","1 неделю"],"qs":"Despues de completar trabajo en caliente (hot work) cerca de combustibles, una vigilancia contra incendios debe continuar durante al menos aproximadamente:","optss":["Nada de tiempo","5 segundos","30 minutos (para detectar una ignicion latente)","1 semana"],"rs":"La combustion latente puede encenderse minutos despues de la soldadura fuerte/corte; mantenga una vigilancia contra incendios durante al menos 30 minutos (mas si las condiciones lo justifican) y tenga un extintor listo."},
  {"id":488,"sec":"Safety & Field Practices","q":"When carrying ladders or working with equipment near overhead power lines (under 50 kV), maintain a minimum clearance of at least:","opts":["2 inches","1 foot","10 feet","No clearance needed"],"correct":2,"re":"OSHA requires keeping at least 10 ft from energized overhead lines up to 50 kV (more for higher voltages); contact can be fatal - look up and plan the route.","rr":"OSHA требует держать не менее 10 футов от воздушных линий под напряжением до 50 кВ (больше для высших напряжений); контакт смертелен - смотрите вверх и планируйте маршрут.","qr":"При переноске лестниц или работе с оборудованием рядом с воздушными ЛЭП (до 50 кВ) держите минимальный зазор не менее:","optsr":["2 дюймов","1 фута","10 футов","Зазор не нужен"],"qs":"Al cargar escaleras o trabajar con equipos cerca de lineas electricas aereas (menos de 50 kV), mantenga una distancia minima de al menos:","optss":["2 pulgadas","1 pie","10 pies","No se necesita distancia"],"rs":"OSHA requiere mantenerse al menos a 10 ft de las lineas aereas energizadas de hasta 50 kV (mas para voltajes mas altos); el contacto puede ser mortal; mire hacia arriba y planifique la ruta."},
  {"id":489,"sec":"Safety & Field Practices","q":"On a rooftop or other wet/outdoor location, power tools should be plugged into:","opts":["An extension cord with no ground","A GFCI-protected circuit","The disconnect terminals","Any outlet"],"correct":1,"re":"GFCI protection in wet/outdoor locations cuts power on a ground fault within milliseconds, protecting the worker from electrocution.","rr":"GFCI-защита во влажных/уличных местах отключает питание при замыкании на землю за миллисекунды, защищая работника от поражения током.","qr":"На крыше или в другом влажном/уличном месте электроинструмент следует включать в:","optsr":["Удлинитель без земли","Цепь с GFCI-защитой","Клеммы разъединителя","Любую розетку"],"qs":"En una azotea u otra ubicacion humeda/exterior, las herramientas electricas deben conectarse a:","optss":["Un cable de extension sin tierra","Un circuito protegido por GFCI","Las terminales del desconectador","Cualquier tomacorriente"],"rs":"La proteccion GFCI en ubicaciones humedas/exteriores corta la energia ante una falla a tierra en milisegundos, protegiendo al trabajador de la electrocucion."},
  {"id":490,"sec":"Safety & Field Practices","q":"The 'ABC' of a personal fall-arrest system stands for Anchorage, Body harness, and:","opts":["Battery","Connector (lanyard/lifeline)","Compressor","Conduit"],"correct":1,"re":"A personal fall-arrest system needs an Anchorage point, a full-Body harness, and a Connector (lanyard/SRL/lifeline) - all three rated and used correctly.","rr":"Системе защиты от падения нужны точка анкеровки (Anchorage), полная привязь (Body harness) и соединитель (Connector - строп/SRL/линь) - все три рассчитаны и правильно применены.","qr":"'ABC' системы защиты от падения - это Anchorage (анкер), Body harness (страховочная привязь) и:","optsr":["Battery (батарея)","Connector (строп/линь)","Compressor (компрессор)","Conduit (кабель-канал)"],"qs":"El 'ABC' de un sistema personal de detencion de caidas (fall-arrest) significa Anclaje (Anchorage), Arnes de cuerpo (Body harness) y:","optss":["Bateria (Battery)","Conector (Connector) (cordon/cuerda de vida)","Compresor (Compressor)","Conducto (Conduit)"],"rs":"Un sistema personal de detencion de caidas necesita un punto de Anclaje, un arnes de cuerpo completo (Body) y un Conector (cordon/SRL/cuerda de vida), los tres clasificados y usados correctamente."},
  {"id":491,"sec":"Safety & Field Practices","q":"Open floor or roof holes and skylights on a jobsite must be:","opts":["Left open","Guarded with a cover or guardrail to prevent falls","Marked with paint only","Filled with refrigerant"],"correct":1,"re":"Skylights and floor/roof openings are fall hazards; protect them with a secured, load-rated cover or guardrails, and label covers.","rr":"Световые люки и проёмы в полу/крыше - опасность падения; защищайте их закреплённой, нагрузочно-рассчитанной крышкой или ограждениями и маркируйте крышки.","qr":"Открытые проёмы в полу/крыше и световые люки на объекте должны быть:","optsr":["Оставлены открытыми","Защищены крышкой или ограждением для предотвращения падения","Только помечены краской","Заполнены хладагентом"],"qs":"Los agujeros abiertos en pisos o techos y los tragaluces en una obra deben estar:","optss":["Dejados abiertos","Protegidos con una cubierta o baranda para prevenir caidas","Marcados solo con pintura","Rellenos con refrigerante"],"rs":"Los tragaluces y las aberturas de piso/techo son peligros de caida; protejalos con una cubierta asegurada y clasificada para carga o con barandas, y etiquete las cubiertas."},
  {"id":492,"sec":"Safety & Field Practices","q":"Disturbing painted surfaces in a home built before 1978 may release lead, so the technician should:","opts":["Burn the paint off","Ignore it","Sand it dry freely","Follow lead-safe (RRP) work practices and contain dust"],"correct":3,"re":"Pre-1978 paint may contain lead; use lead-safe renovation practices (containment, wet methods, cleanup) and proper certification when disturbing it.","rr":"Краска до 1978 может содержать свинец; применяйте lead-safe методы ремонта (сдерживание, влажные методы, уборка) и нужную сертификацию при её нарушении.","qr":"Нарушение окрашенных поверхностей в доме, построенном до 1978, может высвободить свинец, поэтому техник должен:","optsr":["Выжигать краску","Игнорировать","Свободно шлифовать насухо","Соблюдать lead-safe (RRP) практики и сдерживать пыль"],"qs":"Alterar superficies pintadas en una vivienda construida antes de 1978 puede liberar plomo, por lo que el tecnico debe:","optss":["Quemar la pintura para retirarla","Ignorarlo","Lijarla en seco libremente","Seguir practicas de trabajo seguras con plomo (RRP) y contener el polvo"],"rs":"La pintura anterior a 1978 puede contener plomo; use practicas de renovacion seguras con plomo (contencion, metodos humedos, limpieza) y la certificacion adecuada al alterarla."},
  {"id":493,"sec":"Safety & Field Practices","q":"If a CO alarm sounds and occupants have symptoms, the correct immediate action is to:","opts":["Silence the alarm","Open a window and keep working","Evacuate occupants to fresh air, then ventilate and find the source","Run the furnace harder"],"correct":2,"re":"Carbon monoxide is life-threatening; get everyone to fresh air first, call for help if symptomatic, then shut down the suspect appliance and diagnose the source.","rr":"Угарный газ опасен для жизни; сначала выведите всех на свежий воздух, при симптомах вызовите помощь, затем отключите подозрительный прибор и найдите источник.","qr":"Если сработал CO-сигнализатор и у людей есть симптомы, правильное немедленное действие:","optsr":["Заглушить сигнализатор","Открыть окно и продолжать работать","Вывести людей на свежий воздух, затем проветрить и найти источник","Сильнее гонять печь"],"qs":"Si una alarma de CO suena y los ocupantes tienen sintomas, la accion inmediata correcta es:","optss":["Silenciar la alarma","Abrir una ventana y seguir trabajando","Evacuar a los ocupantes al aire fresco, luego ventilar y encontrar la fuente","Hacer funcionar el calefactor (furnace) con mas fuerza"],"rs":"El monoxido de carbono es mortal; lleve primero a todos al aire fresco, pida ayuda si hay sintomas, luego apague el aparato sospechoso y diagnostique la fuente."},
  {"id":494,"sec":"Safety & Field Practices","q":"A digital multimeter used for measuring on building power should carry a CAT rating that:","opts":["Is always CAT I","Is the cheapest","Does not matter","Matches or exceeds the circuit's category (e.g., CAT III for distribution)"],"correct":3,"re":"The CAT (measurement category) rating ensures the meter can safely handle transient overvoltages on that circuit; using an underrated meter risks arc-flash injury.","rr":"Рейтинг CAT (категория измерения) гарантирует, что прибор безопасно выдержит переходные перенапряжения этой цепи; недостаточный рейтинг грозит травмой от дугового разряда.","qr":"Цифровой мультиметр для измерений на сетевом питании здания должен иметь CAT-рейтинг, который:","optsr":["Всегда CAT I","Самый дешёвый","Неважен","Соответствует или выше категории цепи (например CAT III для распределения)"],"qs":"Un multimetro digital usado para mediciones en la alimentacion del edificio debe tener una clasificacion CAT que:","optss":["Siempre sea CAT I","Sea la mas barata","No importa","Coincida o supere la categoria del circuito (por ejemplo, CAT III para distribucion)"],"rs":"La clasificacion CAT (categoria de medicion) asegura que el medidor pueda manejar de forma segura las sobretensiones transitorias en ese circuito; usar un medidor subclasificado arriesga lesiones por arco electrico (arc-flash)."},
  {"id":495,"sec":"Safety & Field Practices","q":"Lithium-ion power-tool batteries should be:","opts":["Charged on flammable surfaces","Punctured to test them","Thrown in water","Kept from damage/heat and charged with the correct charger; damaged packs removed from service"],"correct":3,"re":"Damaged, overheated, or improperly charged Li-ion packs can vent or catch fire; use the right charger, avoid heat/impact, and dispose of damaged packs safely.","rr":"Повреждённые, перегретые или неправильно заряженные Li-ion могут воспламениться; используйте верное зарядное, берегите от жара/удара и безопасно утилизируйте повреждённые.","qr":"Литий-ионные аккумуляторы электроинструмента следует:","optsr":["Заряжать на горючих поверхностях","Прокалывать для проверки","Бросать в воду","Беречь от повреждений/жара и заряжать правильным зарядным; повреждённые - выводить из эксплуатации"],"qs":"Las baterias de iones de litio para herramientas electricas deben:","optss":["Cargarse sobre superficies inflamables","Perforarse para probarlas","Arrojarse al agua","Mantenerse alejadas de danos/calor y cargarse con el cargador correcto; los paquetes danados deben retirarse de servicio"],"rs":"Los paquetes de iones de litio danados, sobrecalentados o cargados incorrectamente pueden liberar gases o incendiarse; use el cargador correcto, evite el calor/impacto y deseche los paquetes danados de forma segura."},
  {"id":496,"sec":"Safety & Field Practices","q":"On a GHS chemical label, the 'flame' pictogram indicates the product is:","opts":["Heavy","Flammable","Cold","Toxic"],"correct":1,"re":"GHS pictograms convey hazards at a glance: the flame means flammable, the skull-and-crossbones means acutely toxic, the exploding-bomb means explosive, etc.","rr":"GHS-пиктограммы передают опасности с первого взгляда: пламя - горюч, череп с костями - остротоксичен, взрывающаяся бомба - взрывоопасен и т.д.","qr":"На GHS-этикетке химиката пиктограмма 'пламя' указывает, что продукт:","optsr":["Тяжёлый","Горюч","Холодный","Токсичен"],"qs":"En una etiqueta quimica GHS, el pictograma de la 'llama' indica que el producto es:","optss":["Pesado","Inflamable","Frio","Toxico"],"rs":"Los pictogramas GHS transmiten los peligros de un vistazo: la llama significa inflamable, la calavera con huesos cruzados significa toxicidad aguda, la bomba explotando significa explosivo, etc."},
  {"id":497,"sec":"Safety & Field Practices","q":"First aid for a minor burn from hot metal or a torch is to:","opts":["Rub it with flux","Cool the burn with running water and cover it; do not break blisters","Apply ice directly and pop blisters","Ignore it"],"correct":1,"re":"Cool a thermal burn with cool (not ice-cold) running water, cover loosely, and avoid breaking blisters; seek medical care for serious burns.","rr":"Охладите термический ожог прохладной (не ледяной) проточной водой, неплотно прикройте и не вскрывайте пузыри; при серьёзных ожогах обратитесь за медпомощью.","qr":"Первая помощь при лёгком ожоге горячим металлом или горелкой:","optsr":["Натереть флюсом","Охладить ожог проточной водой и прикрыть; не вскрывать пузыри","Прикладывать лёд напрямую и вскрывать пузыри","Игнорировать"],"qs":"Los primeros auxilios para una quemadura menor por metal caliente o una antorcha consisten en:","optss":["Frotarla con fundente (flux)","Enfriar la quemadura con agua corriente y cubrirla; no reventar las ampollas","Aplicar hielo directamente y reventar las ampollas","Ignorarla"],"rs":"Enfrie una quemadura termica con agua corriente fria (no helada), cubrala sin apretar y evite reventar las ampollas; busque atencion medica para quemaduras graves."},
  {"id":498,"sec":"Safety & Field Practices","q":"Safe ladder use requires maintaining three points of contact and:","opts":["Facing the ladder while climbing, not overreaching","Climbing with both hands full","Facing away from the ladder","Standing on the top rung"],"correct":0,"re":"Keep three points of contact, face the ladder, keep your belt buckle between the rails (no overreaching), and never stand on the top cap/rung.","rr":"Сохраняйте три точки контакта, держитесь лицом к лестнице, пряжка ремня между стойками (без перетягивания) и никогда не стойте на верхней крышке/ступени.","qr":"Безопасное использование лестницы требует сохранять три точки контакта и:","optsr":["Подниматься лицом к лестнице, не перетягиваясь вбок","Лезть с занятыми обеими руками","Стоять спиной к лестнице","Стоять на верхней ступени"],"qs":"El uso seguro de escaleras requiere mantener tres puntos de contacto y:","optss":["Mirar hacia la escalera al subir, sin estirarse en exceso","Subir con ambas manos ocupadas","Mirar en direccion contraria a la escalera","Pararse en el peldano superior"],"rs":"Mantenga tres puntos de contacto, mire hacia la escalera, mantenga la hebilla del cinturon entre los rieles (sin estirarse en exceso) y nunca se pare en la tapa/peldano superior."},
  {"id":499,"sec":"Safety & Field Practices","q":"Ladders and materials carried on a vehicle rack must be:","opts":["Stacked above the legal height","Properly secured/tied down so they cannot shift or fall in transit","Left untied for quick access","Loosely placed"],"correct":1,"re":"Unsecured loads can fall off and cause crashes or injuries; tie down ladders and materials and check the straps before driving.","rr":"Незакреплённый груз может упасть и вызвать аварию или травмы; привязывайте лестницы и материалы и проверяйте стяжки перед поездкой.","qr":"Лестницы и материалы на багажнике автомобиля должны быть:","optsr":["Сложены выше допустимой высоты","Надёжно закреплены/привязаны, чтобы не сместились и не упали в пути","Оставлены непривязанными для быстрого доступа","Свободно положены"],"qs":"Las escaleras y los materiales transportados en un portaequipajes de vehiculo deben estar:","optss":["Apilados por encima de la altura legal","Debidamente asegurados/amarrados para que no puedan moverse ni caer durante el transporte","Dejados sin amarrar para acceso rapido","Colocados de forma suelta"],"rs":"Las cargas sin asegurar pueden caerse y causar choques o lesiones; amarre las escaleras y los materiales y revise las correas antes de conducir."},
  {"id":500,"sec":"Safety & Field Practices","q":"If a job cannot be completed safely with the available tools, PPE, or conditions, the correct action is to:","opts":["Remove the safety guards","Rush to finish anyway","Skip the PPE","Stop work, address the hazard, and get the right equipment/help before continuing"],"correct":3,"re":"Production never justifies an unsafe shortcut; every worker can and should stop work to correct a hazard, obtain proper PPE/equipment, and follow the SDS and codes.","rr":"Выработка никогда не оправдывает небезопасный обход; любой работник может и должен остановить работу, устранить опасность, получить нужные СИЗ/оборудование и соблюдать SDS и нормы.","qr":"Если работу нельзя выполнить безопасно с имеющимися инструментами, СИЗ или условиями, правильное действие:","optsr":["Снять защитные ограждения","Всё равно спешно закончить","Пропустить СИЗ","Остановить работу, устранить опасность и получить нужное оборудование/помощь до продолжения"],"qs":"Si un trabajo no puede completarse de forma segura con las herramientas, el PPE o las condiciones disponibles, la accion correcta es:","optss":["Retirar las protecciones de seguridad","Apresurarse a terminar de todos modos","Omitir el PPE","Detener el trabajo, atender el peligro y conseguir el equipo/ayuda adecuados antes de continuar"],"rs":"La produccion nunca justifica un atajo inseguro; todo trabajador puede y debe detener el trabajo para corregir un peligro, obtener el PPE/equipo adecuado y seguir la SDS y los codigos."}
];
